AbsenceModal:
function AbsenceModal({emp, onSave, onClose}){
  const ABSENCE_TYPES=(()=>{
    try{
      const s=JSON.parse(localStorage.getItem('jsr_absence_types_v1')||'null');
      if(s&&s.length>0) return Object.fromEntries(s.filter(t=>t.active).map(t=>[t.id,{label:t.label,color:t.color,bg:t.bg||t.color+'22',icon:t.icon,paid:t.paid!==false}]));
    }catch(e){}
    return {sick:{label:'Krank',color:'var(--red)',bg:'rgba(239,68,68,.15)',icon:'🤒'},vacation:{label:'Urlaub',color:'var(--amber)',bg:'rgba(245,158,11,.15)',icon:'🏖'},unpaid:{label:'Unbezahlt',color:'var(--muted)',bg:'rgba(107,114,128,.15)',icon:'⏸'}};
  })();
  const [absences, setAbsences]=useState(emp.absences||[]);
  const [selType, setSelType]=useState('sick');
  const [note, setNote]=useState('');
  const [paid, setPaid]=useState(true);
  const [viewDate, setViewDate]=useState(new Date());
  const [activeTab, setActiveTab]=useState('calendar'); // calendar | summary

  const year=viewDate.getFullYear();
  const month=viewDate.getMonth();
  const firstDay=new Date(year,month,1);
  const lastDay=new Date(year,month+1,0);
  const startDow=(firstDay.getDay()+6)%7;
  const days=[];
  for(let i=0;i<startDow;i++)days.push(null);
  for(let d=1;d<=lastDay.getDate();d++)days.push(new Date(year,month,d));

  // Yearly stats
  const currentYear = new Date().getFullYear();
  const yearAbsences = absences.filter(a=>new Date(a.date).getFullYear()===currentYear);
  const vacationDays = yearAbsences.filter(a=>a.type==='vacation').length;
  const sickDays = yearAbsences.filter(a=>a.type==='sick').length;
  const unpaidDays = yearAbsences.filter(a=>a.type==='unpaid'&&a.paid===false).length;
  const paidAbsenceDays = yearAbsences.filter(a=>a.type==='unpaid'&&a.paid!==false).length;
  const vacationQuota = emp.vacation_days_quota || 20;
  const vacationLeft = vacationQuota - vacationDays;

  function getAbsence(d){
    if(!d)return null;
    return absences.find(a=>a.date===d.toISOString().slice(0,10));
  }

  function toggleDay(d){
    if(!d)return;
    const dateStr=d.toISOString().slice(0,10);
    const existing=absences.find(a=>a.date===dateStr);
    if(existing){
      if(existing.type===selType){setAbsences(prev=>prev.filter(a=>a.date!==dateStr));}
      else{setAbsences(prev=>prev.map(a=>a.date===dateStr?{...a,type:selType,note,paid}:a));}
    } else {
      setAbsences(prev=>[...prev,{id:'a'+Date.now(),type:selType,date:dateStr,note,paid}]);
    }
  }

  const warnings=analyzeAbsences(absences);
  const DOW=['Mo','Di','Mi','Do','Fr','Sa','So'];
  const todayStr=new Date().toISOString().slice(0,10);

  // Month summary
  const monthAbs = absences.filter(a=>{
    const d=new Date(a.date);
    return d.getMonth()===month&&d.getFullYear()===year;
  });

  // All years in absences
  const years = [...new Set(absences.map(a=>new Date(a.date).getFullYear()))].sort().reverse();
  if(!years.includes(currentYear)) years.unshift(currentYear);

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:680}}>
        <div className="modal-header">
          <div>
            <span className="modal-title">📅 Abwesenheiten — {emp.first_name} {emp.last_name}</span>
            <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>{emp.position} · {emp.location}</div>
          </div>
          <button className="btn" onClick={onClose}>×</button>
        </div>

        {/* Tabs */}
        <div style={{display:'flex',borderBottom:'1px solid var(--border)',background:'var(--surface)',flexShrink:0}}>
          {[['calendar','📅 Kalender'],['summary','📊 Jahresübersicht']].map(([k,l])=>(
            <button key={k} onClick={()=>setActiveTab(k)}
              style={{padding:'10px 18px',background:'none',border:'none',cursor:'pointer',fontSize:13,fontWeight:500,color:activeTab===k?'var(--blue)':'var(--muted)',borderBottom:activeTab===k?'2px solid var(--blue)':'2px solid transparent',fontFamily:'var(--font-body)'}}>
              {l}
            </button>
          ))}
        </div>

        <div className="modal-body">
          {/* Warnings */}
          {warnings.map((w,i)=>(
            <div key={i} className={`warn-box ${w.level==='red'?'warn-red':'warn-amber'}`} style={{marginBottom:8,padding:'8px 12px'}}>
              <span style={{fontSize:12,fontWeight:500,color:w.level==='red'?'var(--red)':'var(--amber)'}}>{w.msg}</span>
            </div>
          ))}

          {activeTab==='calendar'&&(<>
            {/* Type selector */}
            <div style={{display:'flex',gap:8,marginBottom:12,alignItems:'center',flexWrap:'wrap'}}>
              <span style={{fontSize:12,color:'var(--muted)'}}>Typ:</span>
              {Object.entries(ABSENCE_TYPES).map(([k,v])=>(
                <button key={k} className={`btn btn-sm ${selType===k?'btn-primary':''}`}
                  style={{background:selType===k?v.bg:'transparent',color:selType===k?v.color:'var(--muted)',borderColor:selType===k?v.color:'var(--border)'}}
                  onClick={()=>setSelType(k)}>{v.icon} {v.label}</button>
              ))}
              {selType==='unpaid'&&(
                <label style={{display:'flex',alignItems:'center',gap:6,fontSize:12,color:'var(--dim)',cursor:'pointer'}}>
                  <input type="checkbox" checked={paid} onChange={e=>setPaid(e.target.checked)} style={{accentColor:'var(--blue)'}}/>
                  Bezahlt
                </label>
              )}
              <input className="form-input" style={{flex:1,fontSize:12,padding:'4px 8px'}} placeholder="Notiz (optional)" value={note} onChange={e=>setNote(e.target.value)}/>
            </div>

            {/* Month navigation */}
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:8}}>
              <button className="btn btn-sm" onClick={()=>setViewDate(new Date(year,month-1,1))}>‹</button>
              <span style={{fontWeight:600,fontSize:14}}>{firstDay.toLocaleDateString('de-DE',{month:'long',year:'numeric'})}</span>
              <button className="btn btn-sm" onClick={()=>setViewDate(new Date(year,month+1,1))}>›</button>
            </div>

            {/* Calendar */}
            <div className="cal-grid">
              {DOW.map(d=><div key={d} style={{textAlign:'center',fontSize:10,fontWeight:600,color:'var(--muted)',padding:'2px 0'}}>{d}</div>)}
              {days.map((d,i)=>{
                if(!d)return<div key={'e'+i}/>;
                const absence=getAbsence(d);
                const dateStr=d.toISOString().slice(0,10);
                const dow=d.getDay();
                const isWeekend=dow===0||dow===6;
                const isToday=dateStr===todayStr;
                let absClass='';
                if(absence) absClass=absence.type;
                return(
                  <div key={dateStr}
                    className={`cal-day${absClass?' '+absClass:''}${isToday?' today':''}${isWeekend?' weekend':''}`}
                    onClick={()=>!isWeekend&&toggleDay(d)}
                    title={absence?`${ABSENCE_TYPES[absence.type]?.label}${absence.paid===false?' (unbezahlt)':absence.type==='unpaid'&&absence.paid?' (bezahlt)':''}${absence.note?': '+absence.note:''}`:''}>
                    <span style={{fontSize:12}}>{d.getDate()}</span>
                    {absence&&<span style={{fontSize:9}}>{ABSENCE_TYPES[absence.type]?.icon}{absence.type==='unpaid'?absence.paid?'💰':'❌':''}</span>}
                  </div>
                );
              })}
            </div>

            {/* Month summary */}
            <div style={{display:'flex',gap:10,marginTop:12,flexWrap:'wrap'}}>
              {Object.entries(ABSENCE_TYPES).map(([k,v])=>{
                const count=monthAbs.filter(a=>a.type===k).length;
                return count>0?<span key={k} style={{fontSize:11,padding:'2px 8px',borderRadius:4,background:v.bg,color:v.color}}>{v.icon} {count}x {v.label}</span>:null;
              })}
            </div>
          </>)}

          {activeTab==='summary'&&(<>
            {/* Year selector */}
            <div style={{display:'flex',gap:8,marginBottom:16,alignItems:'center'}}>
              <span style={{fontSize:12,color:'var(--muted)'}}>Jahr:</span>
              {years.map(y=>(
                <button key={y} className={`btn btn-sm ${y===currentYear?'btn-primary':''}`} style={{fontFamily:'var(--font-mono)'}}>{y}</button>
              ))}
            </div>

            {/* Vacation quota */}
            <div className="card" style={{marginBottom:12}}>
              <div className="card-header">
                <span className="card-title">🏖 Urlaubskontingent {currentYear}</span>
                <div style={{display:'flex',alignItems:'center',gap:8}}>
                  <span style={{fontSize:12,color:'var(--muted)'}}>Gesamt:</span>
                  <input type="number" style={{width:60,background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'3px 6px',color:'var(--text)',fontSize:12,fontFamily:'var(--font-mono)',outline:'none'}}
                    value={emp.vacation_days_quota||20}
                    onChange={e=>onSave({...emp,absences,vacation_days_quota:Number(e.target.value)},true)}/>
                  <span style={{fontSize:12,color:'var(--muted)'}}>Tage</span>
                </div>
              </div>
              <div className="card-body">
                <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:12,marginBottom:12}}>
                  {[
                    {label:'Gesamt',val:vacationQuota,color:'var(--muted)',icon:'📋'},
                    {label:'Verbraucht',val:vacationDays,color:'var(--amber)',icon:'✅'},
                    {label:'Verbleibend',val:Math.max(0,vacationLeft),color:vacationLeft<=5?'var(--red)':vacationLeft<=10?'var(--amber)':'var(--green)',icon:'🏖'},
                  ].map((k,i)=>(
                    <div key={i} style={{textAlign:'center',padding:'10px',background:'var(--surface)',borderRadius:'var(--r)',border:'1px solid var(--border)'}}>
                      <div style={{fontSize:10,color:'var(--muted)',marginBottom:4}}>{k.icon} {k.label}</div>
                      <div style={{fontSize:24,fontWeight:700,color:k.color,fontFamily:'var(--font-mono)'}}>{k.val}</div>
                      <div style={{fontSize:10,color:'var(--muted)'}}>Tage</div>
                    </div>
                  ))}
                </div>
                <div style={{marginBottom:4,display:'flex',justifyContent:'space-between',fontSize:11,color:'var(--muted)'}}>
                  <span>Verbraucht</span><span>{Math.round(vacationDays/vacationQuota*100)}%</span>
                </div>
                <div className="progress-track" style={{height:10}}>
                  <div className="progress-fill" style={{width:`${Math.min(vacationDays/vacationQuota*100,100)}%`,background:vacationLeft<=5?'var(--red)':vacationLeft<=10?'var(--amber)':'var(--green)'}}/>
                </div>
              </div>
            </div>

            {/* Annual stats */}
            <div style={{display:'grid',gridTemplateColumns:'repeat(2,1fr)',gap:10,marginBottom:12}}>
              {[
                {label:'🤒 Kranktage',val:sickDays,color:'var(--red)',sub:`${sickDays>10?'⚠️ Hoch':sickDays>5?'Mittel':'Normal'}`},
                {label:'⏸ Bezahlte Abwesenheit',val:paidAbsenceDays,color:'var(--blue)',sub:'Sonstiger bezahlter Ausfall'},
                {label:'❌ Unbezahlte Abwesenheit',val:unpaidDays,color:'var(--muted)',sub:'Kein Lohn, kein Umsatz'},
                {label:'📅 Gesamt Ausfalltage',val:sickDays+vacationDays+unpaidDays+paidAbsenceDays,color:'var(--amber)',sub:`von ${Math.round(52*5*0.9)} Arbeitstagen/Jahr`},
              ].map((k,i)=>(
                <div key={i} style={{padding:'10px 14px',background:'var(--surface)',borderRadius:'var(--r)',border:'1px solid var(--border)'}}>
                  <div style={{fontSize:11,color:'var(--muted)',marginBottom:4}}>{k.label}</div>
                  <div style={{fontSize:22,fontWeight:700,color:k.color,fontFamily:'var(--font-mono)'}}>{k.val} <span style={{fontSize:12,fontWeight:400}}>Tage</span></div>
                  <div style={{fontSize:10,color:'var(--muted)',marginTop:2}}>{k.sub}</div>
                </div>
              ))}
            </div>

            {/* Monthly breakdown */}
            <div className="card">
              <div className="card-header"><span className="card-title">Monatliche Aufstellung {currentYear}</span></div>
              <table>
                <thead><tr>
                  <th>Monat</th><th>🤒 Krank</th><th>🏖 Urlaub</th><th>⏸ Bezahlt</th><th>❌ Unbezahlt</th><th>Gesamt</th>
                </tr></thead>
                <tbody>
                  {Array.from({length:12},(_,mi)=>{
                    const moAbs=absences.filter(a=>{const d=new Date(a.date);return d.getMonth()===mi&&d.getFullYear()===currentYear;});
                    const sick=moAbs.filter(a=>a.type==='sick').length;
                    const vac=moAbs.filter(a=>a.type==='vacation').length;
                    const unpaidP=moAbs.filter(a=>a.type==='unpaid'&&a.paid!==false).length;
                    const unpaidU=moAbs.filter(a=>a.type==='unpaid'&&a.paid===false).length;
                    const total=sick+vac+unpaidP+unpaidU;
                    const isCurrentMonth=mi===new Date().getMonth()&&currentYear===new Date().getFullYear();
                    return(
                      <tr key={mi} style={{background:isCurrentMonth?'rgba(59,130,246,.06)':'transparent',fontWeight:isCurrentMonth?600:400}}>
                        <td style={{fontSize:12}}>{new Date(currentYear,mi,1).toLocaleDateString('de-DE',{month:'long'})}{isCurrentMonth?' ◀':''}</td>
                        <td style={{fontFamily:'var(--font-mono)',color:sick>0?'var(--red)':'var(--muted)',fontWeight:sick>0?600:400}}>{sick||'—'}</td>
                        <td style={{fontFamily:'var(--font-mono)',color:vac>0?'var(--amber)':'var(--muted)'}}>{vac||'—'}</td>
                        <td style={{fontFamily:'var(--font-mono)',color:unpaidP>0?'var(--blue)':'var(--muted)'}}>{unpaidP||'—'}</td>
                        <td style={{fontFamily:'var(--font-mono)',color:unpaidU>0?'var(--muted)':'var(--muted)'}}>{unpaidU||'—'}</td>
                        <td style={{fontFamily:'var(--font-mono)',fontWeight:total>0?600:400,color:total>5?'var(--red)':total>2?'var(--amber)':'var(--text)'}}>{total||'—'}</td>
                      </tr>
                    );
                  })}
                  <tr style={{borderTop:'2px solid var(--border2)',background:'var(--surface)',fontWeight:700}}>
                    <td style={{fontSize:12}}>Gesamt {currentYear}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--red)'}}>{sickDays}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--amber)'}}>{vacationDays}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--blue)'}}>{paidAbsenceDays}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--muted)'}}>{unpaidDays}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--amber)',fontWeight:700}}>{sickDays+vacationDays+paidAbsenceDays+unpaidDays}</td>
                  </tr>
                </tbody>
              </table>
            </div>
          </>)}
        </div>

        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Abbrechen</button>
          <button className="btn btn-primary" onClick={()=>onSave({...emp,absences})}>Speichern</button>
        </div>
      </div>
    </div>
  );
}

// ── Employee Form Modal ───────────────────────────────────

BonusModal:
function BonusModal({emp, onSave, onClose}){
  const [bonuses, setBonuses]=useState(emp.bonuses||[]);
  const [form, setForm]=useState({type:'einmalig',amount:'',reason:'',date:new Date().toISOString().slice(0,10)});
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));

  function addBonus(){
    if(!form.amount||!form.reason) return;
    setBonuses(b=>[...b,{id:'b'+Date.now(),...form,amount:Number(form.amount)}]);
    setForm({type:'einmalig',amount:'',reason:'',date:new Date().toISOString().slice(0,10)});
  }

  const totalBonus=bonuses.reduce((s,b)=>s+Number(b.amount||0),0);

  return(
    <div className="modal-overlay">
      <div className="modal modal-sm" style={{width:520}}>
        <div className="modal-header"><span className="modal-title">💰 Bonus — {emp.first_name} {emp.last_name}</span><button className="btn" onClick={onClose}>×</button></div>
        <div className="modal-body">
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8,marginBottom:10}}>
            <div className="form-group"><label className="form-label">Typ</label>
              <select className="form-select" value={form.type} onChange={e=>set('type',e.target.value)}>
                {['einmalig','stündlich','täglich','wöchentlich','monatlich'].map(t=><option key={t}>{t}</option>)}
              </select>
            </div>
            <div className="form-group"><label className="form-label">Betrag (€)</label>
              <input className="form-input" type="number" value={form.amount} onChange={e=>set('amount',e.target.value)} placeholder="z.B. 150"/>
            </div>
          </div>
          <div className="form-group" style={{marginBottom:10}}>
            <label className="form-label">Grund</label>
            <input className="form-input" value={form.reason} onChange={e=>set('reason',e.target.value)} placeholder="z.B. Sales Ziel erreicht, Bestes QA Ergebnis..."/>
          </div>
          <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:8,marginBottom:16}}>
            <div className="form-group"><label className="form-label">Datum</label><input className="form-input" type="date" value={form.date} onChange={e=>set('date',e.target.value)}/></div>
            <div style={{display:'flex',alignItems:'flex-end'}}><button className="btn btn-green" onClick={addBonus}>+ Hinzufügen</button></div>
          </div>
          <div style={{borderTop:'1px solid var(--border)',paddingTop:12}}>
            <div style={{display:'flex',justifyContent:'space-between',marginBottom:8}}>
              <span style={{fontSize:12,fontWeight:600,color:'var(--muted)'}}>BONUS-HISTORY</span>
              <span style={{fontSize:13,fontWeight:700,color:'var(--green)',fontFamily:'var(--font-mono)'}}>{totalBonus.toLocaleString('de-DE')} € gesamt</span>
            </div>
            {bonuses.length===0&&<div style={{color:'var(--muted)',fontSize:12}}>Noch keine Boni</div>}
            {[...bonuses].reverse().map(b=>(
              <div key={b.id} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'7px 0',borderBottom:'1px solid var(--border)'}}>
                <div>
                  <div style={{fontSize:13}}>{b.reason}</div>
                  <div style={{fontSize:11,color:'var(--muted)'}}>{b.type} · {new Date(b.date).toLocaleDateString('de-DE')}</div>
                </div>
                <div style={{display:'flex',alignItems:'center',gap:8}}>
                  <span style={{fontFamily:'var(--font-mono)',fontWeight:600,color:'var(--green)'}}>{Number(b.amount).toLocaleString('de-DE')} €</span>
                  <button className="btn btn-sm" onClick={()=>setBonuses(bs=>bs.filter(x=>x.id!==b.id))} style={{color:'var(--red)',padding:'2px 6px'}}>×</button>
                </div>
              </div>
            ))}
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Abbrechen</button>
          <button className="btn btn-primary" onClick={()=>onSave({...emp,bonuses})}>Speichern</button>
        </div>
      </div>
    </div>
  );
}

