ReferralModal:
function ReferralModal({emp, employees, onSave, onClose}){
  const [referrals, setReferrals] = useState(emp.referrals||[]);
  const [form, setForm] = useState({
    referred_name:'', referred_id:'', status:'cv_received',
    bonus_amount:'', date:new Date().toISOString().slice(0,10),
    tranche1_paid:false, tranche2_paid:false,
    tranche1_month:1, tranche2_month:4,
    tranche1_pct:50, tranche2_pct:50,
  });
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));

  // Load referral config
  const cfg=(()=>{try{return JSON.parse(localStorage.getItem('jsr_referral_config_v1')||'null')||REFERRAL_CONFIG_DEFAULT;}catch(e){return {tranche1_pct:50,tranche1_month:1,tranche2_pct:50,tranche2_month:4};}})();

  function calcTranche(ref, tranche){
    const totalBonus=parseFloat(ref.bonus_amount||0);
    const pct=tranche===1?cfg.tranche1_pct:cfg.tranche2_pct;
    return Math.round(totalBonus*pct/100*100)/100;
  }

  function getReferredEmp(ref){
    return employees.find(e=>e.id===ref.referred_id||(e.first_name+' '+e.last_name)===ref.referred_name);
  }

  function getActiveMonths(emp2){
    if(!emp2||emp2.status!=='active') return 0;
    const startDate=emp2.training_end||emp2.training_start;
    if(!startDate) return 0;
    const diff=new Date()-new Date(startDate);
    return Math.floor(diff/(1000*60*60*24*30));
  }

  function trancheStatus(ref, tranche){
    const refEmp=getReferredEmp(ref);
    const months=getActiveMonths(refEmp);
    const targetMonth=tranche===1?cfg.tranche1_month:cfg.tranche2_month;
    const paid=tranche===1?ref.tranche1_paid:ref.tranche2_paid;
    if(paid) return {status:"paid",label:"Ausgezahlt ✓",color:"var(--green)"};
    if(!refEmp||refEmp.status!=="active") return {status:"blocked",label:"Referral nicht aktiv",color:"var(--red)"};
    if(months>=targetMonth) return {status:"due",label:"Fällig — Monat "+months+" aktiv",color:"var(--amber)"};
    return {status:"pending",label:"Ausstehend — Monat "+(targetMonth-months)+" noch",color:"var(--muted)"};
  }

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:580}}>
        <div className="modal-header">
          <div style={{fontSize:15,fontWeight:700}}>Referrals — {emp.first_name} {emp.last_name}</div>
          <button className="btn" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          <div style={{padding:'10px 12px',background:'var(--blue-bg)',borderRadius:'var(--r-md)',marginBottom:14,fontSize:12,color:'var(--blue)'}}>
            Tranche 1: {cfg.tranche1_pct}% nach Monat {cfg.tranche1_month} aktiv · Tranche 2: {cfg.tranche2_pct}% nach Monat {cfg.tranche2_month} aktiv
          </div>

          {/* Existing referrals */}
          {referrals.length>0&&(
            <div style={{marginBottom:16}}>
              {referrals.map((ref,i)=>{
                const t1=trancheStatus(ref,1);
                const t2=trancheStatus(ref,2);
                const total=parseFloat(ref.bonus_amount||0);
                return(
                  <div key={i} style={{padding:'10px 12px',border:'1px solid var(--border)',borderRadius:'var(--r-md)',marginBottom:8}}>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:6}}>
                      <div style={{fontWeight:600,fontSize:13}}>{ref.referred_name}</div>
                      <div style={{fontFamily:'var(--mono)',fontWeight:700}}>{total.toLocaleString('de-DE',{minimumFractionDigits:2})} €</div>
                    </div>
                    <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8}}>
                      {[1,2].map(t=>{
                        const ts=t===1?t1:t2;
                        const amt=calcTranche(ref,t);
                        const paid=t===1?ref.tranche1_paid:ref.tranche2_paid;
                        return(
                          <div key={t} style={{padding:'7px 10px',borderRadius:'var(--r)',
                            background:ts.status==='paid'?'var(--green-bg)':ts.status==='due'?'var(--amber-bg,#fef3c7)':'var(--surface-2)'}}>
                            <div style={{fontSize:10,fontWeight:700,color:ts.color,marginBottom:2}}>Tranche {t} — {amt.toLocaleString('de-DE',{minimumFractionDigits:2})} €</div>
                            <div style={{fontSize:11,color:ts.color}}>{ts.label}</div>
                            {ts.status==='due'&&!paid&&(
                              <button onClick={()=>{
                                const updated=[...referrals];
                                updated[i]={...ref,[t===1?'tranche1_paid':'tranche2_paid']:true,[t===1?'tranche1_paid_date':'tranche2_paid_date']:new Date().toISOString().slice(0,10)};
                                setReferrals(updated);
                              }} style={{marginTop:4,padding:'2px 8px',fontSize:10,borderRadius:4,border:'none',background:'var(--amber)',color:'white',cursor:'pointer',fontWeight:700}}>
                                Als ausgezahlt markieren
                              </button>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* New referral form */}
          <div style={{borderTop:'1px solid var(--border)',paddingTop:14}}>
            <div style={{fontSize:12,fontWeight:700,marginBottom:8}}>Neuen Referral hinzufügen</div>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Name des Referrals</label>
                <select className="form-select" value={form.referred_id||''} onChange={e=>{
                  const selEmp=employees.find(x=>x.id===e.target.value);
                  set('referred_id',e.target.value);
                  if(selEmp) set('referred_name',selEmp.first_name+' '+selEmp.last_name);
                }}>
                  <option value=''>Mitarbeiter wählen…</option>
                  {employees.filter(e=>e.id!==emp.id).map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Bonus Gesamt (€)</label>
                <input className="form-input" type="number" min="0" value={form.bonus_amount} onChange={e=>set('bonus_amount',e.target.value)} placeholder="z.B. 200"/>
              </div>
            </div>
            {form.bonus_amount>0&&(
              <div style={{fontSize:12,color:'var(--muted)',marginBottom:8,padding:'6px 10px',background:'var(--surface-2)',borderRadius:'var(--r)'}}>
                Tranche 1 ({cfg.tranche1_pct}%): {(form.bonus_amount*cfg.tranche1_pct/100).toFixed(2)} € nach Monat {cfg.tranche1_month} aktiv ·
                Tranche 2 ({cfg.tranche2_pct}%): {(form.bonus_amount*cfg.tranche2_pct/100).toFixed(2)} € nach Monat {cfg.tranche2_month} aktiv
              </div>
            )}
            <button className="btn btn-primary" onClick={()=>{
              if(!form.referred_name||!form.bonus_amount) return alert('Name und Bonus Pflicht');
              setReferrals(r=>[...r,{...form,tranche1_paid:false,tranche2_paid:false}]);
              setForm({referred_name:'',referred_id:'',status:'cv_received',bonus_amount:'',date:new Date().toISOString().slice(0,10),tranche1_paid:false,tranche2_paid:false,tranche1_pct:cfg.tranche1_pct,tranche2_pct:cfg.tranche2_pct,tranche1_month:cfg.tranche1_month,tranche2_month:cfg.tranche2_month});
            }}>+ Referral hinzufügen</button>
          </div>

          <div style={{display:'flex',gap:10,justifyContent:'flex-end',marginTop:16}}>
            <button className="btn" onClick={onClose}>Abbrechen</button>
            <button className="btn btn-primary" onClick={()=>onSave({...emp,referrals})}>Speichern</button>
          </div>
        </div>
      </div>
    </div>
  );
}

QualityModal:
function QualityModal({emp, onSave, onClose}){
  const [ratings, setRatings]=useState(emp.quality_ratings||[]);
  const [form, setForm]=useState({rating:'gut',note:'',date:new Date().toISOString().slice(0,10)});
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));

  function addRating(){
    setRatings(r=>[...r,{id:'q'+Date.now(),...form}]);
    setForm({rating:'gut',note:'',date:new Date().toISOString().slice(0,10)});
  }

  const q=qualityScore(ratings);
  const badCount=ratings.filter(r=>r.rating==='schlecht').length;

  return(
    <div className="modal-overlay">
      <div className="modal modal-sm" style={{width:500}}>
        <div className="modal-header"><span className="modal-title">⭐ Qualität — {emp.first_name} {emp.last_name}</span><button className="btn" onClick={onClose}>×</button></div>
        <div className="modal-body">
          {badCount>=3&&(
            <div className="warn-box warn-red" style={{marginBottom:12}}>
              <span style={{color:'var(--red)',fontWeight:600}}>🚨 {badCount} schlechte Bewertungen — Überwachung empfohlen!</span>
            </div>
          )}
          {q&&<div style={{display:'flex',gap:12,marginBottom:16,padding:12,background:'var(--surface)',borderRadius:'var(--r)',border:'1px solid var(--border)'}}>
            <div style={{textAlign:'center'}}>
              <div style={{fontSize:22,fontWeight:700,color:qualityColor(q)}}>{q.score>0?'+':''}{q.score}</div>
              <div style={{fontSize:10,color:'var(--muted)'}}>Score</div>
            </div>
            <div style={{textAlign:'center'}}>
              <div style={{fontSize:22,fontWeight:700,color:'var(--red)'}}>{q.bad}</div>
              <div style={{fontSize:10,color:'var(--muted)'}}>Schlecht</div>
            </div>
            <div style={{textAlign:'center'}}>
              <div style={{fontSize:22,fontWeight:700,color:'var(--muted)'}}>{q.total}</div>
              <div style={{fontSize:10,color:'var(--muted)'}}>Gesamt</div>
            </div>
          </div>}
          <div style={{display:'flex',gap:8,marginBottom:10}}>
            {Object.entries(QUALITY_RATINGS).map(([k,v])=>(
              <button key={k} className={`btn ${form.rating===k?'btn-primary':''}`} style={{flex:1,background:form.rating===k?v.bg:'transparent',color:form.rating===k?v.color:'var(--muted)',borderColor:form.rating===k?v.color:'var(--border)'}} onClick={()=>set('rating',k)}>
                {v.icon} {v.label}
              </button>
            ))}
          </div>
          <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:8,marginBottom:16}}>
            <div className="form-group"><label className="form-label">Notiz (Auftraggeber-Feedback)</label><input className="form-input" value={form.note} onChange={e=>set('note',e.target.value)} placeholder="z.B. Kundenzufriedenheit hoch..."/></div>
            <div className="form-group"><label className="form-label">Datum</label><input className="form-input" type="date" value={form.date} onChange={e=>set('date',e.target.value)}/></div>
          </div>
          <button className="btn btn-primary" onClick={addRating} style={{width:'100%',marginBottom:16}}>+ Bewertung hinzufügen</button>
          <div style={{borderTop:'1px solid var(--border)',paddingTop:12}}>
            {[...ratings].reverse().map(r=>(
              <div key={r.id} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'6px 0',borderBottom:'1px solid var(--border)'}}>
                <div>
                  <span style={{padding:'2px 7px',borderRadius:4,fontSize:11,fontWeight:600,background:QUALITY_RATINGS[r.rating]?.bg,color:QUALITY_RATINGS[r.rating]?.color}}>{QUALITY_RATINGS[r.rating]?.icon} {QUALITY_RATINGS[r.rating]?.label}</span>
                  <span style={{fontSize:12,color:'var(--dim)',marginLeft:8}}>{r.note}</span>
                </div>
                <div style={{display:'flex',gap:6,alignItems:'center'}}>
                  <span style={{fontSize:11,color:'var(--muted)'}}>{new Date(r.date).toLocaleDateString('de-DE')}</span>
                  <button className="btn btn-sm" onClick={()=>setRatings(rs=>rs.filter(x=>x.id!==r.id))} style={{color:'var(--red)',padding:'2px 6px'}}>×</button>
                </div>
              </div>
            ))}
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Abbrechen</button>
          <button className="btn btn-primary" onClick={()=>onSave({...emp,quality_ratings:ratings})}>Speichern</button>
        </div>
      </div>
    </div>
  );
}

