CommModal:
function CommModal({recipients, onClose}){
  const [channel, setChannel]=useState('email');
  const [msg, setMsg]=useState('');
  const [subject, setSubject]=useState('');

  function send(){
    if(channel==='email'){
      const mailto=`mailto:${recipients.map(r=>r.email).filter(Boolean).join(',')}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(msg)}`;
      window.open(mailto);
    } else if(channel==='whatsapp'){
      if(recipients.length===1){
        const phone=(recipients[0]?.phone||'').replace(/\D/g,'');
        window.open('https://wa.me/'+phone+'?text='+encodeURIComponent(msg));
      } else {
        // Multiple: open one by one
        recipients.forEach((r,i)=>setTimeout(()=>{
          const phone=(r.phone||'').replace(/\D/g,'');
          if(phone) window.open('https://wa.me/'+phone+'?text='+encodeURIComponent(msg));
        },i*500));
      }
    } else if(channel==='sms'){
      const phones=recipients.map(r=>r.phone).filter(Boolean).join(',');
      window.open(`sms:${phones}?body=${encodeURIComponent(msg)}`);
    }
  }

  const templates=[
    {label:'🎂 Geburtstag',text:'Liebe/r {name},\n\nherzliche Glückwünsche zu deinem Geburtstag! Wir wünschen dir einen wunderschönen Tag! 🎉\n\nDein JSR Team'},
    {label:'📢 Info',text:'Liebe Kolleginnen und Kollegen,\n\n'},
    {label:'✅ Schulung',text:'Liebe/r {name},\n\nbitte denke an die anstehende Schulung. Bei Fragen stehen wir dir gerne zur Verfügung.\n\nDein JSR Team'},
    {label:'⚠️ Feedback',text:'Liebe/r {name},\n\nwir möchten kurz mit dir über deine aktuelle Performance sprechen. Bitte melde dich bei uns.\n\nDein JSR Team'},
  ];

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:560}}>
        <div className="modal-header">
          <span className="modal-title">📨 Nachricht senden ({recipients.length} Empfänger)</span>
          <button className="btn" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          <div style={{display:'flex',gap:8,marginBottom:16}}>
            {[['email','✉️ E-Mail'],['whatsapp','💬 WhatsApp'],['sms','📱 SMS']].map(([k,l])=>(
              <button key={k} className={`btn ${channel===k?'btn-primary':''}`} style={{flex:1}} onClick={()=>setChannel(k)}>{l}</button>
            ))}
          </div>
          <div style={{marginBottom:12}}>
            <div style={{fontSize:11,color:'var(--muted)',marginBottom:6}}>Empfänger</div>
            <div style={{display:'flex',flexWrap:'wrap',gap:5}}>
              {recipients.map(r=>(
                <span key={r.id} style={{padding:'2px 8px',borderRadius:4,fontSize:11,background:'var(--blue-bg)',color:'var(--blue)'}}>
                  {r.first_name} {r.last_name}
                  {channel==='email'&&!r.email&&<span style={{color:'var(--red)',marginLeft:4}}>⚠ keine Mail</span>}
                  {channel==='whatsapp'&&!r.phone&&<span style={{color:'var(--red)',marginLeft:4}}>⚠ keine Tel</span>}
                </span>
              ))}
            </div>
          </div>
          <div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:12}}>
            {templates.map(t=>(
              <button key={t.label} className="btn btn-sm" onClick={()=>setMsg(t.text.replace(/{name}/g,recipients.length===1?recipients[0].first_name:'Team'))}>{t.label}</button>
            ))}
          </div>
          {channel==='email'&&(
            <div className="form-group" style={{marginBottom:10}}>
              <label className="form-label">Betreff</label>
              <input className="form-input" value={subject} onChange={e=>setSubject(e.target.value)} placeholder="Betreff eingeben..."/>
            </div>
          )}
          <div className="form-group" style={{marginBottom:16}}>
            <label className="form-label">Nachricht</label>
            <textarea className="form-input" rows={6} value={msg} onChange={e=>setMsg(e.target.value)} placeholder="Nachricht eingeben..." style={{resize:'vertical'}}/>
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Abbrechen</button>
          <button className="btn btn-primary" onClick={send}>
            {channel==='email'?'✉️ E-Mail öffnen':channel==='whatsapp'?'💬 WhatsApp öffnen':'📱 SMS öffnen'}
          </button>
        </div>
      </div>
    </div>
  );
}

