EmployeeList:
function EmployeeList({employees, projects, onEdit, onAdd, onAbsence, onBonus, onReferral, onQuality, onComm}){
  const [filter, setFilter] = useState('all');
  const [search, setSearch] = useState('');
  const [showTerminated, setShowTerminated] = useState(false);
  const [sortCol, setSortCol] = useState('last_name');
  const [sortDir, setSortDir] = useState('asc');
  const [projectFilter, setProjectFilter] = useState('all');

  function toggleSort(col){
    if(sortCol === col) setSortDir(d => d==='asc'?'desc':'asc');
    else { setSortCol(col); setSortDir('asc'); }
  }

  function sortIcon(col){
    if(sortCol !== col) return ' ↕';
    return sortDir === 'asc' ? ' ↑' : ' ↓';
  }

  const filtered = employees.filter(e => {
    if(!showTerminated && e.status==='terminated') return false;
    if(filter!=='all' && e.status!==filter) return false;
    if(projectFilter!=='all' && e.project_id!==projectFilter) return false;
    if(search){
      const q = search.toLowerCase();
      return (e.first_name+' '+e.last_name+' '+(e.position||'')).toLowerCase().includes(q);
    }
    return true;
  });

  const sorted = [...filtered].sort((a,b) => {
    let va, vb;
    const proj_a = projects.find(p=>p.id===a.project_id);
    const proj_b = projects.find(p=>p.id===b.project_id);
    switch(sortCol){
      case 'last_name':   va=a.last_name||''; vb=b.last_name||''; break;
      case 'position':    va=a.position||''; vb=b.position||''; break;
      case 'location':    va=a.location||''; vb=b.location||''; break;
      case 'status':      va=a.status||''; vb=b.status||''; break;
      case 'project':     va=proj_a?.name||''; vb=proj_b?.name||''; break;
      case 'language':    va=a.language_level||''; vb=b.language_level||''; break;
      case 'salary':
        va=(()=>{const r=parseFloat(a.hourly_rate||0),h=parseFloat(a.work_hours||8);return r>0?r*h*22:Number(a.Math.round(parseFloat(hourly_rate||0)*parseFloat(work_hours||8)*22)||0);})();
        vb=(()=>{const r=parseFloat(b.hourly_rate||0),h=parseFloat(b.work_hours||8);return r>0?r*h*22:Number(b.Math.round(parseFloat(hourly_rate||0)*parseFloat(work_hours||8)*22)||0);})();
        break;
      case 'sick':
        va=(a.absences||[]).filter(x=>x.type==='sick').length;
        vb=(b.absences||[]).filter(x=>x.type==='sick').length;
        break;
      case 'quality':
        const qa=qualityScore(a.quality_ratings||[]); va=qa?qa.score:-999;
        const qb=qualityScore(b.quality_ratings||[]); vb=qb?qb.score:-999;
        break;
      default: va=''; vb='';
    }
    if(typeof va==='number') return sortDir==='asc'?va-vb:vb-va;
    return sortDir==='asc'?va.localeCompare(vb):vb.localeCompare(va);
  });

  function exportExcel(){
    const rows = [
      ['Vorname','Nachname','Position','Standort','Status','Projekt','Sprache','Gehalt','Kranktage','Urlaubstage','Qualitätsscore'],
      ...sorted.map(e => {
        const proj = projects.find(p=>p.id===e.project_id);
        const q = qualityScore(e.quality_ratings||[]);
        const sick = (e.absences||[]).filter(a=>a.type==='sick').length;
        const vac = (e.absences||[]).filter(a=>a.type==='vacation').length;
        const salary = e.status==='terminated'?0:(()=>{const r=parseFloat(e.hourly_rate||0);const h=parseFloat(e.work_hours||8);return r>0?Math.round(r*h*22):Number(Math.round(parseFloat(e.hourly_rate||0)*parseFloat(e.work_hours||8)*22)||0);})();
        return [
          e.first_name||'',
          e.last_name||'',
          e.position||'',
          e.location||'',
          statusLabel(e.status),
          proj?.name||'',
          e.language_level||'',
          salary,
          sick,
          vac,
          q?q.score:''
        ];
      })
    ];

    // Build CSV with BOM for Excel German locale
    const bom = '\uFEFF';
    const csv = bom + rows.map(r =>
      r.map(v => {
        const s = String(v);
        return s.includes(',') || s.includes('"') || s.includes('\n')
          ? '"' + s.replace(/"/g, '""') + '"'
          : s;
      }).join(';')
    ).join('\n');

    const blob = new Blob([csv], {type:'text/csv;charset=utf-8'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    const filterLabel = filter==='all'?'Alle':statusLabel(filter);
    a.download = 'JSR_Mitarbeiter_'+filterLabel+'_'+new Date().toISOString().slice(0,10)+'.csv';
    a.click();
    URL.revokeObjectURL(url);
  }

  const thStyle = (col) => ({
    cursor:'pointer',
    userSelect:'none',
    whiteSpace:'nowrap',
    color: sortCol===col ? 'var(--blue)' : 'var(--muted)',
    fontWeight: sortCol===col ? 700 : 600,
  });

  const [importResult, setImportResult] = useState(null);

  function handleEmpImport(file,e){
    if(!file) return;
    const reader=new FileReader();
    reader.onload=ev=>{
      try{
        const wb=XLSX.read(new Uint8Array(ev.target.result),{type:'array',cellDates:true});
        const ws=wb.Sheets[wb.SheetNames[0]];
        const rows=XLSX.utils.sheet_to_json(ws,{header:1,defval:''});
        const imported=[];const errors=[];
        rows.slice(4).forEach((row,ri)=>{
          const fn=String(row[0]||'').trim();
          const ln=String(row[1]||'').trim();
          if(!fn&&!ln) return;
          if(!fn||!ln){errors.push('Zeile '+(ri+5)+': Vor/Nachname fehlt');return;}
          const dateStr=v=>v instanceof Date?v.toISOString().slice(0,10):String(v||'').slice(0,10);
          imported.push({
            id:'emp_'+Date.now()+'_'+ri+Math.random().toString(36).slice(2,6),
            status:'active',
            first_name:fn,last_name:ln,
            birthday:dateStr(row[2]),
            gender:String(row[3]||'m').trim().toLowerCase(),
            email:String(row[4]||'').trim(),
            phone:String(row[5]||'').trim(),
            city:String(row[6]||'').trim(),
            staff_number:String(row[7]||'').trim(),
            hire_date:dateStr(row[8]),
            contract_start:dateStr(row[9]),
            contract_end:dateStr(row[10]),
            contract:String(row[11]||'permanent').trim(),
            work_model:String(row[12]||'full_time').trim(),
            work_hours:String(row[13]||'8').trim(),
            hourly_rate:String(row[14]||'0').trim(),
            monthly_bonus:parseFloat(row[15])||0,
            location:String(row[16]||'al').trim(),
            position:String(row[17]||'').trim(),
            work_weekend:String(row[18]||'').toLowerCase()==='ja',
            work_holidays:String(row[19]||'').toLowerCase()==='ja',
            vacation_days_quota:parseInt(row[20])||20,
            productive_pct:parseInt(row[21])||80,
            project_id:String(row[22]||'').trim(),
            project_skill:String(row[23]||'').trim(),
            language_level:String(row[24]||'').trim(),
            writing_level:String(row[25]||'').trim(),
            assessed_level:String(row[24]||'').trim(),
            languages_str:String(row[26]||'').trim(),
            bank_name:String(row[27]||'').trim(),
            bank_account:String(row[28]||'').trim(),
            bank_holder:String(row[29]||'').trim(),
            bank_currency:String(row[30]||'ALL').trim(),
            id_number:String(row[31]||'').trim(),
            tax_id:String(row[32]||'').trim(),
            social_security:String(row[33]||'').trim(),
            health_insurance:String(row[34]||'').trim(),
            portal_password:String(row[35]||'1234').trim(),
            notes:'',warnings:[],certificates:[],hardware_devices:[],absences:[],referrals:[],quality_ratings:[],
          });
        });
        setImportResult({imported,errors,filename:file.name});
        if(e&&e.target) e.target.value='';
      }catch(err){alert('Fehler: '+err.message);}
    };
    reader.readAsArrayBuffer(file);
  }

  function confirmEmpImport(){
    if(!importResult) return;
    const existing=(employees||[]).filter(e=>
      !importResult.imported.find(i=>i.staff_number&&i.staff_number===e.staff_number)
    );
    const merged=[...existing,...importResult.imported];
    setEmployees(merged);
    localStorage.setItem('jsr_emp_v3',JSON.stringify(merged));
    setImportResult(null);
    alert(importResult.imported.length+' Mitarbeiter erfolgreich importiert!');
  }

  return(
    <div>
      <div style={{display:'flex',gap:8,marginBottom:14,flexWrap:'wrap',alignItems:'center'}}>
        <input
          style={{background:'var(--card)',border:'1px solid var(--border)',borderRadius:'var(--r)',
            padding:'6px 10px',color:'var(--text)',fontFamily:'var(--font-body)',fontSize:13,
            outline:'none',width:200}}
          placeholder="Suche…" value={search} onChange={e=>setSearch(e.target.value)}/>
        <button className={`btn btn-sm ${filter==='all'?'btn-primary':''}`} onClick={()=>setFilter('all')}>
          Alle ({employees.filter(e=>showTerminated||e.status!=='terminated').length})
        </button>
        <button className={`btn btn-sm ${filter==='active'?'btn-primary':''}`} onClick={()=>setFilter('active')}>⚡ Aktiv ({employees.filter(e=>e.status==='active').length})</button>
        <button className={`btn btn-sm ${filter==='training'?'btn-primary':''}`} onClick={()=>setFilter('training')}>📚 Schulung ({employees.filter(e=>e.status==='training').length})</button>
        <button className={`btn btn-sm ${filter==='training_planned'?'btn-primary':''}`} onClick={()=>setFilter('training_planned')}>📅 Geplant ({employees.filter(e=>e.status==='training_planned').length})</button>
        <button className={`btn btn-sm ${filter==='contract'?'btn-primary':''}`} onClick={()=>setFilter('contract')}>📝 Vertrag ({employees.filter(e=>e.status==='contract').length})</button>
        <button className={`btn btn-sm ${filter==='inactive'?'btn-primary':''}`} onClick={()=>setFilter('inactive')}>⏸ Inaktiv ({employees.filter(e=>e.status==='inactive').length})</button>
