// ── Quality Rating System ──────────────────────────────────
const QUALITY_RATINGS = {
  schlecht: {label:'Schlecht',color:'var(--red)',bg:'var(--red-bg)',icon:'👎',score:-1},
  gut: {label:'Gut',color:'var(--green)',bg:'var(--green-bg)',icon:'👍',score:1},
  super: {label:'Super',color:'var(--teal)',bg:'var(--teal-bg)',icon:'⭐',score:2},
};

function qualityScore(ratings){
  if(!ratings||ratings.length===0) return null;
  const s=ratings.reduce((sum,r)=>sum+(QUALITY_RATINGS[r.rating]?.score||0),0);
  return {score:s, bad:ratings.filter(r=>r.rating==='schlecht').length, total:ratings.length};
}
function qualityColor(q){
  if(!q) return 'var(--muted)';
  if(q.bad>=3) return 'var(--red)';
  if(q.score<0) return 'var(--amber)';
  if(q.score>=4) return 'var(--teal)';
  return 'var(--green)';
}

