TrainingPlans:
function TrainingPlans({plans, setPlans, projects, employees}){
  const [modal, setModal]=useState(null);
  function savePlan(form){if(form.id)setPlans(ps=>ps.map(p=>p.id===form.id?form:p));else setPlans(ps=>[...ps,{...form,id:'tp'+Date.now()}]);setModal(null);}
  return(
    <div>
      {modal&&<TrainingPlanModal plan={modal==='add'?null:modal} projects={projects} employees={employees} onSave={savePlan} onClose={()=>setModal(null)}/>}
      <div style={{display:'flex',justifyContent:'flex-end',marginBottom:16}}>
        <button className="btn btn-primary" onClick={()=>setModal('add')}>+ Schulung planen</button>
      </div>
      {plans.map(plan=>{
        const proj=projects.find(p=>p.id===plan.project_id);
        const confirmed=plan.confirmed_ids?.length||0;
        const open=plan.planned_count-confirmed;
        const progress=trainingProgress(plan);
        const d=daysUntil(plan.start_date);
        const warnLevel=open>0&&d!==null&&d>=0?(d<=7?'red':d<=14?'amber':null):null;
        const confirmedEmps=(plan.confirmed_ids||[]).map(id=>employees.find(e=>e.id===id)).filter(Boolean);
        return(
          <div key={plan.id}>
            {warnLevel&&(
              <div className={`warn-box warn-${warnLevel}`} style={{marginBottom:8}}>
                <div>
                  <div style={{fontWeight:600,color:warnLevel==='red'?'var(--red)':'var(--amber)'}}>{warnLevel==='red'?'🚨':'⚠️'} {plan.name} — noch {open} Plätze offen</div>
                  <div style={{fontSize:12,color:'var(--dim)',marginTop:1}}>Start in {d} Tagen ({fmtDate(plan.start_date)})</div>
                </div>
                <div style={{textAlign:'right'}}>
                  <div style={{fontSize:24,fontWeight:700,fontFamily:'var(--font-mono)',color:warnLevel==='red'?'var(--red)':'var(--amber)'}}>−{open}</div>
                </div>
              </div>
            )}
            <div className="card">
              <div className="card-header">
                <div><span className="card-title">{plan.name}</span><span style={{fontSize:11,color:'var(--muted)',marginLeft:8}}>{proj?.name} · {plan.mode}</span></div>
                <div style={{display:'flex',gap:8,alignItems:'center'}}>
                  {progress>=100&&<span className="badge badge-green">✓ Abgeschlossen</span>}
                  {progress>0&&progress<100&&<span className="badge badge-blue">▶ Läuft · {progress}%</span>}
                  {progress===0&&<span className="badge badge-amber">○ Geplant</span>}
                  <button className="btn btn-sm" onClick={()=>setModal(plan)}>✎</button>
                </div>
              </div>
              <div className="card-body">
                <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(200px,1fr)',gap:16,marginBottom:12}}>
                  <div><div style={{fontSize:11,color:'var(--muted)',marginBottom:2}}>Zeitraum</div><div style={{fontSize:12,fontWeight:500}}>{fmtDate(plan.start_date)} → {fmtDate(plan.end_date)}</div></div>
                  <div>
                    <div style={{fontSize:11,color:'var(--muted)',marginBottom:2}}>Teilnehmer</div>
                    <div style={{display:'flex',gap:6,alignItems:'center'}}>
                      <span style={{fontSize:18,fontWeight:700,color:'var(--green)',fontFamily:'var(--font-mono)'}}>{confirmed}</span>
                      <span style={{color:'var(--muted)',fontSize:13}}>/ {plan.planned_count}</span>
                      {open>0&&<span className="badge badge-red">−{open}</span>}
                    </div>
                  </div>
                  <div><div style={{fontSize:11,color:'var(--muted)',marginBottom:2}}>Skill-Fokus</div><div style={{fontSize:12}}>{plan.skill_focus||'—'}</div></div>
                  <div>
                    <div style={{fontSize:11,color:'var(--muted)',marginBottom:2}}>Fortschritt</div>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <div style={{flex:1}}><div className="progress-track"><div className="progress-fill" style={{width:`${progress}%`,background:progress===100?'var(--green)':progress>0?'var(--blue)':'var(--muted)'}}/></div></div>
                      <span style={{fontSize:11,fontFamily:'var(--font-mono)',color:'var(--dim)'}}>{progress}%</span>
                    </div>
                  </div>
                </div>
                {confirmedEmps.length>0&&(
                  <div style={{display:'flex',flexWrap:'wrap',gap:5}}>
                    {confirmedEmps.map(e=>(
                      <div key={e.id} style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'3px 8px',fontSize:11}}>
                        {statusIcon(e.status)} {e.first_name} {e.last_name} <span style={{color:'var(--muted)'}}>{e.location}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

