Timeline:
function Timeline({employees, projects, plans, forecast}){
  const now = new Date();
  const todayYear = now.getFullYear();
  const todayMonth = now.getMonth();

  const allDates = plans.flatMap(p => [p.start_date, p.end_date].filter(Boolean));
  const minYear = allDates.length > 0
    ? Math.min(todayYear, ...allDates.map(d => new Date(d).getFullYear()))
    : todayYear;
  const maxYear = allDates.length > 0
    ? Math.max(todayYear, ...allDates.map(d => new Date(d).getFullYear()))
    : todayYear;

  const totalMonths = (maxYear - minYear + 1) * 12;
  const months = Array.from({length: totalMonths}, (_,i) => ({
    date: new Date(minYear + Math.floor(i/12), i%12, 1),
    year: minYear + Math.floor(i/12),
    month: i%12,
    idx: i,
  }));
  const todayIdx = (todayYear - minYear) * 12 + todayMonth;

  const ganttItems = plans.map(p => {
    const proj = projects.find(x => x.id === p.project_id);
    return {
      id: p.id, name: p.name,
      project: proj?.name || '',
      colorHex: p.project_id === 'p1' ? '#1d4ed8' : '#7c3aed',
      start: p.start_date, end: p.end_date,
      planned: p.planned_count || 0,
      confirmed: (p.confirmed_ids || []).length,
      isFuture: p.start_date ? new Date(p.start_date) > now : false,
    };
  }).sort((a,b) => new Date(a.start) - new Date(b.start));

  return(
    <div style={{display:'flex',flexDirection:'column',gap:14}}>

      {/* Gantt */}
      <div style={{background:'var(--surface)',border:'1px solid var(--border)',
        borderRadius:'var(--r-lg)',overflow:'hidden'}}>
        <div style={{overflowX:'auto'}}>
          <div style={{minWidth: 180 + totalMonths*40}}>
            <div style={{display:'grid',
              gridTemplateColumns:'180px repeat('+totalMonths+',minmax(36px,1fr))',
              borderBottom:'2px solid var(--border)',background:'var(--surface-2)'}}>
              <div style={{padding:'8px 12px',fontSize:10,fontWeight:600,
                color:'var(--muted)',textTransform:'uppercase'}}>Batch</div>
              {months.map((m,i) => (
                <div key={i} style={{
                  padding:'6px 2px',textAlign:'center',fontSize:9,
                  fontWeight:i===todayIdx||m.month===0?700:400,
                  color:i===todayIdx?'#1d4ed8':m.month===0?'var(--text)':'var(--muted)',
                  borderLeft:m.month===0&&i>0?'2px solid var(--border2)':'1px solid var(--border)',
                  background:i===todayIdx?'var(--blue-bg)':'transparent'}}>
                  {m.date.toLocaleDateString('de-DE',{month:'short'})}
                  {m.month===0&&<div style={{fontSize:8,opacity:.7}}>{m.year}</div>}
                </div>
              ))}
            </div>
            {ganttItems.map((item, rowIdx) => {
              const pct = item.planned>0?Math.round(item.confirmed/item.planned*100):0;
              const startD = item.start ? new Date(item.start) : null;
              const endD = item.end ? new Date(item.end) : startD;
              return (
                <div key={item.id} style={{
                  display:'grid',
                  gridTemplateColumns:'180px repeat('+totalMonths+',minmax(36px,1fr))',
                  borderBottom:'1px solid var(--border)',
                  background:rowIdx%2===0?'transparent':'var(--surface-2)'}}>
                  <div style={{padding:'8px 12px',borderRight:'1px solid var(--border)'}}>
                    <div style={{fontSize:11,fontWeight:500,overflow:'hidden',
                      textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{item.name}</div>
                    <div style={{display:'flex',gap:5,marginTop:3}}>
                      <span style={{fontSize:9,padding:'1px 5px',borderRadius:3,
                        background:item.colorHex+'22',color:item.colorHex,fontWeight:600}}>
                        {item.project}
                      </span>
                      <span style={{fontSize:9,fontWeight:700,
                        color:item.isFuture?'var(--amber)':'var(--green)'}}>
                        +{item.planned} MA
                      </span>
                      <span style={{fontSize:9,color:'var(--muted)'}}>
                        {item.confirmed}/{item.planned} best.
                      </span>
                    </div>
                  </div>
                  {months.map((m,mi) => {
                    if (!startD) return <div key={mi} style={{borderLeft:'1px solid var(--border)'}}/>;
                    const cellEnd = new Date(m.year, m.month+1, 0);
                    const inRange = startD <= cellEnd && endD >= m.date;
                    const isFirst = startD >= m.date && startD <= cellEnd;
                    const isLast = endD >= m.date && endD <= cellEnd;
                    return (
                      <div key={mi} style={{
                        borderLeft:m.month===0&&mi>0?'2px solid var(--border2)':'1px solid var(--border)',
                        background:mi===todayIdx?'rgba(29,78,216,.04)':'transparent',
                        padding:'9px 2px',display:'flex',alignItems:'center',justifyContent:'center'}}>
                        {inRange && (
                          <div style={{
                            width:'88%',height:12,
                            borderRadius:isFirst&&isLast?5:isFirst?'5px 0 0 5px':isLast?'0 5px 5px 0':0,
                            background:item.colorHex,opacity:.8,position:'relative',overflow:'hidden'}}>
                            <div style={{position:'absolute',inset:0,width:pct+'%',
                              background:'white',opacity:.3}}/>
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              );
            })}
            {ganttItems.length>0&&(
              <div style={{display:'flex',gap:20,padding:'8px 12px',
                background:'var(--surface-2)',borderTop:'2px solid var(--border)',
                fontSize:11,color:'var(--muted)'}}>
                <span style={{fontWeight:600,color:'var(--text)',minWidth:150}}>GESAMT</span>
                <span>{ganttItems.length} Batches</span>
                <span>{ganttItems.reduce((s,i)=>s+i.planned,0)} Plätze</span>
                <span style={{color:'var(--green)'}}>✓ {ganttItems.reduce((s,i)=>s+i.confirmed,0)} best.</span>
                <span style={{color:'var(--amber)'}}>○ {ganttItems.reduce((s,i)=>s+Math.max(0,i.planned-i.confirmed),0)} offen</span>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Detail Cards */}
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12}}>
        {ganttItems.map(item => {
          const open = item.planned - item.confirmed;
          const dStart = item.start?Math.round((new Date(item.start)-now)/86400000):null;
          const pct = item.planned>0?Math.round(item.confirmed/item.planned*100):0;
          const barColor = pct>=100?'#059669':pct>=60?'#16a34a':pct>=30?'#d97706':'#ef4444';
          return(
            <div key={item.id} style={{background:'var(--surface)',
              border:'1px solid '+item.colorHex+'44',borderRadius:'var(--r-lg)',padding:'12px 14px'}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:8}}>
                <div>
                  <div style={{fontSize:12,fontWeight:600}}>{item.name}</div>
                  <div style={{fontSize:10,color:'var(--muted)',marginTop:2}}>
                    {item.project}
                    {item.start?' · '+new Date(item.start).toLocaleDateString('de-DE'):''}
                    {item.end?' → '+new Date(item.end).toLocaleDateString('de-DE'):''}
                  </div>
                </div>
                <div style={{textAlign:'right',flexShrink:0,marginLeft:12}}>
                  <div style={{fontSize:18,fontWeight:700,
                    color:open>0?'var(--red)':'var(--green)',fontFamily:'var(--mono)'}}>{open}</div>
                  <div style={{fontSize:9,color:'var(--muted)'}}>offen</div>
                </div>
              </div>
              <div style={{height:5,background:'var(--border)',borderRadius:3,overflow:'hidden',marginBottom:6}}>
                <div style={{height:'100%',width:pct+'%',background:barColor,borderRadius:3}}/>
              </div>
              <div style={{display:'flex',justifyContent:'space-between',fontSize:10,color:'var(--muted)'}}>
                <span>{item.confirmed}/{item.planned} ({pct}%)</span>
                {dStart!==null&&(
                  <span style={{color:dStart<=0?'var(--green)':dStart<=7?'var(--red)':dStart<=14?'var(--amber)':'var(--muted)',fontWeight:dStart<=14?600:400}}>
                    {dStart<=0?'Läuft':'Start in '+dStart+'d'}
                  </span>
                )}
              </div>
            </div>
          );
        })}
        {ganttItems.length===0&&(
          <div style={{gridColumn:'1/-1',padding:40,textAlign:'center',fontSize:13,color:'var(--muted)'}}>
            Keine Schulungen geplant
          </div>
        )}
      </div>
    </div>
  );
}

ProductivityView:
function ProductivityView({employees, projects, onAbsence}){
  const GROSS = 160;
  const activeEmps = employees.filter(e=>!['terminated','inactive'].includes(e.status)&&e.status==='active');
  const today = new Date().toISOString().slice(0,10);

  const rows = activeEmps.map(e=>{
    const proj=projects.find(p=>p.id===e.project_id);
    const todayAbsence=(e.absences||[]).find(a=>a.date===today);
    const isAbsent=!!todayAbsence;
    const pct=e.productive_pct||85;
    const prodHours=isAbsent?0:Math.round(GROSS*pct/100);
    const rate=proj?.rate_active||0;
    const billingMode=proj?.billing_mode||'productive_hours';
    const revenue=isAbsent?0:(billingMode==='monthly_flat'?Number(proj?.monthly_flat||0):prodHours*rate);
    const cost=Number(Math.round(parseFloat(e.hourly_rate||0)*parseFloat(e.work_hours||8)*22))||0;
    return {e,proj,todayAbsence,isAbsent,pct,prodHours,rate,revenue,cost,margin:revenue-cost};
  });

  const totalRev=rows.reduce((s,r)=>s+r.revenue,0);
  const totalCost=rows.reduce((s,r)=>s+r.cost,0);
  const absentToday=rows.filter(r=>r.isAbsent).length;
  const lostRev=rows.filter(r=>r.isAbsent).reduce((s,r)=>{
    const proj=projects.find(p=>p.id===r.e.project_id);
    return s+(proj?.rate_active||0)*Math.round(160*(r.e.productive_pct||85)/100);
  },0);

  return(
    <div>
      <div className="grid-4">
        {[
          {label:'Monatsumsatz (produktiv)',val:`${totalRev.toLocaleString('de-DE')} €`,color:'var(--green)',icon:'💶'},
          {label:'Personalkosten',val:`${totalCost.toLocaleString('de-DE')} €`,color:'var(--red)',icon:'💸'},
          {label:'Deckungsbeitrag',val:`${(totalRev-totalCost).toLocaleString('de-DE')} €`,color:totalRev>=totalCost?'var(--teal)':'var(--red)',icon:'📊'},
          {label:'Ausfall heute',val:absentToday>0?`${absentToday} MA · -${lostRev.toLocaleString('de-DE')} €`:'Kein Ausfall',color:absentToday>0?'var(--amber)':'var(--muted)',icon:'⚠️'},
        ].map((k,i)=>(
          <div key={i} className="kpi">
            <div style={{fontSize:18,marginBottom:6}}>{k.icon}</div>
            <div className="kpi-val" style={{color:k.color,fontSize:18}}>{k.val}</div>
            <div className="kpi-label">{k.label}</div>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="card-header"><span className="card-title">⏱ Produktivstunden & Abwesenheit</span></div>
        <div className="table-responsive"><table>
          <thead><tr>
            <th>Mitarbeiter</th><th>Heute</th><th>Projekt</th>
            <th>Brutto-Std</th><th>Produktiv %</th><th>Prod-Std</th>
            <th>€/h</th><th>Umsatz/Mo</th><th>Kosten/Mo</th><th>Marge</th><th>Abwesenheiten</th>
          </tr></thead>
          <tbody>
            {rows.map(({e,proj,todayAbsence,isAbsent,pct,prodHours,rate,revenue,cost,margin})=>{
              const warnings=analyzeAbsences(e.absences||[]);
              const hasWarn=warnings.length>0;
              return(
                <tr key={e.id} style={{background:isAbsent?'rgba(239,68,68,.04)':hasWarn?'rgba(245,158,11,.03)':'transparent'}}>
                  <td>
                    <div style={{fontWeight:500}}>{e.first_name} {e.last_name}</div>
                    {hasWarn&&<div style={{fontSize:10,color:'var(--amber)',marginTop:2}}>{warnings[0].msg}</div>}
                  </td>
                  <td>
                    {isAbsent
                      ?<span className="badge badge-red">{ABSENCE_TYPES[todayAbsence.type]?.icon} {ABSENCE_TYPES[todayAbsence.type]?.label}</span>
                      :<span className="badge badge-green">⚡ Anwesend</span>
                    }
                  </td>
                  <td style={{fontSize:12}}>{proj?.name||'—'}</td>
                  <td style={{fontFamily:'var(--font-mono)',fontSize:12}}>{GROSS}h</td>
                  <td>
                    <div style={{display:'flex',alignItems:'center',gap:5}}>
                      <div style={{width:40,height:4,background:'var(--border)',borderRadius:2,overflow:'hidden'}}>
                        <div style={{height:'100%',width:`${pct}%`,background:'var(--blue)',borderRadius:2}}/>
                      </div>
                      <span style={{fontSize:11,fontFamily:'var(--font-mono)'}}>{pct}%</span>
                    </div>
                  </td>
                  <td style={{fontFamily:'var(--font-mono)',fontSize:12,color:isAbsent?'var(--red)':'var(--text)',fontWeight:isAbsent?600:400}}>{prodHours}h</td>
                  <td style={{fontFamily:'var(--font-mono)',fontSize:12}}>{rate}€</td>
                  <td style={{fontFamily:'var(--font-mono)',fontSize:12,color:isAbsent?'var(--muted)':'var(--green)',fontWeight:600}}>{revenue.toLocaleString('de-DE')} €</td>
                  <td style={{fontFamily:'var(--font-mono)',fontSize:12,color:'var(--red)'}}>{cost.toLocaleString('de-DE')} €</td>
                  <td style={{fontFamily:'var(--font-mono)',fontSize:12,fontWeight:600,color:margin>=0?'var(--teal)':'var(--red)'}}>{margin.toLocaleString('de-DE')} €</td>
                  <td>
                    <button className="btn btn-sm" onClick={()=>onAbsence(e)}>📅 {(e.absences||[]).length} Tage</button>
                  </td>
                </tr>
              );
            })}
            {rows.length===0&&<tr><td colSpan={11} style={{textAlign:'center',padding:20,color:'var(--muted)'}}>Keine aktiven Mitarbeiter</td></tr>}
          </tbody>
        </table></div>
      </div>
    </div>
  );
}

