Cockpit:
function Cockpit({employees, projects, plans, forecast, onAbsence, team}){
  const active=employees.filter(e=>e.status==='active');
  const inTraining=employees.filter(e=>e.status==='training');
  const pipeline=employees.filter(e=>['cv_received','in_system','presented','selected'].includes(e.status));
  const now=new Date();
  const todayStr=now.toISOString().slice(0,10);
  const year=now.getFullYear();
  const todayM=now.getMonth();

  const monthRevenue=projects.reduce((s,p)=>{
    const n=active.filter(e=>e.project_id===p.id).length;
    return s+(p.billing_mode==='monthly_flat'?n*(p.monthly_flat||0):n*(p.rate_active||0)*160*0.85);
  },0);
  const monthCost=active.reduce((s,e)=>s+Number(Math.round(parseFloat(e.hourly_rate||0)*parseFloat(e.work_hours||8)*22)||1400),0)+
    inTraining.reduce((s,e)=>s+(()=>{const r=parseFloat(e.hourly_rate||0),h=parseFloat(e.work_hours||8);return r>0?Math.round(r*h*22):900;})(),0);
  const margin=monthRevenue>0?Math.round((monthRevenue-monthCost)/monthRevenue*100):0;

  const todayAbsent=employees.filter(e=>(e.absences||[]).some(a=>a.date===todayStr&&a.type==='sick'));
  const todayVac=employees.filter(e=>(e.absences||[]).some(a=>a.date===todayStr&&a.type==='vacation'));
  const safePlans = plans.filter(p=>p!=null&&p.planned_count!=null);
  const urgentPlans=safePlans.filter(p=>{
    if(!p||!p.start_date) return false;
    const d=daysUntil(p.start_date);
    return d!==null&&d<=14&&d>=0&&(p.planned_count-(p.confirmed_ids?.length||0))>0;
  });

  const pipelineSteps=[
    {key:'cv_received',label:'CV erhalten',color:'#94a3b8'},
    {key:'in_system',label:'Im System',color:'#3b82f6'},
    {key:'presented',label:'Vorgestellt',color:'#8b5cf6'},
    {key:'selected',label:'Selektiert',color:'#0d9488'},
    {key:'training',label:'Schulung',color:'#7c3aed'},
    {key:'active',label:'Aktiv',color:'#059669'},
  ];
  const maxP=Math.max(...pipelineSteps.map(s=>employees.filter(e=>e.status===s.key).length),1);

  const months=Array.from({length:12},(_,i)=>new Date(year,i,1));
  const projColors=Object.fromEntries((projects||[]).map(p=>[p.id,p.color||'#1d4ed8']));
  function mVal(proj,mi){
    const base=employees.filter(e=>e.project_id===proj.id&&['active','training'].includes(e.status)).length;
    if(mi<=todayM) return base;
    let cum=base;
    for(let m=todayM+1;m<=mi;m++){
      cum+=plans.filter(p2=>p2&&p2.project_id===proj.id&&p2.start_date&&
        new Date(p2.start_date).getFullYear()===year&&
        new Date(p2.start_date).getMonth()===m
      ).reduce((s,p2)=>s+p2.planned_count,0);
    }
    return cum;
  }
  const runData=projects.map(proj=>({proj,vals:months.map((_,i)=>mVal(proj,i))}));
  const maxV=Math.max(...runData.flatMap(d=>d.vals),6);
  const W=560,H=120,pL=26,pR=8,pT=8,pB=24;
  const iW=W-pL-pR,iH=H-pT-pB;
  const xP=i=>pL+i*(iW/11);
  const yP=v=>pT+iH-Math.round((v/maxV)*iH);

  const kpis=[
    {val:active.length,label:'Aktiv',sub:'Mitarbeiter',color:'#1d4ed8'},
    {val:inTraining.length,label:'Schulung',sub:'Mitarbeiter',color:'#7c3aed'},
    {val:pipeline.length,label:'Pipeline',sub:'Kandidaten',color:'#0d9488'},
    {val:Math.round(monthRevenue/1000)+'k',label:'Umsatz/Mo',sub:'Vormonat est.',color:'#059669'},
    {val:Math.round(monthCost/1000)+'k',label:'Kosten/Mo',sub:'Personal',color:'#dc2626'},
  ];

  const financeRows=[
    {label:'Umsatz',val:monthRevenue,color:'#059669'},
    {label:'Personalkosten',val:monthCost,color:'#dc2626'},
    {label:'Deckungsbeitrag',val:monthRevenue-monthCost,color:monthRevenue>=monthCost?'#1d4ed8':'#dc2626'},
  ];

  return(
    <React.Fragment>

      {/* ── Kein Stundenlohn Warnung ── */}
      {(()=>{
        const noSalary=employees.filter(e=>e.status==='active'&&!parseFloat(e.hourly_rate||0));
        if(!noSalary.length) return null;
        return(
          <div style={{marginBottom:14,padding:'10px 14px',background:'var(--red-bg)',borderRadius:'var(--r)',border:'1px solid rgba(239,68,68,.2)'}}>
            <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:6}}>
              <span style={{fontSize:16}}>⚠️</span>
              <span style={{fontWeight:700,fontSize:13,color:'var(--red)'}}>Kein Stundenlohn: {noSalary.length} aktive Mitarbeiter</span>
            </div>
            <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
              {noSalary.map(e=>(
                <span key={e.id} style={{padding:'3px 10px',borderRadius:20,background:'rgba(239,68,68,.1)',border:'1px solid rgba(239,68,68,.2)',fontSize:12,fontWeight:600,color:'var(--red)'}}>
                  {e.first_name} {e.last_name}
                </span>
              ))}
            </div>
          </div>
        );
      })()}

      {/* ── Auslaufende Verträge ── */}
      {(()=>{
        // Show to superadmin or users with 'all' access (management)
        const sess=JSON.parse(sessionStorage.getItem('jsr_team')||localStorage.getItem('jsr_session_v1')||'{}');
        const isPrivileged=!sess.access||(sess.access==='all'||sess.access?.includes?.('superadmin'));
        if(!isPrivileged) return null;
        const months=parseInt(localStorage.getItem('jsr_contract_reminder_months')||'1');
        const today=new Date();
        const cutoff=new Date(today);
        cutoff.setMonth(cutoff.getMonth()+months);
        const expiring=employees.filter(e=>{
          if(!e.contract_end||e.status==='terminated'||e.status==='inactive') return false;
          const end=new Date(e.contract_end);
          return end>=today && end<=cutoff;
        }).sort((a,b)=>new Date(a.contract_end)-new Date(b.contract_end));
        if(!expiring.length) return null;
        return(
          <div style={{marginBottom:14,background:'var(--card)',borderRadius:'var(--r)',border:'1.5px solid rgba(239,68,68,.3)',overflow:'hidden'}}>
            <div style={{padding:'10px 16px',background:'var(--red-bg)',borderBottom:'1px solid rgba(239,68,68,.15)',display:'flex',alignItems:'center',gap:8}}>
              <span style={{fontSize:16}}>📋</span>
              <span style={{fontWeight:700,fontSize:13,color:'var(--red)'}}>
                {expiring.length} Vertrag{expiring.length>1?'e':''} läuft{expiring.length===1?'':'en'} in {months} Monat{months>1?'en':''} ab
              </span>
            </div>
            {expiring.map(emp=>{
              const end=new Date(emp.contract_end);
              const days=Math.round((end-new Date())/(864e5));
              const urgent=days<=30;
              return(
                <div key={emp.id} style={{display:'flex',alignItems:'center',gap:10,padding:'9px 16px',
                  borderBottom:'1px solid var(--border)',background:urgent?'rgba(239,68,68,.04)':'transparent'}}>
                  <div style={{width:32,height:32,borderRadius:'50%',background:urgent?'var(--red-bg)':'var(--amber-bg)',
                    display:'flex',alignItems:'center',justifyContent:'center',fontSize:14,flexShrink:0}}>
                    {urgent?'🚨':'⚠️'}
                  </div>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:700,fontSize:13}}>{emp.first_name} {emp.last_name}</div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>{emp.position} · #{emp.staff_number}</div>
                  </div>
                  <div style={{textAlign:'right'}}>
                    <div style={{fontWeight:700,fontSize:12,color:urgent?'var(--red)':'var(--amber)'}}>
                      {days<=0?'Abgelaufen!':days===1?'Morgen':days+'d'}
                    </div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>
                      {new Date(emp.contract_end).toLocaleDateString('de-DE')}
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        );
      })()}

      {/* ── Hardware Alert ── */}
      {(()=>{
        const hwAlerts=employees.filter(e=>{
          if(e.hw_done||e.hardware==='yes'||e.hardware==='no'||!e.hardware) return false;
          if(e.hardware!=='order') return false;
          if(!e.hw_deadline) return true;
          return Math.round((new Date(e.hw_deadline)-new Date())/(1000*60*60*24))<=7;
        });
        if(!hwAlerts.length) return null;
        return(
          <div style={{marginBottom:14,padding:'12px 16px',background:'var(--red-bg)',borderRadius:'var(--r)',border:'1px solid rgba(239,68,68,.2)'}}>
            <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:8}}>
              <span style={{fontSize:18}}>🚨</span>
              <span style={{fontWeight:700,fontSize:13,color:'var(--red)'}}>Hardware-Alarm — {hwAlerts.length} Mitarbeiter brauchen Hardware</span>
            </div>
            <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
              {hwAlerts.map(emp=>{
                const days=emp.hw_deadline?Math.round((new Date(emp.hw_deadline)-new Date())/(1000*60*60*24)):null;
                return(
                  <div key={emp.id} style={{padding:'6px 12px',borderRadius:8,background:'rgba(239,68,68,.08)',border:'1px solid rgba(239,68,68,.2)',fontSize:12}}>
                    <strong>{emp.first_name} {emp.last_name}</strong>
                    <span style={{color:'var(--red)',marginLeft:6,fontWeight:700}}>
                      {days===null?'⚠ Kein Termin':days<0?`🚨 ${Math.abs(days)}d überfällig`:`⏰ in ${days}d`}
                    </span>
                    {(emp.start_date||emp.contract_start)&&<span style={{color:'var(--muted)',marginLeft:6}}>Start: {emp.start_date||emp.contract_start}</span>}
                  </div>
                );
              })}
            </div>
            <div style={{marginTop:6,fontSize:11,color:'var(--muted)'}}>→ Onboarding-Tab zur Verwaltung</div>
          </div>
        );
      })()}

      {/* ── HEUTE ZU ERLEDIGEN ── */}
      {(()=>{
        const today=new Date().toISOString().slice(0,10);
        const tasks=[];
        // Offene Löhne (draft/confirmed)
        try{
          const slips=JSON.parse(localStorage.getItem('jsr_payslips_v1')||'{}');
          const month=today.slice(0,7);
          const open=(slips[month]||[]).filter(s=>s.status!=='paid');
          if(open.length) tasks.push({icon:'💰',label:open.length+' Gehaltsabrechnungen offen',color:'var(--amber)',tab:'payroll'});
        }catch(e){}
        // Neue CVs diese Woche
        try{
          const cvs=JSON.parse(localStorage.getItem('jsr_cvs_v1')||'[]');
          const weekAgo=new Date(Date.now()-7*864e5).toISOString().slice(0,10);
          const newCvs=cvs.filter(c=>c.cv_date>=weekAgo&&c.status==='cv_inbound');
          if(newCvs.length) tasks.push({icon:'📥',label:newCvs.length+' neue CVs diese Woche (Inbound)',color:'var(--blue)',tab:'cvs'});
        }catch(e){}
        // CVs > 7 Tage ohne Phasenwechsel
        try{
          const cvs=JSON.parse(localStorage.getItem('jsr_cvs_v1')||'[]');
          const stuck=cvs.filter(c=>{
            if(['active','rejected_by_us','blacklist','rejected_by_applicant','rejected_by_client'].includes(c.status)) return false;
            const last=c.last_status_change||c.cv_date;
            if(!last) return false;
            return Math.round((new Date()-new Date(last))/(864e5))>7;
          });
          if(stuck.length) tasks.push({icon:'⏳',label:stuck.length+' CVs seit >7 Tagen ohne Aktion',color:'var(--red)',tab:'cvs'});
        }catch(e){}
        // MA ohne Stundenlohn
        const noSal=employees.filter(e=>e.status==='active'&&!parseFloat(e.hourly_rate||0));
        // Auslaufende Verträge (für heute-widget)
        try{
          const cMonths=parseInt(localStorage.getItem('jsr_contract_reminder_months')||'1');
          const cCutoff=new Date();cCutoff.setMonth(cCutoff.getMonth()+cMonths);
          const cExp=employees.filter(e=>e.contract_end&&e.status!=='terminated'&&e.status!=='inactive'&&new Date(e.contract_end)>=new Date()&&new Date(e.contract_end)<=cCutoff);
          if(cExp.length) tasks.push({icon:'📋',label:cExp.length+' Vertrag'+(cExp.length>1?'e':'')+(cExp.length>1?' laufen':' läuft')+' bald ab',color:'var(--red)',tab:'employees'});
        }catch(e){}
        if(noSal.length) tasks.push({icon:'⚠️',label:noSal.length+' aktive MA ohne Stundenlohn',color:'var(--red)',tab:'employees'});

        if(!tasks.length) return null;
        return(
          <div style={{marginBottom:14,background:'var(--card)',borderRadius:'var(--r)',border:'1px solid var(--border)'}}>
            <div style={{padding:'10px 16px',borderBottom:'1px solid var(--border)',fontWeight:700,fontSize:12,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em'}}>
              ✅ Heute zu erledigen
            </div>
            {tasks.map((t,i)=>(
              <div key={i} style={{display:'flex',alignItems:'center',gap:10,padding:'10px 16px',borderBottom:i<tasks.length-1?'1px solid var(--border)':'none',cursor:'pointer'}}
                onClick={()=>window.dispatchEvent&&window.dispatchEvent(new CustomEvent('navigate',{detail:t.tab}))}>
                <span style={{fontSize:18}}>{t.icon}</span>
                <span style={{fontSize:13,fontWeight:600,color:t.color,flex:1}}>{t.label}</span>
                <span style={{fontSize:11,color:'var(--muted)'}}>→</span>
              </div>
            ))}
          </div>
        );
      })()}

      {/* ── Neue CVs heute ── */}
      {(()=>{
        const today=new Date().toISOString().slice(0,10);
        try{
          const cvs=JSON.parse(localStorage.getItem('jsr_cvs_v1')||'[]');
          const todayCvs=cvs.filter(c=>c.cv_date===today||c.id&&c.id.startsWith('cv_')&&new Date(parseInt((c.id||'').replace('cv_',''))).toISOString().slice(0,10)===today);
