                        color:mg>=20?'#059669':mg>=10?'#d97706':'#dc2626'}}>
                        {cost.toLocaleString('de-DE')} € · {mg}%
                      </span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

      </div>

      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:12,marginBottom:12}}>

        <div style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r-lg)',overflow:'hidden'}}>
          <div style={{padding:'10px 14px',borderBottom:'1px solid var(--border)',
            display:'flex',justifyContent:'space-between',fontSize:12,fontWeight:600}}>
            <span>Anstehende Schulungen</span>
            <span style={{color:'var(--muted)',fontWeight:400}}>{safePlans.length} total</span>
          </div>
          <div>
            {[...safePlans].sort((a,b)=>new Date(a.start_date)-new Date(b.start_date)).slice(0,6).map(p=>{
              const d=daysUntil(p.start_date);
              const proj=projects.find(x=>x.id===p.project_id);
              const confirmed=(p.confirmed_ids||[]).length;
              const pct=p.planned_count>0?Math.min(confirmed/p.planned_count*100,100):0;
              const barColor=confirmed>=p.planned_count?'#059669':pct>=60?'#16a34a':pct>=30?'#d97706':'#ef4444';
              return(
                <div key={p.id} style={{padding:'8px 14px',borderBottom:'1px solid var(--border)',
                  display:'flex',alignItems:'center',gap:10}}>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:12,fontWeight:500,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                      {p.name}
                    </div>
                    <div style={{fontSize:10,color:'var(--muted)',marginTop:1}}>
                      {proj?.name} · {fmtDate(p.start_date)}
                    </div>
                    <div style={{marginTop:4,height:4,background:'var(--border)',borderRadius:2,overflow:'hidden'}}>
                      <div style={{height:'100%',width:pct+'%',background:barColor,borderRadius:2}}/>
                    </div>
                  </div>
                  <div style={{textAlign:'right',flexShrink:0}}>
                    {d!==null&&d>=0&&d<=14&&(
                      <div style={{fontSize:10,fontWeight:600,color:d<=3?'var(--red)':'var(--amber)',marginBottom:2}}>
                        {d===0?'Heute!':d+'d'}
                      </div>
                    )}
                    <span style={{fontSize:10,padding:'2px 7px',borderRadius:3,fontWeight:700,
                      fontFamily:'var(--mono)',
                      background:confirmed>=p.planned_count?'#dcfce7':pct>=60?'#f0fdf4':pct>=30?'#fffbeb':'#fef2f2',
                      color:barColor}}>
                      {confirmed}/{p.planned_count}
                    </span>
                  </div>
                </div>
              );
            })}
            {plans.length===0&&(
              <div style={{padding:20,fontSize:12,color:'var(--muted)',textAlign:'center'}}>
                Keine Schulungen geplant
              </div>
            )}
          </div>
        </div>

        <div style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r-lg)',overflow:'hidden'}}>
          <div style={{padding:'10px 14px',borderBottom:'1px solid var(--border)',
            display:'flex',justifyContent:'space-between',fontSize:12,fontWeight:600}}>
            <span>Recruiting Bedarf</span>
            <span style={{color:'var(--red)',fontFamily:'var(--mono)',fontWeight:700}}>
              {safePlans.reduce((s,p)=>s+Math.max(0,p.planned_count-(p.confirmed_ids||[]).length),0)} offen
            </span>
          </div>
          <div>
            {safePlans
              .filter(p=>Math.max(0,p.planned_count-(p.confirmed_ids||[]).length)>0)
              .sort((a,b)=>new Date(a.start_date)-new Date(b.start_date))
              .map(p=>{
                const open=Math.max(0,p.planned_count-(p.confirmed_ids||[]).length);
                const d=daysUntil(p.start_date);
                const proj=projects.find(x=>x.id===p.project_id);
                const color=d!==null&&d<=7?'var(--red)':d!==null&&d<=14?'var(--amber)':'var(--blue)';
                const bg=d!==null&&d<=7?'var(--red-bg)':d!==null&&d<=14?'var(--amber-bg)':'var(--blue-bg)';
                return(
                  <div key={p.id} style={{padding:'8px 14px',borderBottom:'1px solid var(--border)',
                    display:'flex',alignItems:'center',gap:10}}>
                    <div style={{width:30,height:30,borderRadius:'var(--r-md)',background:bg,
                      display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
                      <span style={{fontSize:15,fontWeight:800,color,fontFamily:'var(--mono)'}}>{open}</span>
                    </div>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:12,fontWeight:500,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                        {p.name}
                      </div>
                      <div style={{fontSize:10,color:'var(--muted)',marginTop:1}}>
                        {proj?.name}{d!==null?' · in '+d+'d':''}
                      </div>
                    </div>
                    <span style={{fontSize:10,padding:'2px 7px',borderRadius:3,background:bg,color,fontWeight:600,flexShrink:0}}>
                      {d!==null&&d<=7?'Dringend':d!==null&&d<=14?'Bald':'Geplant'}
                    </span>
                  </div>
                );
              })}
            {safePlans.filter(p=>p.planned_count-(p.confirmed_ids||[]).length>0).length===0&&(
              <div style={{padding:20,fontSize:12,color:'#059669',textAlign:'center',fontWeight:500}}>
                Alle Schulungen voll besetzt
              </div>
            )}
          </div>
        </div>

      </div>


    </React.Fragment>
  );
}

