function OrgChart({projects, employees, orgCharts, setOrgCharts}){
  const [selProj, setSelProj] = useState((projects||[])[0]?.id||'');
  const [editMode, setEditMode] = useState(false);
  const [dragging, setDragging] = useState(null);
  const [dragOver, setDragOver] = useState(null);
  const [showAddNode, setShowAddNode] = useState(null);
  const [newNodeForm, setNewNodeForm] = useState({title:'',skill:'',role:''});

  const proj = (projects||[]).find(p=>p.id===selProj);
  const projEmployees = (employees||[]).filter(e=>e.project_id===selProj&&e.status==='active');

  const NODE_PALETTE = ['#1d4ed8','#7c3aed','#059669','#d97706','#dc2626','#0d9488','#db2777'];

  function autoBuild(){
    if(!proj) return;
    const skills = proj.skills||[];
    const byRole = (roles) => projEmployees.filter(e=>roles.includes(e.position));
    const leaders = byRole(['Projektleiter','Teamleiter','Team Lead']);
    const trainers = byRole(['Trainer']);
    const qms     = byRole(['QM']);
    const agents  = projEmployees.filter(e=>!['Projektleiter','Teamleiter','Team Lead','Trainer','QM','Ansprechpartner'].includes(e.position));

    const rootId = 'root_'+selProj;
    const nodes = [{
      id:rootId, title:proj.name, subtitle:'Projektleitung',
      color:'#1d4ed8', employees:leaders.map(e=>e.id), children:[],
    }];

    skills.forEach((sk, si)=>{
      const skillId = 'skill_'+sk.key+'_'+selProj;
      const skillAgents = agents.filter(e=>e.primary_skill===sk.key);
      const tl = projEmployees.find(e=>e.primary_skill===sk.key&&['Teamleiter','Team Lead'].includes(e.position));
      const allEmps = tl ? [tl.id, ...skillAgents.map(e=>e.id)] : skillAgents.map(e=>e.id);
      nodes.push({
        id:skillId, title:sk.label, subtitle:sk.key.toUpperCase(),
        color:NODE_PALETTE[(si+1)%NODE_PALETTE.length],
        employees:allEmps, children:[],
      });
      nodes[0].children.push(skillId);
    });

    // Agents with no primary_skill go under first skill or root
    const assignedIds = new Set(nodes.flatMap(n=>n.employees));
    const unmatched = agents.filter(e=>!assignedIds.has(e.id));
    if(unmatched.length && nodes.length>1){
      nodes[1].employees = [...nodes[1].employees, ...unmatched.map(e=>e.id)];
    } else if(unmatched.length){
      nodes[0].employees = [...nodes[0].employees, ...unmatched.map(e=>e.id)];
    }

    if(trainers.length){
      const tId='trainer_'+selProj;
      nodes.push({id:tId,title:'Training',subtitle:'TRAINER',color:'#059669',employees:trainers.map(e=>e.id),children:[]});
      nodes[0].children.push(tId);
    }
    if(qms.length){
      const qId='qm_'+selProj;
      nodes.push({id:qId,title:'Quality',subtitle:'QM',color:'#d97706',employees:qms.map(e=>e.id),children:[]});
      nodes[0].children.push(qId);
    }

    setOrgCharts(prev=>({...prev,[selProj]:{id:selProj,nodes,rootId,auto_built:new Date().toISOString().slice(0,10)}}));
  }

  const chart = orgCharts[selProj]||null;
  const nodes = chart?.nodes||[];
  const rootId = chart?.rootId||null;

  function getNode(id){return nodes.find(n=>n.id===id);}
  function updateChart(newNodes){
    setOrgCharts(prev=>({...prev,[selProj]:{...prev[selProj],nodes:newNodes}}));
  }
  function addChildNode(parentId){
    const newId='node_'+Date.now();
    const ci=nodes.length%NODE_PALETTE.length;
    const newNode={id:newId,title:newNodeForm.title||'Neuer Bereich',subtitle:newNodeForm.role||'',
      color:NODE_PALETTE[ci],skill:newNodeForm.skill||'',employees:[],children:[]};
    updateChart([...nodes,newNode].map(n=>n.id===parentId?{...n,children:[...n.children,newId]}:n));
    setShowAddNode(null);setNewNodeForm({title:'',skill:'',role:''});
  }
  function removeNode(nodeId){
    if(!window.confirm('Bereich löschen?')) return;
    updateChart(nodes.filter(n=>n.id!==nodeId).map(n=>({...n,children:n.children.filter(c=>c!==nodeId)})));
  }
  function dropEmpOnNode(empId,nodeId){
    updateChart(nodes.map(n=>({...n,
      employees:n.id===nodeId?[...new Set([...n.employees,empId])]:n.employees.filter(e=>e!==empId)
    })));
    setDragging(null);setDragOver(null);
  }
  function removeEmpFromNode(empId,nodeId){
    updateChart(nodes.map(n=>n.id===nodeId?{...n,employees:n.employees.filter(e=>e!==empId)}:n));
  }

  function NodeCard({nodeId, depth}){
    const node = getNode(nodeId);
    if(!node) return null;
    const nodeEmps = (node.employees||[]).map(id=>employees.find(e=>e.id===id)).filter(Boolean);
    const isRoot = nodeId===rootId;
    const isDragTarget = dragOver===nodeId;

    return(
      <div style={{display:'flex',flexDirection:'column',alignItems:'center'}}>
        {depth>0&&<div style={{width:1,height:24,background:'var(--border2)'}}/>}

        <div
          onDragOver={e=>{e.preventDefault();setDragOver(nodeId);}}
          onDragLeave={()=>setDragOver(null)}
          onDrop={()=>dragging&&dropEmpOnNode(dragging,nodeId)}
          style={{
            background:isDragTarget?node.color+'12':'var(--card)',
            border:'1.5px solid '+(isDragTarget?node.color:node.color+'44'),
            borderTop:'3px solid '+node.color,
            borderRadius:10,
            padding:'14px 16px',
            minWidth:170, maxWidth:230,
            boxShadow:isDragTarget
              ?'0 8px 32px '+node.color+'22'
              :'0 2px 8px rgba(0,0,0,.06)',
            transition:'all .15s',
            position:'relative',
          }}>

          {/* Title */}
          <div style={{marginBottom:10}}>
            <div style={{fontSize:13,fontWeight:800,color:'var(--text)',lineHeight:1.2}}>{node.title}</div>
            {node.subtitle&&<div style={{fontSize:10,fontWeight:700,color:node.color,
              textTransform:'uppercase',letterSpacing:'.07em',marginTop:3}}>{node.subtitle}</div>}
          </div>

          {/* Staff count badge */}
          <div style={{position:'absolute',top:10,right:10,
            width:22,height:22,borderRadius:'50%',
            background:node.color+'18',border:'1px solid '+node.color+'44',
            display:'flex',alignItems:'center',justifyContent:'center',
            fontSize:10,fontWeight:800,color:node.color}}>
            {nodeEmps.length}
          </div>

          {/* Divider */}
          <div style={{height:1,background:'var(--border)',marginBottom:10}}/>

          {/* Employees */}
          <div style={{display:'flex',flexDirection:'column',gap:4,minHeight:18}}>
            {nodeEmps.map(emp=>(
              <div key={emp.id}
                draggable={editMode}
                onDragStart={e=>{e.stopPropagation();setDragging(emp.id);}}
                style={{display:'flex',alignItems:'center',gap:7,
                  padding:'4px 6px',borderRadius:6,
                  background:'var(--surface-2)',
                  border:'1px solid var(--border)',
                  cursor:editMode?'grab':'default'}}>
                <div style={{width:20,height:20,borderRadius:'50%',flexShrink:0,
                  background:emp.photo_color||node.color,
                  display:'flex',alignItems:'center',justifyContent:'center',
                  fontSize:8,fontWeight:800,color:'#fff',letterSpacing:0}}>
                  {(emp.first_name||'')[0]}{(emp.last_name||'')[0]}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:11,fontWeight:600,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>
                    {emp.first_name} {emp.last_name}
                  </div>
                  {(emp.primary_skill||emp.position)&&(
                    <div style={{fontSize:9,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.05em'}}>
                      {emp.primary_skill||emp.position}
                    </div>
                  )}
                </div>
                {editMode&&(
                  <span onClick={()=>removeEmpFromNode(emp.id,nodeId)}
                    style={{color:'var(--red)',cursor:'pointer',fontSize:14,lineHeight:1,flexShrink:0,opacity:.6}}>×</span>
                )}
              </div>
            ))}
            {nodeEmps.length===0&&(
              <div style={{fontSize:10,color:'var(--dim)',fontStyle:'italic',padding:'4px 0',textAlign:'center'}}>
                {editMode?'↓ hier ablegen':'—'}
              </div>
            )}
          </div>

          {/* Edit controls */}
          {editMode&&(
            <div style={{marginTop:10,display:'flex',gap:5}}>
              <button onClick={()=>setShowAddNode(nodeId)}
                style={{flex:1,padding:'5px',border:'1.5px dashed var(--border2)',
                  borderRadius:6,background:'transparent',color:'var(--muted)',
                  fontSize:10,fontWeight:700,cursor:'pointer',fontFamily:'var(--font)'}}>
                + Unterbereich
              </button>
              {!isRoot&&<button onClick={()=>removeNode(nodeId)}
                style={{width:26,border:'1px solid var(--red-bg)',borderRadius:6,
                  background:'var(--red-bg)',color:'var(--red)',fontSize:12,cursor:'pointer'}}>×</button>}
            </div>
          )}
        </div>

        {/* Children */}
        {node.children&&node.children.length>0&&(
          <div style={{display:'flex',flexDirection:'column',alignItems:'center'}}>
            <div style={{width:1,height:20,background:'var(--border2)'}}/>
            <div style={{position:'relative',display:'flex',gap:16,alignItems:'flex-start'}}>
              {node.children.length>1&&(
                <div style={{position:'absolute',top:0,left:80,right:80,height:1,background:'var(--border2)'}}/>
              )}
              {node.children.map(childId=>(
                <div key={childId} style={{display:'flex',flexDirection:'column',alignItems:'center'}}>
                  <NodeCard nodeId={childId} depth={depth+1}/>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  }

  const assignedIds=new Set(nodes.flatMap(n=>n.employees||[]));
  const unassigned=projEmployees.filter(e=>!assignedIds.has(e.id));

  return(
    <div>
      {/* Add node modal */}
      {showAddNode&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:360}}>
            <div className="modal-header"><span className="modal-title">+ Unterbereich hinzufügen</span>
              <button className="btn" onClick={()=>setShowAddNode(null)}>×</button></div>
            <div className="modal-body">
              <div className="form-group"><label className="form-label">Bezeichnung</label>
                <input className="form-input" value={newNodeForm.title} autoFocus
                  onChange={e=>setNewNodeForm(f=>({...f,title:e.target.value}))} placeholder="z.B. Inbound, Sales…"/></div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Rolle</label>
                  <select className="form-select" value={newNodeForm.role} onChange={e=>setNewNodeForm(f=>({...f,role:e.target.value}))}>
                    <option value=''>—</option>{['Teamleiter','Trainer','QM','Agent','Ansprechpartner'].map(r=><option key={r}>{r}</option>)}</select></div>
                <div className="form-group"><label className="form-label">Skill</label>
                  <select className="form-select" value={newNodeForm.skill} onChange={e=>setNewNodeForm(f=>({...f,skill:e.target.value}))}>
                    <option value=''>—</option>{(proj?.skills||[]).map(s=><option key={s.key} value={s.key}>{s.label}</option>)}</select></div>
              </div>
              <div style={{display:'flex',gap:8,justifyContent:'flex-end',marginTop:12}}>
                <button className="btn" onClick={()=>setShowAddNode(null)}>Abbrechen</button>
                <button className="btn btn-primary" onClick={()=>addChildNode(showAddNode)}>Hinzufügen</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Toolbar */}
      <div style={{display:'flex',gap:10,alignItems:'center',marginBottom:16,flexWrap:'wrap'}}>
        <select className="form-select" style={{width:200}} value={selProj} onChange={e=>setSelProj(e.target.value)}>
          {(projects||[]).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        <button className="btn btn-primary btn-sm" onClick={autoBuild}>⚡ Auto-Build</button>
        <button className="btn btn-sm" onClick={()=>setEditMode(e=>!e)}
          style={{background:editMode?'var(--amber-bg)':'transparent',
            color:editMode?'var(--amber)':'var(--muted)',
            border:'1.5px solid '+(editMode?'var(--amber)':'var(--border)')}}>
          {editMode?'✓ Bearbeiten aktiv':'✏ Bearbeiten'}
        </button>
        {chart?.auto_built&&<span style={{fontSize:11,color:'var(--muted)'}}>Stand: {chart.auto_built}</span>}
        <span style={{fontSize:11,color:'var(--muted)',marginLeft:'auto'}}>{projEmployees.length} aktive Mitarbeiter</span>
      </div>

      {/* Chart */}
      {!chart?(
        <div style={{padding:48,textAlign:'center',color:'var(--muted)',
          background:'var(--card)',borderRadius:'var(--r)',border:'2px dashed var(--border)'}}>
          <div style={{fontSize:40,marginBottom:12}}>🏗</div>
          <div style={{fontWeight:700,fontSize:15,marginBottom:6,color:'var(--text)'}}>
            Kein Organigramm für {proj?.name||'dieses Projekt'}
          </div>
          <div style={{fontSize:13,marginBottom:16}}>
            Automatisch aus Projekt-Skills ({(proj?.skills||[]).map(s=>s.label).join(', ')||'—'}) und Mitarbeiter-Rollen generieren
          </div>
          <button className="btn btn-primary" onClick={autoBuild}>⚡ Jetzt Auto-Build</button>
        </div>
      ):(
        <div style={{overflowX:'auto',background:'var(--surface-2)',
          borderRadius:12,border:'1px solid var(--border)',padding:'32px 40px'}}>
          <div style={{display:'inline-flex',minWidth:'100%',justifyContent:'center'}}>
            <NodeCard nodeId={rootId} depth={0}/>
          </div>
        </div>
      )}

      {/* Unassigned */}
      {editMode&&unassigned.length>0&&(
        <div style={{marginTop:12,padding:'12px 16px',background:'var(--amber-bg)',
          borderRadius:'var(--r)',border:'1px solid rgba(217,119,6,.2)'}}>
          <div style={{fontSize:12,fontWeight:700,color:'var(--amber)',marginBottom:8}}>
            ⚠ {unassigned.length} Mitarbeiter nicht zugeordnet — auf Bereich ziehen:
          </div>
          <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
            {unassigned.map(emp=>(
              <div key={emp.id} draggable onDragStart={()=>setDragging(emp.id)}
                style={{padding:'4px 10px',borderRadius:20,background:'var(--card)',
                  border:'1px solid var(--border)',fontSize:12,fontWeight:600,cursor:'grab',
                  display:'flex',alignItems:'center',gap:6}}>
                <div style={{width:18,height:18,borderRadius:'50%',
                  background:emp.photo_color||'#1d4ed8',
                  display:'flex',alignItems:'center',justifyContent:'center',
                  fontSize:8,fontWeight:800,color:'#fff'}}>
                  {(emp.first_name||'')[0]}{(emp.last_name||'')[0]}
                </div>
                {emp.first_name} {emp.last_name}
                <span style={{fontSize:10,color:'var(--muted)'}}>({emp.primary_skill||emp.position||'—'})</span>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

