function ForecastView({projects, employees, plans, forecast, setForecast}){
  const [showAddBatch, setShowAddBatch]=useState(false);
  const [newBatch, setNewBatch]=useState({project_id:'p1',name:'',start_date:'',active_date:'',planned_agents:5,status:'planned',monthly_rate:24,training_rate:18,avg_salary:800,notes:''});
  const setNB=(k,v)=>setNewBatch(f=>({...f,[k]:v}));
  const [editCosts, setEditCosts]=useState(false);
  const [costs, setCosts]=useState(forecast.fixed_costs);
  const setC=(k,v)=>setCosts(c=>({...c,[k]:Number(v)||0}));

  function saveCosts(){setForecast(f=>({...f,fixed_costs:costs}));setEditCosts(false);}
  function addBatch(){
    if(!newBatch.name||!newBatch.start_date) return;
    setForecast(f=>({...f,future_batches:[...f.future_batches,{...newBatch,id:'fb'+Date.now(),planned_agents:Number(newBatch.planned_agents),monthly_rate:Number(newBatch.monthly_rate),training_rate:Number(newBatch.training_rate)}]}));
    setShowAddBatch(false);
    setNewBatch({project_id:'p1',name:'',start_date:'',active_date:'',planned_agents:5,status:'planned',monthly_rate:24,training_rate:18,avg_salary:800,notes:''});
  }
  function removeBatch(id){setForecast(f=>({...f,future_batches:f.future_batches.filter(b=>b.id!==id)}));}

  const totalFixedCost=Object.values(costs).reduce((s,v)=>s+Number(v||0),0);

  // Build 12-month forecast
  const now=new Date();
  const months=Array.from({length:12},(_,i)=>{
    const d=new Date(now.getFullYear(),now.getMonth()+i,1);
    return {date:d, label:d.toLocaleDateString('de-DE',{month:'short',year:'2-digit'})};
  });

  function getMonthStats(monthDate){
    const mo=monthDate.getMonth(), yr=monthDate.getFullYear();
    const moStr=`${yr}-${String(mo+1).padStart(2,'0')}`;

    // Current active employees
    const activeEmps=employees.filter(e=>e.status==='active');
    const trainingEmps=employees.filter(e=>e.status==='training');

    // Future batches in this month
    const batchesTraining=forecast.future_batches.filter(b=>{
      if(!b.start_date) return false;
      const s=new Date(b.start_date);
      const a=b.active_date?new Date(b.active_date):null;
      return s.getMonth()===mo&&s.getFullYear()===yr;
    });
    const batchesActive=forecast.future_batches.filter(b=>{
      if(!b.active_date) return false;
      const a=new Date(b.active_date);
      return a.getMonth()===mo&&a.getFullYear()===yr;
    });

    const futureTraining=batchesTraining.reduce((s,b)=>s+b.planned_agents,0);
    const futureActive=batchesActive.reduce((s,b)=>s+b.planned_agents,0);

    // Revenue estimate
    const currentRevenue=projects.reduce((s,p)=>{
      const pEmps=activeEmps.filter(e=>e.project_id===p.id).length;
      if(p.billing_mode==='monthly_flat') return s+pEmps*(p.monthly_flat||0);
      return s+pEmps*(p.rate_active||0)*160*(0.85);
    },0);
    const futureRevenue=forecast.future_batches.filter(b=>{
      if(!b.active_date) return false;
      const a=new Date(b.active_date);
      return a<=monthDate;
    }).reduce((s,b)=>s+b.planned_agents*b.monthly_rate*160*0.85,0);

    // Cost estimate
    const currentCost=activeEmps.reduce((s,e)=>s+Number(Math.round(parseFloat(e.hourly_rate||0)*parseFloat(e.work_hours||8)*22)||0),0)+
                      trainingEmps.reduce((s,e)=>s+(()=>{const r=parseFloat(e.hourly_rate||0),h=parseFloat(e.work_hours||8);return r>0?Math.round(r*h*22):0;})(),0);
    // Zukünftige Kosten: aus Batch avg_salary oder Schätzung
    const futureCostTraining=batchesTraining.reduce((s,b)=>s+b.planned_agents*(Number(b.avg_salary)||700),0);
    const futureCostActive=batchesActive.reduce((s,b)=>s+b.planned_agents*(Number(b.avg_salary)||800),0);
    const futureCost=futureCostTraining+futureCostActive;

    return {
      activeEmps:activeEmps.length+futureActive,
      trainingEmps:trainingEmps.length+futureTraining,
      revenue:Math.round(currentRevenue+futureRevenue),
      cost:Math.round(currentCost+futureCost+totalFixedCost),
      batches:[...batchesTraining,...batchesActive],
    };
  }

  return(
    <div>
      {/* Location Capacity */}
      <div className="grid-2">
        {['tirana','prishtina'].map(loc=>{
          const cap=forecast.location_capacity?.[loc]||{total_seats:20,notes:''};
          const officeEmps=employees.filter(e=>e.location===loc.charAt(0).toUpperCase()+loc.slice(1)&&['active','training'].includes(e.status)&&(e.work_mode||'office')!=='homeoffice');
          const remoteEmps=employees.filter(e=>e.location===loc.charAt(0).toUpperCase()+loc.slice(1)&&['active','training'].includes(e.status)&&e.work_mode==='homeoffice');
          const totalActive=employees.filter(e=>e.location===loc.charAt(0).toUpperCase()+loc.slice(1)&&['active','training'].includes(e.status)).length;
          const freeSeats=cap.total_seats-officeEmps.length;
          const pct=Math.round(officeEmps.length/cap.total_seats*100);
          // Future batches filling seats
          const futureFill=forecast.future_batches.filter(b=>{
            const proj=projects.find(p=>p.id===b.project_id);
            return proj?.location?.toLowerCase()===loc;
          }).reduce((s,b)=>s+b.planned_agents,0);

          return(
            <div key={loc} className="card">
              <div className="card-header">
                <span className="card-title">📍 {loc.charAt(0).toUpperCase()+loc.slice(1)} — Kapazität</span>
                <span className={`badge ${freeSeats<=3?'badge-red':freeSeats<=8?'badge-amber':'badge-green'}`}>{freeSeats} Plätze frei</span>
              </div>
              <div className="card-body">
                <div style={{marginBottom:12}}>
                  <div style={{display:'flex',justifyContent:'space-between',marginBottom:4}}>
                    <span style={{fontSize:12,color:'var(--muted)'}}>Auslastung Office</span>
                    <span style={{fontSize:12,fontFamily:'var(--font-mono)',fontWeight:600}}>{officeEmps.length} / {cap.total_seats} Plätze ({pct}%)</span>
                  </div>
                  <div className="progress-track" style={{height:10}}>
                    <div className="progress-fill" style={{width:`${Math.min(pct,100)}%`,background:pct>=90?'var(--red)':pct>=70?'var(--amber)':'var(--green)'}}/>
                  </div>
                </div>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:10,marginBottom:10}}>
                  <div style={{background:'var(--surface)',borderRadius:'var(--r)',padding:'8px 10px',border:'1px solid var(--border)'}}>
                    <div style={{fontSize:10,color:'var(--muted)'}}>🏢 Office</div>
                    <div style={{fontSize:18,fontWeight:700,color:'var(--blue)',fontFamily:'var(--font-mono)'}}>{officeEmps.length}</div>
                  </div>
                  <div style={{background:'var(--surface)',borderRadius:'var(--r)',padding:'8px 10px',border:'1px solid var(--border)'}}>
                    <div style={{fontSize:10,color:'var(--muted)'}}>🏠 Homeoffice</div>
                    <div style={{fontSize:18,fontWeight:700,color:'var(--purple)',fontFamily:'var(--font-mono)'}}>{remoteEmps.length}</div>
                  </div>
                  <div style={{background:'var(--surface)',borderRadius:'var(--r)',padding:'8px 10px',border:'1px solid var(--border)'}}>
                    <div style={{fontSize:10,color:'var(--muted)'}}>📋 Geplant+</div>
                    <div style={{fontSize:18,fontWeight:700,color:'var(--amber)',fontFamily:'var(--font-mono)'}}>{futureFill}</div>
                  </div>
                </div>
                {futureFill>0&&freeSeats-futureFill<0&&(
                  <div className="warn-box warn-red" style={{padding:'8px 12px'}}>
                    <span style={{fontSize:12,color:'var(--red)',fontWeight:600}}>🚨 Kapazitätsengpass! Geplante MA ({futureFill}) > Freie Plätze ({freeSeats})</span>
                  </div>
                )}
                {editCosts&&(
                  <div style={{marginTop:10}}>
                    <div className="form-group"><label className="form-label">Gesamt-Plätze</label>
                      <input className="form-input" type="number" value={cap.total_seats}
                        onChange={e=>setForecast(f=>({...f,location_capacity:{...f.location_capacity,[loc]:{...cap,total_seats:Number(e.target.value)}}}))}/>
                    </div>
                    <div className="form-group" style={{marginTop:6}}><label className="form-label">Notiz</label>
                      <input className="form-input" value={cap.notes}
                        onChange={e=>setForecast(f=>({...f,location_capacity:{...f.location_capacity,[loc]:{...cap,notes:e.target.value}}}))}/>
                    </div>
                  </div>
                )}
                {!editCosts&&cap.notes&&<div style={{fontSize:11,color:'var(--muted)',marginTop:6}}>{cap.notes}</div>}
              </div>
            </div>
          );
        })}
      </div>

      {/* Fixed Costs */}
      <div className="card">
        <div className="card-header">
          <span className="card-title">🏢 Monatliche Fixkosten</span>
          <div style={{display:'flex',gap:8,alignItems:'center'}}>
            <span style={{fontFamily:'var(--font-mono)',fontWeight:700,color:'var(--red)'}}>{totalFixedCost.toLocaleString('de-DE')} €/Mo</span>
            <button className="btn btn-sm" onClick={()=>setEditCosts(e=>!e)}>{editCosts?'✓ Speichern':'✎ Bearbeiten'}</button>
            {editCosts&&<button className="btn btn-sm" onClick={saveCosts}>Speichern</button>}
          </div>
        </div>
        <div className="card-body">
          <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:10}}>
            {[
              ['buero_tirana','🏠 Miete Tirana'],
              ['buero_prishtina','🏠 Miete Prishtina'],
              ['strom_tirana','⚡ Strom Tirana'],
              ['strom_prishtina','⚡ Strom Prishtina'],
              ['internet_tirana','🌐 Internet Tirana'],
              ['internet_prishtina','🌐 Internet Prishtina'],
              ['nebenkosten_tirana','📦 Nebenk. Tirana'],
              ['nebenkosten_prishtina','📦 Nebenk. Prishtina'],
              ['software_tools','💻 Software & Tools'],
              ['management','👔 Management'],
              ['other','📋 Sonstiges'],
            ].map(([k,l])=>(
              <div key={k} style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'10px 12px'}}>
                <div style={{fontSize:11,color:'var(--muted)',marginBottom:4}}>{l}</div>
                {editCosts?(
