                ):(
                  <div style={{fontSize:15,fontWeight:600,fontFamily:'var(--font-mono)',color:'var(--red)'}}>{Number(costs[k]||0).toLocaleString('de-DE')} €</div>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Future Batches */}
      <div className="card">
        <div className="card-header">
          <span className="card-title">📋 Geplante zukünftige Batches</span>
          <button className="btn btn-primary btn-sm" onClick={()=>setShowAddBatch(s=>!s)}>+ Batch planen</button>
        </div>
        {showAddBatch&&(
          <div style={{padding:16,borderBottom:'1px solid var(--border)',background:'var(--surface)'}}>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:10,marginBottom:10}}>
              <div className="form-group"><label className="form-label">Name</label><input className="form-input" value={newBatch.name} onChange={e=>setNB('name',e.target.value)} placeholder="z.B. HC Batch Jun 2025"/></div>
              <div className="form-group"><label className="form-label">Projekt</label>
                <select className="form-select" value={newBatch.project_id} onChange={e=>setNB('project_id',e.target.value)}>
                  {projects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div className="form-group"><label className="form-label">Geplante Agenten</label><input className="form-input" type="number" value={newBatch.planned_agents} onChange={e=>setNB('planned_agents',e.target.value)}/></div>
            </div>
            <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr 1fr',gap:10,marginBottom:10}}>
              <div className="form-group"><label className="form-label">Schulungsstart</label><input className="form-input" type="date" value={newBatch.start_date} onChange={e=>setNB('start_date',e.target.value)}/></div>
              <div className="form-group"><label className="form-label">Aktiv ab</label><input className="form-input" type="date" value={newBatch.active_date} onChange={e=>setNB('active_date',e.target.value)}/></div>
              <div className="form-group"><label className="form-label">€/h aktiv</label><input className="form-input" type="number" value={newBatch.monthly_rate} onChange={e=>setNB('monthly_rate',e.target.value)}/></div>
              <div className="form-group"><label className="form-label">€/h Schulung</label><input className="form-input" type="number" value={newBatch.training_rate} onChange={e=>setNB('training_rate',e.target.value)}/></div>
              <div className="form-group"><label className="form-label">Ø Gehalt/MA (€/Mo)</label><input className="form-input" type="number" value={newBatch.avg_salary||800} onChange={e=>setNB('avg_salary',e.target.value)} placeholder="800"/></div>
            </div>
            <div style={{display:'flex',gap:10,alignItems:'flex-end'}}>
              <div className="form-group" style={{flex:1}}><label className="form-label">Notizen</label><input className="form-input" value={newBatch.notes} onChange={e=>setNB('notes',e.target.value)}/></div>
              <button className="btn btn-green" onClick={addBatch}>+ Hinzufügen</button>
              <button className="btn" onClick={()=>setShowAddBatch(false)}>Abbrechen</button>
            </div>
          </div>
        )}
        <div className="card-body" style={{padding:0}}>
          <table>
            <thead><tr><th>Name</th><th>Projekt</th><th>Agenten</th><th>Schulungsstart</th><th>Aktiv ab</th><th>€/h Aktiv</th><th>Ø Gehalt/MA</th><th>Notiz</th><th></th></tr></thead>
            <tbody>
              {forecast.future_batches.length===0&&<tr><td colSpan={8} style={{textAlign:'center',padding:20,color:'var(--muted)'}}>Keine geplanten Batches</td></tr>}
              {forecast.future_batches.map(b=>{
                const proj=projects.find(p=>p.id===b.project_id);
                const dStart=daysUntil(b.start_date);
                return(
                  <tr key={b.id}>
                    <td style={{fontWeight:500}}>{b.name}</td>
                    <td><span className="badge badge-blue">{proj?.name}</span></td>
                    <td style={{fontFamily:'var(--font-mono)',fontWeight:700,color:'var(--green)'}}>{b.planned_agents}</td>
                    <td>
                      <div style={{fontSize:12}}>{fmtDate(b.start_date)}</div>
                      {dStart!==null&&dStart>0&&<div style={{fontSize:10,color:'var(--muted)'}}>in {dStart} Tagen</div>}
                    </td>
                    <td style={{fontSize:12}}>{fmtDate(b.active_date)}</td>
                    <td style={{fontFamily:'var(--font-mono)',fontSize:12}}>{b.monthly_rate}€</td>
