                    <td style={{fontSize:12,color:'var(--muted)'}}>{b.notes}</td>
                    <td><button className="btn btn-sm" onClick={()=>removeBatch(b.id)} style={{color:'var(--red)'}}>×</button></td>
                  </tr>
                );
              })}
            </tbody>
