      </div>

      {/* 12-Month Forecast */}
      <div className="card">
        <div className="card-header"><span className="card-title">📈 Jahres-Forecast (12 Monate)</span></div>
        <div style={{overflowX:'auto'}}>
          <table style={{minWidth:900}}>
            <thead><tr>
              <th style={{minWidth:100}}>Monat</th>
              <th>👥 Aktiv</th>
              <th>📚 Schulung</th>
              <th>💶 Umsatz est.</th>
              <th>💸 Kosten est.</th>
              <th>📊 Marge est.</th>
              <th>🎯 Batches</th>
            </tr></thead>
            <tbody>
              {months.map(({date,label},i)=>{
                const stats=getMonthStats(date);
                const margin=stats.revenue-stats.cost;
                const isNow=i===0;
                return(
                  <tr key={label} style={{background:isNow?'rgba(59,130,246,.06)':'transparent'}}>
                    <td style={{fontWeight:isNow?700:400,color:isNow?'var(--blue)':'var(--text)'}}>{label}{isNow&&' ◀'}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--teal)',fontWeight:600}}>{stats.activeEmps}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--purple)'}}>{stats.trainingEmps}</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--green)',fontWeight:600}}>{stats.revenue.toLocaleString('de-DE')} €</td>
                    <td style={{fontFamily:'var(--font-mono)',color:'var(--red)'}}>{stats.cost.toLocaleString('de-DE')} €</td>
                    <td style={{fontFamily:'var(--font-mono)',fontWeight:700,color:margin>=0?'var(--teal)':'var(--red)'}}>{margin>=0?'+':''}{margin.toLocaleString('de-DE')} €</td>
                    <td>
                      {stats.batches.map(b=>(
                        <span key={b.id} className="badge badge-amber" style={{fontSize:9,marginRight:3}}>{b.name?.split(' ').slice(-2).join(' ')}</span>
                      ))}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

