TestEditor:
function TestEditor({testQuestions, setTestQuestions}){
  const [editQ, setEditQ] = useState(null);
  const [form, setForm] = useState({type:'verstehen',question:'',options:['','','',''],correct:0,placeholder:''});
  const set = (k,v) => setForm(f=>({...f,[k]:v}));
  const setOpt = (i,v) => setForm(f=>({...f,options:f.options.map((o,j)=>j===i?v:o)}));

  function openNew(){
    setForm({type:'verstehen',question:'',options:['','','',''],correct:0,placeholder:''});
    setEditQ('new');
  }
  function openEdit(q){
    setForm({...q,options:q.options||['','','','']});
    setEditQ(q.id);
  }
  function save(){
    if(!form.question) return;
    if(editQ==='new'){
      setTestQuestions(qs=>[...qs,{...form,id:'q'+Date.now()}]);
    } else {
      setTestQuestions(qs=>qs.map(q=>q.id===editQ?{...form,id:editQ}:q));
    }
    setEditQ(null);
  }
  function del(id){ if(window.confirm('Frage löschen?')) setTestQuestions(qs=>qs.filter(q=>q.id!==id)); }
  function moveUp(i){ if(i===0) return; const a=[...testQuestions]; [a[i-1],a[i]]=[a[i],a[i-1]]; setTestQuestions(a); }
  function moveDown(i){ if(i===testQuestions.length-1) return; const a=[...testQuestions]; [a[i],a[i+1]]=[a[i+1],a[i]]; setTestQuestions(a); }

  return(
    <div>
      {editQ&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:620}}>
            <div className="modal-header">
              <span className="modal-title">{editQ==='new'?'Neue Frage':'Frage bearbeiten'}</span>
              <button className="btn" onClick={()=>setEditQ(null)}>×</button>
            </div>
            <div className="modal-body">
              <div className="form-row">
                <div className="form-group"><label className="form-label">Typ</label>
                  <select className="form-select" value={form.type} onChange={e=>set('type',e.target.value)}>
                    <option value="verstehen">📋 Verständnis (Multiple Choice)</option>
                    <option value="schreiben">✍️ Schriftlich (Freitext)</option>
                  </select>
                </div>
              </div>
              <div className="form-group" style={{marginBottom:12}}>
                <label className="form-label">Frage</label>
                <textarea className="form-input" rows={3} value={form.question} onChange={e=>set('question',e.target.value)} style={{resize:'vertical'}}/>
              </div>
              {form.type==='verstehen'&&(
                <>
                  <div style={{fontSize:11,color:'var(--muted)',marginBottom:8,fontWeight:600,textTransform:'uppercase'}}>Antwortoptionen (richtige markieren)</div>
                  {[0,1,2].map(i=>(
                    <div key={i} style={{display:'flex',gap:8,alignItems:'center',marginBottom:6}}>
                      <input type="radio" name="correct" checked={form.correct===i} onChange={()=>set('correct',i)} style={{accentColor:'var(--green)',flexShrink:0}}/>
                      <input className="form-input" style={{flex:1}} value={form.options[i]||''} onChange={e=>setOpt(i,e.target.value)} placeholder={`Option ${i+1}`}/>
                      {form.correct===i&&<span style={{fontSize:10,color:'var(--green)',fontWeight:600}}>✓ Richtig</span>}
                    </div>
                  ))}
                </>
              )}
              {form.type==='schreiben'&&(
                <div className="form-group">
                  <label className="form-label">Platzhalter-Text</label>
                  <input className="form-input" value={form.placeholder||''} onChange={e=>set('placeholder',e.target.value)} placeholder="z.B. Schreibe deine Antwort auf Deutsch..."/>
                </div>
              )}
            </div>
            <div className="modal-footer">
              <button className="btn" onClick={()=>setEditQ(null)}>Abbrechen</button>
              <button className="btn btn-primary" onClick={save}>Speichern</button>
            </div>
          </div>
        </div>
      )}

      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div style={{fontSize:13,color:'var(--muted)'}}>{testQuestions.filter(q=>q.type==='verstehen').length} Verständnis · {testQuestions.filter(q=>q.type==='schreiben').length} Schriftlich</div>
        <button className="btn btn-primary" onClick={openNew}>+ Neue Frage</button>
      </div>

      {testQuestions.map((q,i)=>(
        <div key={q.id} className="card" style={{marginBottom:8}}>
          <div className="card-body" style={{padding:'10px 14px'}}>
            <div style={{display:'flex',gap:10,alignItems:'flex-start'}}>
              <div style={{display:'flex',flexDirection:'column',gap:3}}>
                <button className="btn btn-sm" style={{padding:'2px 6px',fontSize:10}} onClick={()=>moveUp(i)}>↑</button>
                <button className="btn btn-sm" style={{padding:'2px 6px',fontSize:10}} onClick={()=>moveDown(i)}>↓</button>
              </div>
              <div style={{flex:1}}>
                <div style={{display:'flex',gap:8,alignItems:'center',marginBottom:4}}>
                  <span style={{fontSize:10,padding:'2px 7px',borderRadius:4,background:q.type==='verstehen'?'var(--blue-bg)':'var(--purple-bg)',color:q.type==='verstehen'?'var(--blue)':'var(--purple)',fontWeight:600}}>
                    {q.type==='verstehen'?'📋 Verständnis':'✍️ Schriftlich'}
                  </span>
                  <span style={{fontSize:10,color:'var(--muted)'}}>Frage {i+1}</span>
                </div>
                <div style={{fontSize:13,fontWeight:500,marginBottom:q.type==='verstehen'?8:0}}>{q.question}</div>
                {q.type==='verstehen'&&(
                  <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
                    {(q.options||[]).map((o,oi)=>(
                      <span key={oi} style={{fontSize:11,padding:'2px 8px',borderRadius:4,background:oi===q.correct?'var(--green-bg)':'var(--surface)',color:oi===q.correct?'var(--green)':'var(--dim)',border:`1px solid ${oi===q.correct?'rgba(34,197,94,.3)':'var(--border)'}`}}>
                        {oi===q.correct?'✓ ':''}{o}
                      </span>
                    ))}
                  </div>
                )}
              </div>
              <div style={{display:'flex',gap:4}}>
                <button className="btn btn-sm" onClick={()=>openEdit(q)}>✎</button>
                <button className="btn btn-sm" style={{color:'var(--red)'}} onClick={()=>del(q.id)}>×</button>
              </div>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

