LanguageTestPage:
function LanguageTestPage({token, cvList, onComplete, testQuestions}){
  const questions = testQuestions||LANGUAGE_TEST_QUESTIONS;
  const cv = cvList.find(c=>c.test_token===token);
  const [answers, setAnswers] = useState({});
  const [submitted, setSubmitted] = useState(false);
  const setA = (id, val) => setAnswers(a=>({...a,[id]:val}));

  if(!cv) return <div style={{padding:40,textAlign:'center',color:'var(--muted)'}}>Ungültiger Test-Link</div>;
  if(cv.test_completed||submitted) return(
    <div style={{maxWidth:600,margin:'60px auto',padding:32,background:'var(--card)',borderRadius:'var(--r-lg)',border:'1px solid var(--green)',textAlign:'center'}}>
      <div style={{fontSize:40,marginBottom:16}}>✅</div>
      <div style={{fontSize:20,fontWeight:600,marginBottom:8}}>Test abgeschlossen!</div>
      <div style={{fontSize:13,color:'var(--muted)'}}>Vielen Dank {cv.first_name}! Wir werden deine Antworten prüfen und uns melden.</div>
    </div>
  );

  function submit(){
    const verstehen = (testQuestions||LANGUAGE_TEST_QUESTIONS).filter(q=>q.type==='verstehen').filter(q=>answers[q.id]===q.correct).length;
    const schreiben = (testQuestions||LANGUAGE_TEST_QUESTIONS).filter(q=>q.type==='schreiben').filter(q=>(answers[q.id]||'').length>50).length;
    onComplete(cv.id, answers, {verstehen, schreiben});
    setSubmitted(true);
  }

  const allDone = (testQuestions||LANGUAGE_TEST_QUESTIONS).every(q=>q.type==='verstehen'?answers[q.id]!==undefined:(answers[q.id]||'').length>20);

  return(
    <div style={{maxWidth:680,margin:'0 auto',padding:'24px 16px'}}>
      <div style={{textAlign:'center',marginBottom:32}}>
        <div style={{fontSize:24,fontWeight:700,marginBottom:4}}>Sprach & Kompetenz Test</div>
        <div style={{fontSize:14,color:'var(--muted)'}}>Hallo {cv.first_name}! Bitte beantworte alle Fragen so gut du kannst.</div>
        <div style={{fontSize:12,color:'var(--muted)',marginTop:4}}>Position: {cv.target_role} · Dauer: ca. 10-15 Minuten</div>
      </div>

      <div style={{marginBottom:12,padding:'8px 16px',background:'var(--blue-bg)',borderRadius:'var(--r)',border:'1px solid rgba(59,130,246,.3)',fontSize:12,color:'var(--blue)'}}>
        📋 Teil 1: Verständnisfragen (Multiple Choice)
      </div>
      {(testQuestions||LANGUAGE_TEST_QUESTIONS).filter(q=>q.type==='verstehen').map((q,i)=>(
        <div key={q.id} className="card" style={{marginBottom:12}}>
          <div className="card-body">
            <div style={{fontSize:13,fontWeight:500,marginBottom:12,lineHeight:1.5}}>{i+1}. {q.question}</div>
            {q.options.map((opt,oi)=>(
              <label key={oi} style={{display:'flex',alignItems:'center',gap:10,padding:'8px 12px',borderRadius:'var(--r)',cursor:'pointer',marginBottom:6,background:answers[q.id]===oi?'var(--blue-bg)':'var(--surface)',border:`1px solid ${answers[q.id]===oi?'rgba(59,130,246,.4)':'var(--border)'}`,transition:'all .15s'}}>
                <input type="radio" name={q.id} checked={answers[q.id]===oi} onChange={()=>setA(q.id,oi)} style={{accentColor:'var(--blue)'}}/>
                <span style={{fontSize:13}}>{opt}</span>
              </label>
            ))}
          </div>
        </div>
      ))}

      <div style={{marginBottom:12,marginTop:24,padding:'8px 16px',background:'var(--purple-bg)',borderRadius:'var(--r)',border:'1px solid rgba(167,139,250,.3)',fontSize:12,color:'var(--purple)'}}>
        ✍️ Teil 2: Schriftliche Antworten
      </div>
      {(testQuestions||LANGUAGE_TEST_QUESTIONS).filter(q=>q.type==='schreiben').map((q,i)=>(
        <div key={q.id} className="card" style={{marginBottom:12}}>
          <div className="card-body">
            <div style={{fontSize:13,fontWeight:500,marginBottom:10,lineHeight:1.5}}>{i+6}. {q.question}</div>
            <textarea
              className="form-input"
              rows={4}
              placeholder={q.placeholder}
              value={answers[q.id]||''}
              onChange={e=>setA(q.id,e.target.value)}
              style={{resize:'vertical',width:'100%'}}
            />
            <div style={{fontSize:10,color:'var(--muted)',marginTop:4,textAlign:'right'}}>{(answers[q.id]||'').length} Zeichen</div>
          </div>
        </div>
      ))}

      <button
        className={`btn ${allDone?'btn-primary':''}`}
        style={{width:'100%',padding:'12px',fontSize:14,marginTop:8,opacity:allDone?1:.5}}
        disabled={!allDone}
        onClick={submit}
      >
        ✅ Test abschicken
      </button>
      {!allDone&&<div style={{textAlign:'center',fontSize:11,color:'var(--muted)',marginTop:6}}>Bitte alle Fragen beantworten</div>}
    </div>
  );
}

