CVModal:
function CVModal({cv, projects, team, onSave, onClose}){
  // Role helpers
  const isHR = !team || ['role_superadmin','role_management'].includes(team?.role_id);
  const isTeamLead = team?.role_id === 'role_teamlead';
  const canSeeHRInternal = isHR; // HR notes, salary context, AI assessment
  const canSeeProbes = isHR || isTeamLead; // can see/add Hörprobe + Schriftprobe

  const [form, setForm] = useState(cv||{
    first_name:'',last_name:'',email:'',phone:'',city:'',birthday:'',gender:'',
    language_level:'',writing_level:'',languages_str:'',dialect:'',
    education:'',education_level:'',experience_years:'',work_history:'',
    notes:'',target_project:'',target_role:'',primary_skill:'',
    cv_date:new Date().toISOString().slice(0,10),status:(cv?.status&&cv.status!=='')?cv.status:'cv_inbound',
    available_from:'',homeoffice_pref:'',
    work_hours:'8',work_model:'morning',work_weekend:'no',work_holidays:'no',
    work_notes:'',start_date:'',
    bank_name:'',bank_account:'',id_card:'',hardware:'',
    photo_color:'#1d4ed8',audio_url:'',audio_transcript:'',writing_sample:'',
    skills:[],better_phone:false,better_email:false,is_structured:false,sales_potential:false,
    // Einschätzung HR
    hr_notes:'',hr_rating:'',dialect:'',hobbies:'',
    assessed_level:'',assessed_writing:'',assessment_note:'',
    ai_level:'',ai_writing:'',ai_confidence_level:'',ai_confidence_writing:'',
    ai_reasoning_audio:'',ai_reasoning_writing:'',
    contract:null,
  });
  const [tab, setTab] = useState('basis');
  const set = (k,v) => setForm(f=>({...f,[k]:v}));

  // ── KI-Bewertung ────────────────────────────────────────────
  const [aiLoading, setAiLoading] = useState({writing:false, audio:false});
  const [aiResult,  setAiResult]  = useState({writing:null,  audio:null});

  async function runAiAssessment(type){
    const apiKey = localStorage.getItem('jsr_anthropic_key')||'';
    if(!apiKey){
      alert('Kein Anthropic API-Key hinterlegt.\nBitte in Admin → System → API-Keys eintragen.');
      return;
    }

    const LEVELS = {
      A2:{label:'A2',color:'#dc2626',bg:'#fef2f2',desc:'Sehr einfach, viele Fehler'},
      B1:{label:'B1',color:'#d97706',bg:'#fffbeb',desc:'Verständlich, aber Fehler'},
      B2:{label:'B2',color:'#059669',bg:'#ecfdf5',desc:'Gut & professionell'},
      C1:{label:'C1',color:'#2563eb',bg:'#eff6ff',desc:'Sehr gut, kaum Fehler'},
      C2:{label:'C2',color:'#7c3aed',bg:'#f5f3ff',desc:'Muttersprachliches Niveau'},
    };

    setAiLoading(l=>({...l,[type]:true}));
    setAiResult(r=>({...r,[type]:null}));

    try {
      let prompt = '';
      if(type==='writing'){
        const text = (form.writing_sample||'').trim();
        if(!text || text.length < 20){
          alert('Bitte zuerst eine Schriftprobe eingeben.');
          setAiLoading(l=>({...l,[type]:false}));
          return;
        }
        prompt = `Du bist ein Sprachexperte der deutschen Sprache. Bewerte folgenden Text eines Bewerbers für eine deutschsprachige Kundendienst-Stelle.

Aufgabe des Bewerbers war: Eine kurze Antwort-Mail auf eine Kunden-E-Mail schreiben (Problem mit doppelter Buchungsabbuchung).

Bewerber-Antwort:
"${text}"

Gib genau folgendes JSON zurück (nur JSON, kein Markdown):
{
  "level": "B2",
  "confidence": "hoch",
  "strengths": "kurze Stärken (max 1 Satz)",
  "weaknesses": "kurze Schwächen (max 1 Satz, leer wenn keine)",
  "reasoning": "1-2 Sätze warum dieses Level"
}

Levels: A2 (Sehr einfach), B1 (Verständlich mit Fehlern), B2 (Gut & professionell), C1 (Sehr gut), C2 (Nahezu muttersprachlich).
Sei streng aber fair. Für Kundenservice ist B2 das Minimum.`;
      } else {
        // Audio: HR gibt Transkript ein
        const transcript = (form.audio_transcript||'').trim();
        if(!transcript || transcript.length < 20){
          alert('Bitte zuerst ein Transkript der Hörprobe eingeben.');
          setAiLoading(l=>({...l,[type]:false}));
          return;
        }
        prompt = `Du bist ein Sprachexperte der deutschen Sprache. Bewerte folgendes Transkript einer mündlichen Äußerung eines Bewerbers für eine deutschsprachige Kundendienst-Stelle.

Vorlesetext war: "Guten Tag, mein Name ist [Name]. Ich freue mich, heute bei JSR BPO vorzusprechen. Im Kundenkontakt ist mir eine freundliche und klare Kommunikation besonders wichtig — denn zufriedene Kunden sind das Ziel jedes guten Gesprächs."

Transkript (vom HR-Mitarbeiter nach Anhören eingetragen):
"${transcript}"

Gib genau folgendes JSON zurück (nur JSON, kein Markdown):
{
  "level": "B2",
  "confidence": "mittel",
  "strengths": "kurze Stärken (max 1 Satz)",
  "weaknesses": "kurze Schwächen (max 1 Satz, leer wenn keine)",
  "reasoning": "1-2 Sätze warum dieses Level"
}

Levels: A2, B1, B2, C1, C2. Für Kundenservice ist B2 das Minimum.`;
      }

      const res = await fetch('https://api.anthropic.com/v1/messages',{
        method:'POST',
        headers:{
          'Content-Type':'application/json',
          'x-api-key':apiKey,
          'anthropic-version':'2023-06-01',
          'anthropic-dangerous-direct-browser-access':'true'
        },
        body:JSON.stringify({
          model:'claude-sonnet-4-20250514',
          max_tokens:300,
          messages:[{role:'user',content:prompt}]
        })
      });

      const data = await res.json();
      if(data.error) throw new Error(data.error.message);

      const raw = data.content?.[0]?.text || '{}';
      const clean = raw.replace(/```json|```/g,'').trim();
      const result = JSON.parse(clean);

      // Save AI assessment separately (FYI only — does NOT auto-fill HR final rating)
      const lvl = result.level;
      if(['A2','B1','B2','C1','C2'].includes(lvl)){
        if(type==='writing'){
          set('ai_writing', lvl);
          set('ai_confidence_writing', result.confidence||'');
          set('ai_reasoning_writing', result.reasoning||'');
        }
        if(type==='audio'){
          set('ai_level', lvl);
          set('ai_confidence_level', result.confidence||'');
          set('ai_reasoning_audio', result.reasoning||'');
        }
      }

      setAiResult(r=>({...r,[type]:{...result, levelMeta: LEVELS[lvl]||LEVELS['B2']}}));
    } catch(err){
      setAiResult(r=>({...r,[type]:{error:'Fehler: '+err.message}}));
    } finally {
      setAiLoading(l=>({...l,[type]:false}));
    }
  };

  // Progressive fields based on status
  const STATUS_ORDER = ['cv_inbound','cv_accepted','cv_confirmed','invited','interview','selection1','selection2','contract','training_planned','training','parking','active'];
  const statusIdx = STATUS_ORDER.indexOf(form.status);
  const atLeast = (s) => statusIdx >= STATUS_ORDER.indexOf(s);
  const isTerminal = ['rejected_by_us','rejected_by_applicant','rejected_by_client','blacklist','terminated','inactive'].includes(form.status);
  const showAll = atLeast('training_planned') || isTerminal;

  const TABS = [
    {id:'basis',    label:'Basis',    icon:'👤', always:true},
    {id:'sprache',  label:'Sprache',  icon:'🗣', always:true},
    {id:'arbeit',   label:'Zeiten',   icon:'⏰', always:true},
    {id:'hr',       label:'HR',       icon:'📋', show: atLeast('cv_accepted') && isHR},
    {id:'phase',    label:'Phase',    icon:'📊', always:true},
    {id:'vertrag',  label:'Vertrag',  icon:'📝', show: atLeast('selection2') && isHR},
  ].filter(t=>t.always||t.show);

  const fromLP = cv && cv.source==='LP'; // came from landing page

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:640,maxHeight:'90vh',display:'flex',flexDirection:'column'}}>
        <div className="modal-header">
          <div>
            <div style={{fontWeight:700,fontSize:15}}>
              {cv?`${cv.first_name} ${cv.last_name}`:'Neuer Bewerber'}
              {fromLP&&<span style={{marginLeft:8,fontSize:10,padding:'2px 7px',borderRadius:20,background:'var(--green-bg)',color:'var(--green)',fontWeight:700}}>via LP</span>}
            </div>
            {cv&&(()=>{const s=STATUS_FLOW.find(x=>x.key===form.status);return s?<span style={{fontSize:11,padding:'2px 8px',borderRadius:20,background:s.color+'22',color:s.color,fontWeight:700,marginTop:3,display:'inline-block'}}>{s.icon} {s.label}</span>:null;})()}
          </div>
          <button className="btn" onClick={onClose}>×</button>
        </div>

        {/* TABS */}
        <div style={{display:'flex',borderBottom:'1px solid var(--border)',padding:'0 16px',flexShrink:0,overflowX:'auto'}}>
          {TABS.map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)}
              style={{padding:'10px 14px',border:'none',background:'transparent',cursor:'pointer',
                fontFamily:'var(--font)',fontSize:12,fontWeight:700,whiteSpace:'nowrap',
                color:tab===t.id?'var(--blue)':'var(--muted)',
                borderBottom:tab===t.id?'2px solid var(--blue)':'2px solid transparent',marginBottom:-1}}>
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        <div className="modal-body" style={{flex:1,overflowY:'auto'}}>


          {/* ── BASIS (immer sichtbar, LP-Felder readonly wenn vom LP) ── */}
          {tab==='basis'&&(
            <div>
              {fromLP&&atLeast('cv_inbound')&&!atLeast('cv_accepted')&&(
                <div style={{padding:'8px 12px',background:'var(--blue-bg)',borderRadius:'var(--r-md)',
                  marginBottom:12,fontSize:12,color:'var(--blue)',border:'1px solid rgba(29,78,216,.15)'}}>
                  ℹ Daten vom Bewerber über die Landing Page — erst nach Akzeptieren erweiterbar.
                </div>
              )}
              <div className="form-row">
                <div className="form-group"><label className="form-label">Vorname *</label>
                  <input className="form-input" value={form.first_name||''} onChange={e=>set('first_name',e.target.value)} placeholder="Vorname"/></div>
                <div className="form-group"><label className="form-label">Nachname *</label>
                  <input className="form-input" value={form.last_name||''} onChange={e=>set('last_name',e.target.value)} placeholder="Nachname"/></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">E-Mail</label>
                  <input className="form-input" type="email" value={form.email||''} onChange={e=>set('email',e.target.value)}/></div>
                <div className="form-group"><label className="form-label">Telefon</label>
                  <input className="form-input" value={form.phone||''} onChange={e=>set('phone',e.target.value)}/></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Stadt</label>
                  <input className="form-input" value={form.city||''} onChange={e=>set('city',e.target.value)}/></div>
                <div className="form-group"><label className="form-label">Geburtsdatum</label>
                  <input className="form-input" type="date" value={form.birthday||''} onChange={e=>set('birthday',e.target.value)}/></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Geschlecht</label>
                  <select className="form-select" value={form.gender||''} onChange={e=>set('gender',e.target.value)}>
                    <option value=''>—</option><option value='m'>Männlich</option><option value='f'>Weiblich</option><option value='d'>Divers</option>
                  </select></div>
                <div className="form-group"><label className="form-label">CV Datum</label>
                  <input className="form-input" type="date" value={form.cv_date||''} onChange={e=>set('cv_date',e.target.value)}/></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Ausbildung / Beruf</label>
                  <input className="form-input" value={form.education||''} onChange={e=>set('education',e.target.value)} placeholder="z.B. BWL, IT"/></div>
                <div className="form-group"><label className="form-label">Ausbildungsgrad</label>
                  <select className="form-select" value={form.education_level||''} onChange={e=>set('education_level',e.target.value)}>
                    <option value=''>—</option><option value='school'>Schule</option><option value='bachelor'>Bachelor (laufend)</option><option value='bachelor_done'>Bachelor abgeschlossen</option><option value='master'>Master</option><option value='other'>Sonstiges</option>
                  </select></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Berufserfahrung (Jahre)</label>
                  <input className="form-input" type="number" min="0" value={form.experience_years||''} onChange={e=>set('experience_years',e.target.value)}/></div>
                <div className="form-group"><label className="form-label">Notizen (intern)</label>
                  <input className="form-input" value={form.notes||''} onChange={e=>set('notes',e.target.value)}/></div>
              </div>
              <div className="form-group"><label className="form-label">Bisherige Stationen</label>
                <textarea className="form-input" rows={2} value={form.work_history||''} onChange={e=>set('work_history',e.target.value)} placeholder="Arbeitgeber, Positionen…"/></div>

              {/* Hörprobe */}
              <div style={{borderTop:'1px solid var(--border)',paddingTop:14,marginTop:4}}>
