                  {!form.audio_url&&<span style={{marginLeft:8,fontSize:10,color:'var(--amber)',fontWeight:600}}>Erforderlich</span>}
                  {form.audio_url&&<span style={{marginLeft:8,fontSize:10,color:'var(--green)',fontWeight:600}}>✓ vorhanden</span>}
                </div>

                {/* Vorlesetext */}
                <div style={{padding:'12px 14px',background:'var(--blue-bg)',borderRadius:'var(--r-md)',
                  border:'1px solid rgba(29,78,216,.15)',marginBottom:12}}>
                  <div style={{fontSize:10,fontWeight:700,color:'var(--blue)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:6}}>
                    📋 Vorlesetext
                  </div>
                  <div style={{fontSize:13,color:'var(--text)',lineHeight:1.7,fontStyle:'italic'}}>
                    „Guten Tag, mein Name ist {form.first_name||'[Name]'}. Ich freue mich, heute bei JSR BPO vorzusprechen. Im Kundenkontakt ist mir eine freundliche und klare Kommunikation besonders wichtig — denn zufriedene Kunden sind das Ziel jedes guten Gesprächs."
                  </div>
                </div>

                {/* Audio player or recorder */}
                {form.audio_url?(
                  <div style={{display:'flex',alignItems:'center',gap:10,padding:'10px 12px',
                    background:'var(--green-bg)',borderRadius:'var(--r-md)',border:'1px solid rgba(5,150,105,.2)',marginBottom:12}}>
                    <audio controls src={form.audio_url} style={{flex:1,height:32}}/>
                    <button type="button" className="btn btn-sm" onClick={()=>set('audio_url','')}
                      style={{color:'var(--red)',border:'1px solid rgba(239,68,68,.3)',fontSize:11,flexShrink:0}}>
                      × Neu
                    </button>
                  </div>
                ):(
                  <div style={{marginBottom:12}}><AudioRecorder onRecorded={dataUrl=>set('audio_url',dataUrl)} maxSeconds={30}/></div>
                )}

                {/* HR Bewertung Hörprobe */}
                {canSeeHRInternal&&<div style={{background:'var(--surface-2)',borderRadius:'var(--r)',padding:'12px 14px',border:'1px solid var(--border)'}}>
