                <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:8}}>Pipeline</div>
                <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
                  {(()=>{
                    // Pipeline steps in order (excluding terminal)
                    const PIPE=[
                      {key:'cv_inbound',      label:'Inbound',        icon:'📥'},
                      {key:'cv_accepted',     label:'Akzeptiert',     icon:'📄'},
                      {key:'cv_confirmed',    label:'Angelegt',       icon:'✅'},
                      {key:'invited',         label:'Einladung',      icon:'✉️'},
                      {key:'interview',       label:'Vorstellung',    icon:'🤝'},
                      {key:'selection1',      label:'Selektion 1',    icon:'🔍'},
                      {key:'selection2',      label:'Selektion 2',    icon:'🎯'},
                      {key:'contract',        label:'Arbeitsvertrag', icon:'📝'},
                      {key:'training_planned',label:'Schulung geplant',icon:'📅'},
                      {key:'training',        label:'Schulung',       icon:'📚'},
                      {key:'active',          label:'Aktiv',          icon:'⚡'},
                    ];
                    const curIdx=PIPE.findIndex(s=>s.key===form.status);
                    return(
                      <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
                        {PIPE.map((s,i)=>{
                          const isDone   = i < curIdx;
                          const isActive = i === curIdx;
                          const isNext   = i === curIdx+1;
                          const isFuture = i > curIdx+1;
                          const canClick = isDone || isActive || isNext;
                          const col = '#059669'; // green for all states
                          return(
                            <button key={s.key} type="button"
                              disabled={!canClick}
                              onClick={()=>canClick&&set('status',s.key)}
                              style={{
                                padding:'7px 13px',
                                borderRadius:20,
                                fontFamily:'var(--font)',
                                fontSize:12,
                                fontWeight:isActive?800:600,
                                border:'2px solid '+(
                                  isActive?'#059669':
                                  isDone?'rgba(5,150,105,.35)':
                                  isNext?'rgba(5,150,105,.25)':
                                  'var(--border)'
                                ),
                                background:
                                  isActive?'rgba(5,150,105,.18)':
                                  isDone?'rgba(5,150,105,.06)':
                                  'transparent',
                                color:
                                  isActive?'#059669':
                                  isDone?'rgba(5,150,105,.55)':
                                  isNext?'var(--muted)':
                                  'var(--border)',
                                opacity:isFuture?0.4:1,
                                cursor:canClick?'pointer':'not-allowed',
                                transform:isActive?'scale(1.06)':'scale(1)',
                                boxShadow:isActive?'0 2px 10px rgba(5,150,105,.25)':'none',
                                transition:'all .15s',
                              }}>
                              {isDone&&<span style={{marginRight:4,fontSize:10}}>✓</span>}
                              {s.icon} {s.label}
                              {isNext&&<span style={{marginLeft:4,fontSize:9,opacity:.6}}>←</span>}
                            </button>
                          );
                        })}
                      </div>
                    );
                  })()}
                </div>
              </div>
              <div style={{paddingTop:12,borderTop:'1px solid var(--border)'}}>
                <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:8}}>Abschluss</div>
                <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
                  {STATUS_FLOW.filter(s=>s.terminal).map(s=>{
                    const isActive=form.status===s.key;
                    return(
                      <button key={s.key} type="button" onClick={()=>set('status',s.key)}
                        style={{padding:'5px 12px',borderRadius:20,cursor:'pointer',fontFamily:'var(--font)',
                          fontSize:11,fontWeight:700,border:'2px solid '+(isActive?s.color:'var(--border)'),
                          background:isActive?s.color+'22':'transparent',color:isActive?s.color:'var(--muted)',
                          transition:'all .15s'}}>
                        {s.icon} {s.label}
                      </button>
                    );
                  })}
                </div>
              </div>
              {form.status&&(()=>{
                const s=STATUS_FLOW.find(x=>x.key===form.status);
                if(!s) return null;
                return(
                  <div style={{marginTop:14,padding:'12px 16px',borderRadius:'var(--r-md)',
                    background:s.color+'15',border:'1.5px solid '+s.color,display:'flex',alignItems:'center',gap:10}}>
                    <span style={{fontSize:20}}>{s.icon}</span>
                    <div>
                      <div style={{fontWeight:700,color:s.color,fontSize:14}}>{s.label}</div>
                      <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>
                        {s.key==='selection2'||s.key==='contract'?'✅ Vertrag kann jetzt angelegt werden':
                         s.key==='active'?'⚠ Speichern = Konvertierung zu Mitarbeiter':
                         s.key==='interview'?'✅ Einschätzungs-Felder werden freigeschaltet':
                         s.key==='selection1'?'✅ Skill-Felder werden freigeschaltet':
                         s.key==='cv_accepted'?'✅ HR-Notizen und Zielstelle werden freigeschaltet':''}
                      </div>
                    </div>
                  </div>
                );
              })()}
            </div>
          )}

          {/* ── VERTRAG (ab selection2) ── */}
          {tab==='vertrag'&&(
            <div>
              {atLeast('selection2')
                ?<ContractSection cv={form} onContractSaved={contract=>{
                    setForm(f=>({...f, contract, status:'contract'}));
                  }} onPromote={isHR?()=>{
                    if(window.confirm('Arbeitsvertrag unterschrieben — CV jetzt zu Mitarbeiter konvertieren?')){
                      onSave({...form, status:'active'});
                    }
                  }:undefined}/>
                :<div style={{padding:32,textAlign:'center',color:'var(--muted)'}}>
                  <div style={{fontSize:36,marginBottom:10}}>📝</div>
                  <div style={{fontWeight:600,marginBottom:6}}>Vertrag erst ab Selektion 2</div>
                  <div style={{fontSize:12}}>Phasen-Tab → Selektion 2 setzen, dann erscheint der Vertrag hier.</div>
                </div>
              }
            </div>
          )}

        </div>

        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Abbrechen</button>
          <button className="btn btn-primary" onClick={()=>onSave(form)}>Speichern</button>
        </div>
      </div>
    </div>
  );
}

CVResultsModal:
function CVResultsModal({cv, onClose, onPromote}){
  const allQs = LANGUAGE_TEST_QUESTIONS;
  const verstehen = allQs.filter(q=>q.type==='verstehen');
  const schreiben = allQs.filter(q=>q.type==='schreiben');
  const correctVerstehen = verstehen.filter(q=>cv.test_answers[q.id]===q.correct).length;
  const writtenFilled = schreiben.filter(q=>(cv.test_answers[q.id]||'').length>50).length;
  const writtenQuality = schreiben.filter(q=>(cv.test_answers[q.id]||'').length>120).length; // ausführliche Antworten
  const overallScore = Math.round((correctVerstehen/Math.max(verstehen.length,1)*100 + writtenFilled/Math.max(schreiben.length,1)*100 + writtenQuality/Math.max(schreiben.length,1)*50) / 2.5);

  const langLevel = getLangLevel(overallScore);

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:660}}>
        <div className="modal-header">
          <span className="modal-title">📊 Testergebnis — {cv.first_name} {cv.last_name}</span>
          <button className="btn" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {/* Score Summary */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:12,marginBottom:16}}>
            <div style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'12px 16px',textAlign:'center'}}>
              <div style={{fontSize:28,fontWeight:700,color:'var(--blue)',fontFamily:'var(--font-mono)'}}>{correctVerstehen}/{verstehen.length}</div>
              <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>Verständnis korrekt</div>
            </div>
            <div style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'12px 16px',textAlign:'center'}}>
              <div style={{fontSize:28,fontWeight:700,color:'var(--purple)',fontFamily:'var(--font-mono)'}}>{writtenFilled}/{schreiben.length}</div>
              <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>Schriftlich beantwortet</div>
            </div>
            <div style={{background:langLevel.bg,border:`2px solid ${langLevel.color}`,borderRadius:'var(--r)',padding:'12px 16px',textAlign:'center',gridColumn:'span 1'}}>
              <div style={{fontSize:32,fontWeight:800,color:langLevel.color,fontFamily:'var(--font-mono)',letterSpacing:'.05em'}}>{langLevel.level}</div>
              <div style={{fontSize:12,fontWeight:600,color:langLevel.color,marginTop:2}}>{langLevel.label}</div>
              <div style={{fontSize:10,color:'var(--muted)',marginTop:4}}>{overallScore}% Gesamtscore</div>
            </div>
          </div>

          {/* Level Description */}
          <div style={{padding:'10px 14px',background:langLevel.bg,border:`1px solid ${langLevel.color}44`,borderRadius:'var(--r)',marginBottom:16,display:'flex',alignItems:'center',gap:12}}>
            <div style={{fontSize:28,fontWeight:800,color:langLevel.color,fontFamily:'var(--font-mono)',minWidth:40}}>{langLevel.level}</div>
            <div>
              <div style={{fontSize:13,fontWeight:600,color:langLevel.color}}>{langLevel.label}</div>
              <div style={{fontSize:12,color:'var(--dim)',marginTop:2}}>{langLevel.desc}</div>
              <div style={{fontSize:11,color:'var(--muted)',marginTop:3}}>Empfehlung: {langLevel.level==='A1'?'❌ Nicht geeignet':langLevel.level==='A2'?'⚠️ Nur mit Vorbehalt':langLevel.level==='B1'?'✅ Für einfache Aufgaben geeignet':langLevel.level==='B2'?'✅ Gut geeignet für Call Center':langLevel.level==='C1'?'⭐ Sehr gut geeignet, auch für komplexe Anfragen':'⭐ Exzellent — für Senior-Positionen geeignet'}</div>
            </div>
          </div>

          {/* Verständnis Fragen */}
          <div style={{marginBottom:12,fontSize:12,fontWeight:600,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em'}}>Verständnisfragen</div>
          {verstehen.map((q,i)=>{
            const ans = cv.test_answers[q.id];
            const correct = ans===q.correct;
            return(
              <div key={q.id} style={{marginBottom:8,padding:'8px 12px',borderRadius:'var(--r)',background:correct?'var(--green-bg)':'var(--red-bg)',border:`1px solid ${correct?'rgba(34,197,94,.3)':'rgba(239,68,68,.3)'}`}}>
                <div style={{fontSize:12,fontWeight:500,marginBottom:4}}>{i+1}. {q.question.slice(0,80)}...</div>
                <div style={{fontSize:11,color:'var(--muted)'}}>
                  Antwort: <strong style={{color:correct?'var(--green)':'var(--red)'}}>{q.options[ans]||'Nicht beantwortet'}</strong>
                  {!correct&&<span style={{marginLeft:8,color:'var(--green)'}}>✓ Richtig: {q.options[q.correct]}</span>}
                </div>
              </div>
            );
          })}

          {/* Schriftliche Antworten */}
          <div style={{marginTop:16,marginBottom:12,fontSize:12,fontWeight:600,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em'}}>Schriftliche Antworten</div>
          {schreiben.map((q,i)=>{
            const ans = cv.test_answers[q.id]||'';
            const filled = ans.length>50;
            return(
              <div key={q.id} style={{marginBottom:10,padding:'10px 12px',borderRadius:'var(--r)',background:'var(--surface)',border:'1px solid var(--border)'}}>
                <div style={{fontSize:12,fontWeight:500,marginBottom:6}}>{i+6}. {q.question.slice(0,80)}...</div>
                <div style={{fontSize:12,color:filled?'var(--text)':'var(--muted)',lineHeight:1.5,fontStyle:filled?'normal':'italic'}}>
                  {ans||'Nicht beantwortet'}
                </div>
                {ans&&<div style={{fontSize:10,color:'var(--muted)',marginTop:4}}>{ans.length} Zeichen</div>}
              </div>
            );
          })}
        </div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Schließen</button>
          {overallScore>=35&&<button className="btn btn-green" onClick={()=>onPromote(cv)}>🎯 Als Mitarbeiter übernehmen ({langLevel.level})</button>}
        </div>
      </div>
    </div>
  );
}

