  const [modal, setModal] = useState(null);
  const [testView, setTestView] = useState(null);
  const [savedFeedback, setSavedFeedback] = useState(null);
  const [quickView, setQuickView] = useState(null); // token
  const [resultsModal, setResultsModal] = useState(null);
  const [filter, setFilter] = useState('all');

  function saveCv(form){
    if(form.id){
      if(form.status==='active'){
        // Auto-promote to employee when status set to active
        onPromoteToEmployee(form);
        setModal(null);
        return;
      }
      setCvList(l=>l.map(c=>c.id===form.id?form:c));
      setSavedFeedback(form.id);
      setTimeout(()=>setSavedFeedback(null),2000);
    } else {
      setCvList(l=>[...l,{...form,id:'cv'+Date.now(),test_token:'tok_cv'+Date.now(),status:form.status||'cv_inbound',source:form.source||'HR'}]);
    }
    setModal(null);
  }

  function sendTest(cv){
    setCvList(l=>l.map(c=>c)); // test_sent removed
    // In real app: send email with link
    alert('Test-Link für '+cv.first_name+' '+cv.last_name);
  }

  function completeTest(cvId, answers, scores){
    setCvList(l=>l.map(c=>c.id===cvId?{...c,status:'test_done',test_completed:true,test_answers:answers,test_scores:scores}:c));
  }

  function deleteCv(id){ if(window.confirm('Bewerber löschen?')) setCvList(l=>l.filter(c=>c.id!==id)); }

  const STATUS_NORM={'new':'cv_inbound','test_sent':'cv_inbound','test_done':'cv_accepted','reviewed':'cv_accepted','rejected':'rejected_by_us','accepted':'contract'};
  const normStatus=(s)=>STATUS_NORM[s]||s;
  const filtered = filter==='all' ? cvList : cvList.filter(c=>normStatus(c.status)===filter);

  // If test token in URL
  if(testView){
    return(
      <div>
        <div style={{display:'flex',alignItems:'center',gap:12,padding:'12px 0',marginBottom:8}}>
          <button className="btn" onClick={()=>setTestView(null)}>← Zurück zu CVs</button>
          <span style={{fontSize:13,color:'var(--muted)'}}>Test-Vorschau — so sieht der Bewerber den Test</span>
        </div>
        <LanguageTestPage token={testView} cvList={cvList} onComplete={(id,ans,sc)=>{completeTest(id,ans,sc);setTestView(null);}}/>
      </div>
    );
  }

  return(
    <div>
      {modal&&<CVModal cv={modal==='add'?null:modal} projects={projects} team={team} onSave={saveCv} onClose={()=>setModal(null)}/>}
      {resultsModal&&<CVResultsModal cv={resultsModal} onClose={()=>setResultsModal(null)} onPromote={cv=>{onPromoteToEmployee(cv);setResultsModal(null);}}/>}

      {/* Toolbar */}
      <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:8,flexWrap:'wrap'}}>
        <button className="btn btn-primary btn-sm" onClick={()=>setModal('add')}>+ Neuer Bewerber</button>
        <div style={{flex:1}}/>
        <span style={{fontSize:12,color:'var(--muted)'}}>{filtered.length} von {cvList.length} Bewerbern</span>
      </div>

      {/* Filter Pills */}
      <div style={{display:'flex',gap:5,flexWrap:'wrap',marginBottom:12}}>
          <button onClick={()=>setFilter('all')}
            style={{padding:'4px 11px',borderRadius:20,border:'1.5px solid '+(filter==='all'?'var(--blue)':'var(--border)'),
              background:filter==='all'?'var(--blue-bg)':'transparent',color:filter==='all'?'var(--blue)':'var(--muted)',
              fontSize:11,fontWeight:700,cursor:'pointer',fontFamily:'var(--font)'}}>
            Alle ({cvList.length})
          </button>
          {STATUS_FLOW.filter(s=>!s.terminal).map(s=>{
            const count=cvList.filter(c=>c.status===s.key).length;
            if(!count) return null;
            const active=filter===s.key;
            return(
              <button key={s.key} onClick={()=>setFilter(s.key)}
                style={{padding:'4px 11px',borderRadius:20,fontSize:11,fontWeight:700,cursor:'pointer',fontFamily:'var(--font)',
                  border:'1.5px solid '+(active?s.color:s.color+'44'),
                  background:active?s.color+'22':'transparent',
                  color:active?s.color:'var(--muted)'}}>
                {s.icon} {s.label} ({count})
              </button>
            );
          })}
      </div>

      {/* Quick View Panel */}
      {quickView&&(
        <div style={{position:'fixed',top:0,right:0,width:380,height:'100vh',background:'var(--card)',
          boxShadow:'-4px 0 20px rgba(0,0,0,.12)',zIndex:1000,display:'flex',flexDirection:'column'}}>
          <div style={{padding:'14px 16px',borderBottom:'1px solid var(--border)',display:'flex',alignItems:'center',gap:10}}>
            <div style={{width:40,height:40,borderRadius:'50%',background:quickView.photo_color||'var(--blue)',
              display:'flex',alignItems:'center',justifyContent:'center',fontSize:16,color:'#fff',fontWeight:700,flexShrink:0}}>
              {(quickView.first_name||'?')[0]}{(quickView.last_name||'?')[0]}
            </div>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:15}}>{quickView.first_name} {quickView.last_name}</div>
              {(()=>{const s=STATUS_FLOW.find(x=>x.key===quickView.status);return s?<span style={{fontSize:11,padding:'2px 8px',borderRadius:20,background:s.color+'18',color:s.color,fontWeight:700}}>{s.icon} {s.label}</span>:null;})()}
            </div>
            <button className="btn btn-sm btn-primary" onClick={()=>{setModal(quickView);setQuickView(null);}}>✏ Öffnen</button>
            <button className="btn btn-sm" onClick={()=>setQuickView(null)}>×</button>
          </div>
          <div style={{padding:'12px 16px',flex:1,overflowY:'auto'}}>
            {[
              ['E-Mail',quickView.email],['Telefon',quickView.phone],['Stadt',quickView.city],
              ['Geburtsdatum',quickView.birthday],['Deutsch',quickView.language_level],
              ['Schrift',quickView.writing_level],['Sprachen',quickView.languages_str],
              ['Erfahrung',quickView.experience_years?(quickView.experience_years+' Jahre'):null],
              ['Ausbildung',quickView.education],
              ['Stunden/Tag',quickView.work_hours?(quickView.work_hours+'h'):null],
              ['Wochenende',quickView.work_weekend==='yes'?'Ja':'Nein'],
              ['Notiz',quickView.notes||quickView.hr_notes],
            ].filter(([,v])=>v).map(([k,v])=>(
              <div key={k} style={{display:'flex',gap:8,padding:'6px 0',borderBottom:'1px solid var(--border)'}}>
                <div style={{width:90,fontSize:11,fontWeight:700,color:'var(--muted)',flexShrink:0}}>{k}</div>
                <div style={{fontSize:13,flex:1}}>{v}</div>
              </div>
            ))}
            {quickView.audio_url&&<div style={{marginTop:12}}><div style={{fontSize:11,fontWeight:700,color:'var(--muted)',marginBottom:6}}>🎙 Hörprobe</div><audio controls src={quickView.audio_url} style={{width:'100%',height:32}}/></div>}
            {quickView.hr_rating&&<div style={{marginTop:10,padding:'8px 12px',background:'var(--green-bg)',borderRadius:'var(--r-md)',fontSize:12,fontWeight:600,color:'var(--green)'}}>Einschätzung: {({sehr_gut:'⭐⭐⭐ Sehr gut',gut:'⭐⭐ Gut',ok:'⭐ OK',schwach:'❌ Schwach'})[quickView.hr_rating]}</div>}
          </div>
        </div>
      )}

      {/* CV Table */}
      <div className="card">
        <div className="table-responsive"><table>
          <thead><tr>
            <th>Name</th>
            <th>Kontakt</th>
            <th style={{textAlign:"center"}}>Deutsch</th>
            <th>Status</th>
            <th style={{textAlign:"center"}}>🎙</th>
            <th style={{textAlign:"center"}}>Nächste Phase</th>
            <th>Aktionen</th>
          </tr></thead>
          <tbody>
            {filtered.length===0&&<tr><td colSpan={7} style={{textAlign:'center',padding:24,color:'var(--muted)'}}>Keine Bewerber</td></tr>}
            {filtered.map(cv=>{
              const proj = projects.find(p=>p.id===cv.target_project);
              const st = STATUS_FLOW.find(s=>s.key===normStatus(cv.status));
              const correctV = cv.test_completed ? LANGUAGE_TEST_QUESTIONS.filter(q=>q.type==='verstehen'&&cv.test_answers[q.id]===q.correct).length : null;
              const totalV = LANGUAGE_TEST_QUESTIONS.filter(q=>q.type==='verstehen').length;
              const writtenF = cv.test_completed ? LANGUAGE_TEST_QUESTIONS.filter(q=>q.type==='schreiben'&&(cv.test_answers[q.id]||'').length>50).length : null;
              const overallScore = cv.test_completed ? Math.round(((correctV/totalV)+(writtenF/5))/2*100) : null;

              return(
                <tr key={cv.id} onClick={()=>setQuickView(cv)} style={{cursor:'pointer'}} className="table-row-hover">
                  <td>
                    <div style={{fontWeight:600,fontSize:13}}>{cv.first_name} {cv.last_name}</div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>{cv.city}{cv.source==='LP'&&<span style={{marginLeft:6,fontSize:9,padding:'1px 5px',borderRadius:20,background:'var(--green-bg)',color:'var(--green)',fontWeight:700}}>LP</span>}</div>
                  </td>
                  <td>
                    <div style={{fontSize:12}}>{cv.email||'—'}</div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>{cv.phone}</div>
                  </td>
                  <td style={{textAlign:'center'}}>
                    {cv.language_level?<span style={{fontWeight:700,color:'var(--blue)',fontSize:13}}>{cv.language_level}</span>:<span style={{color:'var(--dim)'}}>—</span>}
                    {cv.writing_level&&<div style={{fontSize:10,color:'var(--muted)'}}>Schrift: {cv.writing_level}</div>}
                  </td>
                  <td>
                    {(()=>{const s=STATUS_FLOW.find(x=>x.key===normStatus(cv.status));return s?<span style={{padding:'3px 8px',borderRadius:20,fontSize:11,fontWeight:700,background:s.color+'18',color:s.color,border:'1px solid '+s.color+'33',whiteSpace:'nowrap'}}>{s.icon} {s.label}</span>:<span style={{color:'var(--dim)',fontSize:11}}>{cv.status||'—'}</span>;})()}
                    {cv.cv_date&&<div style={{fontSize:10,color:'var(--dim)',marginTop:2}}>{new Date(cv.cv_date).toLocaleDateString('de-DE')}</div>}
                  </td>
                  {/* Hörprobe */}
                  <td style={{textAlign:'center'}}>
                    {cv.audio_url
                      ?<span title="Hörprobe vorhanden" style={{fontSize:16,cursor:'pointer'}} onClick={e=>{e.stopPropagation();setQuickView(cv);}}>🎙</span>
                      :<span style={{color:'var(--border)',fontSize:14}}>○</span>}
                  </td>
                  {/* Nächste Phase bereit? */}
                  <td style={{textAlign:'center'}}>
                    {(()=>{
                      const PIPE=['cv_inbound','cv_accepted','cv_confirmed','invited','interview','selection1','selection2','contract','training_planned','training','active'];
                      const REQ={'cv_accepted':['first_name','last_name','email','phone'],'cv_confirmed':['first_name','last_name','email','phone','language_level','audio_url'],'invited':['first_name','last_name','email','phone','language_level'],'selection1':['first_name','last_name','email','phone','language_level','target_project'],'selection2':['first_name','last_name','email','phone','language_level','target_project','primary_skill']};
                      const cur=PIPE.indexOf(normStatus(cv.status));
                      const next=PIPE[cur+1];
                      if(!next||cur<0) return null;
                      const missing=(REQ[next]||[]).filter(f=>!cv[f]||String(cv[f]).trim()==='');
                      const nextS=STATUS_FLOW.find(s=>s.key===next);
                      if(missing.length===0){
                        return<span style={{fontSize:11,padding:'2px 8px',borderRadius:20,background:'var(--green-bg)',color:'var(--green)',fontWeight:700,border:'1px solid rgba(5,150,105,.2)',whiteSpace:'nowrap',cursor:'pointer'}}
                          onClick={e=>{e.stopPropagation();setModal(cv);}}>
                          ✓ {nextS?.label}
                        </span>;
                      }
                      return<span style={{fontSize:10,color:'var(--amber)',fontWeight:600}} title={'Fehlt: '+missing.join(', ')}>⚠ {missing.length} Feld{missing.length>1?'er':''}</span>;
                    })()}
                  </td>
                  <td onClick={e=>e.stopPropagation()}>
                    <div style={{display:'flex',gap:4}}>
                      <button className="btn btn-sm" title="Bearbeiten" onClick={()=>setModal(cv)}>✎</button>
                      <button className="btn btn-sm" title="Löschen" onClick={()=>deleteCv(cv.id)} style={{color:'var(--red)'}}>×</button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table></div>
      </div>
    </div>
  );
}

