KnowledgeBase:
function KnowledgeBase({projects, employees, kbData, setKbData}){
  const [selProj, setSelProj] = useState('all');
  const [selSkill, setSelSkill] = useState('all');
  const [search, setSearch] = useState('');
  const [editArticle, setEditArticle] = useState(null);
  const [viewArticle, setViewArticle] = useState(null);
  const [form, setForm] = useState({project_id:'',skill:'',title:'',content:'',tags:[],level:'Grundlagen'});
  const setF = (k,v) => setForm(f=>({...f,[k]:v}));

  const articles = kbData.articles||[];
  const skills = [...new Set(articles.map(a=>a.skill))];

  const filtered = articles.filter(a=>{
    if(selProj!=='all'&&a.project_id!==selProj) return false;
    if(selSkill!=='all'&&a.skill!==selSkill) return false;
    if(search){
      const q=search.toLowerCase();
      return a.title.toLowerCase().includes(q)||a.content.toLowerCase().includes(q)||(a.tags||[]).some(t=>t.toLowerCase().includes(q));
    }
    return true;
  });

  function saveArticle(){
    if(!form.title) return;
    if(editArticle==='new'){
      setKbData(d=>({...d,articles:[...d.articles,{...form,id:'kb'+Date.now(),created_at:new Date().toISOString().slice(0,10)}]}));
    } else {
      setKbData(d=>({...d,articles:d.articles.map(a=>a.id===editArticle?{...form,id:editArticle}:a)}));
    }
    setEditArticle(null);
  }
  function delArticle(id){ if(window.confirm('Artikel löschen?')) setKbData(d=>({...d,articles:d.articles.filter(a=>a.id!==id)})); }

  // Simple markdown renderer
  function renderMd(text){
    if(!text) return '';
    return text
      .replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>')
      .split('\n').join('<br/>');
  }

  return(
    <div>
      {/* View Article Modal */}
      {viewArticle&&(
        <div className="modal-overlay" onClick={()=>setViewArticle(null)}>
          <div className="modal" style={{width:680}} onClick={e=>e.stopPropagation()}>
            <div className="modal-header">
              <div>
                <span className="modal-title">{viewArticle.title}</span>
                <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>{viewArticle.skill} · {viewArticle.level}</div>
              </div>
              <button className="btn" onClick={()=>setViewArticle(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{fontSize:13,lineHeight:1.8,color:'var(--text)'}} dangerouslySetInnerHTML={{__html:renderMd(viewArticle.content)}}/>
              <div style={{marginTop:16,display:'flex',gap:6,flexWrap:'wrap'}}>
                {(viewArticle.tags||[]).map(t=><span key={t} className="badge badge-blue">{t}</span>)}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn" onClick={()=>{setForm(viewArticle);setEditArticle(viewArticle.id);setViewArticle(null);}}>✎ Bearbeiten</button>
              <button className="btn btn-primary" onClick={()=>setViewArticle(null)}>Schließen</button>
            </div>
          </div>
        </div>
      )}

      {/* Edit Modal */}
      {editArticle&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:680}}>
            <div className="modal-header">
              <span className="modal-title">{editArticle==='new'?'Neuer Artikel':'Artikel bearbeiten'}</span>
              <button className="btn" onClick={()=>setEditArticle(null)}>×</button>
            </div>
            <div className="modal-body">
              <div className="form-row">
                <div className="form-group"><label className="form-label">Titel</label><input className="form-input" value={form.title} onChange={e=>setF('title',e.target.value)} placeholder="z.B. Beschwerdebearbeitung: HEAT-Methode"/></div>
                <div className="form-group"><label className="form-label">Skill / Kategorie</label><input className="form-input" value={form.skill} onChange={e=>setF('skill',e.target.value)} placeholder="z.B. Inbound Telefonie"/></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Projekt</label>
                  <select className="form-select" value={form.project_id} onChange={e=>setF('project_id',e.target.value)}>
                    <option value="">Allgemein (alle Projekte)</option>
                    {projects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
                <div className="form-group"><label className="form-label">Level</label>
                  <select className="form-select" value={form.level} onChange={e=>setF('level',e.target.value)}>
                    {['Grundlagen','Fortgeschritten','Experte'].map(l=><option key={l}>{l}</option>)}
                  </select>
                </div>
              </div>
              <div className="form-group" style={{marginBottom:12}}>
                <label className="form-label">Inhalt (Markdown: **fett**, Zeilenumbrüche mit Enter)</label>
                <textarea className="form-input" rows={10} value={form.content} onChange={e=>setF('content',e.target.value)} style={{resize:'vertical',fontFamily:'var(--font-mono)',fontSize:12}}/>
              </div>
              <div className="form-group">
                <label className="form-label">Tags (kommagetrennt)</label>
                <input className="form-input" value={(form.tags||[]).join(', ')} onChange={e=>setF('tags',e.target.value.split(',').map(t=>t.trim()).filter(Boolean))} placeholder="z.B. Telefon, Beschwerde, Basics"/>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn" onClick={()=>setEditArticle(null)}>Abbrechen</button>
              <button className="btn btn-primary" onClick={saveArticle}>Speichern</button>
            </div>
          </div>
        </div>
      )}

      {/* Toolbar */}
      <div style={{display:'flex',gap:8,marginBottom:14,flexWrap:'wrap',alignItems:'center'}}>
        <input style={{background:'var(--card)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'6px 10px',color:'var(--text)',fontFamily:'var(--font-body)',fontSize:13,outline:'none',width:220}} placeholder="🔍 Suche..." value={search} onChange={e=>setSearch(e.target.value)}/>
        <select style={{background:'var(--card)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'6px 10px',color:'var(--text)',fontSize:13,outline:'none'}} value={selProj} onChange={e=>setSelProj(e.target.value)}>
          <option value="all">Alle Projekte</option>
          <option value="">Allgemein</option>
          {projects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        <select style={{background:'var(--card)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'6px 10px',color:'var(--text)',fontSize:13,outline:'none'}} value={selSkill} onChange={e=>setSelSkill(e.target.value)}>
          <option value="all">Alle Skills</option>
          {skills.map(s=><option key={s}>{s}</option>)}
        </select>
        <button className="btn btn-primary" onClick={()=>{setForm({project_id:'',skill:'',title:'',content:'',tags:[],level:'Grundlagen'});setEditArticle('new');}} style={{marginLeft:'auto'}}>+ Artikel erstellen</button>
      </div>

      {/* Articles Grid */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(320px,1fr))',gap:12}}>
        {filtered.length===0&&<div style={{gridColumn:'1/-1',textAlign:'center',padding:40,color:'var(--muted)'}}>Keine Artikel gefunden</div>}
        {filtered.map(a=>{
          const proj=projects.find(p=>p.id===a.project_id);
          return(
            <div key={a.id} className="card" style={{cursor:'pointer'}} onClick={()=>setViewArticle(a)}>
              <div className="card-body">
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:8}}>
                  <div style={{flex:1}}>
                    <div style={{fontSize:13,fontWeight:600,marginBottom:4,color:'var(--text)'}}>{a.title}</div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>{a.skill}{proj?` · ${proj.name}`:'  · Allgemein'}</div>
                  </div>
                  <span style={{fontSize:10,padding:'2px 7px',borderRadius:4,background:a.level==='Grundlagen'?'var(--green-bg)':a.level==='Fortgeschritten'?'var(--amber-bg)':'var(--red-bg)',color:a.level==='Grundlagen'?'var(--green)':a.level==='Fortgeschritten'?'var(--amber)':'var(--red)',fontWeight:600,flexShrink:0,marginLeft:8}}>{a.level}</span>
                </div>
                <div style={{fontSize:12,color:'var(--dim)',lineHeight:1.5,overflow:'hidden',display:'-webkit-box',WebkitLineClamp:3,WebkitBoxOrient:'vertical'}}>
                  {a.content.replace(/\*\*/g,'').slice(0,150)}...
                </div>
                <div style={{display:'flex',gap:5,marginTop:8,flexWrap:'wrap',justifyContent:'space-between',alignItems:'center'}}>
                  <div style={{display:'flex',gap:4,flexWrap:'wrap'}}>
                    {(a.tags||[]).slice(0,3).map(t=><span key={t} className="badge badge-blue" style={{fontSize:9}}>{t}</span>)}
                  </div>
                  <div style={{display:'flex',gap:4}}>
                    <button className="btn btn-sm" style={{fontSize:10}} onClick={e=>{e.stopPropagation();setForm(a);setEditArticle(a.id);}}>✎</button>
                    <button className="btn btn-sm" style={{fontSize:10,color:'var(--red)'}} onClick={e=>{e.stopPropagation();delArticle(a.id);}}>×</button>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

