ELearning:
function ELearning({projects, employees, elData, setElData, kbData}){
  const [view, setView] = useState('list'); // list | course | edit_course | take_course
  const [selCourse, setSelCourse] = useState(null);
  const [selEmp, setSelEmp] = useState(null);
  const [moduleIdx, setModuleIdx] = useState(0);
  const [quizAnswers, setQuizAnswers] = useState({});
  const [editCourse, setEditCourse] = useState(null);
  const [courseForm, setCourseForm] = useState({project_id:'',title:'',description:'',level:'Grundlagen',skill:'',duration_min:30,modules:[]});
  const setCF = (k,v) => setCourseForm(f=>({...f,[k]:v}));

  const courses = elData.courses||[];

  function startCourse(course, emp){
    setSelCourse(course);
    setSelEmp(emp);
    setModuleIdx(0);
    setQuizAnswers({});
    setView('take_course');
  }

  function completeCourse(){
    setElData(d=>({...d,courses:d.courses.map(c=>c.id===selCourse.id?{...c,completed_ids:[...new Set([...(c.completed_ids||[]),selEmp.id])]}:c)}));
    setView('list');
    alert(`🎓 ${selEmp.first_name} hat "${selCourse.title}" abgeschlossen!`);
  }

  function enrollEmp(courseId, empId){
    setElData(d=>({...d,courses:d.courses.map(c=>c.id===courseId?{...c,enrolled_ids:[...new Set([...(c.enrolled_ids||[]),empId])]}:c)}));
  }

  function saveCourse(){
    if(!courseForm.title) return;
    if(editCourse==='new'){
      setElData(d=>({...d,courses:[...d.courses,{...courseForm,id:'el'+Date.now(),enrolled_ids:[],completed_ids:[]}]}));
    } else {
      setElData(d=>({...d,courses:d.courses.map(c=>c.id===editCourse?{...courseForm,id:editCourse}:c)}));
    }
    setView('list');
  }

  // Take Course View
  if(view==='take_course'&&selCourse&&selEmp){
    const module = selCourse.modules[moduleIdx];
    const isLast = moduleIdx===selCourse.modules.length-1;
    const kbArticle = module.kb_article_id ? kbData.articles?.find(a=>a.id===module.kb_article_id) : null;
    const quiz = module.quiz||[];
    const quizDone = quiz.length===0||quiz.every((_,i)=>quizAnswers[`${module.id}_${i}`]!==undefined);

    return(
      <div style={{maxWidth:700,margin:'0 auto'}}>
        <div style={{display:'flex',alignItems:'center',gap:12,marginBottom:20}}>
          <button className="btn" onClick={()=>setView('list')}>← Kurs verlassen</button>
          <div style={{flex:1}}>
            <div style={{fontSize:15,fontWeight:600}}>{selCourse.title}</div>
            <div style={{fontSize:12,color:'var(--muted)'}}>👤 {selEmp.first_name} {selEmp.last_name} · Modul {moduleIdx+1}/{selCourse.modules.length}</div>
          </div>
          <div style={{fontSize:12,fontFamily:'var(--font-mono)',color:'var(--blue)'}}>{Math.round((moduleIdx)/selCourse.modules.length*100)}%</div>
        </div>

        {/* Progress */}
        <div className="progress-track" style={{marginBottom:20,height:8}}>
          <div className="progress-fill" style={{width:`${(moduleIdx/selCourse.modules.length)*100}%`,background:'var(--blue)'}}/>
        </div>

        {/* Module Steps */}
        <div style={{display:'flex',gap:6,marginBottom:20,flexWrap:'wrap'}}>
          {selCourse.modules.map((m,i)=>(
            <div key={m.id} style={{padding:'4px 10px',borderRadius:4,fontSize:11,fontWeight:500,background:i<moduleIdx?'var(--green-bg)':i===moduleIdx?'var(--blue-bg)':'var(--surface)',color:i<moduleIdx?'var(--green)':i===moduleIdx?'var(--blue)':'var(--muted)',border:`1px solid ${i<moduleIdx?'rgba(34,197,94,.3)':i===moduleIdx?'rgba(59,130,246,.3)':'var(--border)'}`}}>
              {i<moduleIdx?'✓':i===moduleIdx?'▶':'○'} {m.title}
            </div>
          ))}
        </div>

        {/* Module Content */}
        <div className="card" style={{marginBottom:16}}>
          <div className="card-header"><span className="card-title">📖 {module.title}</span></div>
          <div className="card-body">
            {kbArticle&&(
              <div style={{padding:12,background:'var(--blue-bg)',borderRadius:'var(--r)',border:'1px solid rgba(59,130,246,.3)',marginBottom:12}}>
                <div style={{fontSize:11,color:'var(--blue)',fontWeight:600,marginBottom:6}}>📚 Wissensbasis: {kbArticle.title}</div>
                <div style={{fontSize:13,lineHeight:1.7}} dangerouslySetInnerHTML={{__html:kbArticle.content.replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>').split('\n').join('<br/>')}}/>
              </div>
            )}
            <div style={{fontSize:13,lineHeight:1.7,color:'var(--text)'}} dangerouslySetInnerHTML={{__html:module.content.split('\n').join('<br/>')}}/>
          </div>
        </div>

        {/* Quiz */}
        {quiz.length>0&&(
          <div className="card" style={{marginBottom:16}}>
            <div className="card-header"><span className="card-title">❓ Wissenscheck</span></div>
            <div className="card-body">
              {quiz.map((q,qi)=>{
                const ans = quizAnswers[`${module.id}_${qi}`];
                const answered = ans!==undefined;
                return(
                  <div key={qi} style={{marginBottom:12}}>
                    <div style={{fontSize:13,fontWeight:500,marginBottom:8}}>{q.q}</div>
                    {q.options.map((opt,oi)=>(
                      <label key={oi} style={{display:'flex',alignItems:'center',gap:8,padding:'7px 10px',borderRadius:'var(--r)',cursor:answered?'default':'pointer',marginBottom:5,background:answered?(oi===q.correct?'var(--green-bg)':ans===oi?'var(--red-bg)':'var(--surface)'):'var(--surface)',border:`1px solid ${answered?(oi===q.correct?'rgba(34,197,94,.4)':ans===oi?'rgba(239,68,68,.4)':'var(--border)'):'var(--border)'}`,transition:'all .15s'}}>
                        <input type="radio" name={`${module.id}_${qi}`} checked={ans===oi} onChange={()=>!answered&&setQuizAnswers(a=>({...a,[`${module.id}_${qi}`]:oi}))} style={{accentColor:'var(--blue)'}}/>
                        <span style={{fontSize:13}}>{opt}</span>
                        {answered&&oi===q.correct&&<span style={{marginLeft:'auto',color:'var(--green)',fontSize:12}}>✓ Richtig</span>}
                        {answered&&ans===oi&&oi!==q.correct&&<span style={{marginLeft:'auto',color:'var(--red)',fontSize:12}}>✗ Falsch</span>}
                      </label>
                    ))}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        <div style={{display:'flex',justifyContent:'flex-end',gap:10}}>
          {moduleIdx>0&&<button className="btn" onClick={()=>setModuleIdx(i=>i-1)}>← Zurück</button>}
          {!isLast&&<button className={`btn ${quizDone?'btn-primary':''}`} disabled={!quizDone} onClick={()=>setModuleIdx(i=>i+1)}>Weiter →</button>}
          {isLast&&<button className={`btn btn-green ${quizDone?'':'btn-disabled'}`} disabled={!quizDone} onClick={completeCourse}>🎓 Kurs abschließen</button>}
        </div>
      </div>
    );
  }

  return(
    <div>
      <div style={{display:'flex',justifyContent:'space-between',marginBottom:16}}>
        <div style={{fontSize:13,color:'var(--muted)'}}>{courses.length} Kurse · {courses.reduce((s,c)=>s+(c.enrolled_ids||[]).length,0)} Einschreibungen · {courses.reduce((s,c)=>s+(c.completed_ids||[]).length,0)} Abschlüsse</div>
        <button className="btn btn-primary" onClick={()=>{setCourseForm({project_id:'',title:'',description:'',level:'Grundlagen',skill:'',duration_min:30,modules:[]});setEditCourse('new');setView('edit_course');}}>+ Neuer Kurs</button>
      </div>

      {view==='edit_course'&&(
        <div className="card" style={{marginBottom:16}}>
          <div className="card-header"><span className="card-title">{editCourse==='new'?'Neuer Kurs':'Kurs bearbeiten'}</span></div>
          <div className="card-body">
            <div className="form-row">
              <div className="form-group"><label className="form-label">Titel</label><input className="form-input" value={courseForm.title} onChange={e=>setCF('title',e.target.value)}/></div>
              <div className="form-group"><label className="form-label">Skill</label><input className="form-input" value={courseForm.skill} onChange={e=>setCF('skill',e.target.value)}/></div>
            </div>
            <div className="form-row">
              <div className="form-group"><label className="form-label">Projekt</label>
                <select className="form-select" value={courseForm.project_id} onChange={e=>setCF('project_id',e.target.value)}>
                  <option value="">Allgemein</option>
                  {projects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div className="form-group"><label className="form-label">Level</label>
                <select className="form-select" value={courseForm.level} onChange={e=>setCF('level',e.target.value)}>
                  {['Grundlagen','Fortgeschritten','Experte'].map(l=><option key={l}>{l}</option>)}
                </select>
              </div>
            </div>
            <div className="form-group" style={{marginBottom:12}}><label className="form-label">Beschreibung</label><textarea className="form-input" rows={2} value={courseForm.description} onChange={e=>setCF('description',e.target.value)} style={{resize:'vertical'}}/></div>
            <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
              <button className="btn" onClick={()=>setView('list')}>Abbrechen</button>
              <button className="btn btn-primary" onClick={saveCourse}>Kurs speichern</button>
            </div>
          </div>
        </div>
      )}

      {/* Course Cards */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(340px,1fr))',gap:12}}>
        {courses.map(course=>{
          const proj=projects.find(p=>p.id===course.project_id);
          const enrolled=(course.enrolled_ids||[]).map(id=>employees.find(e=>e.id===id)).filter(Boolean);
          const completed=(course.completed_ids||[]).map(id=>employees.find(e=>e.id===id)).filter(Boolean);
          const completionPct=enrolled.length>0?Math.round(completed.length/enrolled.length*100):0;
          const eligibleEmps=employees.filter(e=>['active','training'].includes(e.status)&&!(course.enrolled_ids||[]).includes(e.id));

          return(
            <div key={course.id} className="card">
              <div className="card-body">
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:10}}>
                  <div>
                    <div style={{fontSize:14,fontWeight:600,marginBottom:3}}>{course.title}</div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>{course.skill}{proj?` · ${proj.name}`:' · Allgemein'} · {course.duration_min} Min.</div>
                  </div>
                  <span style={{fontSize:10,padding:'2px 7px',borderRadius:4,background:course.level==='Grundlagen'?'var(--green-bg)':course.level==='Fortgeschritten'?'var(--amber-bg)':'var(--red-bg)',color:course.level==='Grundlagen'?'var(--green)':course.level==='Fortgeschritten'?'var(--amber)':'var(--red)',fontWeight:600}}>{course.level}</span>
                </div>
                <div style={{fontSize:12,color:'var(--dim)',marginBottom:10,lineHeight:1.4}}>{course.description}</div>
                <div style={{marginBottom:10}}>
                  <div style={{display:'flex',justifyContent:'space-between',marginBottom:3}}>
                    <span style={{fontSize:11,color:'var(--muted)'}}>{completed.length}/{enrolled.length} abgeschlossen</span>
                    <span style={{fontSize:11,fontFamily:'var(--font-mono)',color:'var(--blue)'}}>{completionPct}%</span>
                  </div>
                  <div className="progress-track"><div className="progress-fill" style={{width:`${completionPct}%`,background:'var(--green)'}}/></div>
                </div>
                <div style={{display:'flex',gap:6,marginBottom:10,flexWrap:'wrap'}}>
                  {enrolled.map(e=>(
                    <span key={e.id} style={{fontSize:10,padding:'2px 7px',borderRadius:4,background:(course.completed_ids||[]).includes(e.id)?'var(--green-bg)':'var(--blue-bg)',color:(course.completed_ids||[]).includes(e.id)?'var(--green)':'var(--blue)',cursor:'pointer'}} onClick={()=>startCourse(course,e)}>
                      {(course.completed_ids||[]).includes(e.id)?'✓ ':''}{e.first_name}
                    </span>
                  ))}
                </div>
                <div style={{display:'flex',gap:6}}>
                  {eligibleEmps.length>0&&(
                    <select style={{flex:1,background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'5px 8px',color:'var(--text)',fontSize:12,outline:'none'}} onChange={e=>{if(e.target.value){enrollEmp(course.id,e.target.value);e.target.value='';}}} defaultValue="">
                      <option value="">+ MA einschreiben...</option>
                      {eligibleEmps.map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name}</option>)}
                    </select>
                  )}
                  <button className="btn btn-sm" onClick={()=>{setEditCourse(course.id);setCourseForm(course);setView('edit_course');}}>✎</button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

