RecruitingKanban:
function RecruitingKanban({employees, setEmployees, cvList, setCvList, projects}){
  const [dragging, setDragging] = useState(null);
  const [dragType, setDragType] = useState(null); // 'cv' | 'emp'
  const [selectedItem, setSelectedItem] = useState(null);
  const [filterProject, setFilterProject] = useState('all');

  const KANBAN_COLS = STATUS_FLOW.filter(s=>s.kanban);
  const KANBAN_KEYS = new Set(KANBAN_COLS.map(c=>c.key));

  // Normalize old CV statuses to new STATUS_FLOW keys
  const STATUS_MAP = {
    'new':'cv_inbound','test_sent':'cv_inbound','test_done':'cv_accepted',
    'reviewed':'cv_accepted','rejected':'rejected_by_us','accepted':'contract',
    'cv_received':'cv_inbound','in_system':'cv_accepted','presented':'selection1',
    'selected':'selection2',
  };
  function normalizeStatus(s){ return STATUS_MAP[s]||s; }

  // Combine CVs and employees for the funnel
  const allItems = [
    ...(cvList||[]).map(c=>({...c, _type:'cv', status:normalizeStatus(c.status)})),
    ...(employees||[])
      .filter(e=>!['active','terminated','inactive'].includes(e.status))
      .map(e=>({...e, _type:'emp', status:normalizeStatus(e.status)})),
  ];

  function onDrop(newStatus){
    if(!dragging) return;
    if(dragType==='cv'){
      // If moving CV to 'active' → auto-promote handled by parent
      if(newStatus==='active'){
        const cv=(cvList||[]).find(c=>c.id===dragging);
        if(cv && window.confirm('CV von '+cv.first_name+' '+cv.last_name+' zu Mitarbeiter konvertieren?')){
          // Trigger promotion via status save — CVsView handles it
          setCvList&&setCvList(l=>l.map(c=>c.id===dragging?{...c,status:'active'}:c));
        }
      } else {
        setCvList&&setCvList(l=>l.map(c=>c.id===dragging?{...c,status:newStatus,status_changed:new Date().toISOString().slice(0,10)}:c));
      }
    } else {
      setEmployees(es=>es.map(e=>e.id===dragging?{...e,status:newStatus,status_changed:new Date().toISOString().slice(0,10)}:e));
    }
    setDragging(null);
    setDragType(null);
  }

  function confirmCV(itemId, type){
    if(type==='cv'){
      setCvList&&setCvList(l=>l.map(c=>c.id===itemId?{...c,status:'cv_confirmed',cv_confirmed_at:new Date().toISOString().slice(0,10)}:c));
    } else {
      setEmployees(es=>es.map(e=>e.id===itemId?{...e,status:'cv_confirmed',cv_confirmed_at:new Date().toISOString().slice(0,10)}:e));
    }
  }

  return(
    <div>
      {selectedItem&&(
        selectedItem._type==='cv'
          ?<CVModal
              cv={selectedItem}
              projects={projects||[]}
              onSave={updatedCv=>{
                if(updatedCv.status==='active'){
                  // auto-promote
                  if(window.confirm('CV zu Mitarbeiter konvertieren?')){
                    setCvList&&setCvList(l=>l.filter(c=>c.id!==updatedCv.id));
                  }
                } else {
                  setCvList&&setCvList(l=>l.map(c=>c.id===updatedCv.id?updatedCv:c));
                }
                setSelectedItem(null);
              }}
              onClose={()=>setSelectedItem(null)}
            />
          :<EmployeeModal
              emp={selectedItem}
              projects={projects||[]}
              onSave={updatedEmp=>{
                setEmployees(es=>es.map(e=>e.id===updatedEmp.id?updatedEmp:e));
                setSelectedItem(null);
              }}
              onClose={()=>setSelectedItem(null)}
            />
      )}
      <div style={{display:'flex',gap:10,alignItems:'center',marginBottom:12,flexWrap:'wrap'}}>
        <div style={{fontSize:12,color:'var(--muted)'}}>
          Drag & Drop — CVs und Mitarbeiter durch die Pipeline ziehen
        </div>
        <div style={{marginLeft:'auto',display:'flex',gap:8,alignItems:'center'}}>
          <select className="form-select" style={{width:160}}
            value={filterProject} onChange={e=>setFilterProject(e.target.value)}>
            <option value="all">Alle Projekte</option>
            {(projects||[]).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
        </div>
      </div>

      <div style={{display:'flex',gap:8,overflowX:'auto',paddingBottom:12}}>
        {KANBAN_COLS.map(col=>{
          let colItems = allItems.filter(item=>item.status===col.key);
          if(filterProject!=='all') colItems=colItems.filter(item=>
            item.target_project===filterProject||item.project_id===filterProject
          );

          return(
            <div key={col.key}
              style={{minWidth:165,flex:'0 0 165px'}}
              onDragOver={e=>e.preventDefault()}
              onDrop={()=>onDrop(col.key)}>

              <div style={{padding:'6px 10px',borderRadius:'var(--r)',marginBottom:6,
                background:col.color+'22',borderLeft:'3px solid '+col.color,
                display:'flex',alignItems:'center',justifyContent:'space-between'}}>
                <span style={{fontSize:11,fontWeight:700,color:col.color}}>
                  {col.icon} {col.label}
                </span>
                <span style={{fontSize:10,background:'rgba(0,0,0,.08)',borderRadius:10,padding:'1px 6px',fontWeight:700}}>
                  {colItems.length}
                </span>
              </div>

              <div style={{minHeight:60,display:'flex',flexDirection:'column',gap:5}}>
                {colItems.map(item=>{
                  const name=(item.first_name||'?')+' '+(item.last_name||'');
                  const isCV=item._type==='cv';
                  return(
                    <div key={item.id}
                      draggable
                      onDragStart={e=>{e.stopPropagation();setDragging(item.id);setDragType(item._type);}}
                      onClick={()=>setSelectedItem(item)}
                      style={{padding:'7px 9px',cursor:'pointer',
                        background:'var(--card)',
                        border:'1px solid '+(isCV?'rgba(37,99,235,.3)':'rgba(5,150,105,.3)'),
                        borderRadius:'var(--r)',cursor:'grab',fontSize:11,
                        boxShadow:'0 1px 3px rgba(0,0,0,.06)'}}>
                      <div style={{display:'flex',alignItems:'center',gap:5,marginBottom:3}}>
                        <span style={{fontSize:9,padding:'1px 5px',borderRadius:8,fontWeight:700,
                          background:isCV?'var(--blue-bg)':'var(--green-bg)',
                          color:isCV?'var(--blue)':'var(--green)'}}>
                          {isCV?'CV':'MA'}
                        </span>
                        <span style={{fontWeight:600,flex:1,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                          {name}
                        </span>
                        {(()=>{
                          const since=item.last_status_change||item.cv_date;
                          if(!since) return null;
                          const d=Math.round((new Date()-new Date(since))/(864e5));
                          const col=d>14?'var(--red)':d>7?'var(--amber)':'var(--dim)';
                          return<div style={{fontSize:9,color:col,fontWeight:d>7?700:400,marginTop:2}}>
                            {d===0?'Heute':d===1?'Gestern':d+'d in Phase'}{d>7?' ⚠':''}
                          </div>;
                        })()}
                      </div>
                      <div style={{color:'var(--muted)',fontSize:10,display:'flex',gap:4,flexWrap:'wrap'}}>
                        {item.language_level&&<span>{item.language_level}</span>}
                        {item.location&&<span>{item.location==='Tirana'?'🇦🇱':'🇽🇰'}</span>}
                        {item.primary_skill&&<span style={{background:'var(--surface-2)',borderRadius:6,padding:'0 4px'}}>{item.primary_skill}</span>}
                      </div>
                      {col.key==='cv_accepted'&&(
                        <button
                          onClick={e=>{e.stopPropagation();confirmCV(item.id,item._type);}}
                          style={{marginTop:5,width:'100%',padding:'3px',border:'none',
                            borderRadius:4,background:'var(--green)',color:'white',
                            fontSize:10,fontWeight:700,cursor:'pointer'}}>
                          ✓ CV bestätigen
                        </button>
                      )}
                    </div>
                  );
                })}
                {colItems.length===0&&(
                  <div style={{height:40,border:'1.5px dashed var(--border)',borderRadius:'var(--r)',
                    display:'flex',alignItems:'center',justifyContent:'center',
                    fontSize:10,color:'var(--border)'}}>
                    Ablegen
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* Active employees */}
      {(employees||[]).filter(e=>e.status==='active').length>0&&(
        <div className="card" style={{marginTop:12}}>
          <div className="card-header">
            <span className="card-title">⚡ Aktive Mitarbeiter</span>
            <span style={{fontSize:11,color:'var(--muted)'}}>{(employees||[]).filter(e=>e.status==='active').length}</span>
          </div>
          <div style={{display:'flex',flexWrap:'wrap',gap:6,padding:'10px 14px'}}>
            {(employees||[]).filter(e=>e.status==='active').map(e=>(
              <div key={e.id} style={{padding:'4px 10px',borderRadius:20,fontSize:11,
                background:'var(--green-bg)',color:'var(--green)',fontWeight:600,
                border:'1px solid rgba(5,150,105,.2)'}}>
                {e.first_name} {e.last_name}
                {e.primary_skill&&<span style={{marginLeft:4,opacity:.7}}>· {e.primary_skill}</span>}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

OnboardingView:
function OnboardingView({employees, setEmployees}){
  const [selId, setSelId] = useState(null);
  const [hwModal, setHwModal] = useState(null);
  const [empModal, setEmpModal] = useState(null); // {emp, tab} // emp for hardware date modal
  const [hwDate, setHwDate] = useState('');

  const today = new Date().toISOString().slice(0,10);

  // Employees in onboarding pipeline
  // Onboarding: MA die kürzlich konvertiert wurden (max 60 Tage) oder noch in Schulung
  const onboardEmps = employees.filter(e=>{
    if(['contract','training_planned','training'].includes(e.status)) return true;
    if(e.status==='active'){
      const convertDate=e.converted_at||e.contract_start||e.start_date;
      if(!convertDate) return false;
      const days=Math.round((new Date()-new Date(convertDate))/(1000*60*60*24));
      return days<=60; // Aktive MA max 60 Tage nach Konvertierung
    }
    return false;
  }).sort((a,b)=>{
    const da=a.start_date||a.contract_start||'9999';
    const db=b.start_date||b.contract_start||'9999';
    return da.localeCompare(db);
  });

  // Hardware alert logic: needs_hardware when hardware==='order' AND start_date exists
  function hwStatus(emp){
    if(!emp.hardware||emp.hardware==='no') return null;
    if(emp.hardware==='yes'||emp.hw_done) return 'done';
    if(emp.hardware==='order'){
      if(!emp.hw_deadline) return 'needs_date';
      const days=Math.round((new Date(emp.hw_deadline)-new Date())/(1000*60*60*24));
      if(days<0) return 'overdue';
      if(days<=7) return 'urgent';
      return 'pending';
    }
    return null;
  }

  function hwLabel(emp){
    const s=hwStatus(emp);
    const cfg={
      done:    {label:'✅ Hardware bereit',     bg:'var(--green-bg)', c:'var(--green)',  bd:'rgba(5,150,105,.2)'},
      needs_date:{label:'📅 Termin fehlt',      bg:'var(--amber-bg)', c:'var(--amber)', bd:'rgba(217,119,6,.2)'},
      urgent:  {label:'⚡ Diese Woche fällig',  bg:'var(--red-bg)',   c:'var(--red)',   bd:'rgba(239,68,68,.2)'},
      overdue: {label:'🚨 Überfällig!',          bg:'var(--red-bg)',   c:'var(--red)',   bd:'rgba(239,68,68,.3)'},
      pending: {label:'🔄 Hardware bestellt',   bg:'var(--blue-bg)', c:'var(--blue)',  bd:'rgba(29,78,216,.2)'},
    };
    return cfg[s]||null;
  }

  function markHwDone(emp){
    setEmployees(es=>es.map(e=>e.id===emp.id?{...e,hw_done:true,hw_done_at:new Date().toISOString().slice(0,10),hardware:'yes'}:e));
  }

  function saveHwDate(emp, date){
    setEmployees(es=>es.map(e=>e.id===emp.id?{...e,hw_deadline:date}:e));
    setHwModal(null);
  }

  const sel = selId ? onboardEmps.find(e=>e.id===selId) : null;

  // Checklist items
  function checks(emp){
    return [
      {label:'E-Mail vorhanden',     done:!!emp.email,         req:true,  tab:'hr',     field:'email',         hint:'HR & Verwaltung → E-Mail (oben)'},
      {label:'Telefon vorhanden',    done:!!emp.phone,         req:true,  tab:'hr',     field:'phone',         hint:'HR & Verwaltung → Telefon (oben)'},
      {label:'Startdatum gesetzt',   done:!!emp.start_date||!!emp.contract_start, req:true, tab:'vertrag', hint:'Vertrag-Tab → Startdatum eintragen'},
      {label:'Vertrag unterzeichnet',done:!!(emp.contract?.signed)||!!emp.contract_signed_manual, req:true, tab:'vertrag', hint:'Vertrag-Tab → Unterschrift bestätigen'},
      {label:'Bankdaten hinterlegt', done:!!emp.bank_account,  req:true,  tab:'dokumente', hint:'Bankdaten-Tab → IBAN eintragen'},
      {label:'Personalausweis / Kopie', done:!!emp.id_card_file||!!emp.id_card, req:false, tab:'dokumente', hint:'Bankdaten-Tab → Ausweis hochladen'},
      {label:'Hardware',             done:hwStatus(emp)==='done', req:true, hw:true, hwSt:hwStatus(emp), deadline:emp.hw_deadline, hint:'Hardware-Termin setzen'},
      {label:'Portal-Passwort',      done:!!emp.portal_password, req:false, tab:'hr',  field:'portal_password', hint:'HR & Verwaltung → Portal-Passwort'},
      {label:'DSGVO unterzeichnet',  done:!!emp.dsgvo_signed,  req:false, tab:'dokumente', field:'dsgvo_signed', hint:'Bankdaten-Tab → DSGVO'},
    ];
  }

  function completionPct(emp){
    const c=checks(emp);
    const req=c.filter(x=>x.req);
    const done=req.filter(x=>x.done).length;
    return Math.round(done/req.length*100);
  }

  // Hardware alerts for overview
  const hwAlerts = onboardEmps.filter(e=>['needs_date','urgent','overdue'].includes(hwStatus(e)));

  return(
    <div>
      {/* Employee Modal from checklist click */}
      {empModal&&<EmployeeModal
        emp={empModal.emp}
        employees={employees}
        projects={[]}
        initialTab={empModal.tab||'hr'}
        onSave={updated=>{setEmployees(es=>es.map(e=>e.id===updated.id?updated:e));setEmpModal(null);}}
        onClose={()=>setEmpModal(null)}
      />}

      {/* Hardware Date Modal */}
      {hwModal&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:380}}>
            <div className="modal-header">
              <span className="modal-title">📅 Hardware-Termin setzen</span>
              <button className="btn" onClick={()=>setHwModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{fontWeight:600,marginBottom:12}}>{hwModal.first_name} {hwModal.last_name}</div>
              <div style={{fontSize:12,color:'var(--muted)',marginBottom:12}}>
                Bis wann muss die Hardware eingerichtet sein damit {hwModal.first_name} arbeiten kann?
                {(hwModal.start_date||hwModal.contract_start)&&<span> (Start: <strong>{hwModal.start_date||hwModal.contract_start}</strong>)</span>}
              </div>
              <div className="form-group">
                <label className="form-label">Hardware-Deadline</label>
                <input className="form-input" type="date" value={hwDate||hwModal.hw_deadline||hwModal.start_date||hwModal.contract_start||''} onChange={e=>setHwDate(e.target.value)}/>
              </div>
              <div style={{display:'flex',gap:8,justifyContent:'flex-end',marginTop:12}}>
                <button className="btn" onClick={()=>setHwModal(null)}>Abbrechen</button>
                <button className="btn btn-primary" onClick={()=>saveHwDate(hwModal,hwDate)}>Speichern</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Hardware Alert Banner */}
      {hwAlerts.length>0&&(
        <div style={{marginBottom:14,background:'var(--red-bg)',borderRadius:'var(--r)',border:'1px solid rgba(239,68,68,.2)',overflow:'hidden'}}>
          <div style={{padding:'10px 14px',borderBottom:'1px solid rgba(239,68,68,.1)',display:'flex',alignItems:'center',gap:8}}>
            <span style={{fontSize:16}}>🚨</span>
            <span style={{fontWeight:700,fontSize:13,color:'var(--red)'}}>
              {hwAlerts.length} Hardware-{hwAlerts.length===1?'Alarm':'Alarme'}
            </span>
            <span style={{fontSize:12,color:'var(--muted)',marginLeft:4}}>Handlungsbedarf</span>
          </div>
          {hwAlerts.map(emp=>{
            const s=hwStatus(emp);
            const days=emp.hw_deadline?Math.round((new Date(emp.hw_deadline)-new Date())/(1000*60*60*24)):null;
            return(
              <div key={emp.id} style={{padding:'10px 14px',borderBottom:'1px solid rgba(239,68,68,.08)',
                display:'flex',alignItems:'center',gap:10,flexWrap:'wrap'}}>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:13}}>{emp.first_name} {emp.last_name}</div>
                  <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>
                    {s==='needs_date'&&'Kein Hardware-Termin gesetzt'}
                    {s==='urgent'&&`Fällig in ${days} Tag${days===1?'':'en'} — ${emp.hw_deadline}`}
                    {s==='overdue'&&`Überfällig seit ${Math.abs(days)} Tag${Math.abs(days)===1?'':'en'} — ${emp.hw_deadline}`}
                    {(emp.start_date||emp.contract_start)&&<span> · Start: {emp.start_date||emp.contract_start}</span>}
                  </div>
                </div>
                <div style={{display:'flex',gap:6}}>
                  <button className="btn btn-sm" onClick={()=>{setHwModal(emp);setHwDate(emp.hw_deadline||'');}}>
                    📅 Termin
                  </button>
                  <button className="btn btn-sm" style={{background:'var(--green)',color:'white',border:'none'}}
                    onClick={()=>markHwDone(emp)}>
                    ✅ Erledigt
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      <div style={{display:'grid',gridTemplateColumns:'280px 1fr',gap:14}}>
        {/* Employee list */}
        <div className="card" style={{height:'fit-content'}}>
          <div className="card-header"><span className="card-title">Mitarbeiter ({onboardEmps.length})</span></div>
          {onboardEmps.length===0?(
            <div style={{padding:20,textAlign:'center',color:'var(--muted)',fontSize:12}}>Keine aktiven Einträge</div>
          ):(
            onboardEmps.map(emp=>{
              const pct=completionPct(emp);
              const hw=hwLabel(emp);
              const isSelected=selId===emp.id;
              return(
                <div key={emp.id} onClick={()=>setSelId(isSelected?null:emp.id)}
                  style={{padding:'10px 14px',borderBottom:'1px solid var(--border)',cursor:'pointer',
                    background:isSelected?'var(--blue-bg)':'transparent',
                    borderLeft:isSelected?'3px solid var(--blue)':'3px solid transparent'}}>
                  <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:4}}>
                    <div style={{fontWeight:600,fontSize:13}}>{emp.first_name} {emp.last_name}</div>
                    <div style={{fontSize:11,fontWeight:700,color:pct===100?'var(--green)':pct>60?'var(--amber)':'var(--red)'}}>{pct}%</div>
                  </div>
                  <div style={{height:4,background:'var(--border)',borderRadius:2,marginBottom:5}}>
                    <div style={{height:4,borderRadius:2,width:pct+'%',
                      background:pct===100?'var(--green)':pct>60?'var(--amber)':'var(--red)',transition:'width .3s'}}/>
                  </div>
                  <div style={{display:'flex',alignItems:'center',gap:6,flexWrap:'wrap'}}>
                    <span style={{fontSize:10,color:'var(--muted)'}}>{(STATUS_FLOW.find(s=>s.key===emp.status)||{label:emp.status||'—'}).label}</span>
                    {hw&&<span style={{fontSize:9,padding:'1px 6px',borderRadius:20,fontWeight:700,
                      background:hw.bg,color:hw.c,border:'1px solid '+hw.bd}}>{hw.label}</span>}
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* Checklist detail */}
        <div>
          {sel?(
            <div className="card">
              <div className="card-header" style={{flexWrap:'wrap',gap:8}}>
                <div>
                  <span className="card-title">{sel.first_name} {sel.last_name}</span>
                  <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>#{sel.staff_number} · Start: {sel.start_date||sel.contract_start||'—'}</div>
                </div>
                <div style={{display:'flex',gap:6}}>
                  {(()=>{const hw=hwLabel(sel);return hw?<span style={{fontSize:11,padding:'3px 10px',borderRadius:20,fontWeight:700,background:hw.bg,color:hw.c,border:'1px solid '+hw.bd}}>{hw.label}</span>:null;})()}
                </div>
              </div>
              <div style={{padding:'14px 16px'}}>
                {checks(sel).map((c,i)=>(
                  <div key={i} style={{display:'flex',alignItems:'flex-start',gap:10,padding:'9px 0',
                    borderBottom:'1px solid var(--border)',
                    cursor:(!c.done&&(c.tab||c.hw))?'pointer':'default'}}
                    onClick={()=>{
                      if(c.done) return;
                      if(c.hw){setHwModal(sel);setHwDate(sel.hw_deadline||sel.start_date||'');}
                      else if(c.tab) setEmpModal({emp:sel,tab:c.tab});
                    }}>
                    <div style={{width:22,height:22,borderRadius:'50%',flexShrink:0,
                      background:c.done?'var(--green-bg)':'var(--red-bg)',
                      border:'1.5px solid '+(c.done?'rgba(5,150,105,.3)':'rgba(239,68,68,.3)'),
                      display:'flex',alignItems:'center',justifyContent:'center',fontSize:12,
                      transition:'transform .15s',
                      transform:(!c.done&&(c.tab||c.hw))?'scale(1.1)':'scale(1)'}}>
                      {c.done?'✓':'→'}
                    </div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:13,fontWeight:600,color:c.done?'var(--text)':'var(--red)'}}>
                        {c.label}
                        {c.req&&!c.done&&<span style={{fontSize:10,color:'var(--red)',marginLeft:5,fontWeight:400}}>Pflicht</span>}
                        {!c.done&&c.hint&&<span style={{fontSize:10,color:'var(--muted)',marginLeft:8}}>→ {c.hint}</span>}
                      </div>
                      {c.hw&&!c.done&&(
                        <div style={{marginTop:5,display:'flex',gap:6,flexWrap:'wrap'}}>
                          {c.deadline&&(
                            <span style={{fontSize:11,color:'var(--muted)'}}>
                              Termin: <strong>{c.deadline}</strong>
                            </span>
                          )}
                          <button className="btn btn-sm" onClick={()=>{setHwModal(sel);setHwDate(sel.hw_deadline||sel.start_date||'');}}>
                            📅 Termin setzen
                          </button>
                          <button className="btn btn-sm" style={{background:'var(--green)',color:'white',border:'none'}}
                            onClick={()=>markHwDone(sel)}>
                            ✅ Als erledigt markieren
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ):(
            <div className="card" style={{padding:40,textAlign:'center',color:'var(--muted)'}}>
              <div style={{fontSize:32,marginBottom:8}}>👈</div>
              <div>Mitarbeiter links auswählen</div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

SkillMatrix:
function SkillMatrix({employees, projects}){
  const [selProj, setSelProj] = useState('all');
  const activeEmps = employees.filter(e=>['active','training'].includes(e.status)&&e.status!=='terminated'&&(selProj==='all'||e.project_id===selProj));
  const allSkills = (()=>{
    try{
      const adminSkills = JSON.parse(localStorage.getItem('jsr_skills_v1')||'null');
      const empSkills = activeEmps.flatMap(e=>e.skills||[]);
      const combined = adminSkills
        ? [...new Set([...adminSkills.filter(s=>s.active).map(s=>s.name), ...empSkills])]
        : [...new Set(empSkills)];
      return combined.sort();
    }catch(e){return [...new Set(activeEmps.flatMap(e=>e.skills||[]))].sort();}
  })();

  const levels = {
    2:{label:'Experte',color:'var(--green)',bg:'var(--green-bg)'},
    1:{label:'Grundlagen',color:'var(--blue)',bg:'var(--blue-bg)'},
    0:{label:'—',color:'var(--muted)',bg:'transparent'},
  };

  function getSkillLevel(emp, skill){
    if(!(emp.skills||[]).includes(skill)) return 0;
    // Check if certified in elearning (simplified)
    return (emp.skills||[]).includes(skill) ? 1 : 0;
  }

  return(
    <div>
      <div style={{display:'flex',gap:10,marginBottom:16,alignItems:'center',flexWrap:'wrap'}}>
        <button className={`btn btn-sm ${selProj==='all'?'btn-primary':''}`} onClick={()=>setSelProj('all')}>Alle</button>
        {projects.map(p=><button key={p.id} className={`btn btn-sm ${selProj===p.id?'btn-primary':''}`} onClick={()=>setSelProj(p.id)}>{p.name}</button>)}
        <div style={{marginLeft:'auto',display:'flex',gap:12}}>
          {[1,0].map(l=><span key={l} style={{fontSize:11,display:'flex',alignItems:'center',gap:5}}>
            <span style={{width:12,height:12,borderRadius:3,background:levels[l].bg,border:`1px solid ${levels[l].color}44`,display:'inline-block'}}/>
            {levels[l].label}
          </span>)}
        </div>
      </div>

      <div className="card" style={{overflow:'auto'}}>
        <table style={{minWidth:600}}>
          <thead>
            <tr>
              <th style={{minWidth:150,position:'sticky',left:0,background:'#f9fafb',zIndex:5}}>Mitarbeiter</th>
              {allSkills.map(s=>(
                <th key={s} style={{minWidth:90,textAlign:'center',fontSize:10,fontWeight:600,color:'var(--muted)',padding:'8px 6px',whiteSpace:'nowrap',letterSpacing:'.03em'}}>{s}</th>
              ))}
              <th style={{textAlign:'center',minWidth:60}}>Skills</th>
            </tr>
          </thead>
          <tbody>
            {activeEmps.map(e=>{
              const proj=projects.find(p=>p.id===e.project_id);
              const skillCount=(e.skills||[]).length;
              return(
                <tr key={e.id}>
                  <td style={{position:'sticky',left:0,background:'var(--card)',zIndex:4,borderRight:'1px solid var(--border)'}}>
                    <div style={{fontWeight:500,fontSize:12}}>{e.first_name} {e.last_name}</div>
                    <div style={{fontSize:10,color:'var(--muted)'}}>{proj?.name||'—'} · {e.location}</div>
                  </td>
                  {allSkills.map(s=>{
                    const has=(e.skills||[]).includes(s);
                    return(
                      <td key={s} style={{textAlign:'center',padding:'6px 4px'}}>
                        {has?<div style={{width:20,height:20,borderRadius:4,background:'var(--green-bg)',border:'1px solid rgba(34,197,94,.4)',display:'inline-flex',alignItems:'center',justifyContent:'center',fontSize:11,color:'var(--green)'}}>✓</div>
                        :<div style={{width:20,height:20,borderRadius:4,background:'var(--border)',display:'inline-block',opacity:.3}}/>}
                      </td>
                    );
                  })}
                  <td style={{textAlign:'center'}}>
                    <span style={{fontFamily:'var(--font-mono)',fontWeight:700,fontSize:13,color:skillCount>=3?'var(--green)':skillCount>=2?'var(--blue)':'var(--amber)'}}>{skillCount}</span>
                  </td>
                </tr>
              );
            })}
            {/* Coverage row */}
            <tr style={{borderTop:'2px solid var(--border2)',background:'var(--surface)'}}>
              <td style={{position:'sticky',left:0,background:'var(--surface)',zIndex:4,fontWeight:600,fontSize:11,color:'var(--muted)',borderRight:'1px solid var(--border)'}}>Abdeckung</td>
              {allSkills.map(s=>{
                const count=activeEmps.filter(e=>(e.skills||[]).includes(s)).length;
                const pct=activeEmps.length>0?Math.round(count/activeEmps.length*100):0;
                return(
                  <td key={s} style={{textAlign:'center',padding:'4px'}}>
                    <div style={{fontSize:10,fontFamily:'var(--font-mono)',color:pct>=50?'var(--green)':pct>=25?'var(--amber)':'var(--red)',fontWeight:600}}>{count}</div>
                    <div style={{fontSize:9,color:'var(--muted)'}}>{pct}%</div>
                  </td>
                );
              })}
              <td/>
            </tr>
          </tbody>
        </table>
      </div>
    </div>
  );
}

