TimeTracking:
function TimeTracking({employees}){
  const [loginEmp, setLoginEmp] = useState(null);
  const [pin, setPin] = useState('');
  const [pinError, setPinError] = useState('');
  const [sessions, setSessions] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_time_v1')||'[]');}
    catch(e){return [];}
  });
  const [locTab, setLocTab] = useState('Tirana');

  useEffect(()=>{localStorage.setItem('jsr_time_v1',JSON.stringify(sessions));},[sessions]);

  const LOCATIONS = ['Tirana','Prishtina'];
  const activeEmps = employees.filter(e=>['active','training'].includes(e.status));
  const today = new Date().toISOString().slice(0,10);

  function nowTime(){
    return new Date().toLocaleTimeString('de-DE',{hour:'2-digit',minute:'2-digit'});
  }
  function minutesBetween(t1, t2){
    if(!t1||!t2) return 0;
    const [h1,m1]=t1.split(':').map(Number);
    const [h2,m2]=t2.split(':').map(Number);
    return Math.max(0,(h2*60+m2)-(h1*60+m1));
  }

  function getSession(emp){
    return sessions.find(s=>s.emp_id===emp.id&&s.date===today&&!s.clock_out)||null;
  }
  function getDoneSession(emp){
    return sessions.find(s=>s.emp_id===emp.id&&s.date===today&&s.clock_out)||null;
  }

  function clockIn(emp){
    if(getSession(emp)||getDoneSession(emp)){setPinError('Bereits gestempelt!');return;}
    setSessions(ss=>[...ss,{
      id:'ts'+Date.now(), emp_id:emp.id, date:today,
      clock_in:nowTime(), clock_out:null, hours:null,
      pauses:[], smokes:[],
      pause_active:null, smoke_active:null
    }]);
    setLoginEmp(null); setPin('');
  }

  function clockOut(emp){
    setSessions(ss=>ss.map(s=>{
      if(s.emp_id!==emp.id||s.date!==today||s.clock_out) return s;
      const outStr=nowTime();
      const gross=minutesBetween(s.clock_in,outStr);
      const pauseMins=(s.pauses||[]).reduce((a,p)=>a+(p.duration||0),0);
      const smokeMins=(s.smokes||[]).reduce((a,p)=>a+(p.duration||0),0);
      const net=Math.max(0,gross-pauseMins-smokeMins);
      return {...s, clock_out:outStr,
        pause_active:null, smoke_active:null,
        hours:Math.round(net/6)/10,
        hours_gross:Math.round(gross/6)/10,
        pause_total:pauseMins, smoke_total:smokeMins};
    }));
    setLoginEmp(null); setPin('');
  }

  function startPause(emp, type){
    // type: 'pause' or 'smoke'
    setSessions(ss=>ss.map(s=>{
      if(s.emp_id!==emp.id||s.date!==today||s.clock_out) return s;
      if(s.pause_active||s.smoke_active) return s; // already in a break
      const key = type==='pause'?'pause_active':'smoke_active';
      return {...s, [key]:nowTime()};
    }));
    setLoginEmp(null); setPin('');
  }

  function endPause(emp, type){
    setSessions(ss=>ss.map(s=>{
      if(s.emp_id!==emp.id||s.date!==today||s.clock_out) return s;
      const key = type==='pause'?'pause_active':'smoke_active';
      const listKey = type==='pause'?'pauses':'smokes';
      const start = s[key];
      if(!start) return s;
      const dur = minutesBetween(start, nowTime());
      const entry = {start, end:nowTime(), duration:dur};
      return {...s, [key]:null, [listKey]:[...(s[listKey]||[]),entry]};
    }));
    setLoginEmp(null); setPin('');
  }

  function handleLogin(){
    const emp=loginEmp?.emp;
    const action=loginEmp?.action;
    if(!emp||!action) return;
    if(pin!=='123'){setPinError('Falscher PIN (Demo: 123)');return;}
    if(action==='in') clockIn(emp);
    else if(action==='out') clockOut(emp);
    else if(action==='pause_start') startPause(emp,'pause');
    else if(action==='pause_end') endPause(emp,'pause');
    else if(action==='smoke_start') startPause(emp,'smoke');
    else if(action==='smoke_end') endPause(emp,'smoke');
  }

  function openLogin(emp, action){
    setLoginEmp({emp,action});
    setPin(''); setPinError('');
  }

  const todaySessions = sessions.filter(s=>s.date===today);

  function locationStats(loc){
    const emps=activeEmps.filter(e=>(e.location||'').toLowerCase().includes(loc.toLowerCase()));
    const checkedIn=emps.filter(e=>getSession(e));
    const checkedOut=emps.filter(e=>getDoneSession(e));
    const onPause=emps.filter(e=>{const s=getSession(e);return s&&(s.pause_active||s.smoke_active);});
    return {emps,checkedIn,checkedOut,onPause};
  }

  function getStatus(emp){
    const s=getSession(emp);
    const d=getDoneSession(emp);
    if(d) return {label:'Ausgestempelt',color:'var(--muted)',bg:'var(--surface-2)',icon:'✓'};
    if(!s) return {label:'Nicht eingestempelt',color:'var(--amber)',bg:'var(--surface)',icon:'○'};
    if(s.smoke_active) return {label:'Raucherpause seit '+s.smoke_active,color:'#92400e',bg:'#fef3c7',icon:'🚬'};
    if(s.pause_active) return {label:'Pause seit '+s.pause_active,color:'#1e40af',bg:'#dbeafe',icon:'☕'};
    return {label:'Eingestempelt '+s.clock_in,color:'var(--green)',bg:'var(--green-bg)',icon:'✅'};
  }

  function getActions(emp){
    const s=getSession(emp);
    const d=getDoneSession(emp);
    if(d) return [];
    if(!s) return [{label:'⬇ Einstempeln',action:'in',color:'var(--green)',bg:'var(--green-bg)'}];
    const actions=[{label:'⬆ Ausstempeln',action:'out',color:'var(--red)',bg:'var(--red-bg)'}];
    if(s.pause_active){
      actions.push({label:'☕ Pause beenden',action:'pause_end',color:'#1e40af',bg:'#dbeafe'});
    } else if(s.smoke_active){
      actions.push({label:'🚬 Raucherpause beenden',action:'smoke_end',color:'#92400e',bg:'#fef3c7'});
    } else {
      actions.push({label:'☕ Pause starten',action:'pause_start',color:'#1e40af',bg:'#dbeafe'});
      actions.push({label:'🚬 Raucherpause',action:'smoke_start',color:'#92400e',bg:'#fef3c7'});
    }
    return actions;
  }

  return(
    <div>

      {/* Login Modal */}
      {loginEmp&&(
        <div className="modal-overlay">
          <div className="modal modal-sm" style={{width:360}}>
            <div className="modal-header">
              <div>
                <div style={{fontSize:16,fontWeight:700}}>
                  {loginEmp.emp.first_name} {loginEmp.emp.last_name}
                </div>
                <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>
                  {loginEmp.emp.position} · {loginEmp.emp.location}
                </div>
              </div>
              <button className="btn" onClick={()=>{setLoginEmp(null);setPin('');setPinError('');}}>×</button>
            </div>
            <div className="modal-body" style={{textAlign:'center'}}>
              <div style={{marginBottom:12,padding:'10px',borderRadius:'var(--r)',
                background:loginEmp.action.includes('in')&&!loginEmp.action.includes('out')?'var(--green-bg)':
                  loginEmp.action==='out'?'var(--red-bg)':
                  loginEmp.action.includes('pause')?'#dbeafe':'#fef3c7',
                fontWeight:600,fontSize:13,
                color:loginEmp.action.includes('in')&&!loginEmp.action.includes('out')?'var(--green)':
                  loginEmp.action==='out'?'var(--red)':
                  loginEmp.action.includes('pause')?'#1e40af':'#92400e'}}>
                {loginEmp.action==='in'?'⬇ Einstempeln':
                 loginEmp.action==='out'?'⬆ Ausstempeln':
                 loginEmp.action==='pause_start'?'☕ Pause starten':
                 loginEmp.action==='pause_end'?'☕ Pause beenden':
                 loginEmp.action==='smoke_start'?'🚬 Raucherpause starten':
                 '🚬 Raucherpause beenden'}
              </div>
              <input className="form-input" type="password" placeholder="PIN eingeben"
                value={pin} onChange={e=>{setPin(e.target.value);setPinError('');}}
                onKeyDown={e=>e.key==='Enter'&&handleLogin()}
                style={{textAlign:'center',fontSize:20,letterSpacing:8,marginBottom:8}}
                autoFocus/>
              {pinError&&<div style={{color:'var(--red)',fontSize:12,marginBottom:8}}>{pinError}</div>}
              <button className="btn btn-primary" style={{width:'100%'}} onClick={handleLogin}>
                Bestätigen
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Location Tabs */}
      <div style={{display:'flex',gap:0,marginBottom:16,borderBottom:'2px solid var(--border)'}}>
        {LOCATIONS.map(loc=>{
          const stats=locationStats(loc);
          return(
            <button key={loc} onClick={()=>setLocTab(loc)}
              style={{padding:'10px 24px',border:'none',background:'transparent',cursor:'pointer',
                fontSize:13,fontWeight:locTab===loc?700:400,
                color:locTab===loc?'var(--blue)':'var(--muted)',
                borderBottom:locTab===loc?'2px solid var(--blue)':'2px solid transparent',
                marginBottom:-2,display:'flex',alignItems:'center',gap:8}}>
              <span style={{fontSize:16}}>{loc==='Tirana'?'🇦🇱':'🇽🇰'}</span>
              {loc}
              <span style={{fontSize:11,padding:'1px 7px',borderRadius:20,fontWeight:600,
                background:locTab===loc?'var(--blue-bg)':'var(--surface-2)',
                color:locTab===loc?'var(--blue)':'var(--muted)'}}>
                {stats.emps.length} MA
              </span>
              {stats.checkedIn.length>0&&(
                <span style={{fontSize:11,padding:'1px 7px',borderRadius:20,fontWeight:600,
                  background:'var(--green-bg)',color:'var(--green)'}}>
                  {stats.checkedIn.length} ✓
                </span>
              )}
              {stats.onPause.length>0&&(
                <span style={{fontSize:11,padding:'1px 7px',borderRadius:20,fontWeight:600,
                  background:'#fef3c7',color:'#92400e'}}>
                  {stats.onPause.length} ☕
                </span>
              )}
            </button>
          );
        })}
      </div>

      {LOCATIONS.map(loc=>{
        if(loc!==locTab) return null;
        const {emps,checkedIn,checkedOut,onPause}=locationStats(loc);
        const notChecked=emps.filter(e=>!todaySessions.find(s=>s.emp_id===e.id));
        const totalPauseMins=todaySessions.filter(s=>emps.some(e=>e.id===s.emp_id))
          .reduce((a,s)=>a+(s.pause_total||0)+(s.smoke_total||0),0);

        return(
          <div key={loc}>
            {/* KPI */}
            <div style={{display:'grid',gridTemplateColumns:'repeat(5,1fr)',gap:10,marginBottom:16}}>
              {[
                {label:'Mitarbeiter',val:emps.length,color:'var(--blue)'},
                {label:'Eingestempelt',val:checkedIn.length,color:'var(--green)'},
                {label:'In Pause/Raucher',val:onPause.length,color:'#92400e'},
                {label:'Ausgestempelt',val:checkedOut.length,color:'var(--muted)'},
                {label:'Noch nicht',val:notChecked.length,color:'var(--amber)'},
              ].map((s,i)=>(
                <div key={i} className="card" style={{padding:'12px 14px',textAlign:'center'}}>
                  <div style={{fontSize:22,fontWeight:700,color:s.color,fontFamily:'var(--mono)'}}>{s.val}</div>
                  <div style={{fontSize:11,color:'var(--muted)',marginTop:4}}>{s.label}</div>
                </div>
              ))}
            </div>

            {/* Employee Grid */}
            <div className="card">
              <div className="card-header">
                <span className="card-title">{loc==='Tirana'?'🇦🇱':'🇽🇰'} Mitarbeiter {loc}</span>
                <span style={{fontSize:11,color:'var(--muted)'}}>Heute · {today}</span>
              </div>
              <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(220px,1fr)',gap:8,padding:'10px 14px'}}>
                {emps.length===0&&(
                  <div style={{gridColumn:'1/-1',padding:20,textAlign:'center',color:'var(--muted)',fontSize:13}}>
                    Keine Mitarbeiter in {loc}
                  </div>
                )}
                {emps.map(e=>{
                  const st=getStatus(e);
                  const actions=getActions(e);
                  const sess=getSession(e)||getDoneSession(e);
                  const pauseMins=(sess?.pauses||[]).reduce((a,p)=>a+(p.duration||0),0);
                  const smokeMins=(sess?.smokes||[]).reduce((a,p)=>a+(p.duration||0),0);
                  return(
                    <div key={e.id} style={{
                      padding:'10px 12px',borderRadius:'var(--r-lg)',
                      border:'1px solid var(--border)',
                      background:st.bg, transition:'all .15s'}}>
                      <div style={{fontWeight:600,fontSize:12,marginBottom:1}}>
                        {e.first_name} {e.last_name}
                      </div>
                      <div style={{fontSize:10,color:'var(--muted)',marginBottom:6}}>{e.position}</div>
                      <div style={{fontSize:11,color:st.color,fontWeight:600,marginBottom:6}}>
                        {st.icon} {st.label}
                      </div>
                      {sess&&(pauseMins>0||smokeMins>0)&&(
                        <div style={{fontSize:10,color:'var(--muted)',marginBottom:6,display:'flex',gap:8}}>
                          {pauseMins>0&&<span>☕ {pauseMins}min</span>}
                          {smokeMins>0&&<span>🚬 {smokeMins}min</span>}
                        </div>
                      )}
                      <div style={{display:'flex',gap:4,flexWrap:'wrap'}}>
                        {actions.map(a=>(
                          <button key={a.action}
                            onClick={()=>openLogin(e,a.action)}
                            style={{fontSize:10,padding:'3px 8px',borderRadius:'var(--r)',
                              border:'none',cursor:'pointer',fontWeight:600,
                              background:a.bg,color:a.color}}>
                            {a.label}
                          </button>
                        ))}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Today table */}
            {todaySessions.filter(s=>emps.some(e=>e.id===s.emp_id)).length>0&&(
              <div className="card" style={{marginTop:12}}>
                <div className="card-header">
                  <span className="card-title">📋 Heutige Einträge — {loc}</span>
                </div>
                <table>
                  <thead>
                    <tr>
                      <th>Mitarbeiter</th>
                      <th>Einstempel</th>
                      <th>Ausstempel</th>
                      <th>☕ Pause</th>
                      <th>🚬 Raucher</th>
                      <th>Netto</th>
                      <th>Brutto</th>
                    </tr>
                  </thead>
                  <tbody>
                    {todaySessions.filter(s=>emps.some(e=>e.id===s.emp_id)).map(s=>{
                      const emp=emps.find(e=>e.id===s.emp_id);
                      const pauseMins=(s.pauses||[]).reduce((a,p)=>a+(p.duration||0),0)+(s.pause_active?minutesBetween(s.pause_active,new Date().toLocaleTimeString('de-DE',{hour:'2-digit',minute:'2-digit'})):0);
                      const smokeMins=(s.smokes||[]).reduce((a,p)=>a+(p.duration||0),0)+(s.smoke_active?minutesBetween(s.smoke_active,new Date().toLocaleTimeString('de-DE',{hour:'2-digit',minute:'2-digit'})):0);
                      return(
                        <tr key={s.id}>
                          <td style={{fontWeight:500}}>{emp?.first_name} {emp?.last_name}</td>
                          <td style={{fontFamily:'var(--mono)',color:'var(--green)'}}>{s.clock_in}</td>
                          <td style={{fontFamily:'var(--mono)',color:s.clock_out?'var(--muted)':'var(--amber)'}}>
                            {s.clock_out||'—'}
                          </td>
                          <td style={{fontFamily:'var(--mono)',color:pauseMins>0?'#1e40af':'var(--muted)'}}>
                            {pauseMins>0?pauseMins+'min':'—'}
                          </td>
                          <td style={{fontFamily:'var(--mono)',color:smokeMins>0?'#92400e':'var(--muted)'}}>
                            {smokeMins>0?smokeMins+'min':'—'}
                          </td>
                          <td style={{fontFamily:'var(--mono)',fontWeight:600,color:'var(--green)'}}>
                            {s.hours?s.hours+'h':'laufend'}
                          </td>
                          <td style={{fontFamily:'var(--mono)',color:'var(--muted)'}}>
                            {s.hours_gross?s.hours_gross+'h':'—'}
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        );
      })}

      <div className="card" style={{marginTop:16,textAlign:'center',padding:20}}>
        <div style={{fontSize:13,color:'var(--muted)',marginBottom:10}}>
          Mitarbeiter können sich auch direkt über die Stempeluhr einloggen:
        </div>
        <a href="/stempel.html" target="_blank"
          style={{display:'inline-flex',alignItems:'center',gap:8,padding:'8px 20px',
            borderRadius:'var(--r-md)',background:'var(--blue)',color:'white',
            fontWeight:600,fontSize:13,textDecoration:'none'}}>
          🕐 Zur Stempeluhr →
        </a>
      </div>
    </div>
  );
}

ProjectDashboard:
function ProjectDashboard({projects, employees, plans, forecast}){
  const [selProj, setSelProj] = useState(projects[0]?.id||'');
  const proj = projects.find(p=>p.id===selProj);
  if(!proj) return null;

  const projEmps = employees.filter(e=>e.project_id===selProj&&e.status!=='terminated');
  const activeEmps = projEmps.filter(e=>e.status==='active');
  const trainingEmps = projEmps.filter(e=>e.status==='training');

  // Laufende Schulungs-Batches für dieses Projekt
  const activePlans = plans.filter(p=>p.project_id===selProj);

  // Skills der aktiven MA
  const skillMap = {};
  activeEmps.forEach(e=>(e.skills||[]).forEach(s=>{skillMap[s]=(skillMap[s]||0)+1;}));

  // Standort-Verteilung
  const tirana = projEmps.filter(e=>e.location==='Tirana');
  const prishtina = projEmps.filter(e=>e.location==='Prishtina');

  // Pipeline für dieses Projekt (alle die noch nicht aktiv/training sind aber zugewiesen)
  // Wir schauen in Training Plans wer für dieses Projekt eingeplant ist
  const allConfirmed = activePlans.flatMap(p=>p.confirmed_ids||[]);
  const confirmedEmps = allConfirmed.map(id=>employees.find(e=>e.id===id)).filter(Boolean);

  // Zukünftige geplante Batches
  const futureBatches = (forecast?.future_batches||[]).filter(b=>b.project_id===selProj);

  // Billing info
  const billingMode = proj.billing_mode||'productive_hours';
  const monthlyRevenue = billingMode==='monthly_flat'
    ? activeEmps.length*(proj.monthly_flat||0)
    : activeEmps.length*(proj.rate_active||0)*160*0.85;
  const trainingCost = trainingEmps.length*(proj.rate_training||0)*160*0.85;

  return(
    <div>
      {/* Project Selector */}
      <div style={{display:'flex',gap:10,marginBottom:20}}>
        {projects.map(p=>(
          <button key={p.id} className={`btn ${selProj===p.id?'btn-primary':''}`} style={{fontSize:14,padding:'8px 20px'}} onClick={()=>setSelProj(p.id)}>
            {p.name}
          </button>
        ))}
      </div>

      {/* Project Header */}
      <div className="card">
        <div className="card-body">
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',flexWrap:'wrap',gap:16}}>
            <div>
              <div style={{fontSize:20,fontWeight:700,color:'var(--text)',marginBottom:4}}>{proj.name}</div>
              <div style={{fontSize:13,color:'var(--muted)'}}>{proj.client} · 📍 {proj.location}</div>
              <div style={{display:'flex',gap:8,marginTop:10,flexWrap:'wrap'}}>
                <span className="badge badge-blue">💶 {proj.rate_active}€/h aktiv</span>
                <span className="badge badge-amber">💶 {proj.rate_training}€/h Schulung</span>
                <span className="badge badge-muted">{billingMode==='monthly_flat'?`Pauschale ${(proj.monthly_flat||0).toLocaleString('de-DE')}€/MA`:'Abrechnung: Produktivstunden'}</span>
              </div>
            </div>
            <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:12}}>
              {[
                {val:activeEmps.length,label:'⚡ Aktiv',color:'var(--teal)'},
                {val:trainingEmps.length,label:'📚 In Schulung',color:'var(--purple)'},
                {val:tirana.length,label:'📍 Tirana',color:'var(--blue)'},
                {val:prishtina.length,label:'📍 Prishtina',color:'var(--green)'},
              ].map((k,i)=>(
                <div key={i} style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'10px 14px',textAlign:'center'}}>
                  <div style={{fontSize:20,fontWeight:700,color:k.color,fontFamily:'var(--font-mono)'}}>{k.val}</div>
                  <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>{k.label}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="grid-2">
        {/* Schulungsplan */}
        <div className="card">
          <div className="card-header"><span className="card-title">📋 Schulungsschritte</span></div>
          <div className="card-body">
            <div style={{display:'flex',flexDirection:'column',gap:8}}>
              {proj.trainings.map((t,i)=>{
                const inThisStep = trainingEmps.filter(e=>e.training_id===t.id);
                return(
                  <div key={t.id} style={{display:'flex',alignItems:'center',gap:10,padding:'10px 12px',background:'var(--surface)',borderRadius:'var(--r)',border:'1px solid var(--border)'}}>
                    <div style={{width:28,height:28,borderRadius:'50%',background:'var(--blue-bg)',border:'2px solid var(--blue)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:12,fontWeight:700,color:'var(--blue)',flexShrink:0}}>{t.seq}</div>
                    <div style={{flex:1}}>
                      <div style={{fontSize:13,fontWeight:500}}>{t.name}</div>
                      <div style={{fontSize:11,color:'var(--muted)'}}>{t.weeks} Woche{t.weeks>1?'n':''}</div>
                    </div>
                    <div style={{textAlign:'right'}}>
                      <div style={{fontSize:15,fontWeight:700,color:'var(--purple)',fontFamily:'var(--font-mono)'}}>{inThisStep.length}</div>
                      <div style={{fontSize:10,color:'var(--muted)'}}>aktuell</div>
                    </div>
                    {i < proj.trainings.length-1 && <span style={{color:'var(--muted)'}}>→</span>}
                  </div>
                );
              })}
              <div style={{display:'flex',alignItems:'center',gap:10,padding:'10px 12px',background:'var(--teal-bg)',borderRadius:'var(--r)',border:'1px solid rgba(45,212,191,.3)'}}>
                <div style={{width:28,height:28,borderRadius:'50%',background:'var(--teal)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:14,flexShrink:0}}>⚡</div>
                <div style={{flex:1}}><div style={{fontSize:13,fontWeight:500,color:'var(--teal)'}}>Aktiver Einsatz</div></div>
                <div style={{textAlign:'right'}}>
                  <div style={{fontSize:15,fontWeight:700,color:'var(--teal)',fontFamily:'var(--font-mono)'}}>{activeEmps.length}</div>
                  <div style={{fontSize:10,color:'var(--muted)'}}>aktiv</div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Skills der aktiven MA */}
        <div className="card">
          <div className="card-header"><span className="card-title">🎯 Skills aktiver Mitarbeiter</span></div>
          <div className="card-body">
            {Object.keys(skillMap).length===0&&<div style={{color:'var(--muted)',fontSize:12}}>Keine Skills erfasst</div>}
            {Object.entries(skillMap).sort((a,b)=>b[1]-a[1]).map(([skill,count])=>(
              <div key={skill} style={{marginBottom:8}}>
                <div style={{display:'flex',justifyContent:'space-between',marginBottom:3}}>
                  <span style={{fontSize:12}}>{skill}</span>
                  <span style={{fontSize:11,fontFamily:'var(--font-mono)',color:'var(--blue)'}}>{count} MA</span>
                </div>
                <div className="progress-track">
                  <div className="progress-fill" style={{width:`${(count/Math.max(activeEmps.length,1))*100}%`,background:'var(--blue)'}}/>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Laufende Schulungs-Batches */}
      {activePlans.length>0&&(
        <div className="card">
          <div className="card-header"><span className="card-title">📅 Laufende & geplante Schulungs-Batches</span></div>
          <div className="card-body">
            {activePlans.map(plan=>{
              const confirmed = plan.confirmed_ids?.length||0;
              const open = plan.planned_count - confirmed;
              const progress = trainingProgress(plan);
              const dStart = daysUntil(plan.start_date);

              // Pipeline-Phasen für diesen Batch
              const confirmedEmpsList = (plan.confirmed_ids||[]).map(id=>employees.find(e=>e.id===id)).filter(Boolean);
              const clientAccepted = confirmedEmpsList.filter(e=>e.status==='selected'||e.status==='training'||e.status==='active');
              const inTrainingNow = confirmedEmpsList.filter(e=>e.status==='training');
              const droppedOut = confirmedEmpsList.filter(e=>e.status==='inactive'||e.status==='terminated');
              const becameActive = confirmedEmpsList.filter(e=>e.status==='active');

              return(
                <div key={plan.id} style={{marginBottom:20,paddingBottom:20,borderBottom:'1px solid var(--border)'}}>
                  <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:12}}>
                    <div>
                      <div style={{fontWeight:600,fontSize:14}}>{plan.name}</div>
                      <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>{plan.mode} · {fmtDate(plan.start_date)} → {fmtDate(plan.end_date)}</div>
                    </div>
                    <div style={{display:'flex',gap:8}}>
                      {progress>=100&&<span className="badge badge-green">✓ Abgeschlossen</span>}
                      {progress>0&&progress<100&&<span className="badge badge-blue">▶ Läuft · {progress}%</span>}
                      {progress===0&&dStart!==null&&<span className="badge badge-amber">○ Start in {dStart} Tagen</span>}
                    </div>
                  </div>

                  {/* Fortschrittsbalken */}
                  {progress>0&&(
                    <div style={{marginBottom:12}}>
                      <div style={{display:'flex',justifyContent:'space-between',marginBottom:4}}>
                        <span style={{fontSize:11,color:'var(--muted)'}}>Schulungsfortschritt</span>
                        <span style={{fontSize:11,fontFamily:'var(--font-mono)',fontWeight:600,color:'var(--blue)'}}>{progress}%</span>
                      </div>
                      <div className="progress-track" style={{height:10}}>
                        <div className="progress-fill" style={{width:`${progress}%`,background:progress===100?'var(--green)':'var(--blue)'}}/>
                      </div>
                    </div>
                  )}

                  {/* Pipeline Flow */}
                  <div style={{display:'grid',gridTemplateColumns:'repeat(5,1fr)',gap:8,marginBottom:12}}>
                    {[
                      {label:'Geplant',val:plan.planned_count,color:'var(--muted)',icon:'📋'},
                      {label:'Eingeplant',val:confirmed,color:'var(--blue)',icon:'✅'},
                      {label:'Vom AG akzeptiert',val:clientAccepted.length,color:'var(--green)',icon:'👔'},
                      {label:'In Schulung',val:inTrainingNow.length,color:'var(--purple)',icon:'S'},
                      {label:'Aktiv geworden',val:becameActive.length,color:'var(--teal)',icon:'!'},
                    ].map((s,i)=>(
                      <div key={i} style={{background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r)',padding:'8px 10px',textAlign:'center'}}>
                        <div style={{fontSize:16}}>{s.icon}</div>
                        <div style={{fontSize:18,fontWeight:700,color:s.color,fontFamily:'var(--font-mono)'}}>{s.val}</div>
                        <div style={{fontSize:10,color:'var(--muted)',marginTop:2}}>{s.label}</div>
                      </div>
                    ))}
                  </div>

                  {open>0&&(
                    <div className={`warn-box ${dStart!==null&&dStart<=7?'warn-red':'warn-amber'}`} style={{padding:'8px 14px'}}>
                      <span style={{fontSize:12,fontWeight:600,color:dStart!==null&&dStart<=7?'var(--red)':'var(--amber)'}}>
                        {dStart!==null&&dStart<=7?'🚨':'⚠️'} Noch {open} Plätze offen bis Schulungsstart
                        {dStart!==null&&` (in ${dStart} Tagen)`}
                      </span>
                    </div>
                  )}

                  {droppedOut.length>0&&(
                    <div style={{marginTop:8,fontSize:12,color:'var(--red)'}}>
                      ⚠️ {droppedOut.length} Teilnehmer ausgefallen
                    </div>
                  )}

                  {/* Teilnehmer Liste */}
                  {confirmedEmpsList.length>0&&(
                    <div style={{marginTop:10,display:'flex',flexWrap:'wrap',gap:5}}>
                      {confirmedEmpsList.map(e=>(
                        <div key={e.id} style={{padding:'3px 8px',borderRadius:4,fontSize:11,background:'var(--surface)',border:`1px solid ${statusColor(e.status)}44`}}>
                          <span style={{color:statusColor(e.status)}}>{statusIcon(e.status)}</span> {e.first_name} {e.last_name}
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Zukünftige Batches */}
      {futureBatches.length>0&&(
        <div className="card">
          <div className="card-header"><span className="card-title">📈 Geplante zukünftige Batches</span></div>
          <div className="card-body" style={{padding:0}}>
            <div className="table-responsive"><table>
              <thead><tr><th>Name</th><th>Agenten geplant</th><th>Schulungsstart</th><th>Aktiv ab</th><th>€/h</th><th>Ø Gehalt</th><th>Notiz</th></tr></thead>
              <tbody>
                {futureBatches.map(b=>{
                  const d=daysUntil(b.start_date);
                  return(
                    <tr key={b.id}>
                      <td style={{fontWeight:500}}>{b.name}</td>
                      <td style={{fontFamily:'var(--font-mono)',fontWeight:700,color:'var(--green)'}}>{b.planned_agents}</td>
                      <td>
                        <div style={{fontSize:12}}>{fmtDate(b.start_date)}</div>
                        {d!==null&&d>0&&<div style={{fontSize:10,color:'var(--muted)'}}>in {d} Tagen</div>}
                      </td>
                      <td style={{fontSize:12}}>{fmtDate(b.active_date)}</td>
                      <td style={{fontFamily:'var(--font-mono)',fontSize:12}}>{b.monthly_rate}€</td>
                      <td style={{fontFamily:'var(--font-mono)',fontSize:12,color:'var(--amber)'}}>{(b.avg_salary||800).toLocaleString('de-DE')} €</td>
                      <td style={{fontSize:12,color:'var(--muted)'}}>{b.notes}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table></div>
          </div>
        </div>
      )}

      {/* Aktive Mitarbeiter Übersicht */}
      {activeEmps.length>0&&(
        <div className="card">
          <div className="card-header"><span className="card-title">👥 Aktive Mitarbeiter auf {proj.name}</span></div>
          <div className="card-body" style={{padding:0}}>
            <div className="table-responsive"><table>
              <thead><tr><th>Name</th><th>Standort</th><th>Arbeitsort</th><th>Skills</th><th>Sprache</th><th>Produktiv %</th><th>Umsatz/Mo est.</th></tr></thead>
              <tbody>
                {activeEmps.map(e=>{
                  const rev = billingMode==='monthly_flat'
                    ? (proj.monthly_flat||0)
                    : Math.round((proj.rate_active||0)*160*(e.productive_pct||85)/100);
                  return(
                    <tr key={e.id}>
                      <td style={{fontWeight:500}}>{e.first_name} {e.last_name}</td>
                      <td><span className="badge badge-muted">{e.location}</span></td>
                      <td>{e.work_mode==='homeoffice'?'🏠 HO':e.work_mode==='hybrid'?'🔄 Hybrid':'🏢 Office'}</td>
                      <td>{(e.skills||[]).slice(0,3).map(s=><span key={s} className="skill-chip">{s}</span>)}</td>
                      <td><span className="badge badge-blue">{e.language_level}</span></td>
                      <td>
                        <div style={{display:'flex',alignItems:'center',gap:5}}>
                          <div style={{width:40,height:4,background:'var(--border)',borderRadius:2,overflow:'hidden'}}>
                            <div style={{height:'100%',width:`${e.productive_pct||85}%`,background:'var(--blue)',borderRadius:2}}/>
                          </div>
                          <span style={{fontSize:11,fontFamily:'var(--font-mono)'}}>{e.productive_pct||85}%</span>
                        </div>
                      </td>
                      <td style={{fontFamily:'var(--font-mono)',fontSize:12,color:'var(--green)',fontWeight:600}}>{rev.toLocaleString('de-DE')} €</td>
                    </tr>
                  );
                })}
              </tbody>
            </table></div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── Project Profitability ─────────────────────────────────

ProjectProfitability:
function ProjectProfitability({projects, employees, forecast, setForecast}){
  const [selProj, setSelProj] = useState(projects[0]?.id||'');
  const [editMonth, setEditMonth] = useState(null); // 'YYYY-MM' | null
  const [editForm, setEditForm] = useState({});
  const setEF = (k,v) => setEditForm(f=>({...f,[k]:v}));

  const proj = projects.find(p=>p.id===selProj);
  const actuals = forecast.monthly_actuals || {};

  // Allgemeinkosten berechnen
  const fixedCosts = forecast.fixed_costs || {};
  const totalFixed = Object.values(fixedCosts).reduce((s,v)=>s+Number(v||0),0);

  // Aktive MA gesamt (für Umlage)
  const totalActiveEmps = employees.filter(e=>e.status==='active').length||1;
  const projActiveEmps = employees.filter(e=>e.status==='active'&&e.project_id===selProj).length;
  const fixedAllocation = projActiveEmps > 0 ? Math.round(totalFixed * projActiveEmps / totalActiveEmps) : 0;

  // Letzte 12 Monate
  const months = Array.from({length:12},(_,i)=>{
    const d = new Date();
    d.setDate(1);
    d.setMonth(d.getMonth() - (11-i));
    return d.toISOString().slice(0,7); // YYYY-MM
  });

  function openEdit(month){
    const existing = actuals[month]?.[selProj] || {};
    setEditForm({
      revenue: existing.revenue||'',
      cost_personnel: existing.cost_personnel||'',
      cost_other: existing.cost_other||'',
      invoice_nr: existing.invoice_nr||'',
      notes: existing.notes||'',
    });
    setEditMonth(month);
  }

  function saveActual(){
    setForecast(f=>({
      ...f,
      monthly_actuals: {
        ...f.monthly_actuals,
        [editMonth]: {
          ...(f.monthly_actuals?.[editMonth]||{}),
          [selProj]: {
            revenue: Number(editForm.revenue)||0,
            cost_personnel: Number(editForm.cost_personnel)||0,
            cost_other: Number(editForm.cost_other)||0,
            invoice_nr: editForm.invoice_nr||'',
            notes: editForm.notes||'',
          }
        }
      }
    }));
    setEditMonth(null);
  }

  function deleteActual(month){
    setForecast(f=>{
      const newActuals = {...f.monthly_actuals};
      if(newActuals[month]) {
        newActuals[month] = {...newActuals[month]};
        delete newActuals[month][selProj];
      }
      return {...f, monthly_actuals: newActuals};
    });
  }

  function fmtMonth(m){
    const [y,mo] = m.split('-');
    return new Date(y,mo-1,1).toLocaleDateString('de-DE',{month:'long',year:'numeric'});
  }

  // Rows mit Ist-Zahlen
  const rows = months.map(month=>{
    const data = actuals[month]?.[selProj];
    const rev = data?.revenue||0;
    const costPersonnel = data?.cost_personnel||0;
    const costOther = data?.cost_other||0;
    const totalCost = costPersonnel + costOther + fixedAllocation;
    const profit = rev - totalCost;
    const margin = rev > 0 ? Math.round(profit/rev*100) : null;
    const hasData = !!data;
    return {month, data, rev, costPersonnel, costOther, totalCost, profit, margin, hasData};
  });

  const filledRows = rows.filter(r=>r.hasData);
  const totRev = filledRows.reduce((s,r)=>s+r.rev,0);
  const totCost = filledRows.reduce((s,r)=>s+r.totalCost,0);
  const totProfit = totRev - totCost;
  const avgMargin = totRev > 0 ? Math.round(totProfit/totRev*100) : null;

  return(
    <div>
      {/* Edit Modal */}
      {editMonth&&(
        <div className="modal-overlay">
          <div className="modal modal-sm" style={{width:480}}>
            <div className="modal-header">
              <span className="modal-title">📊 Ist-Zahlen — {proj?.name} · {fmtMonth(editMonth)}</span>
              <button className="btn" onClick={()=>setEditMonth(null)}>×</button>
            </div>
            <div className="modal-body">
              <div className="form-row">
                <div className="form-group"><label className="form-label">Umsatz (Rechnung €)</label>
                  <input className="form-input" type="number" value={editForm.revenue} onChange={e=>setEF('revenue',e.target.value)} placeholder="z.B. 18500"/>
                </div>
                <div className="form-group"><label className="form-label">Rechnungsnummer</label>
                  <input className="form-input" value={editForm.invoice_nr} onChange={e=>setEF('invoice_nr',e.target.value)} placeholder="z.B. HC-2025-003"/>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Personalkosten € (Gehälter)</label>
                  <input className="form-input" type="number" value={editForm.cost_personnel} onChange={e=>setEF('cost_personnel',e.target.value)} placeholder="z.B. 6200"/>
                </div>
                <div className="form-group"><label className="form-label">Sonstige Kosten €</label>
                  <input className="form-input" type="number" value={editForm.cost_other} onChange={e=>setEF('cost_other',e.target.value)} placeholder="z.B. 300"/>
                </div>
              </div>
              <div style={{padding:12,background:'var(--surface)',borderRadius:'var(--r)',border:'1px solid var(--border)',marginBottom:12}}>
                <div style={{fontSize:11,color:'var(--muted)',marginBottom:6}}>Automatisch umgelegte Allgemeinkosten</div>
                <div style={{display:'flex',justifyContent:'space-between'}}>
                  <span style={{fontSize:12,color:'var(--dim)'}}>Fixkosten gesamt: {totalFixed.toLocaleString('de-DE')} € ÷ {totalActiveEmps} MA × {projActiveEmps} MA ({proj?.name})</span>
                  <span style={{fontFamily:'var(--font-mono)',fontWeight:600,color:'var(--red)'}}>{fixedAllocation.toLocaleString('de-DE')} €</span>
                </div>
              </div>
              {editForm.revenue&&(
                <div style={{padding:12,background:'var(--card)',borderRadius:'var(--r)',border:'1px solid var(--border)',marginBottom:12}}>
                  <div style={{fontSize:11,color:'var(--muted)',marginBottom:4}}>Vorschau Ergebnis</div>
                  {(()=>{
                    const rev=Number(editForm.revenue)||0;
                    const cost=Number(editForm.cost_personnel||0)+Number(editForm.cost_other||0)+fixedAllocation;
                    const profit=rev-cost;
                    const margin=rev>0?Math.round(profit/rev*100):0;
                    return <div style={{display:'flex',gap:20}}>
                      <div><div style={{fontSize:11,color:'var(--muted)'}}>Umsatz</div><div style={{fontFamily:'var(--font-mono)',color:'var(--green)',fontWeight:700}}>{rev.toLocaleString('de-DE')} €</div></div>
                      <div><div style={{fontSize:11,color:'var(--muted)'}}>Kosten</div><div style={{fontFamily:'var(--font-mono)',color:'var(--red)',fontWeight:700}}>{cost.toLocaleString('de-DE')} €</div></div>
                      <div><div style={{fontSize:11,color:'var(--muted)'}}>Deckungsbeitrag</div><div style={{fontFamily:'var(--font-mono)',color:profit>=0?'var(--teal)':'var(--red)',fontWeight:700}}>{profit>=0?'+':''}{profit.toLocaleString('de-DE')} €</div></div>
                      <div><div style={{fontSize:11,color:'var(--muted)'}}>Marge</div><div style={{fontFamily:'var(--font-mono)',color:margin>=20?'var(--green)':margin>=10?'var(--amber)':'var(--red)',fontWeight:700}}>{margin}%</div></div>
                    </div>;
                  })()}
                </div>
              )}
              <div className="form-group">
                <label className="form-label">Notizen</label>
                <textarea className="form-input" rows={2} value={editForm.notes} onChange={e=>setEF('notes',e.target.value)} style={{resize:'vertical'}}/>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn" onClick={()=>setEditMonth(null)}>Abbrechen</button>
              <button className="btn btn-primary" onClick={saveActual}>Speichern</button>
            </div>
          </div>
        </div>
      )}

      {/* Project Selector */}
      <div style={{display:'flex',gap:10,marginBottom:16,alignItems:'center',flexWrap:'wrap'}}>
        {projects.map(p=>(
          <button key={p.id} className={`btn ${selProj===p.id?'btn-primary':''}`} style={{fontSize:14,padding:'8px 20px'}} onClick={()=>setSelProj(p.id)}>{p.name}</button>
        ))}
      </div>

      {/* Umlage Info */}
      <div style={{padding:12,background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r-lg)',marginBottom:16,display:'flex',gap:20,alignItems:'center',flexWrap:'wrap'}}>
        <div style={{fontSize:12,color:'var(--muted)'}}>💡 Allgemeinkosten-Umlage</div>
        <div style={{fontSize:12}}><strong style={{color:'var(--text)'}}>{totalFixed.toLocaleString('de-DE')} €</strong> Fixkosten/Mo ÷ <strong style={{color:'var(--text)'}}>{totalActiveEmps}</strong> aktive MA gesamt = <strong style={{color:'var(--amber)'}}>{Math.round(totalFixed/totalActiveEmps).toLocaleString('de-DE')} €/MA</strong></div>
        <div style={{fontSize:12}}>→ <strong style={{color:'var(--text)'}}>{proj?.name}</strong>: {projActiveEmps} MA × {Math.round(totalFixed/totalActiveEmps).toLocaleString('de-DE')} € = <strong style={{color:'var(--red)'}}>{fixedAllocation.toLocaleString('de-DE')} €/Mo</strong></div>
      </div>

      {/* Summary KPIs */}
      {filledRows.length>0&&(
        <div className="grid-4" style={{marginBottom:16}}>
          {[
            {label:`Umsatz (${filledRows.length} Monate)`,val:`${totRev.toLocaleString('de-DE')} €`,color:'var(--green)',icon:'💶'},
            {label:'Kosten gesamt',val:`${totCost.toLocaleString('de-DE')} €`,color:'var(--red)',icon:'💸'},
            {label:'Deckungsbeitrag',val:`${totProfit>=0?'+':''}${totProfit.toLocaleString('de-DE')} €`,color:totProfit>=0?'var(--teal)':'var(--red)',icon:'📊'},
            {label:'Ø Marge',val:avgMargin!==null?`${avgMargin}%`:'—',color:avgMargin>=20?'var(--green)':avgMargin>=10?'var(--amber)':'var(--red)',icon:'📈'},
          ].map((k,i)=>(
            <div key={i} className="kpi">
              <div style={{fontSize:18,marginBottom:6}}>{k.icon}</div>
              <div className="kpi-val" style={{color:k.color,fontSize:18}}>{k.val}</div>
              <div className="kpi-label">{k.label}</div>
            </div>
          ))}
        </div>
      )}

      {/* Monthly Table */}
      <div className="card">
        <div className="card-header">
          <span className="card-title">📊 Monatliche Ist-Zahlen — {proj?.name}</span>
          <span style={{fontSize:11,color:'var(--muted)'}}>Allgemeinkosten-Umlage: {fixedAllocation.toLocaleString('de-DE')} €/Mo automatisch berücksichtigt</span>
        </div>
        <table>
          <thead><tr>
            <th>Monat</th>
            <th>Rechnung</th>
            <th>Umsatz</th>
            <th>Personal-K.</th>
            <th>Sonst. K.</th>
            <th>Umlage Fix</th>
            <th>Kosten ges.</th>
            <th>Ergebnis</th>
            <th>Marge</th>
            <th>Notiz</th>
            <th></th>
          </tr></thead>
          <tbody>
            {rows.map(({month,data,rev,costPersonnel,costOther,totalCost,profit,margin,hasData})=>(
              <tr key={month} style={{background:hasData?'transparent':'rgba(107,114,128,.03)',cursor:'pointer'}} onClick={()=>openEdit(month)}>
                <td style={{fontWeight:hasData?600:400,color:hasData?'var(--text)':'var(--muted)'}}>{fmtMonth(month)}</td>
                <td style={{fontSize:11,fontFamily:'var(--font-mono)',color:'var(--muted)'}}>{data?.invoice_nr||'—'}</td>
                <td style={{fontFamily:'var(--font-mono)',color:hasData?'var(--green)':'var(--muted)',fontWeight:hasData?600:400}}>{hasData?`${rev.toLocaleString('de-DE')} €`:'+ eintragen'}</td>
