                <td>
                  {hasData&&margin!==null&&(
                    <span style={{padding:'2px 8px',borderRadius:4,fontSize:11,fontWeight:600,background:margin>=20?'var(--green-bg)':margin>=10?'var(--amber-bg)':'var(--red-bg)',color:margin>=20?'var(--green)':margin>=10?'var(--amber)':'var(--red)'}}>
                      {margin}%
                    </span>
                  )}
                  {!hasData&&<span style={{color:'var(--muted)',fontSize:11}}>—</span>}
