                    <button className="btn btn-sm" onClick={ev=>{ev.stopPropagation();openEdit(month);}}>✎</button>
                    {hasData&&<button className="btn btn-sm" onClick={ev=>{ev.stopPropagation();deleteActual(month);}} style={{color:'var(--red)'}}>×</button>}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

