function AbsenceOverview({employees, setEmployees, onAbsence}){
  const [selEmp, setSelEmp] = useState(null);
  const [yearFilter, setYearFilter] = useState(new Date().getFullYear());
  const activeEmps = employees.filter(e=>!['terminated'].includes(e.status));
  const currentYear = new Date().getFullYear();

  function getYearStats(emp, year){
    const abs=(emp.absences||[]).filter(a=>new Date(a.date).getFullYear()===year);
    const sick=abs.filter(a=>a.type==='sick').length;
    const vacation=abs.filter(a=>a.type==='vacation').length;
    const paidAbs=abs.filter(a=>a.type==='unpaid'&&a.paid!==false).length;
    const unpaid=abs.filter(a=>a.type==='unpaid'&&a.paid===false).length;
    const quota=emp.vacation_days_quota||20;
    const vacLeft=Math.max(0,quota-vacation);
    return {sick,vacation,paidAbs,unpaid,quota,vacLeft,total:sick+vacation+paidAbs+unpaid};
  }

  return(
    <div>
      {/* Jahr-Filter & Übersicht */}
      <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:16,flexWrap:'wrap'}}>
        <span style={{fontSize:13,fontWeight:600,color:'var(--text)'}}>Jahr:</span>
        {[currentYear-1,currentYear,currentYear+1].map(y=>(
          <button key={y} className={`btn btn-sm ${yearFilter===y?'btn-primary':''}`} onClick={()=>setYearFilter(y)}
            style={{fontFamily:'var(--mono)'}}>{y}</button>
        ))}
        <div style={{marginLeft:'auto',display:'flex',gap:14}}>
          {[
            {label:'Ø Krankheitstage',val:(activeEmps.reduce((s,e)=>s+getYearStats(e,yearFilter).sick,0)/Math.max(activeEmps.length,1)).toFixed(1),color:'var(--red)'},
            {label:'Offene Urlaubstage',val:activeEmps.reduce((s,e)=>s+getYearStats(e,yearFilter).vacLeft,0),color:'var(--amber)'},
            {label:'Verbrauchter Urlaub',val:activeEmps.reduce((s,e)=>s+getYearStats(e,yearFilter).vacation,0),color:'var(--green)'},
          ].map((k,i)=>(
            <div key={i} style={{textAlign:'center',padding:'8px 14px',background:'var(--surface)',border:'1px solid var(--border)',borderRadius:'var(--r-lg)'}}>
              <div style={{fontSize:18,fontWeight:700,color:k.color,fontFamily:'var(--mono)'}}>{k.val}</div>
              <div style={{fontSize:10,color:'var(--muted)',marginTop:2}}>{k.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Tabelle */}
      <div className="card">
        <div className="card-header">
          <span className="card-title">Abwesenheiten {yearFilter} — Alle Mitarbeiter</span>
          <span style={{fontSize:11,color:'var(--muted)'}}>{activeEmps.length} Mitarbeiter</span>
        </div>
        <div className="table-responsive"><table>
          <thead><tr>
            <th>Mitarbeiter</th>
            <th>Standort</th>
            <th style={{color:'var(--red)'}}>🤒 Krank</th>
            <th style={{color:'var(--amber)'}}>🏖 Urlaub</th>
            <th>Urlaub-Kontingent</th>
            <th style={{color:'var(--amber)'}}>Urlaub offen</th>
            <th style={{color:'var(--blue)'}}>⏸ Bezahlt</th>
            <th style={{color:'var(--muted)'}}>❌ Unbezahlt</th>
            <th>Gesamt</th>
            <th></th>
          </tr></thead>
          <tbody>
            {activeEmps.map(e=>{
              const st=getYearStats(e,yearFilter);
              const sickWarn=st.sick>=10;
              const sickNote=st.sick>=5&&st.sick<10;
              return(
                <tr key={e.id} style={{background:sickWarn?'rgba(239,68,68,.03)':'transparent'}}>
                  <td>
                    <div style={{fontWeight:500}}>{e.first_name} {e.last_name}</div>
                    <div style={{fontSize:10,color:'var(--muted)'}}>{e.position}</div>
                  </td>
                  <td><span className="badge badge-muted">{e.location}</span></td>
                  <td>
                    <span style={{fontFamily:'var(--mono)',fontWeight:600,color:sickWarn?'var(--red)':sickNote?'var(--amber)':'var(--text)'}}>
                      {st.sick}
                    </span>
                    {sickWarn&&<span style={{fontSize:9,marginLeft:4,color:'var(--red)',fontWeight:700}}>⚠</span>}
                  </td>
                  <td style={{fontFamily:'var(--mono)',fontWeight:500,color:'var(--amber)'}}>{st.vacation}</td>
                  <td>
                    <div style={{display:'flex',alignItems:'center',gap:6}}>
                      <div style={{width:50,height:4,background:'var(--border)',borderRadius:2,overflow:'hidden'}}>
                        <div style={{height:'100%',width:Math.min(st.vacation/st.quota*100,100)+'%',background:st.vacLeft<=3?'var(--red)':st.vacLeft<=7?'var(--amber)':'var(--green)',borderRadius:2}}/>
                      </div>
                      <span style={{fontSize:11,fontFamily:'var(--mono)',color:'var(--muted)'}}>{st.quota}d</span>
                    </div>
                  </td>
                  <td>
                    <span style={{fontFamily:'var(--mono)',fontWeight:600,color:st.vacLeft<=3?'var(--red)':st.vacLeft<=7?'var(--amber)':'var(--green)'}}>
                      {st.vacLeft}d
                    </span>
                  </td>
                  <td style={{fontFamily:'var(--mono)',color:'var(--blue)'}}>{st.paidAbs||'—'}</td>
                  <td style={{fontFamily:'var(--mono)',color:'var(--muted)'}}>{st.unpaid||'—'}</td>
                  <td style={{fontFamily:'var(--mono)',fontWeight:600,color:st.total>15?'var(--red)':st.total>8?'var(--amber)':'var(--text)'}}>{st.total}</td>
                  <td>
                    <button className="btn btn-sm" onClick={()=>onAbsence(e)}>📅 Eintragen</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table></div>
      </div>

      {/* Monatskalender Übersicht */}
      <div className="card">
        <div className="card-header"><span className="card-title">Monatsübersicht {new Date().toLocaleDateString('de-DE',{month:'long',year:'numeric'})}</span></div>
        <div style={{padding:'12px 16px',overflowX:'auto'}}>
          <div style={{display:'grid',gridTemplateColumns:`140px repeat(${new Date(new Date().getFullYear(),new Date().getMonth()+1,0).getDate()},24px)`,gap:2,minWidth:'fit-content'}}>
            {/* Header */}
            <div style={{fontSize:10,fontWeight:600,color:'var(--muted)',padding:'4px 0'}}>Mitarbeiter</div>
            {Array.from({length:new Date(new Date().getFullYear(),new Date().getMonth()+1,0).getDate()},(_,i)=>{
              const d=new Date(new Date().getFullYear(),new Date().getMonth(),i+1);
              const isWeekend=d.getDay()===0||d.getDay()===6;
              const isToday=d.toISOString().slice(0,10)===new Date().toISOString().slice(0,10);
              return <div key={i} style={{textAlign:'center',fontSize:9,fontWeight:isToday?700:400,color:isToday?'var(--blue)':isWeekend?'var(--dim)':'var(--muted)',paddingBottom:2}}>{i+1}</div>;
            })}
            {/* Rows */}
            {activeEmps.slice(0,10).map(e=>{
              const mo=new Date().getMonth(); const yr=new Date().getFullYear();
              const days=new Date(yr,mo+1,0).getDate();
              return(
                <React.Fragment key={e.id}>
                  <div style={{fontSize:11,fontWeight:500,padding:'2px 0',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{e.first_name} {e.last_name}</div>
                  {Array.from({length:days},(_,i)=>{
                    const dateStr=new Date(yr,mo,i+1).toISOString().slice(0,10);
                    const abs=(e.absences||[]).find(a=>a.date===dateStr);
                    const isWeekend=new Date(yr,mo,i+1).getDay()===0||new Date(yr,mo,i+1).getDay()===6;
                    const bg=abs?.type==='sick'?'#fca5a5':abs?.type==='vacation'?'#fcd34d':abs?.type==='unpaid'?'#d1d5db':isWeekend?'#f3f4f6':'transparent';
                    return <div key={i} style={{height:20,borderRadius:2,background:bg,border:abs?'1px solid rgba(0,0,0,.1)':'none'}} title={abs?`${abs.type}${abs.note?' - '+abs.note:''}`:''}/>;
                  })}
                </React.Fragment>
              );
            })}
          </div>
          <div style={{display:'flex',gap:12,marginTop:10,fontSize:11,color:'var(--muted)'}}>
            {[['#fca5a5','Krank'],['#fcd34d','Urlaub'],['#d1d5db','Abwesend'],['#f3f4f6','Wochenende']].map(([c,l])=>(
              <div key={l} style={{display:'flex',alignItems:'center',gap:5}}>
                <div style={{width:12,height:12,borderRadius:2,background:c}}/>
                {l}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

