function useToast(){
  const [toast,setToast]=useState(null);
  const show=(msg,type='success')=>{
    setToast({msg,type});
    setTimeout(()=>setToast(null),2500);
  };
  const el=toast?<div className={'toast toast-'+toast.type}>{toast.type==='success'?'✓':toast.type==='error'?'✕':'ℹ'} {toast.msg}</div>:null;
  return [show,el];
}

