  function promoteToEmployee(cv){
    // Transfer ALL relevant CV fields to employee
    // Salary/hours/schedule ONLY from contract
    const contract = cv.contract || {};
    const allNums=employees.map(e=>parseInt(e.staff_number||0)).filter(n=>n>0);
    const nextNum=allNums.length>0?Math.max(...allNums)+1:1001;
    const vDef=JSON.parse(localStorage.getItem('jsr_vacation_defaults_v1')||'{"tirana":20,"prishtina":20,"training":15}');
    const vQuota=(cv.location||'').toLowerCase().includes('prishtina')?vDef.prishtina:vDef.tirana;
    const newEmp={
      id:'e'+Date.now(),
      staff_number:String(nextNum),
      // Personal data from CV
      first_name:cv.first_name||'', last_name:cv.last_name||'',
      email:cv.email||'', phone:cv.phone||'', city:cv.city||'',
      birthday:cv.birthday||'', gender:cv.gender||'',
      // Work location & role
      location:cv.location||'Tirana',
      position:cv.target_role||'Agent',
      primary_skill:cv.primary_skill||'',
      project_id:cv.target_project||'',
      status:'active',
      // Language
