      writing_level:cv.writing_level||'B2',
      assessed_level:cv.assessed_level||'',
      assessed_writing:cv.assessed_writing||'',
      assessment_note:cv.assessment_note||'',
      languages_str:cv.languages_str||'',
      dialect:cv.dialect||'',
      // Skills & profile
      skills:cv.skills||[], better_phone:cv.better_phone||false,
      better_email:cv.better_email||false, is_structured:cv.is_structured||false,
      sales_potential:cv.sales_potential||false,
      // Education
      education:cv.education||'', education_level:cv.education_level||'',
      // Work schedule & salary — ONLY from contract
      work_hours:contract.work_hours||cv.work_hours||'8',
      work_model:contract.work_model||cv.work_model||'Vor Ort',
      work_weekend:cv.work_weekend||'no',
      work_holidays:cv.work_holidays||'no',
      work_notes:cv.work_notes||'',
      // Contract data - salary fields
      hourly_rate: contract.hourly_rate||'',
      // salary computed from hourly_rate × work_hours × 22 (no static field needed)
      contract_start: contract.start_date||cv.start_date||'',
      contract_end: contract.end_date||'',
      contract_duration: contract.duration_months||'',
      contract_title: contract.title||'',
      contract_project: contract.project||'',
      start_date: contract.start_date||cv.start_date||'',
      // Bank data from CV
      bank_name:cv.bank_name||'', bank_account:cv.bank_account||'',
      id_card:cv.id_card||'', hardware:cv.hardware||'',
      // Contract signed file
      contract_file: contract.signed_file||null,
      contract_filename: contract.signed_filename||null,
      // Timestamps
      cv_received_at:cv.cv_date||new Date().toISOString().slice(0,10),
      training_id:cv.training_id||'', training_start:cv.training_start||'', training_end:cv.training_end||'',
      // Defaults
      vacation_days_quota:vQuota||20,
      productive_pct:85, notes:'Aus CV-System',
      monthly_bonus:'',
      absences:[], bonuses:[], referrals:[], quality_ratings:[],
      photo_color:cv.photo_color||'#1d4ed8',
      audio_url:cv.audio_url||'',
      work_mode:contract.work_model||cv.homeoffice_pref||'Vor Ort',
      audio_url: cv.audio_url||'',          // Hörprobe mitübertragen
      audio_transcript: cv.audio_transcript||'',
      writing_sample: cv.writing_sample||'', // Schriftprobe mitübertragen
      // 3-Ebenen Sprachbewertung
      ai_level: cv.ai_level||'',            // KI-Einschätzung Sprechen (FYI)
      ai_writing: cv.ai_writing||'',        // KI-Einschätzung Schrift (FYI)
