      id_card_filename: cv.id_card_filename||'',
      // Portal account created on conversion
      portal_password:'jsr'+String(nextNum),  // default: jsr1001 etc.
    };
    setEmployees(es=>[...es,newEmp]);
    // Archive CV before removing (for audit trail)
    try{
      const arch=JSON.parse(localStorage.getItem('jsr_cv_archive_v1')||'[]');
      arch.push({...cv,_archived_at:new Date().toISOString(),_employee_id:newEmp.id,_staff_number:newEmp.staff_number});
      localStorage.setItem('jsr_cv_archive_v1',JSON.stringify(arch));
    }catch(e){}
    // REMOVE from active CV list
    setCvList(l=>l.filter(c=>c.id!==cv.id));
    alert('✅ Mitarbeiter #'+nextNum+' angelegt!\n\nPortal-Login:\nMitarbeiternummer: '+nextNum+'\nPasswort: jsr'+nextNum+'\n\n(Passwort bitte beim ersten Login ändern)');
