function PayrollView({employees, projects, showToast}){
  const [salaryData, setSalaryData] = useState(()=>{try{return JSON.parse(localStorage.getItem('jsr_payroll_v1')||'{}')}catch(e){return {};}});
  const [payslips, setPayslips] = useState(()=>{try{return JSON.parse(localStorage.getItem('jsr_payslips_v1')||'{}')}catch(e){return {};}});
  const [activeTab, setActiveTab] = useState('current'); // current | archive
  const [selMonth, setSelMonth] = useState(()=>{const d=new Date();return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0');});
  const [selEmp, setSelEmp] = useState('all');
  const [bonusModal, setBonusModal] = useState(null);
  const [bonusForm, setBonusForm] = useState({referral_bonus:0,target_bonus:0,special_bonus:0,notes:'',deduction_tax:0,deduction_social:0,deduction_other:0,deduction_notes:'',
    overtime_hours:0,saturday_hours:0,sunday_hours:0,holiday_hours:0,night_hours:0});
  const [previewSlip, setPreviewSlip] = useState(null);
  const [bankUploadModal, setBankUploadModal] = useState(false);
  const [bankMatches, setBankMatches] = useState([]);
  const [manualPayModal, setManualPayModal] = useState(null);
  const [manualPayDate, setManualPayDate] = useState(new Date().toISOString().slice(0,10));

  useEffect(()=>{localStorage.setItem('jsr_payroll_v1',JSON.stringify(salaryData));},[salaryData]);
  useEffect(()=>{localStorage.setItem('jsr_payslips_v1',JSON.stringify(payslips));},[payslips]);

  const activeEmps = employees.filter(e=>e.status==='active');

  const workDays = useMemo(()=>{
    const [y,m]=selMonth.split('-').map(Number);
    let c=0;const d=new Date(y,m-1,1);
    while(d.getMonth()===m-1){if(d.getDay()>0&&d.getDay()<6)c++;d.setDate(d.getDate()+1);}
    return c;
  },[selMonth]);

  const months = useMemo(()=>{
    const list=[];const now=new Date();
    for(let i=0;i<18;i++){const d=new Date(now.getFullYear(),now.getMonth()-i,1);list.push(d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'));}
    return list;
  },[]);

  function fmtMonth(m){const [y,mo]=m.split('-');return new Date(y,mo-1,1).toLocaleDateString('de-DE',{month:'long',year:'numeric'});}
  function eur(v){return Number(v||0).toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2})+' €';}

  function calcSalary(emp){
    const r=parseFloat(emp.hourly_rate||0),h=parseFloat(emp.work_hours||8);
    const base=r>0?Math.round(r*workDays*h*100)/100:0;
    const rec=(salaryData[selMonth]||[]).find(x=>x.emp_id===emp.id)||{};
    const rb=parseFloat(rec.referral_bonus||0),tb=parseFloat(rec.target_bonus||0),sb=parseFloat(rec.special_bonus||0);
    // Zuschläge — Monatssoll entscheidet ob Überstunden vorliegen
    // Monatssoll = workDays × work_hours (aus Vertrag)
    // Überstunden = jede Stunde über dem Monatssoll
    // Sa/So/Feiertag: eigener Zuschlagssatz — ABER wenn gleichzeitig Überstunden:
    //   → immer der HÖHERE Satz wird angesetzt, nie beide addiert
    const cfg=JSON.parse(localStorage.getItem('jsr_surcharge_cfg')||'{}');
    const P=(k,d)=>(cfg[k]!==undefined?cfg[k]:d)/100;
    const otP=P('surcharge_overtime',30);  // Sa 20% < OT 30% → OT gilt
    const saP=P('surcharge_saturday',20);  // Sa 20%
    const suP=P('surcharge_sunday',50);    // So 50% > OT 30% → So gilt
    const hoP=P('surcharge_holiday',50);   // Feiertag 50%
    const niP=P('surcharge_night',25);
    const monthTarget = workDays*h;
    const workedH     = parseFloat(rec.total_worked_hours||monthTarget);
    const overtimeH   = Math.max(0,workedH-monthTarget); // Stunden über Soll
    const saH=parseFloat(rec.saturday_hours||0);
    const suH=parseFloat(rec.sunday_hours||0);
    const hoH=parseFloat(rec.holiday_hours||0);
    const niH=parseFloat(rec.night_hours||0);
    // Überstunden die auf normalen Werktagen (Mo-Fr) anfallen
    const specialH    = saH+suH+hoH;
    const otOnWeekday = Math.max(0,overtimeH-specialH);
    // Für Sa/So/Feiertag: wenn Überstunden vorliegen → max(Tagessatz, OT-Satz)
    // Keine Überstunden → nur Tagessatz
    const isOT = overtimeH>0;
    const saRate = Math.max(saP, isOT?otP:0); // Sa 20% vs OT 30% → OT gewinnt wenn Überstunden
    const suRate = Math.max(suP, isOT?otP:0); // So 50% vs OT 30% → So gewinnt immer
    const hoRate = Math.max(hoP, isOT?otP:0);
    const niRate = Math.max(niP, isOT?otP:0);
    const surcharges=r>0?Math.round((
      otOnWeekday*r*otP +
      saH*r*saRate +
      suH*r*suRate +
      hoH*r*hoRate +
      niH*r*niRate
    )*100)/100:0;
    // Absence deduction: days × daily rate (or manual tax field if set directly)
    const absenceDays=parseFloat(rec.deduction_absence_days||0);
    const dailyRate=r*h;
    const absenceDeduct=absenceDays>0?Math.round(absenceDays*dailyRate*100)/100:parseFloat(rec.deduction_tax||0);
    const dt=absenceDeduct,ds=parseFloat(rec.deduction_social||0),do_=parseFloat(rec.deduction_other||0);
    const totalDeductions=dt+ds+do_;
    const net=(base+rb+tb+sb)-totalDeductions;
    return{base,hourlyRate:r,hoursPerDay:h,grossHours:workDays*h,workDays,referralBonus:rb,targetBonus:tb,specialBonus:sb,totalBonuses:rb+tb+sb,surcharges,gross:base+rb+tb+sb+surcharges,deductionTax:dt,deductionSocial:ds,deductionOther:do_,totalDeductions,net,rec};
  }

  function getSlip(empId,month){return(payslips[month]||[]).find(s=>s.emp_id===empId)||null;}

  // SLIP STATUS: draft → confirmed → paid (locked)
  // locked = paid — cannot be edited
  function isLocked(slip){return slip&&slip.status==='paid';}

  function createPayslip(emp){
    if(!emp.hourly_rate){alert('Kein Stundenlohn im Vertrag für '+emp.first_name+'.');return;}
    const existing=getSlip(emp.id,selMonth);
    if(existing&&isLocked(existing)){alert('Abrechnung bereits überwiesen und gesperrt.');return;}
    const s=calcSalary(emp);
    const slip={
      id:'slip_'+emp.id+'_'+selMonth, emp_id:emp.id, month:selMonth,
      created_at:new Date().toISOString(), status:'draft',
      first_name:emp.first_name, last_name:emp.last_name,
      staff_number:emp.staff_number, position:emp.position,
      location:emp.location, project_id:emp.project_id,
      email:emp.email||'',
      hourly_rate:emp.hourly_rate, work_hours:emp.work_hours, work_model:emp.work_model||'Vor Ort',
      contract_start:emp.contract_start||'',
      work_days:workDays, hours_per_day:s.hoursPerDay, gross_hours:s.grossHours,
      base:s.base, referral_bonus:s.referralBonus, target_bonus:s.targetBonus,
      special_bonus:s.specialBonus, total_bonuses:s.totalBonuses, gross:s.gross,
      bonus_notes:s.rec?.notes||'',
      emp:emp,
      _calc:calcFullPayslip(emp,selMonth,(salaryData[selMonth]||[]).find(x=>x.emp_id===emp.id)||{},employees,[]),
    };
    setPayslips(prev=>{
      const ms=[...(prev[selMonth]||[]).filter(x=>x.emp_id!==emp.id),slip];
      return{...prev,[selMonth]:ms};
    });
    pushToPortal(slip);
    setPreviewSlip(slip);
  }

  function confirmPayslip(slip){
    if(isLocked(slip)) return;
    updateSlip(slip.emp_id,slip.month,{status:'confirmed',confirmed_at:new Date().toISOString()});
  }

  function retractPayslip(slip){
    if(isLocked(slip)){alert('Abrechnung bereits überwiesen — kann nicht zurückgezogen werden.');return;}
    if(!window.confirm('Abrechnung zurückziehen und löschen?')) return;
    setPayslips(prev=>{
      const ms=(prev[slip.month]||[]).filter(x=>x.emp_id!==slip.emp_id);
      return{...prev,[slip.month]:ms};
    });
    setPreviewSlip(null);
  }

  function markPaid(slip, date, method){
    if(isLocked(slip)) return;
    const updated={...slip,status:'paid',paid_at:new Date().toISOString(),payment_date:date||new Date().toISOString().slice(0,10),payment_method:method||'manuell'};
    updateSlip(slip.emp_id,slip.month,{status:'paid',paid_at:updated.paid_at,payment_date:updated.payment_date,payment_method:updated.payment_method});
    pushToPortal(updated);
  }

  function updateSlip(empId,month,updates){
    setPayslips(prev=>{
      const ms=(prev[month]||[]).map(s=>s.emp_id===empId?{...s,...updates}:s);
      return{...prev,[month]:ms};
    });
  }

  function pushToPortal(slip){
    try{
      const k='jsr_payrolls_'+slip.emp_id;
      const ex=JSON.parse(localStorage.getItem(k)||'[]');
      const up=[...ex.filter(p=>p.month!==slip.month),{
        id:slip.id,month:slip.month,month_label:fmtMonth(slip.month),
        net:slip.gross,days:slip.work_days,hours:slip.gross_hours,
        base:slip.base,bonuses:slip.total_bonuses,status:slip.status,
        payment_date:slip.payment_date||null,
      }];
      localStorage.setItem(k,JSON.stringify(up));
    }catch(e){}
  }

  function createAllDrafts(){
    const missing=activeEmps.filter(e=>e.hourly_rate&&!getSlip(e.id,selMonth));
    if(!missing.length){alert('Alle Abrechnungen bereits vorhanden.');return;}
    if(!window.confirm('Entwürfe für '+missing.length+' Mitarbeiter erstellen?')) return;
    missing.forEach(emp=>{
      const s=calcSalary(emp);
      const slip={id:'slip_'+emp.id+'_'+selMonth,emp_id:emp.id,month:selMonth,
        created_at:new Date().toISOString(),status:'draft',
        first_name:emp.first_name,last_name:emp.last_name,staff_number:emp.staff_number,
        position:emp.position,location:emp.location,project_id:emp.project_id,email:emp.email||'',
        hourly_rate:emp.hourly_rate,work_hours:emp.work_hours,work_model:emp.work_model||'Vor Ort',
        contract_start:emp.contract_start||'',work_days:workDays,hours_per_day:s.hoursPerDay,
        gross_hours:s.grossHours,base:s.base,referral_bonus:s.referralBonus,target_bonus:s.targetBonus,
        special_bonus:s.specialBonus,total_bonuses:s.totalBonuses,gross:s.gross,deduction_tax:s.deductionTax,deduction_social:s.deductionSocial,deduction_other:s.deductionOther,total_deductions:s.totalDeductions,net:s.net,bonus_notes:s.rec?.notes||'',deduction_notes:s.rec?.deduction_notes||''};
      setPayslips(prev=>{const ms=[...(prev[selMonth]||[]).filter(x=>x.emp_id!==emp.id),slip];return{...prev,[selMonth]:ms};});
      pushToPortal(slip);
    });
  }

  function confirmAll(){
    const drafts=(payslips[selMonth]||[]).filter(s=>s.status==='draft');
    if(!drafts.length){alert('Keine Entwürfe zum Bestätigen.');return;}
    if(!window.confirm('Alle '+drafts.length+' Entwürfe bestätigen?')) return;
    setPayslips(prev=>{
      const ms=(prev[selMonth]||[]).map(s=>s.status==='draft'?{...s,status:'confirmed',confirmed_at:new Date().toISOString()}:s);
      return{...prev,[selMonth]:ms};
    });
  }

  // BANK CSV PARSING
  function parseBankCSV(text){
    const lines=text.split('\n').filter(l=>l.trim());
    const matches=[];
    lines.forEach(line=>{
      const cols=line.split(/[,;]/).map(c=>c.trim().replace(/^"|"$/g,''));
      // Try to find name + amount in any column
      const nameMatch=cols.find(c=>c.length>3&&/[a-zA-ZäöüÄÖÜ]/.test(c)&&!c.match(/^\d/));
      const amtCol=cols.find(c=>c.match(/^\d[\d.,]+$|^-?\d/));
      if(nameMatch&&amtCol){
        const amt=parseFloat(amtCol.replace(/\./g,'').replace(',','.'));
        if(!isNaN(amt)&&Math.abs(amt)>0) matches.push({name:nameMatch,amount:Math.abs(amt),raw:line});
      }
    });
    return matches;
  }

  function handleBankCSV(e){
    const file=e.target.files[0];if(!file) return;
    const reader=new FileReader();
    reader.onload=ev=>{
      const text=ev.target.result;
      const rows=parseBankCSV(text);
      // Try to match to slips
      const slips=(payslips[selMonth]||[]).filter(s=>s.status==='confirmed'||s.status==='draft');
      const matched=[];
      slips.forEach(slip=>{
        const fullName=(slip.first_name+' '+slip.last_name).toLowerCase();
        const lastName=slip.last_name.toLowerCase();
        const row=rows.find(r=>{
          const rn=r.name.toLowerCase();
          return rn.includes(lastName)||rn.includes(fullName)||fullName.includes(rn);
        });
        const amtMatch=row&&Math.abs(row.amount-slip.gross)<0.02;
        matched.push({slip,row:row||null,amtMatch,nameMatch:!!row});
      });
      setBankMatches(matched);
      setBankUploadModal(true);
    };
    reader.readAsText(file,'UTF-8');
    e.target.value='';
  }

  function applyBankMatches(){
    const date=new Date().toISOString().slice(0,10);
    bankMatches.filter(m=>m.nameMatch).forEach(m=>{
      markPaid(m.slip,date,'Kontoauszug');
    });
    setBankUploadModal(false);
  }

