      '<tfoot><tr class="total-row" style="background:#f0fdf4;"><td colspan="2"><strong>Netto-Auszahlung '+fmtMonth(slip.month)+'</strong></td><td class="right mono"><strong>'+eur(slip.net||slip.gross)+'</strong></td></tr></tfoot></table></div>'+
      '<div style="background:#f8fafc;border-radius:8px;padding:12px;margin-top:12px;font-size:10px;color:#64748b;border:1px solid #e2e8f0;">'+
      'Erstellt am '+new Date(slip.created_at).toLocaleDateString('de-DE')+'. Alle Betraege in EUR, vor lokalen Steuerabzuegen.'+
      (slip.status==='paid'?' Zahlung erfolgt am '+slip.payment_date+' via '+slip.payment_method+'.':'')+
      '</div>'+
      '<div class="footer">'+
      '<div><div class="sig-box">Datum, Unterschrift Arbeitgeber<br><strong>JSR BPO GmbH</strong></div></div>'+
      '<div><div class="sig-box">Datum, Unterschrift Arbeitnehmer<br><strong>'+slip.first_name+' '+slip.last_name+'</strong></div></div>'+
      '</div>'+
      '<div style="margin-top:16px;text-align:center;font-size:9px;color:#94a3b8;">Dok.-Nr.: '+slip.id+' / '+new Date(slip.created_at).toLocaleString('de-DE')+'</div>'+
      '</div></body></html>';
    w.document.write(html);
    w.document.close();w.print();
  }

  function emailPayslip(slip){
    const s=encodeURIComponent('Gehaltsabrechnung '+fmtMonth(slip.month)+' — '+slip.first_name+' '+slip.last_name);
    const b=encodeURIComponent('Liebe/r '+slip.first_name+',\n\nIhre Gehaltsabrechnung für '+fmtMonth(slip.month)+':\n\nGrundgehalt: '+eur(slip.base)+'\nBoni: '+eur(slip.total_bonuses)+'\nGesamt: '+eur(slip.gross)+'\n\nMit freundlichen Grüßen\nJSR BPO GmbH');
    window.open('mailto:'+(slip.email||'')+'?subject='+s+'&body='+b);
  }

  function saveBonuses(){
    if(!bonusModal) return;
    setSalaryData(prev=>{
      const md=[...(prev[selMonth]||[])];const idx=md.findIndex(r=>r.emp_id===bonusModal.id);
      const entry={emp_id:bonusModal.id,month:selMonth,...bonusForm};
      if(idx>=0)md[idx]=entry;else md.push(entry);
      return{...prev,[selMonth]:md};
    });
    setBonusModal(null);
  }

  const displayEmps = selEmp==='all'?activeEmps:activeEmps.filter(e=>e.id===selEmp);
  const monthSlips  = payslips[selMonth]||[];
  const draftCount  = monthSlips.filter(s=>s.status==='draft').length;
  const confirmedCount = monthSlips.filter(s=>s.status==='confirmed').length;
  const paidCount   = monthSlips.filter(s=>s.status==='paid').length;
  const missingCount= displayEmps.filter(e=>e.hourly_rate&&!getSlip(e.id,selMonth)).length;

  function slipStatusBadge(slip){
    if(!slip) return <span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:700,background:'var(--red-bg)',color:'var(--red)',border:'1px solid rgba(239,68,68,.2)'}}>⚠ Fehlt</span>;
    const cfg={
      draft:   {bg:'var(--amber-bg)',c:'var(--amber)',bd:'rgba(217,119,6,.2)',label:'✏ Entwurf'},
      confirmed:{bg:'var(--blue-bg)',c:'var(--blue)',bd:'rgba(29,78,216,.2)',label:'✅ Bestätigt'},
      paid:    {bg:'var(--green-bg)',c:'var(--green)',bd:'rgba(5,150,105,.2)',label:'💸 Überwiesen '+( slip.payment_date||'')},
    }[slip.status]||{bg:'var(--surface-2)',c:'var(--muted)',bd:'var(--border)',label:slip.status};
    return <span style={{padding:'3px 9px',borderRadius:20,fontSize:10,fontWeight:700,background:cfg.bg,color:cfg.c,border:'1px solid '+cfg.bd,cursor:'pointer',whiteSpace:'nowrap'}} onClick={()=>setPreviewSlip(slip)}>{cfg.label}</span>;
  }

  return(
    <div>
      {/* Bank CSV Modal */}
      {bankUploadModal&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:600,maxWidth:"96vw"}}>
            <div className="modal-header">
              <span className="modal-title">🏦 Kontoauszug — Abgleich</span>
              <button className="btn" onClick={()=>setBankUploadModal(false)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{marginBottom:12,fontSize:13,color:'var(--muted)'}}>
                {bankMatches.filter(m=>m.nameMatch).length} von {bankMatches.length} Abrechnungen automatisch gematcht:
              </div>
              {bankMatches.map((m,i)=>(
                <div key={i} style={{display:'flex',alignItems:'center',gap:10,padding:'8px 12px',
                  borderRadius:'var(--r-sm)',marginBottom:6,
                  background:m.nameMatch?'var(--green-bg)':'var(--red-bg)',
                  border:'1px solid '+(m.nameMatch?'rgba(5,150,105,.2)':'rgba(239,68,68,.2)')}}>
                  <span style={{fontSize:18}}>{m.nameMatch?'✅':'❌'}</span>
                  <div style={{flex:1}}>
                    <div style={{fontWeight:700,fontSize:13}}>{m.slip.first_name} {m.slip.last_name}</div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>
                      Soll: {eur(m.slip.gross)}
                      {m.row&&<span> · Konto: {eur(m.row.amount)} {m.amtMatch?'✓':'⚠ Abweichung'}</span>}
                      {!m.row&&' · Nicht gefunden im CSV'}
                    </div>
                  </div>
                  {m.nameMatch&&<span style={{fontSize:10,color:'var(--green)',fontWeight:700}}>{m.amtMatch?'Exakt':'~Passend'}</span>}
                </div>
              ))}
              <div style={{display:'flex',gap:8,justifyContent:'flex-end',marginTop:14}}>
                <button className="btn" onClick={()=>setBankUploadModal(false)}>Abbrechen</button>
                <button className="btn btn-primary" onClick={applyBankMatches}
                  style={{background:'var(--green)',border:'none'}}>
                  ✅ {bankMatches.filter(m=>m.nameMatch).length} als überwiesen markieren
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Manual Pay Modal */}
      {manualPayModal&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:380,maxWidth:"96vw"}}>
            <div className="modal-header">
              <span className="modal-title">💸 Als überwiesen markieren</span>
              <button className="btn" onClick={()=>setManualPayModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{fontWeight:600,marginBottom:12}}>{manualPayModal.first_name} {manualPayModal.last_name} · {eur(manualPayModal.gross)}</div>
              <div className="form-group">
                <label className="form-label">Überweisungsdatum</label>
                <input className="form-input" type="date" value={manualPayDate} onChange={e=>setManualPayDate(e.target.value)}/>
              </div>
              <div style={{padding:'10px 14px',background:'var(--amber-bg)',borderRadius:'var(--r-md)',
                fontSize:12,color:'var(--amber)',border:'1px solid rgba(217,119,6,.2)',marginTop:8}}>
                ⚠ Nach Markierung als überwiesen ist die Abrechnung gesperrt und kann nicht mehr bearbeitet werden.
              </div>
              <div style={{display:'flex',gap:8,justifyContent:'flex-end',marginTop:14}}>
                <button className="btn" onClick={()=>setManualPayModal(null)}>Abbrechen</button>
                <button className="btn btn-primary" style={{background:'var(--green)',border:'none'}}
                  onClick={()=>{markPaid(manualPayModal,manualPayDate,'manuell');setManualPayModal(null);}}>
                  💸 Überwiesen bestätigen
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Slip Preview Modal — full Albanian payroll */}
      {previewSlip&&(
        <PayslipPreviewModal
          slip={previewSlip}
          onClose={()=>setPreviewSlip(null)}
          onApprove={previewSlip.status==='draft'?()=>{
            const u={...previewSlip,status:'confirmed',confirmed_at:new Date().toISOString()};
            setPayslips(prev=>({...prev,[u.month]:(prev[u.month]||[]).map(s=>s.emp_id===u.emp_id?u:s)}));
            pushToPortal(u); setPreviewSlip(null); showToast('✅ Freigegeben!');
          }:null}
          onRetract={!isLocked(previewSlip)?()=>{
            if(!window.confirm('Zurückziehen?'))return;
            setPayslips(prev=>({...prev,[previewSlip.month]:(prev[previewSlip.month]||[]).filter(s=>s.emp_id!==previewSlip.emp_id)}));
            setPreviewSlip(null);
          }:null}
        />
      )}

      {/* Bonus Modal */}
      {bonusModal&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:460}}>
            <div className="modal-header">
              <div><div style={{fontWeight:700,fontSize:15}}>💶 Bonus — {bonusModal.first_name} {bonusModal.last_name}</div>
                <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>{fmtMonth(selMonth)}</div></div>
              <button className="btn" onClick={()=>setBonusModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{padding:'10px 14px',background:'var(--surface-2)',borderRadius:'var(--r-md)',marginBottom:14,fontSize:12}}>
                <div style={{fontWeight:700,color:'var(--muted)',marginBottom:6,textTransform:'uppercase',fontSize:10,letterSpacing:'.06em'}}>Aus Arbeitsvertrag</div>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:8}}>
                  {[['Stundenlohn',eur(bonusModal.hourly_rate)],['Stunden/Tag',(bonusModal.work_hours||'—')+'h'],['Grundgehalt',eur(calcSalary(bonusModal).base)]].map(([l,v])=>(
                    <div key={l}><div style={{color:'var(--muted)',fontSize:10}}>{l}</div><div style={{fontWeight:700,fontFamily:'var(--mono)'}}>{v}</div></div>
                  ))}
                </div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Referral Bonus (€)</label>
                  <input className="form-input" type="number" min="0" step="0.01" value={bonusForm.referral_bonus} onChange={e=>setBonusForm(f=>({...f,referral_bonus:e.target.value}))}/></div>
                <div className="form-group"><label className="form-label">Zielbonus (€)</label>
                  <input className="form-input" type="number" min="0" step="0.01" value={bonusForm.target_bonus} onChange={e=>setBonusForm(f=>({...f,target_bonus:e.target.value}))}/></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Sonderbonus (€)</label>
                  <input className="form-input" type="number" min="0" step="0.01" value={bonusForm.special_bonus} onChange={e=>setBonusForm(f=>({...f,special_bonus:e.target.value}))}/></div>
                <div className="form-group"><label className="form-label">Notiz</label>
                  <input className="form-input" value={bonusForm.notes} onChange={e=>setBonusForm(f=>({...f,notes:e.target.value}))} placeholder="z.B. Überstunden"/></div>
              </div>
              {/* Zuschlagsstunden */}
              <div style={{borderTop:'1px solid var(--border)',paddingTop:12,marginTop:4}}>
                <div style={{fontSize:11,fontWeight:700,color:'var(--purple)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:10}}>
                  ⏰ Zuschlagsstunden
                  <span style={{marginLeft:8,fontWeight:400,fontSize:10,color:'var(--muted)'}}>
                    {(()=>{const c=JSON.parse(localStorage.getItem('jsr_surcharge_cfg')||'{}');return 'Sa '+(c.surcharge_saturday||20)+'% · So/Feiertag '+(c.surcharge_sunday||50)+'% · Nacht '+(c.surcharge_night||25)+'% · ÜS '+(c.surcharge_overtime||30)+'% (ab Monatssoll)';})()}
                  </span>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Gesamt gearbeitete Stunden</label>
                    <input className="form-input" type="number" min="0" step="0.5" value={bonusForm.total_worked_hours||''} onChange={e=>setBonusForm(f=>({...f,total_worked_hours:e.target.value}))} placeholder={String(workDays*(parseFloat(bonusModal.work_hours)||8))}/>
                    <div style={{fontSize:10,color:'var(--muted)',marginTop:2}}>Monatssoll: {workDays*(parseFloat(bonusModal.work_hours)||8)}h — Mehrstunden werden automatisch berechnet</div>
                  </div>
                  <div className="form-group"><label className="form-label">Samstag-Stunden (h)</label>
                    <input className="form-input" type="number" min="0" step="0.5" value={bonusForm.saturday_hours||0} onChange={e=>setBonusForm(f=>({...f,saturday_hours:e.target.value}))}/></div>
                </div>
                <div className="form-row">
                  <div className="form-group"><label className="form-label">Sonntag-Stunden (h)</label>
                    <input className="form-input" type="number" min="0" step="0.5" value={bonusForm.sunday_hours||0} onChange={e=>setBonusForm(f=>({...f,sunday_hours:e.target.value}))}/></div>
                  <div className="form-group"><label className="form-label">Feiertags-Stunden (h)</label>
                    <input className="form-input" type="number" min="0" step="0.5" value={bonusForm.holiday_hours||0} onChange={e=>setBonusForm(f=>({...f,holiday_hours:e.target.value}))}/></div>
                </div>
                <div className="form-row">
                  <div className="form-group"><label className="form-label">Nacht-Stunden 22–6h</label>
                    <input className="form-input" type="number" min="0" step="0.5" value={bonusForm.night_hours||0} onChange={e=>setBonusForm(f=>({...f,night_hours:e.target.value}))}/></div>
                  <div className="form-group">
                    <label className="form-label">Zuschlag berechnet</label>
                    <div style={{padding:'9px 13px',background:'var(--purple-bg)',borderRadius:'var(--r)',fontSize:14,fontWeight:800,color:'var(--purple)',fontFamily:'var(--mono)'}}>
                      {(()=>{
                        const r=parseFloat(bonusModal.hourly_rate||0);
                        const c=JSON.parse(localStorage.getItem('jsr_surcharge_cfg')||'{}');
                        const P=(k,d)=>(c[k]!==undefined?c[k]:d)/100;
                        const otP=P('surcharge_overtime',30),saP=P('surcharge_saturday',20);
                        const suP=P('surcharge_sunday',50),hoP=P('surcharge_holiday',50),niP=P('surcharge_night',25);
                        const mt=workDays*(parseFloat(bonusModal.work_hours)||8);
                        const tw=parseFloat(bonusForm.total_worked_hours||mt);
                        const saH=parseFloat(bonusForm.saturday_hours||0);
                        const suH=parseFloat(bonusForm.sunday_hours||0);
                        const hoH=parseFloat(bonusForm.holiday_hours||0);
                        const niH=parseFloat(bonusForm.night_hours||0);
                        const otH=Math.max(0,tw-mt);
                        const sH=saH+suH+hoH;
                        const otWd=Math.max(0,otH-sH);
                        const isOT=otH>0;
                        const saR=Math.max(saP,isOT?otP:0);
                        const suR=Math.max(suP,isOT?otP:0);
                        const hoR=Math.max(hoP,isOT?otP:0);
                        const niR=Math.max(niP,isOT?otP:0);
                        return eur(Math.round(r*(otWd*otP+saH*saR+suH*suR+hoH*hoR+niH*niR)*100)/100);
                      })()}
                    </div>
                  </div>
                </div>
              </div>
              {/* Deductions */}
              <div style={{borderTop:'1px solid var(--border)',paddingTop:12,marginTop:4}}>
                <div style={{fontSize:11,fontWeight:700,color:'var(--red)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:8}}>Abzüge</div>
                {/* Unpaid absence auto-calc */}
                {(()=>{
                  const absences=(employees||[]).find(e=>e.id===bonusModal.id)?.absences||[];
                  const unpaidDays=absences.filter(a=>{
                    if(a.type!=='vacation'&&a.type!=='sick') return false;
                    const d=a.date||'';
                    return d.startsWith(selMonth)&&a.unpaid;
                  }).length;
                  if(!unpaidDays) return null;
                  const dailyRate=parseFloat(bonusModal.hourly_rate||0)*parseFloat(bonusModal.work_hours||8);
                  const autoDeduct=Math.round(unpaidDays*dailyRate*100)/100;
                  return(
                    <div style={{padding:'8px 12px',background:'var(--amber-bg)',borderRadius:'var(--r-sm)',marginBottom:10,fontSize:12,color:'var(--amber)'}}>
                      ⚠ {unpaidDays} unbezahlte Fehltage erkannt → automatischer Abzug: <strong>{eur(autoDeduct)}</strong>
                    </div>
                  );
                })()}
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Unbezahlter Urlaub / Fehltage (Tage)</label>
                    <input className="form-input" type="number" min="0" step="1" value={bonusForm.deduction_absence_days||0}
                      onChange={e=>{
                        const days=parseFloat(e.target.value||0);
                        const dailyRate=parseFloat(bonusModal.hourly_rate||0)*parseFloat(bonusModal.work_hours||8);
                        setBonusForm(f=>({...f,deduction_absence_days:e.target.value,deduction_tax:Math.round(days*dailyRate*100)/100}));
                      }}/>
                    <div style={{fontSize:10,color:'var(--muted)',marginTop:3}}>
                      Tagessatz: {eur(parseFloat(bonusModal.hourly_rate||0)*parseFloat(bonusModal.work_hours||8))} · Abzug wird automatisch berechnet
                    </div>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Vorschuss-Rückzahlung (€)</label>
                    <input className="form-input" type="number" min="0" step="0.01" value={bonusForm.deduction_social||0}
                      onChange={e=>setBonusForm(f=>({...f,deduction_social:e.target.value}))}/></div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Sonstiger Abzug (€)</label>
                    <input className="form-input" type="number" min="0" step="0.01" value={bonusForm.deduction_other||0}
                      onChange={e=>setBonusForm(f=>({...f,deduction_other:e.target.value}))}/></div>
                  <div className="form-group">
                    <label className="form-label">Abzugsgrund</label>
                    <input className="form-input" value={bonusForm.deduction_notes||''}
                      onChange={e=>setBonusForm(f=>({...f,deduction_notes:e.target.value}))} placeholder="z.B. 2 Tage unentschuldigt, Vorschuss Jan"/></div>
                </div>
              </div>
              {/* Summary */}
              <div style={{background:'var(--surface-2)',borderRadius:'var(--r-md)',overflow:'hidden',marginTop:8}}>
                {[
                  ['Brutto',calcSalary(bonusModal).base+parseFloat(bonusForm.referral_bonus||0)+parseFloat(bonusForm.target_bonus||0)+parseFloat(bonusForm.special_bonus||0),'var(--blue)',false],
                  ['Abzüge gesamt',-(parseFloat(bonusForm.deduction_tax||0)+parseFloat(bonusForm.deduction_social||0)+parseFloat(bonusForm.deduction_other||0)),'var(--red)',false],
                ].map(([l,v,c,bold])=>(
                  <div key={l} style={{display:'flex',justifyContent:'space-between',padding:'6px 14px',borderBottom:'1px solid var(--border)'}}>
                    <span style={{fontSize:12,color:'var(--muted)'}}>{l}</span>
                    <span style={{fontSize:13,fontWeight:600,color:c,fontFamily:'var(--mono)'}}>{v<0?'-':''}{eur(Math.abs(v))}</span>
                  </div>
                ))}
                <div style={{display:'flex',justifyContent:'space-between',padding:'10px 14px',background:'var(--green-bg)'}}>
                  <span style={{fontSize:13,fontWeight:700,color:'var(--green)'}}>Netto-Auszahlung</span>
                  <span style={{fontSize:18,fontWeight:800,color:'var(--green)',fontFamily:'var(--mono)'}}>
                    {eur(Math.max(0,calcSalary(bonusModal).base+parseFloat(bonusForm.referral_bonus||0)+parseFloat(bonusForm.target_bonus||0)+parseFloat(bonusForm.special_bonus||0)-parseFloat(bonusForm.deduction_tax||0)-parseFloat(bonusForm.deduction_social||0)-parseFloat(bonusForm.deduction_other||0)))}
                  </span>
                </div>
              </div>
              <div style={{display:'flex',gap:8,justifyContent:'flex-end',marginTop:12}}>
                <button className="btn" onClick={()=>setBonusModal(null)}>Abbrechen</button>
                <button className="btn btn-primary" onClick={saveBonuses}>💾 Speichern</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* TABS */}
      <div style={{display:'flex',gap:6,marginBottom:10}}>
        {[['current','📋 Aktuell'],['archive','🗂 Archiv']].map(([k,l])=>(
          <button key={k} className={'btn btn-sm'+(activeTab===k?' btn-primary':'')} onClick={()=>setActiveTab(k)}>{l}</button>
        ))}
      </div>

      {activeTab==='current'&&(
      <div>
      {/* TOOLBAR */}
      <div style={{display:'flex',gap:10,alignItems:'center',marginBottom:14,flexWrap:'wrap'}}>
        <select className="form-select" style={{width:200}} value={selMonth} onChange={e=>setSelMonth(e.target.value)}>
          {months.map(m=><option key={m} value={m}>{fmtMonth(m)}</option>)}
        </select>
        <select className="form-select" style={{width:200}} value={selEmp} onChange={e=>setSelEmp(e.target.value)}>
          <option value='all'>Alle aktiven MA ({activeEmps.length})</option>
          {activeEmps.map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name}</option>)}
        </select>
        <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
          {missingCount>0&&<button className="btn btn-sm" onClick={createAllDrafts} style={{background:'var(--blue)',color:'white',border:'none'}}>📄 Alle Entwürfe ({missingCount})</button>}
          {draftCount>0&&<button className="btn btn-sm" onClick={confirmAll} style={{background:'var(--amber)',color:'white',border:'none'}}>✅ Alle bestätigen ({draftCount})</button>}
          <label className="btn btn-sm" style={{cursor:'pointer',background:'var(--teal)',color:'white',border:'none'}}>
            🏦 Kontoauszug hochladen
            <input type="file" accept=".csv,.txt" style={{display:'none'}} onChange={handleBankCSV}/>
          </label>
        </div>
        <div style={{marginLeft:'auto',display:'flex',gap:8,fontSize:11}}>
          {missingCount>0&&<span style={{color:'var(--red)',fontWeight:700}}>⚠ {missingCount} fehlen</span>}
          {draftCount>0&&<span style={{color:'var(--amber)',fontWeight:700}}>✏ {draftCount} Entwurf</span>}
          {confirmedCount>0&&<span style={{color:'var(--blue)',fontWeight:700}}>✅ {confirmedCount} bestätigt</span>}
          {paidCount>0&&<span style={{color:'var(--green)',fontWeight:700}}>💸 {paidCount} überwiesen</span>}
        </div>
      </div>

      {/* TABLE */}
      <div className="card">
        <div className="card-header">
          <span className="card-title">Lohnübersicht — {fmtMonth(selMonth)}</span>
          <span style={{fontSize:11,color:'var(--muted)'}}>{displayEmps.length} Mitarbeiter · {workDays} Werktage</span>
        </div>
