function CandidateShowcase({cvList, projects}){
  const [showcases, setShowcases] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_showcases_v1')||'[]');}
    catch(e){return [];}
  });
  const [showCreate, setShowCreate] = useState(false);
  const [form, setForm] = useState({title:'', project_id:'', note:'', selectedCvs:[]});
  const [preview, setPreview] = useState(null);
  const setF=(k,v)=>setForm(f=>({...f,[k]:v}));

  useEffect(()=>{
    localStorage.setItem('jsr_showcases_v1', JSON.stringify(showcases));
  },[showcases]);

  const approvedCvs = cvList.filter(c=>['test_done','selected','presented'].includes(c.status)||c.language_level);

  function toggleCv(id){
    setForm(f=>({...f,
      selectedCvs: f.selectedCvs.includes(id)
        ? f.selectedCvs.filter(x=>x!==id)
        : [...f.selectedCvs, id]
    }));
  }

  function createShowcase(){
    if(!form.title.trim()) return alert('Bitte Titel eingeben.');
    if(form.selectedCvs.length===0) return alert('Mindestens einen Kandidaten wählen.');
    const token = 'sc_'+Math.random().toString(36).slice(2,10);
    const sc = {
      id: 'sc'+Date.now(),
      token,
      title: form.title,
      project_id: form.project_id,
      note: form.note,
      cv_ids: form.selectedCvs,
      created: new Date().toISOString().slice(0,10),
    };
    setShowcases(s=>[sc,...s]);
    setShowCreate(false);
    setForm({title:'',project_id:'',note:'',selectedCvs:[]});
  }

  function getLink(token){
    return window.location.origin+'/showcase.html?token='+token;
  }

  function copyLink(token){
    navigator.clipboard.writeText(getLink(token));
    alert('Link kopiert!');
  }

  function deleteShowcase(id){
    if(window.confirm('Showcase löschen?')) setShowcases(s=>s.filter(x=>x.id!==id));
  }

  return(
    <div>

      {/* Create Modal */}
      {showCreate&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:680,maxHeight:'90vh',overflowY:'auto'}}>
            <div className="modal-header">
              <div style={{fontSize:15,fontWeight:700}}>🎯 Neuen Kandidaten-Showcase erstellen</div>
              <button className="btn" onClick={()=>setShowCreate(false)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:12}}>
                <div className="form-group">
                  <label className="form-label">Titel der Gruppe *</label>
                  <input className="form-input" value={form.title}
                    onChange={e=>setF('title',e.target.value)}
                    placeholder="z.B. HC Schulungsgruppe Aug 2026"/>
                </div>
                <div className="form-group">
                  <label className="form-label">Projekt</label>
                  <select className="form-select" value={form.project_id}
                    onChange={e=>setF('project_id',e.target.value)}>
                    <option value="">Kein Projekt</option>
                    {projects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
                </div>
              </div>
              <div className="form-group" style={{marginBottom:16}}>
                <label className="form-label">Notiz für Auftraggeber (optional)</label>
                <textarea className="form-input" rows={2} value={form.note}
                  onChange={e=>setF('note',e.target.value)}
                  placeholder="z.B. Vorauswahl für Q3 Ramp-Up — alle Kandidaten haben B2+ Deutsch"/>
              </div>

              <div style={{fontWeight:600,fontSize:12,marginBottom:8,color:'var(--text)'}}>
                Kandidaten auswählen ({form.selectedCvs.length} gewählt):
              </div>
              <div style={{maxHeight:320,overflowY:'auto',border:'1px solid var(--border)',
                borderRadius:'var(--r-md)'}}>
                {approvedCvs.length===0&&(
                  <div style={{padding:20,textAlign:'center',color:'var(--muted)',fontSize:12}}>
                    Keine Kandidaten mit Test-Ergebnis verfügbar
                  </div>
                )}
                {approvedCvs.map(cv=>{
                  const sel = form.selectedCvs.includes(cv.id);
                  const proj = projects.find(p=>p.id===cv.target_project);
                  return(
                    <div key={cv.id}
                      onClick={()=>toggleCv(cv.id)}
                      style={{
                        padding:'10px 14px',
                        borderBottom:'1px solid var(--border)',
                        cursor:'pointer',
                        background:sel?'var(--blue-bg)':'transparent',
                        display:'flex',alignItems:'center',gap:12}}>
                      <div style={{width:20,height:20,borderRadius:4,flexShrink:0,
                        border:'2px solid '+(sel?'var(--blue)':'var(--border)'),
                        background:sel?'var(--blue)':'transparent',
                        display:'flex',alignItems:'center',justifyContent:'center',color:'white',fontSize:12}}>
                        {sel?'✓':''}
                      </div>
                      {cv.photo_url
                        ?<img src={cv.photo_url} style={{width:36,height:36,borderRadius:'50%',objectFit:'cover',flexShrink:0}}/>
                        :<div style={{width:36,height:36,borderRadius:'50%',flexShrink:0,
                          background:cv.photo_color||'var(--blue)',
                          display:'flex',alignItems:'center',justifyContent:'center',
                          color:'white',fontWeight:700,fontSize:14}}>
                          {(cv.first_name||'?')[0]}{(cv.last_name||'?')[0]}
                        </div>
                      }
                      <div style={{flex:1}}>
                        <div style={{fontWeight:600,fontSize:13}}>
                          {cv.first_name} {cv.last_name}
                          {cv.age&&<span style={{fontWeight:400,color:'var(--muted)',fontSize:11}}>, {cv.age} J.</span>}
                        </div>
                        <div style={{fontSize:11,color:'var(--muted)',marginTop:2,display:'flex',gap:8}}>
                          {cv.language_level&&<span>🗣 {cv.language_level}</span>}
                          {cv.education&&<span>🎓 {cv.education}</span>}
                          {proj&&<span>📋 {proj.name}</span>}
                        </div>
                      </div>
                      <div style={{fontSize:10,padding:'2px 8px',borderRadius:20,fontWeight:600,
                        background:cv.status==='selected'?'var(--green-bg)':cv.status==='test_done'?'var(--blue-bg)':'var(--surface-2)',
                        color:cv.status==='selected'?'var(--green)':cv.status==='test_done'?'var(--blue)':'var(--muted)'}}>
                        {cv.status}
                      </div>
                    </div>
                  );
                })}
              </div>

              <div style={{display:'flex',gap:10,justifyContent:'flex-end',marginTop:16}}>
                <button className="btn" onClick={()=>setShowCreate(false)}>Abbrechen</button>
                <button className="btn btn-primary" onClick={createShowcase}>
                  🔗 Showcase erstellen ({form.selectedCvs.length} Kandidaten)
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Preview Modal */}
      {preview&&(
        <div className="modal-overlay" onClick={()=>setPreview(null)}>
          <div className="modal" style={{width:500}} onClick={e=>e.stopPropagation()}>
            <div className="modal-header">
              <span style={{fontWeight:700}}>Vorschau: {preview.title}</span>
              <button className="btn" onClick={()=>setPreview(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{fontSize:12,color:'var(--muted)',marginBottom:12}}>
                Dieser Link wird dem Auftraggeber gesendet:
              </div>
              <div style={{background:'var(--surface-2)',borderRadius:'var(--r-md)',
                padding:'10px 14px',fontFamily:'var(--mono)',fontSize:12,
                wordBreak:'break-all',marginBottom:12}}>
                {getLink(preview.token)}
              </div>
              <div style={{display:'flex',gap:8,marginBottom:16}}>
                <button className="btn btn-primary" style={{flex:1}}
                  onClick={()=>copyLink(preview.token)}>
                  📋 Link kopieren
                </button>
                <a href={getLink(preview.token)} target="_blank"
                  className="btn" style={{flex:1,textDecoration:'none',textAlign:'center'}}>
                  👁 Vorschau öffnen
                </a>
              </div>
              <div style={{fontSize:11,color:'var(--muted)'}}>
                {preview.cv_ids.length} Kandidaten · erstellt {preview.created}
                {preview.note&&<div style={{marginTop:4,fontStyle:'italic'}}>{preview.note}</div>}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:16}}>
        <div>
          <div style={{fontSize:15,fontWeight:700}}>🎯 Kandidaten Showcases</div>
          <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>
            Kandidatengruppen für Auftraggeber zusammenstellen und als Link teilen
          </div>
        </div>
        <button className="btn btn-primary" onClick={()=>setShowCreate(true)}>
          + Neuen Showcase erstellen
