function LocationsView({employees}){
  const [locations, setLocations] = useState(()=>{
    try{ return JSON.parse(localStorage.getItem('jsr_locations_v1')||'null') || [
      {
        id:'loc_tirana', name:'Tirana', country:'Albanien', flag:'🇦🇱', color:'#1d4ed8',
        address:'Rruga e Kavajës, Tirana', active:true,
        capacity:{ total_sqm:250, seats_total:40, seats_used:0 },
        costs_fixed:{
          rent:2800, utilities_electricity:320, utilities_water:80,
          internet:150, cleaning:200, insurance:180, management:1500, other_fixed:0
        },
        notes:''
      },
      {
        id:'loc_prishtina', name:'Prishtina', country:'Kosovo', flag:'🇽🇰', color:'#7c3aed',
        address:'Bulevardi Bill Clinton, Prishtina', active:true,
        capacity:{ total_sqm:180, seats_total:28, seats_used:0 },
        costs_fixed:{
          rent:1800, utilities_electricity:220, utilities_water:60,
          internet:120, cleaning:150, insurance:130, management:1200, other_fixed:0
        },
        notes:''
      }
    ];
    } catch(e){ return []; }
  });

  const [monthlyCosts, setMonthlyCosts] = useState(()=>{
    try{ return JSON.parse(localStorage.getItem('jsr_location_monthly_v1')||'{}'); }
    catch(e){ return {}; }
  });

  const [selTab, setSelTab] = useState('overview');
  const [editLoc, setEditLoc] = useState(null);
  const [showAdd, setShowAdd] = useState(false);
  const [selMonth, setSelMonth] = useState(()=>{
    const d=new Date(); return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0');
  });

  useEffect(()=>{ localStorage.setItem('jsr_locations_v1', JSON.stringify(locations)); },[locations]);
  useEffect(()=>{ localStorage.setItem('jsr_location_monthly_v1', JSON.stringify(monthlyCosts)); },[monthlyCosts]);

  const months = Array.from({length:13},(_,i)=>{
    const d=new Date(); d.setMonth(d.getMonth()-6+i);
    return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0');
  });

  function fmtMonth(m){
    const [y,mo]=m.split('-');
    return new Date(y,mo-1,1).toLocaleDateString('de-DE',{month:'long',year:'numeric'});
  }
  function eur(v){ return Number(v||0).toLocaleString('de-DE')+'€'; }

  function getSeatsUsed(loc){
    return employees.filter(e=>
      ['active','training'].includes(e.status) &&
      (e.location||'').toLowerCase().includes(loc.name.toLowerCase())
    ).length;
  }

  function getFixedTotal(loc){
    const c=loc.costs_fixed||{};
    return Object.values(c).reduce((s,v)=>s+Number(v||0),0);
  }

  function getMonthlyExtra(locId, month){
    return monthlyCosts[locId]?.[month] || {
      team_events:0, repairs:0, supplies:0, travel:0, other:0, other_note:''
    };
  }

  function setMonthlyField(locId, month, field, val){
    setMonthlyCosts(prev=>({
      ...prev,
      [locId]: {
        ...(prev[locId]||{}),
        [month]: { ...(getMonthlyExtra(locId,month)), [field]:val }
      }
    }));
  }

  function getMonthlyTotal(locId, month){
    const e=getMonthlyExtra(locId,month);
    return Object.entries(e).filter(([k])=>k!=='other_note').reduce((s,[,v])=>s+Number(v||0),0);
  }

  function getTotalMonthCost(loc, month){
    return getFixedTotal(loc) + getMonthlyTotal(loc.id, month);
  }

  function costPerSeat(loc, month){
    const used=getSeatsUsed(loc);
    if(!used) return 0;
    return Math.round(getTotalMonthCost(loc,month)/used);
  }

  const FIXED_LABELS = {
    rent:'Miete', utilities_electricity:'Strom', utilities_water:'Wasser',
    internet:'Internet', cleaning:'Reinigung/Hygiene', insurance:'Versicherung',
    management:'Management/Admin', other_fixed:'Sonstiges fix'
  };
  const MONTHLY_LABELS = {
    team_events:'Teamevents', repairs:'Reparaturen/Instandhaltung',
    supplies:'Büromaterial', travel:'Reisekosten', other:'Sonstige variabel'
  };

  function newLocTemplate(){
    return {
      id:'loc_'+Date.now(), name:'', country:'', flag:'🏢', color:'#059669', address:'', active:true,
      capacity:{ total_sqm:0, seats_total:0, seats_used:0 },
      costs_fixed:{ rent:0,utilities_electricity:0,utilities_water:0,internet:0,cleaning:0,insurance:0,management:0,other_fixed:0 },
      notes:''
    };
  }

  const totalSeats = locations.filter(l=>l.active).reduce((s,l)=>s+(l.capacity?.seats_total||0),0);
  const totalUsed = locations.filter(l=>l.active).reduce((s,l)=>s+getSeatsUsed(l),0);
  const totalFixedAll = locations.filter(l=>l.active).reduce((s,l)=>s+getFixedTotal(l),0);
  const totalMonthAll = locations.filter(l=>l.active).reduce((s,l)=>s+getTotalMonthCost(l,selMonth),0);

  return(
    <div>

      {/* Edit/Add Modal */}
      {(editLoc||showAdd)&&(
        <LocEditModal
          editLoc={editLoc}
          showAdd={showAdd}
          FIXED_LABELS={FIXED_LABELS}
          projects={[]}
          onClose={()=>{setEditLoc(null);setShowAdd(false);}}
          onSave={(form,isNew)=>{
            if(isNew){ setLocations(l=>[...l,form]); }
            else { setLocations(l=>l.map(x=>x.id===form.id?form:x)); }
            setEditLoc(null); setShowAdd(false);
          }}
        />
      )}
      {/* Toolbar */}
      <div style={{display:'flex',gap:8,marginBottom:16,flexWrap:'wrap',alignItems:'center'}}>
        <select className="form-select" style={{width:180}} value={selMonth} onChange={e=>setSelMonth(e.target.value)}>
