            </thead>
            <tbody>
              {locations.map(loc=>{
                const total=loc.capacity?.seats_total||0;
                const used=getSeatsUsed(loc);
                const free=Math.max(0,total-used);
                const pct=total>0?Math.round(used/total*100):0;
                const sqm=loc.capacity?.total_sqm||0;
                const sqmPerSeat=total>0?Math.round(sqm/total*10)/10:0;
                return(
                  <tr key={loc.id} style={{opacity:loc.active?1:0.5}}>
                    <td>
                      <div style={{display:'flex',alignItems:'center',gap:8}}>
                        <span style={{fontSize:18}}>{loc.flag}</span>
                        <div>
                          <div style={{fontWeight:500}}>{loc.name}</div>
                          <div style={{fontSize:10,color:'var(--muted)'}}>{loc.country}{!loc.active?' · Inaktiv':''}</div>
                        </div>
                      </div>
                    </td>
                    <td style={{fontFamily:'var(--mono)'}}>{sqm} m²</td>
                    <td style={{fontFamily:'var(--mono)',fontWeight:600}}>{total}</td>
                    <td style={{fontFamily:'var(--mono)',color:'var(--blue)',fontWeight:600}}>{used}</td>
                    <td style={{fontFamily:'var(--mono)',color:free===0?'var(--red)':free<5?'var(--amber)':'var(--green)',fontWeight:600}}>{free}</td>
                    <td>
                      <div style={{display:'flex',alignItems:'center',gap:8}}>
                        <div style={{width:80,height:8,background:'var(--border)',borderRadius:4,overflow:'hidden'}}>
                          <div style={{height:'100%',width:pct+'%',borderRadius:4,
                            background:pct>85?'var(--red)':pct>60?'var(--amber)':'var(--green)'}}/>
                        </div>
                        <span style={{fontSize:12,fontWeight:600,
                          color:pct>85?'var(--red)':pct>60?'var(--amber)':'var(--green)'}}>{pct}%</span>
                      </div>
                    </td>
                    <td style={{fontFamily:'var(--mono)',color:'var(--muted)'}}>{sqmPerSeat||'—'}</td>
                  </tr>
                );
              })}
              <tr style={{background:'var(--surface-2)',fontWeight:700,borderTop:'2px solid var(--border)'}}>
                <td>GESAMT (aktiv)</td>
                <td style={{fontFamily:'var(--mono)'}}>{locations.filter(l=>l.active).reduce((s,l)=>s+(l.capacity?.total_sqm||0),0)} m²</td>
                <td style={{fontFamily:'var(--mono)'}}>{totalSeats}</td>
                <td style={{fontFamily:'var(--mono)',color:'var(--blue)'}}>{totalUsed}</td>
                <td style={{fontFamily:'var(--mono)',color:'var(--green)'}}>{Math.max(0,totalSeats-totalUsed)}</td>
                <td style={{fontFamily:'var(--mono)',fontWeight:700}}>
                  {totalSeats>0?Math.round(totalUsed/totalSeats*100):0}%
                </td>
                <td></td>
              </tr>
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

LocEditModal:
function LocEditModal({editLoc, showAdd, onSave, onClose, projects, FIXED_LABELS}){
  const loc = editLoc || {
    id:'loc_'+Date.now(), name:'', country:'', flag:'🏢', color:'#059669', address:'', active:true,
    capacity:{ total_sqm:0, seats_total:0, seats_used:0 },
    costs_fixed:{ rent:0,utilities_electricity:0,utilities_water:0,internet:0,cleaning:0,insurance:0,management:0,other_fixed:0 },
    notes:''
  };
  const isNew = !editLoc;
  const [form, setForm] = useState(JSON.parse(JSON.stringify(loc)));

  const setF=(path,val)=>{
    setForm(prev=>{
      const next=JSON.parse(JSON.stringify(prev));
      const keys=path.split('.');
      let obj=next;
      for(let i=0;i<keys.length-1;i++) obj=obj[keys[i]];
      obj[keys[keys.length-1]]=val;
      return next;
    });
  };

  function save(){
    if(!form.name.trim()) return alert('Bitte Standortname eingeben.');
    onSave(form, isNew);
  }

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:620,maxHeight:'90vh',overflowY:'auto'}}>
        <div className="modal-header">
          <div style={{fontSize:15,fontWeight:700}}>
            {isNew?'🏢 Neuen Standort anlegen':'✎ Standort bearbeiten: '+form.name}
          </div>
          <button className="btn" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          <div style={{fontWeight:700,fontSize:12,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:10}}>Stammdaten</div>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:12}}>
            <div className="form-group">
              <label className="form-label">Standortname *</label>
              <input className="form-input" value={form.name} onChange={e=>setF('name',e.target.value)} placeholder="z.B. Tirana"/>
            </div>
            <div className="form-group">
              <label className="form-label">Land</label>
              <input className="form-input" value={form.country||''} onChange={e=>setF('country',e.target.value)} placeholder="z.B. Albanien"/>
            </div>
            <div className="form-group">
              <label className="form-label">Flag / Icon (Emoji)</label>
              <input className="form-input" value={form.flag||'🏢'} onChange={e=>setF('flag',e.target.value)} placeholder="🇦🇱"/>
            </div>
            <div className="form-group">
              <label className="form-label">Farbe</label>
              <input className="form-input" type="color" value={form.color||'#059669'} onChange={e=>setF('color',e.target.value)}/>
            </div>
          </div>
          <div className="form-group" style={{marginBottom:12}}>
            <label className="form-label">Adresse</label>
            <input className="form-input" value={form.address||''} onChange={e=>setF('address',e.target.value)} placeholder="Straße, Stadt"/>
          </div>

          <div style={{fontWeight:700,fontSize:12,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginTop:16,marginBottom:10}}>Kapazität</div>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:10,marginBottom:16}}>
            <div className="form-group">
              <label className="form-label">Gesamtfläche (m²)</label>
              <input className="form-input" type="number" value={form.capacity?.total_sqm||0} onChange={e=>setF('capacity.total_sqm',Number(e.target.value))}/>
            </div>
            <div className="form-group">
              <label className="form-label">Seats gesamt</label>
              <input className="form-input" type="number" value={form.capacity?.seats_total||0} onChange={e=>setF('capacity.seats_total',Number(e.target.value))}/>
            </div>
            <div className="form-group">
              <label className="form-label">Aktiv</label>
              <select className="form-select" value={form.active?'1':'0'} onChange={e=>setF('active',e.target.value==='1')}>
                <option value="1">Aktiv</option>
                <option value="0">Inaktiv</option>
              </select>
            </div>
          </div>

          <div style={{fontWeight:700,fontSize:12,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:10}}>Fixkosten pro Monat (€)</div>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:16}}>
            {Object.entries(FIXED_LABELS).map(([k,label])=>(
              <div key={k} className="form-group">
                <label className="form-label">{label}</label>
                <input className="form-input" type="number" min="0"
                  value={form.costs_fixed?.[k]||0}
                  onChange={e=>setF('costs_fixed.'+k,Number(e.target.value))}/>
              </div>
            ))}
          </div>

          <div className="form-group">
            <label className="form-label">Notizen</label>
            <textarea className="form-input" rows={2} value={form.notes||''}
              onChange={e=>setF('notes',e.target.value)} style={{resize:'vertical'}}/>
          </div>

          <div style={{display:'flex',gap:10,justifyContent:'flex-end',marginTop:16}}>
            <button className="btn" onClick={onClose}>Abbrechen</button>
            <button className="btn btn-primary" onClick={save}>Speichern</button>
          </div>
        </div>
      </div>
    </div>
  );
}

LoginScreen:
function LoginScreen({onLogin}){
  const [user, setUser] = useState('');
  const [pass, setPass] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [phase, setPhase] = useState('idle'); // idle | scanning | granted

  // Load accounts from localStorage (set by SuperAdmin)
  // Fallback to hardcoded demo accounts if none exist
  const DEMO_USERS = [
    {user:'admin',pass:'jsr2026',name:'JSR Management',icon:'⬡',access:'all'},
    {user:'demo',pass:'demo',name:'Demo User',icon:'◎',access:'all'},
  ];

  function findUser(userInput, passInput){
    // First check real accounts from jsr_accounts_v1
    try{
      const accounts = JSON.parse(localStorage.getItem('jsr_accounts_v1')||'[]');
      const found = accounts.find(a=>
        a.active &&
        (a.email===userInput || a.name===userInput) &&
        a.login_password===passInput
      );
      if(found){
        const roles = JSON.parse(localStorage.getItem('jsr_roles_v1')||'[]');
        const role = roles.find(r=>r.id===found.role_id);
        return {
          name: found.name,
          icon: role?.icon||'👤',
          access: role?.tabs ? Object.keys(role.tabs).filter(k=>role.tabs[k]) : 'all',
          must_change_pw: found.must_change_pw,
          account_id: found.id,
        };
      }
    }catch(e){}
    // Fallback: demo users
    const demo = DEMO_USERS.find(u=>u.user===userInput&&u.pass===passInput);
    return demo ? {name:demo.name,icon:demo.icon,access:demo.access} : null;
  }

  function handleLogin(){
    if(!user||!pass) return;
    setLoading(true);
    setPhase('scanning');
    setTimeout(()=>{
      const found = findUser(user, pass);
      if(found){
        setPhase('granted');
        setTimeout(()=>onLogin(found), 1200);
      } else {
        setError('Zugang verweigert. Bitte erneut versuchen.');
        setLoading(false);
        setPhase('idle');
      }
    }, 1800);
  }

  return(
    <div style={{
      position:'fixed',inset:0,zIndex:9999,overflow:'hidden',
      background:'#080c14',
      display:'flex',alignItems:'center',justifyContent:'center',
      fontFamily:"'DM Mono', 'Courier New', monospace"
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Mono:wght@300;400;500&family=Syne:wght@600;700;800&display=swap');

        @keyframes grid-scroll {
          0%{transform:perspective(600px) rotateX(20deg) translateY(0)}
          100%{transform:perspective(600px) rotateX(20deg) translateY(60px)}
        }
        @keyframes pulse-ring {
          0%{transform:scale(1);opacity:.6}
          50%{transform:scale(1.08);opacity:.2}
          100%{transform:scale(1);opacity:.6}
        }
        @keyframes scan-line {
          0%{transform:translateY(-100%)}
          100%{transform:translateY(400%)}
        }
        @keyframes fade-up {
          0%{opacity:0;transform:translateY(24px)}
          100%{opacity:1;transform:translateY(0)}
        }
        @keyframes blink {
          0%,100%{opacity:1} 50%{opacity:0}
        }
        @keyframes float {
          0%,100%{transform:translateY(0)} 50%{transform:translateY(-8px)}
        }
        @keyframes granted-flash {
          0%{opacity:0} 10%{opacity:1} 40%{opacity:0} 60%{opacity:1} 100%{opacity:1}
        }
        @keyframes data-flow {
          0%{transform:translateY(0);opacity:0}
          10%{opacity:1}
          90%{opacity:.6}
          100%{transform:translateY(-120px);opacity:0}
        }
        @keyframes rotate-slow {
          0%{transform:rotate(0deg)} 100%{transform:rotate(360deg)}
        }
        @keyframes rotate-slow-rev {
          0%{transform:rotate(0deg)} 100%{transform:rotate(-360deg)}
        }
        @keyframes shimmer {
          0%{background-position:200% center}
