SuperAdminView:
function SuperAdminView({employees, projects, setProjects}){
  const [roles, setRoles] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_roles_v1')||'null')||JSON.parse(JSON.stringify(PRESET_ROLES));}
    catch(e){return JSON.parse(JSON.stringify(PRESET_ROLES));}
  });
  const [accounts, setAccounts] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_accounts_v1')||'[]');}
    catch(e){return [];}
  });
  const [tab, setTab] = useState('roles'); // roles | accounts
  const [editRole, setEditRole] = useState(null);
  const [editAccount, setEditAccount] = useState(null);
  const [showAddAccount, setShowAddAccount] = useState(false);
  const [accForm, setAccForm] = useState({name:'',email:'',role_id:'',location:'',password:'',active:true});
  const setAF=(k,v)=>setAccForm(f=>({...f,[k]:v}));

  useEffect(()=>{localStorage.setItem('jsr_roles_v1',JSON.stringify(roles));},[roles]);
  useEffect(()=>{localStorage.setItem('jsr_accounts_v1',JSON.stringify(accounts));},[accounts]);

  function saveRole(role){
    setRoles(rs=>rs.find(r=>r.id===role.id)?rs.map(r=>r.id===role.id?role:r):[...rs,role]);
    setEditRole(null);
  }

  function deleteRole(id){
    if(window.confirm('Rolle löschen? Alle zugewiesenen Accounts verlieren ihre Rolle.'))
      setRoles(rs=>rs.filter(r=>r.id!==id));
  }

  function saveAccount(form){
    if(!form.name||!form.email||!form.role_id) return alert('Name, E-Mail und Rolle sind Pflichtfelder.');
    if(form.id){
      setAccounts(as=>as.map(a=>a.id===form.id?form:a));
    } else {
      setAccounts(as=>[...as,{...form,id:'acc'+Date.now(),created:new Date().toISOString().slice(0,10),last_login:null,failed_attempts:0}]);
    }
    setShowAddAccount(false);
    setEditAccount(null);
    setAccForm({name:'',email:'',role_id:'',location:'',password:'',active:true});
  }

  function resetPassword(acc){
    const newPw = Math.random().toString(36).slice(2,8).toUpperCase();
    setAccounts(as=>as.map(a=>a.id===acc.id?{...a,password:newPw,must_change_pw:true,failed_attempts:0,active:true}:a));
    alert('Neues Einmal-Passwort fuer '+acc.name+':\n\n'+newPw+'\n\nBitte persoenlich weitergeben. Muss beim naechsten Login geaendert werden.');
  }

  function toggleActive(acc){
    setAccounts(as=>as.map(a=>a.id===acc.id?{...a,active:!a.active}:a));
  }

  const getRoleName=(id)=>roles.find(r=>r.id===id)?.name||'—';
  const getRoleColor=(id)=>roles.find(r=>r.id===id)?.color||'#6b7280';

  return(
    <div>

      {/* Role Edit Modal */}
      {editRole&&(
        <RoleEditModal
          role={editRole}
          onSave={saveRole}
          onClose={()=>setEditRole(null)}
          PERMISSION_TABS={PERMISSION_TABS}
        />
      )}

      {/* Account Modal */}
      {(showAddAccount||editAccount)&&(()=>{
        const form = editAccount||accForm;
        const isEdit = !!editAccount;
        const setF = isEdit
          ? (k,v)=>setEditAccount(a=>({...a,[k]:v}))
          : setAF;
        return(
          <div className="modal-overlay">
            <div className="modal" style={{width:500}}>
              <div className="modal-header">
                <div style={{fontSize:15,fontWeight:700}}>{isEdit?'Account bearbeiten':'Neuen Account anlegen'}</div>
                <button className="btn" onClick={()=>{setShowAddAccount(false);setEditAccount(null);}}>×</button>
              </div>
              <div className="modal-body">
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Vollständiger Name *</label>
                    <input className="form-input" value={form.name||''} onChange={e=>setF('name',e.target.value)} placeholder="Vorname Nachname"/>
                  </div>
                  <div className="form-group">
                    <label className="form-label">E-Mail *</label>
                    <input className="form-input" type="email" value={form.email||''} onChange={e=>setF('email',e.target.value)} placeholder="name@jsr-bpo.com"/>
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Rolle *</label>
                    <select className="form-select" value={form.role_id||''} onChange={e=>setF('role_id',e.target.value)}>
                      <option value="">Rolle wählen…</option>
                      {roles.map(r=><option key={r.id} value={r.id}>{r.icon} {r.name}</option>)}
                    </select>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Standort (optional)</label>
                    <select className="form-select" value={form.location||''} onChange={e=>setF('location',e.target.value)}>
                      <option value="">Alle Standorte</option>
                      <option value="Tirana">🇦🇱 Tirana</option>
                      <option value="Prishtina">🇽🇰 Prishtina</option>
                    </select>
                  </div>
                </div>
                {!isEdit&&(
                  <div className="form-group">
                    <label className="form-label">Initiales Passwort</label>
                    <input className="form-input" type="text" value={form.password||''} onChange={e=>setF('password',e.target.value)} placeholder="Wird beim ersten Login geändert"/>
                  </div>
                )}
                <div className="form-group">
                  <label className="form-label">Mitarbeiter verknüpfen (optional)</label>
                  <select className="form-select" value={form.employee_id||''} onChange={e=>setF('employee_id',e.target.value)}>
                    <option value="">Kein Mitarbeiter</option>
                    {employees.map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name} ({e.position})</option>)}
                  </select>
                </div>
                <div style={{display:'flex',gap:10,justifyContent:'flex-end',marginTop:16}}>
                  <button className="btn" onClick={()=>{setShowAddAccount(false);setEditAccount(null);}}>Abbrechen</button>
                  <button className="btn btn-primary" onClick={()=>saveAccount(form)}>Speichern</button>
                </div>
              </div>
            </div>
          </div>
        );
      })()}

      {/* Tabs */}
      <div style={{display:'flex',gap:0,marginBottom:16,borderBottom:'2px solid var(--border)'}}>
        {[['roles','🎭 Rollen & Berechtigungen'],['accounts','👤 Accounts & Zugänge'],['clients','🏢 Kunden-Accounts'],['projects','📋 Projekte'],['settings','⚙️ Einstellungen']].map(([t,l])=>(
          <button key={t} onClick={()=>setTab(t)}
            style={{padding:'10px 24px',border:'none',background:'transparent',cursor:'pointer',
              fontSize:13,fontWeight:tab===t?700:400,
              color:tab===t?'var(--blue)':'var(--muted)',
              borderBottom:tab===t?'2px solid var(--blue)':'2px solid transparent',marginBottom:-2}}>
            {l}
          </button>
        ))}
      </div>

      {/* ROLES TAB */}
      {tab==='roles'&&(
        <div>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
            <div>
              <div style={{fontSize:14,color:'var(--muted)'}}>
                Rollen definieren welche Tabs und Felder ein Nutzer sehen und bearbeiten darf.
              </div>
            </div>
            <button className="btn btn-primary" onClick={()=>setEditRole({
              id:'role_'+Date.now(),name:'Neue Rolle',color:'#6b7280',icon:'◎',
              description:'',tabs:{},fields:{}
            })}>
              + Neue Rolle
            </button>
          </div>

          <div style={{display:'flex',flexDirection:'column',gap:10}}>
            {roles.map(role=>{
              const tabCount=Object.values(role.tabs||{}).filter(Boolean).length;
              const fieldCount=Object.values(role.fields||{}).filter(Boolean).length;
              const assignedAccs=accounts.filter(a=>a.role_id===role.id);
              return(
                <div key={role.id} className="card" style={{overflow:'hidden'}}>
                  <div style={{display:'flex',alignItems:'center',gap:14,padding:'14px 16px',
