                    <div style={{flex:1}}>
                      <div style={{fontWeight:700,fontSize:15,color:'var(--text)'}}>{role.name}</div>
                      <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>{role.description}</div>
                      <div style={{display:'flex',gap:10,marginTop:6}}>
                        <span style={{fontSize:11,padding:'1px 8px',borderRadius:20,
                          background:'var(--blue-bg)',color:'var(--blue)',fontWeight:600}}>
                          {tabCount} Tabs
                        </span>
                        <span style={{fontSize:11,padding:'1px 8px',borderRadius:20,
                          background:'var(--surface-2)',color:'var(--muted)',fontWeight:600}}>
