                        </span>
                        {assignedAccs.length>0&&(
                          <span style={{fontSize:11,padding:'1px 8px',borderRadius:20,
                            background:'var(--green-bg)',color:'var(--green)',fontWeight:600}}>
                            {assignedAccs.length} Accounts
                          </span>
