                      <td>
                        <span style={{fontSize:11,padding:'2px 8px',borderRadius:20,fontWeight:600,
                          background:getRoleColor(acc.role_id)+'20',
                          color:getRoleColor(acc.role_id)}}>
                          {getRoleName(acc.role_id)}
                        </span>
                      </td>
                      <td style={{fontSize:12,color:'var(--muted)'}}>{acc.location||'Alle'}</td>
                      <td>
                        <span style={{fontSize:11,padding:'2px 8px',borderRadius:20,fontWeight:600,
                          background:acc.active?'var(--green-bg)':'var(--red-bg)',
                          color:acc.active?'var(--green)':'var(--red)'}}>
                          {acc.active?'Aktiv':'Inaktiv'}
                        </span>
                        {(acc.failed_attempts||0)>=3&&(
                          <span style={{marginLeft:4,fontSize:10,color:'var(--red)'}}>
                            ⚠ {acc.failed_attempts} Fehlversuche
                          </span>
                        )}
                      </td>
                      <td style={{fontSize:11,color:'var(--muted)'}}>{acc.created||'—'}</td>
                      <td style={{fontSize:11,color:'var(--muted)'}}>{acc.last_login||'Nie'}</td>
                      <td>
                        <div style={{display:'flex',gap:4}}>
                          <button className="btn btn-sm" onClick={()=>setEditAccount({...acc})}>✎</button>
                          <button className="btn btn-sm" style={{color:'var(--amber)'}}
                            onClick={()=>resetPassword(acc)} title="Passwort zurücksetzen">
                            🔑
                          </button>
                          <button className="btn btn-sm"
                            style={{color:acc.active?'var(--red)':'var(--green)'}}
                            onClick={()=>toggleActive(acc)}>
                            {acc.active?'Sperren':'Entsperren'}
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

RoleEditModal:
function RoleEditModal({role, onSave, onClose, PERMISSION_TABS}){
  const [form, setForm] = useState(JSON.parse(JSON.stringify(role)));
  const setF=(k,v)=>setForm(f=>({...f,[k]:v}));

  function toggleTab(tabKey){
    const newTabs={...form.tabs,[tabKey]:!form.tabs[tabKey]};
    // If disabling tab, also disable all its fields
    const newFields={...form.fields};
    if(!newTabs[tabKey]){
      const tab=PERMISSION_TABS.find(t=>t.key===tabKey);
      tab?.fields.forEach(f=>{newFields[tabKey+'_'+f.key]=false;});
    }
    setForm(f=>({...f,tabs:newTabs,fields:newFields}));
  }

  function toggleField(tabKey, fieldKey){
    const fk=tabKey+'_'+fieldKey;
    setForm(f=>({...f,fields:{...f.fields,[fk]:!f.fields[fk]}}));
  }

  function toggleAllFields(tabKey, val){
    const tab=PERMISSION_TABS.find(t=>t.key===tabKey);
    const newFields={...form.fields};
    tab?.fields.forEach(f=>{newFields[tabKey+'_'+f.key]=val;});
    setForm(f=>({...f,fields:newFields}));
  }

  function selectAll(){
    const tabs=Object.fromEntries(PERMISSION_TABS.map(t=>[t.key,true]));
    const fields=Object.fromEntries(PERMISSION_TABS.flatMap(t=>t.fields.map(f=>[t.key+'_'+f.key,true])));
    setForm(f=>({...f,tabs,fields}));
  }

  function selectNone(){
    setForm(f=>({...f,tabs:{},fields:{}}));
  }

  const tabCount=Object.values(form.tabs||{}).filter(Boolean).length;
  const fieldCount=Object.values(form.fields||{}).filter(Boolean).length;

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:720,maxHeight:'92vh',overflowY:'auto'}}>
        <div className="modal-header">
          <div style={{fontSize:15,fontWeight:700}}>
            {form.id.startsWith('role_')?'Rolle bearbeiten':'Neue Rolle'}
          </div>
          <button className="btn" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">

          {/* Basic info */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:12}}>
            <div className="form-group">
              <label className="form-label">Rollenname *</label>
              <input className="form-input" value={form.name} onChange={e=>setF('name',e.target.value)}/>
            </div>
            <div className="form-group">
              <label className="form-label">Icon (Emoji)</label>
              <input className="form-input" value={form.icon||'◎'} onChange={e=>setF('icon',e.target.value)} style={{fontSize:20}}/>
            </div>
          </div>
          <div style={{display:'grid',gridTemplateColumns:'2fr 1fr',gap:10,marginBottom:16}}>
            <div className="form-group">
              <label className="form-label">Beschreibung</label>
              <input className="form-input" value={form.description||''} onChange={e=>setF('description',e.target.value)} placeholder="Kurze Beschreibung der Rolle"/>
            </div>
            <div className="form-group">
              <label className="form-label">Farbe</label>
              <input className="form-input" type="color" value={form.color||'#6b7280'} onChange={e=>setF('color',e.target.value)}/>
            </div>
          </div>

          {/* Summary + quick actions */}
          <div style={{display:'flex',alignItems:'center',gap:12,marginBottom:16,
            padding:'10px 14px',background:'var(--surface-2)',borderRadius:'var(--r-md)'}}>
            <span style={{fontSize:11,color:'var(--muted)'}}>
              <strong style={{color:'var(--blue)'}}>{tabCount}</strong> Tabs aktiv,
              <strong style={{color:'var(--green)',marginLeft:4}}>{fieldCount}</strong> Felder aktiv
            </span>
            <button className="btn btn-sm" style={{marginLeft:'auto'}} onClick={selectAll}>Alles aktivieren</button>
            <button className="btn btn-sm" onClick={selectNone}>Alles deaktivieren</button>
          </div>

          {/* Permissions grid */}
          <div style={{display:'flex',flexDirection:'column',gap:6}}>
            {PERMISSION_TABS.map(tabDef=>{
              const tabOn=!!(form.tabs||{})[tabDef.key];
              const allFieldsOn=tabDef.fields.every(f=>(form.fields||{})[tabDef.key+'_'+f.key]);
              return(
                <div key={tabDef.key} style={{
                  border:'1px solid var(--border)',
                  borderRadius:'var(--r-md)',
                  overflow:'hidden',
                  opacity:tabOn?1:0.5
                }}>
                  {/* Tab header */}
                  <div style={{
                    display:'flex',alignItems:'center',gap:10,
                    padding:'8px 12px',
                    background:tabOn?'var(--surface-2)':'var(--surface)',
                    cursor:'pointer'
                  }}
                    onClick={()=>toggleTab(tabDef.key)}>
                    <div style={{
                      width:20,height:20,borderRadius:4,flexShrink:0,
                      background:tabOn?form.color||'var(--blue)':'var(--border)',
                      display:'flex',alignItems:'center',justifyContent:'center',
                      color:'white',fontSize:12,fontWeight:700,transition:'background .15s'
                    }}>
                      {tabOn?'✓':''}
                    </div>
                    <span style={{fontSize:13,fontWeight:600}}>{tabDef.icon} {tabDef.label}</span>
                    {tabOn&&(
                      <span style={{fontSize:11,color:'var(--muted)',marginLeft:'auto'}}>
                        {tabDef.fields.filter(f=>(form.fields||{})[tabDef.key+'_'+f.key]).length} / {tabDef.fields.length} Felder
                      </span>
                    )}
                    {tabOn&&(
                      <div style={{display:'flex',gap:6}} onClick={e=>e.stopPropagation()}>
                        <button className="btn btn-sm" style={{fontSize:10,padding:'1px 6px'}}
                          onClick={()=>toggleAllFields(tabDef.key,true)}>Alle</button>
                        <button className="btn btn-sm" style={{fontSize:10,padding:'1px 6px'}}
                          onClick={()=>toggleAllFields(tabDef.key,false)}>Keine</button>
                      </div>
                    )}
                  </div>

                  {/* Fields */}
                  {tabOn&&(
                    <div style={{
                      display:'flex',flexWrap:'wrap',gap:6,
                      padding:'8px 12px',
                      borderTop:'1px solid var(--border)',
                      background:'var(--surface)'
                    }}>
                      {tabDef.fields.map(field=>{
                        const fk=tabDef.key+'_'+field.key;
                        const on=!!(form.fields||{})[fk];
                        return(
                          <div key={field.key}
                            onClick={()=>toggleField(tabDef.key,field.key)}
                            style={{
                              display:'flex',alignItems:'center',gap:5,
                              padding:'4px 10px',borderRadius:20,cursor:'pointer',
                              border:'1px solid '+(on?form.color||'var(--blue)':'var(--border)'),
                              background:on?(form.color||'#1d4ed8')+'18':'transparent',
                              fontSize:12,fontWeight:on?600:400,
                              color:on?form.color||'var(--blue)':'var(--muted)',
                              transition:'all .15s',userSelect:'none'
                            }}>
                            <span style={{fontSize:10}}>{on?'✓':'○'}</span>
                            {field.label}
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          <div style={{display:'flex',gap:10,justifyContent:'flex-end',marginTop:20}}>
            <button className="btn" onClick={onClose}>Abbrechen</button>
            <button className="btn btn-primary" onClick={()=>onSave(form)}>
              Rolle speichern
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

