function ClientAccountsTab({projects}){
  const [clients, setClients] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_client_accounts_v1')||'null')||[];}
    catch(e){return [];}
  });
  const [showModal, setShowModal] = useState(false);
  const [editClient, setEditClient] = useState(null);

  useEffect(()=>{
    localStorage.setItem('jsr_client_accounts_v1', JSON.stringify(clients));
  },[clients]);

  const CLIENT_TABS = [
    {key:'overview',    label:'Projektübersicht',  icon:'📊'},
    {key:'employees',   label:'Mitarbeiter',        icon:'👥'},
    {key:'quality',     label:'Qualitätsberichte',  icon:'⭐'},
    {key:'training',    label:'Schulungen',          icon:'📚'},
    {key:'calendar',    label:'Terminkalender',      icon:'📅'},
    {key:'documents',   label:'Dokumente',           icon:'📁'},
    {key:'invoices',    label:'Rechnungen',          icon:'💳'},
    {key:'messages',    label:'Nachrichten',         icon:'💬'},
    {key:'showcases',   label:'Kandidaten-Showcases',icon:'🎯'},
    {key:'reports',     label:'Berichte',            icon:'📈'},
  ];

  function newClientTemplate(){
    return {
      id:'client_'+Date.now(),
      // Stammdaten
      company_name:'', company_legal:'', industry:'', website:'',
      // Ansprechpartner
      contact_name:'', contact_title:'', contact_email:'', contact_phone:'',
      contact2_name:'', contact2_email:'', contact2_phone:'',
      // Adresse
      address_street:'', address_city:'', address_country:'',
      // Vertrag
      project_name:'', project_id:'', contract_start:'', contract_end:'',
      billing_model:'per_agent', billing_rate:0, billing_currency:'EUR',
      payment_terms:'30', vat_id:'',
      // Login
      login_email:'', login_password:'', active:true, must_change_pw:true,
      // Tabs die dieser Kunde sehen darf
      visible_tabs: {overview:true, employees:true, quality:true, training:true, calendar:true},
      // Notes
      notes:'', created:new Date().toISOString().slice(0,10)
    };
  }

  function save(form){
    if(!form.company_name) return alert('Bitte Firmenname eingeben.');
    if(!form.login_email) return alert('Bitte Login E-Mail eingeben.');
    setClients(cs=>cs.find(c=>c.id===form.id)?cs.map(c=>c.id===form.id?form:c):[...cs,form]);
    setShowModal(false);
    setEditClient(null);
  }

  function resetPassword(client){
    const pw = Math.random().toString(36).slice(2,8).toUpperCase();
    setClients(cs=>cs.map(c=>c.id===client.id?{...c,login_password:pw,must_change_pw:true}:c));
    alert('Neues Passwort fuer '+client.company_name+': '+pw);
  }

  function toggleActive(client){
    setClients(cs=>cs.map(c=>c.id===client.id?{...c,active:!c.active}:c));
  }

  function deleteClient(id){
    if(window.confirm('Kunden-Account loeschen?'))
      setClients(cs=>cs.filter(c=>c.id!==id));
  }

  return(
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div>
          <div style={{fontSize:14,fontWeight:600}}>Kunden-Accounts</div>
          <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>
            Jeder Kunde erhält einen eigenen Login für client.html mit definierten Inhalten.
          </div>
        </div>
        <button className="btn btn-primary" onClick={()=>{setEditClient(newClientTemplate());setShowModal(true);}}>
          + Kunden-Account anlegen
        </button>
      </div>

      {/* Edit Modal */}
      {showModal&&editClient&&(
        <ClientEditModal
          client={editClient}
          onSave={save}
          onClose={()=>{setShowModal(false);setEditClient(null);}}
          CLIENT_TABS={CLIENT_TABS}
          projects={projects}
        />
      )}

      {clients.length===0&&(
        <div className="card" style={{padding:40,textAlign:'center',color:'var(--muted)'}}>
          <div style={{fontSize:32,marginBottom:8}}>🏢</div>
          <div style={{fontWeight:600,marginBottom:4}}>Noch keine Kunden-Accounts</div>
          <div style={{fontSize:12}}>Lege den ersten Account für einen Auftraggeber an.</div>
        </div>
      )}

      <div style={{display:'flex',flexDirection:'column',gap:10}}>
        {clients.map(client=>{
          const tabCount=Object.values(client.visible_tabs||{}).filter(Boolean).length;
          return(
            <div key={client.id} className="card" style={{overflow:'hidden'}}>
              <div style={{display:'grid',gridTemplateColumns:'1fr auto',gap:16,padding:'14px 16px',
                borderLeft:'4px solid var(--blue)'}}>
                <div>
                  <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:4}}>
                    <span style={{fontSize:18}}>🏢</span>
                    <span style={{fontWeight:700,fontSize:15}}>{client.company_name}</span>
                    {client.company_legal&&<span style={{fontSize:11,color:'var(--muted)'}}>({client.company_legal})</span>}
                    <span style={{fontSize:11,padding:'1px 8px',borderRadius:20,fontWeight:600,
                      background:client.active?'var(--green-bg)':'var(--red-bg)',
                      color:client.active?'var(--green)':'var(--red)'}}>
                      {client.active?'Aktiv':'Inaktiv'}
                    </span>
                  </div>

                  <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:8,marginBottom:8}}>
                    {[
                      {icon:'📋',label:'Projekt',val:client.project_name||'—'},
                      {icon:'👤',label:'Kontakt',val:client.contact_name||'—'},
                      {icon:'✉',label:'Login',val:client.login_email||'—'},
                      {icon:'📊',label:'Tabs aktiv',val:tabCount+' von '+CLIENT_TABS.length},
                    ].map((item,i)=>(
                      <div key={i} style={{padding:'6px 10px',background:'var(--surface-2)',borderRadius:'var(--r-md)'}}>
                        <div style={{fontSize:10,color:'var(--muted)',marginBottom:2}}>{item.icon} {item.label}</div>
                        <div style={{fontSize:12,fontWeight:500,color:'var(--text)'}}>{item.val}</div>
                      </div>
                    ))}
                  </div>

                  <div style={{display:'flex',flexWrap:'wrap',gap:4}}>
                    {CLIENT_TABS.filter(t=>(client.visible_tabs||{})[t.key]).map(t=>(
                      <span key={t.key} style={{fontSize:10,padding:'1px 7px',borderRadius:20,
                        background:'var(--blue-bg)',color:'var(--blue)',fontWeight:600}}>
                        {t.icon} {t.label}
                      </span>
                    ))}
                  </div>
                </div>

                <div style={{display:'flex',flexDirection:'column',gap:6,alignItems:'flex-end',justifyContent:'center'}}>
                  <button className="btn btn-sm btn-primary"
                    onClick={()=>{setEditClient(JSON.parse(JSON.stringify(client)));setShowModal(true);}}>
                    ✎ Bearbeiten
                  </button>
                  <button className="btn btn-sm" style={{color:'var(--amber)'}}
                    onClick={()=>resetPassword(client)}>
                    🔑 Passwort
                  </button>
                  <button className="btn btn-sm"
                    style={{color:client.active?'var(--red)':'var(--green)'}}
                    onClick={()=>toggleActive(client)}>
                    {client.active?'Sperren':'Entsperren'}
                  </button>
                  <button className="btn btn-sm" style={{color:'var(--red)'}}
                    onClick={()=>deleteClient(client.id)}>
                    Löschen
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

SystemSettingsTab:
function SystemSettingsTab({projects, setProjects, employees}){
  const [activeSection, setActiveSection] = useState('skills');

  // Skills
  const [skills, setSkills] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_skills_v1')||'null')||SKILLS_ALL.map((s,i)=>({id:'sk'+i,name:s,category:'Allgemein',active:true}));}
    catch(e){return [];}
  });

  // Absence types
  const [absenceTypes, setAbsenceTypes] = useState(()=>{
    try{
      const stored = JSON.parse(localStorage.getItem('jsr_absence_types_v1')||'null');
      if(stored) return stored;
      return Object.entries(ABSENCE_TYPES).map(([key,v])=>({id:key,...v,paid:key!=='unpaid',active:true}));
    }catch(e){return [];}
  });

  // Positions
  const [positions, setPositions] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_positions_v1')||'null')||DEFAULT_POSITIONS.map((p,i)=>({id:'pos'+i,name:p,active:true}));}
    catch(e){return [];}
  });

  // Holidays
  const [holidays, setHolidays] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_holidays_v1')||'null')||DEFAULT_HOLIDAYS;}
    catch(e){return DEFAULT_HOLIDAYS;}
  });

  // Work models
  const [workModels, setWorkModels] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_work_models_v1')||'null')||DEFAULT_WORK_MODELS;}
    catch(e){return [];}
  });

  // Vacation quota
  const [vacationDefaults, setVacationDefaults] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_vacation_defaults_v1')||'null')||{tirana:20,prishtina:20,training:15};}
    catch(e){return {tirana:20,prishtina:20,training:15};}
  });

  // Stempel PINs - read from time sessions and employees
  const [pins, setPins] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_pins_v1')||'{}');}
    catch(e){return {};}
  });

  useEffect(()=>{localStorage.setItem('jsr_skills_v1',JSON.stringify(skills));},[skills]);
  useEffect(()=>{localStorage.setItem('jsr_absence_types_v1',JSON.stringify(absenceTypes));},[absenceTypes]);
  useEffect(()=>{localStorage.setItem('jsr_positions_v1',JSON.stringify(positions));},[positions]);
  useEffect(()=>{localStorage.setItem('jsr_holidays_v1',JSON.stringify(holidays));},[holidays]);
  useEffect(()=>{localStorage.setItem('jsr_work_models_v1',JSON.stringify(workModels));},[workModels]);
  useEffect(()=>{localStorage.setItem('jsr_vacation_defaults_v1',JSON.stringify(vacationDefaults));},[vacationDefaults]);
  useEffect(()=>{localStorage.setItem('jsr_pins_v1',JSON.stringify(pins));},[pins]);

  // Backup
  function exportAllData(){
    const allData = {
      exported: new Date().toISOString(),
      employees: JSON.parse(localStorage.getItem('jsr_emp_v3')||'[]'),
      cvs: JSON.parse(localStorage.getItem('jsr_cvs_v1')||'[]'),
      plans: JSON.parse(localStorage.getItem('jsr_plans_v3')||'[]'),
      payroll: JSON.parse(localStorage.getItem('jsr_payroll_v1')||'{}'),
      projects: JSON.parse(localStorage.getItem('jsr_projects_v1')||'[]'),
      locations: JSON.parse(localStorage.getItem('jsr_locations_v1')||'[]'),
      roles: JSON.parse(localStorage.getItem('jsr_roles_v1')||'[]'),
      accounts: JSON.parse(localStorage.getItem('jsr_accounts_v1')||'[]'),
      clients: JSON.parse(localStorage.getItem('jsr_client_accounts_v1')||'[]'),
      time: JSON.parse(localStorage.getItem('jsr_time_v1')||'[]'),
      showcases: JSON.parse(localStorage.getItem('jsr_showcases_v1')||'[]'),
      skills, absenceTypes, positions, holidays, workModels, vacationDefaults, pins,
    };
    const json = JSON.stringify(allData, null, 2);
    const blob = new Blob([json], {type:'application/json'});
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'JSR_Backup_'+new Date().toISOString().slice(0,10)+'.json';
    a.click();
    URL.revokeObjectURL(url);
  }

  function importBackup(e){
    const file = e.target.files[0];
    if(!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
      try{
        const data = JSON.parse(ev.target.result);
        if(data.employees) localStorage.setItem('jsr_emp_v3', JSON.stringify(data.employees));
        if(data.cvs) localStorage.setItem('jsr_cvs_v1', JSON.stringify(data.cvs));
        if(data.plans) localStorage.setItem('jsr_plans_v3', JSON.stringify(data.plans));
        if(data.payroll) localStorage.setItem('jsr_payroll_v1', JSON.stringify(data.payroll));
        if(data.projects) localStorage.setItem('jsr_projects_v1', JSON.stringify(data.projects));
        if(data.locations) localStorage.setItem('jsr_locations_v1', JSON.stringify(data.locations));
        if(data.roles) localStorage.setItem('jsr_roles_v1', JSON.stringify(data.roles));
        if(data.accounts) localStorage.setItem('jsr_accounts_v1', JSON.stringify(data.accounts));
        if(data.clients) localStorage.setItem('jsr_client_accounts_v1', JSON.stringify(data.clients));
        if(data.time) localStorage.setItem('jsr_time_v1', JSON.stringify(data.time));
        if(data.showcases) localStorage.setItem('jsr_showcases_v1', JSON.stringify(data.showcases));
        alert('Import erfolgreich. Seite wird neu geladen.');
        window.location.reload();
      }catch(err){
        alert('Fehler beim Import: '+err.message);
      }
    };
    reader.readAsText(file);
  }

  // Simple inline editor helpers
  const [newSkill, setNewSkill] = useState('');
  const [newSkillCat, setNewSkillCat] = useState('Allgemein');
  const [newPos, setNewPos] = useState('');
  const [newHolidayLoc, setNewHolidayLoc] = useState('Tirana');
  const [newHoliday, setNewHoliday] = useState({date:'',name:''});
  const [editAbs, setEditAbs] = useState(null);
  const [newAbs, setNewAbs] = useState({id:'',label:'',icon:'📋',color:'var(--blue)',bg:'rgba(29,78,216,.1)',paid:true,active:true});

  const SKILL_CATS = ['Allgemein','Telefonie','Schriftlich','Produkt','Technik','Sprache','Sonstiges'];
  const [referralCfg, setReferralCfg] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_referral_config_v1')||'null')||{tranche1_pct:50,tranche1_month:1,tranche2_pct:50,tranche2_month:4};}
    catch(e){return {tranche1_pct:50,tranche1_month:1,tranche2_pct:50,tranche2_month:4};}
  });
