                if(!newSkill.trim()) return;
                setSkills(ss=>[...ss,{id:'sk'+Date.now(),name:newSkill.trim(),category:newSkillCat,active:true}]);
                setNewSkill('');
              }}>+ Hinzufügen</button>
            </div>
            {SKILL_CATS.filter(cat=>skills.some(s=>s.category===cat)).map(cat=>(
              <div key={cat} style={{padding:'10px 14px',borderBottom:'1px solid var(--border)'}}>
                <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:8}}>{cat}</div>
                <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
                  {skills.filter(s=>s.category===cat).map(skill=>(
                    <div key={skill.id} style={{
                      display:'flex',alignItems:'center',gap:4,padding:'4px 10px',
                      borderRadius:20,border:'1px solid var(--border)',
                      background:skill.active?'var(--surface-2)':'var(--surface)',
                      opacity:skill.active?1:0.5}}>
                      <span style={{fontSize:12,fontWeight:500,color:skill.active?'var(--text)':'var(--muted)'}}>{skill.name}</span>
                      <button onClick={()=>setSkills(ss=>ss.map(s=>s.id===skill.id?{...s,active:!s.active}:s))}
                        style={{border:'none',background:'none',cursor:'pointer',padding:'0 2px',
                          color:skill.active?'var(--muted)':'var(--green)',fontSize:12}}>
                        {skill.active?'○':'✓'}
                      </button>
                      <button onClick={()=>setSkills(ss=>ss.filter(s=>s.id!==skill.id))}
                        style={{border:'none',background:'none',cursor:'pointer',padding:'0 2px',
                          color:'var(--red)',fontSize:12}}>×</button>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}

        {/* ABSENCE TYPES */}
        {activeSection==='absence'&&(
        <div className="card">
          <div className="card-header">
            <span className="card-title">📅 Abwesenheitstypen</span>
            </div>
            <div className="table-responsive"><table>
              <thead><tr><th>Icon</th><th>Bezeichnung</th><th>Farbe</th><th>Bezahlt</th><th>Aktiv</th><th></th></tr></thead>
              <tbody>
                {absenceTypes.map(t=>(
                  <tr key={t.id} style={{opacity:t.active?1:0.5}}>
                    <td style={{fontSize:20,textAlign:'center'}}>{t.icon}</td>
                    <td style={{fontWeight:500}}>{t.label}</td>
                    <td><span style={{display:'inline-block',width:16,height:16,borderRadius:4,background:t.color,verticalAlign:'middle'}}/></td>
                    <td><span style={{fontSize:11,padding:'1px 8px',borderRadius:20,fontWeight:600,
                      background:t.paid?'var(--green-bg)':'var(--red-bg)',
                      color:t.paid?'var(--green)':'var(--red)'}}>
                      {t.paid?'Bezahlt':'Unbezahlt'}
                    </span></td>
                    <td><span style={{fontSize:11,color:t.active?'var(--green)':'var(--muted)'}}>{t.active?'✓ Aktiv':'○ Inaktiv'}</span></td>
                    <td>
                      <div style={{display:'flex',gap:4}}>
                        <button className="btn btn-sm" onClick={()=>setEditAbs({...t})}>✎</button>
                        <button className="btn btn-sm" style={{color:t.active?'var(--amber)':'var(--green)'}}
                          onClick={()=>setAbsenceTypes(ts=>ts.map(x=>x.id===t.id?{...x,active:!x.active}:x))}>
                          {t.active?'Deakt.':'Aktiv.'}
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
                {/* New row */}
                <tr style={{background:'var(--surface-2)'}}>
                  <td><input style={{width:50,padding:'4px',border:'1px solid var(--border)',borderRadius:4,fontSize:16,textAlign:'center'}}
                    value={newAbs.icon} onChange={e=>setNewAbs(a=>({...a,icon:e.target.value}))}/></td>
                  <td><input className="form-input" value={newAbs.label} onChange={e=>setNewAbs(a=>({...a,label:e.target.value}))} placeholder="Bezeichnung..." style={{padding:'5px 8px'}}/></td>
                  <td><input type="color" value={newAbs.color.startsWith('#')?newAbs.color:'#1d4ed8'}
                    onChange={e=>setNewAbs(a=>({...a,color:e.target.value,bg:e.target.value+'33'}))}/></td>
                  <td>
                    <select className="form-select" value={newAbs.paid?'1':'0'} onChange={e=>setNewAbs(a=>({...a,paid:e.target.value==='1'}))} style={{padding:'4px 8px'}}>
                      <option value="1">Bezahlt</option><option value="0">Unbezahlt</option>
                    </select>
                  </td>
                  <td></td>
                  <td>
                    <button className="btn btn-primary btn-sm" onClick={()=>{
                      if(!newAbs.label.trim()) return;
                      setAbsenceTypes(ts=>[...ts,{...newAbs,id:'abs_'+Date.now(),active:true}]);
                      setNewAbs({id:'',label:'',icon:'📋',color:'#1d4ed8',bg:'rgba(29,78,216,.1)',paid:true,active:true});
                    }}>+ Typ anlegen</button>
                  </td>
                </tr>
              </tbody>
            </table></div>
        </div>
        )}

        {/* RAUMKOSTEN */}
        {activeSection==='raumkosten'&&(()=>{
          const rkData=getRkData(rkYear,rkMonth);
          const fixTotal=rkData.fix.reduce((s,f)=>s+(parseFloat(f.amount)||0),0);
          const varTotal=rkData.variable.reduce((s,v)=>s+(parseFloat(v.amount)||0),0);
          const grandTotal=fixTotal+varTotal;
          return(
            <div>
              {/* Month selector */}
              <div className="card" style={{marginBottom:12}}>
                <div className="card-header">
                  <span className="card-title">🏢 Raumkosten — Monatseingabe</span>
                  <div style={{display:'flex',gap:8,alignItems:'center',flexWrap:'wrap'}}>
                    <div style={{display:'flex',gap:4,alignItems:'center'}}>
                      {rkLocations.map(loc=>(
                        <button key={loc.id}
                          onClick={()=>setRkLocId(loc.id)}
                          style={{padding:'4px 10px',borderRadius:6,fontSize:12,fontWeight:700,cursor:'pointer',
                            fontFamily:'var(--font)',border:'1.5px solid '+(rkLocId===loc.id?'var(--blue)':'var(--border)'),
                            background:rkLocId===loc.id?'var(--blue-bg)':'transparent',
                            color:rkLocId===loc.id?'var(--blue)':'var(--muted)'}}>
                          {loc.name}
                        </button>
                      ))}
                      <button style={{padding:'4px 8px',borderRadius:6,fontSize:12,cursor:'pointer',
                        fontFamily:'var(--font)',border:'1px dashed var(--border)',background:'transparent',color:'var(--muted)'}}
                        onClick={()=>{const n=prompt('Name des Standorts:');if(n&&n.trim()){saveRkLocations([...rkLocations,{id:'rk_loc_'+Date.now(),name:n.trim()}]);}}}>
                        + Standort
                      </button>
                    </div>
                    <select className="form-select" style={{width:140}} value={rkMonth}
                      onChange={e=>setRkMonth(parseInt(e.target.value))}>
                      {['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'].map((m,i)=>(
                        <option key={i+1} value={i+1}>{m}</option>
                      ))}
                    </select>
                    <select className="form-select" style={{width:90}} value={rkYear}
                      onChange={e=>setRkYear(parseInt(e.target.value))}>
                      {[2024,2025,2026,2027].map(y=><option key={y} value={y}>{y}</option>)}
                    </select>
                    <div style={{fontWeight:800,fontSize:15,color:'var(--blue)',marginLeft:8}}>
                      Gesamt: {grandTotal.toFixed(2)} €
                    </div>
                  </div>
                </div>
              </div>

              {/* FIXKOSTEN */}
              <div className="card" style={{marginBottom:12}}>
                <div className="card-header">
                  <span className="card-title">📌 Fixkosten</span>
                  <div style={{display:'flex',gap:8,alignItems:'center'}}>
                    <span style={{fontSize:12,fontWeight:700,color:'var(--muted)'}}>
                      Σ {fixTotal.toFixed(2)} €
                    </span>
                    <button className="btn btn-sm btn-primary" onClick={()=>{
                      const newId='rk_fix_'+Date.now();
                      const newCfg={...rkCfg,fix:[...rkCfg.fix,{id:newId,label:'Neue Fixkosten',amount:0}]};
                      saveRkCfg(newCfg);
                    }}>+ Fixkosten</button>
                  </div>
                </div>
                <div>
                  {rkData.fix.map((item,i)=>(
                    <div key={item.id} style={{display:'grid',gridTemplateColumns:'1fr 190px 32px',
                      gap:8,padding:'10px 16px',borderBottom:'1px solid var(--border)',alignItems:'center'}}>
                      <input className="form-input" value={item.label}
                        placeholder="Bezeichnung"
                        onChange={e=>{
                          const newCfg={...rkCfg,fix:rkCfg.fix.map((f,j)=>j===i?{...f,label:e.target.value}:f)};
                          saveRkCfg(newCfg);
                          const upd={...rkData,fix:rkData.fix.map((f,j)=>j===i?{...f,label:e.target.value}:f)};
                          saveRkData(rkYear,rkMonth,upd);
                        }}/>
                      <div style={{display:'flex',alignItems:'center',gap:4}}>
                        <input type="text" inputMode="decimal" className="form-input" min="0" step="0.01"
                          value={item.amount}
                          placeholder={rkCfg.fix[i]?.amount||'0'}
                          style={{textAlign:'right',fontWeight:700,MozAppearance:'textfield',appearance:'none'}}
                          onChange={e=>{
                            const upd={...rkData,fix:rkData.fix.map((f,j)=>j===i?{...f,amount:e.target.value}:f)};
                            saveRkData(rkYear,rkMonth,upd);
                          }}/>
                        <span style={{fontSize:12,color:'var(--muted)',whiteSpace:'nowrap'}}>€</span>
                      </div>
                      <button className="btn btn-sm" style={{color:'var(--red)'}}
                        onClick={()=>{
                          const newCfg={...rkCfg,fix:rkCfg.fix.filter((_,j)=>j!==i)};
                          saveRkCfg(newCfg);
                        }}>×</button>
                    </div>
                  ))}
                </div>
              </div>

              {/* VARIABLE KOSTEN */}
              <div className="card">
                <div className="card-header">
                  <span className="card-title">📊 Variable Kosten (monatlich nach Verbrauch)</span>
                  <div style={{display:'flex',gap:8,alignItems:'center'}}>
                    <span style={{fontSize:12,fontWeight:700,color:'var(--muted)'}}>
                      Σ {varTotal.toFixed(2)} €
                    </span>
                    <button className="btn btn-sm btn-primary" onClick={()=>{
                      const newId='rk_var_'+Date.now();
                      const newCfg={...rkCfg,variable:[...rkCfg.variable,{id:newId,label:'Neue Variable Kosten',amount:0}]};
                      saveRkCfg(newCfg);
                    }}>+ Kosten</button>
                  </div>
                </div>
                <div>
                  {rkData.variable.map((item,i)=>(
                    <div key={item.id} style={{display:'grid',gridTemplateColumns:'1fr 190px 32px',
                      gap:8,padding:'10px 16px',borderBottom:'1px solid var(--border)',alignItems:'center'}}>
                      <input className="form-input" value={item.label}
                        placeholder="Bezeichnung z.B. Strom"
                        onChange={e=>{
                          const newCfg={...rkCfg,variable:rkCfg.variable.map((v,j)=>j===i?{...v,label:e.target.value}:v)};
                          saveRkCfg(newCfg);
                          const upd={...rkData,variable:rkData.variable.map((v,j)=>j===i?{...v,label:e.target.value}:v)};
                          saveRkData(rkYear,rkMonth,upd);
                        }}/>
                      <div style={{display:'flex',alignItems:'center',gap:4}}>
                        <input type="text" inputMode="decimal" className="form-input"
                          value={item.amount===''?'':item.amount}
                          placeholder={rkCfg.variable[i]?.amount||'Betrag'}
                          style={{textAlign:'right',fontWeight:700,MozAppearance:'textfield',appearance:'none',
                            border:(!item.amount&&item.amount!==0)?'2px solid var(--orange, #f59e0b)':'1.5px solid var(--border)'}}
                          onChange={e=>{
                            const upd={...rkData,variable:rkData.variable.map((v,j)=>j===i?{...v,amount:e.target.value}:v)};
                            saveRkData(rkYear,rkMonth,upd);
                          }}/>
                        <span style={{fontSize:12,color:'var(--muted)',whiteSpace:'nowrap'}}>€</span>
                      </div>
                      <button className="btn btn-sm" style={{color:'var(--red)'}}
                        onClick={()=>{
                          const newCfg={...rkCfg,variable:rkCfg.variable.filter((_,j)=>j!==i)};
                          saveRkCfg(newCfg);
                        }}>×</button>
                    </div>
                  ))}
                  {rkData.variable.some(v=>!v.amount&&v.amount!==0)&&(
                    <div style={{padding:'10px 16px',fontSize:12,color:'#92400e',
                      background:'#fffbeb',borderTop:'1px solid var(--border)'}}>
                      ⚠ Nicht alle variablen Kosten eingetragen. Bitte Beträge erfassen.
                    </div>
                  )}
                </div>
              </div>

              {/* OVERHEAD / NEUTRALE STELLEN */}
              <div className="card" style={{marginBottom:12}}>
                <div className="card-header">
                  <span className="card-title">👔 Overhead — Neutrale Stellen</span>
                  <div style={{display:'flex',gap:8,alignItems:'center'}}>
                    <span style={{fontSize:11,color:'var(--muted)'}}>
                      Kosten laufen auf die Fläche, nicht auf Projekte
                    </span>
                    <button className="btn btn-sm btn-primary" onClick={()=>{
                      const overhead=getRkOverhead(rkLocId);
                      const newRole={id:'oh_'+Date.now(),role:'',emp_id:'',custom_label:''};
                      saveRkOverhead(rkLocId,[...overhead,newRole]);
                      bumpOh(); // trigger re-render
                    }}>+ Position</button>
                  </div>
                </div>
                <div>
                  {(()=>{
                    const overhead=getRkOverhead(rkLocId);
                    const activeEmps=(employees||[]).filter(e=>e.status==='active'&&e.location===rkLocations.find(l=>l.id===rkLocId)?.name?.toLowerCase());
                    const allActiveEmps=(employees||[]).filter(e=>e.status==='active');
                    if(overhead.length===0) return(
                      <div style={{padding:'16px',textAlign:'center',color:'var(--muted)',fontSize:12}}>
                        Noch keine Overhead-Positionen. Mit "+ Position" anlegen.
                        <br/><span style={{fontSize:11}}>Beispiel: Managing Director, COO, Office Manager</span>
                      </div>
                    );
                    let ohTotal=0;
                    const rows=overhead.map((oh,i)=>{
                      const emp=allActiveEmps.find(e=>e.id===oh.emp_id);
                      // Monthly cost from employee: hourly_rate * work_hours * ~22 days
                      const empCost=emp?Math.round(parseFloat(emp.hourly_rate||0)*parseFloat(emp.work_hours||8)*22):0;
                      ohTotal+=empCost;
                      return(
                        <div key={oh.id} style={{display:'grid',gridTemplateColumns:'180px 1fr 130px auto',
                          gap:8,padding:'10px 16px',borderBottom:'1px solid var(--border)',alignItems:'center'}}>
                          {/* Role */}
                          <div>
                            <select className="form-select" style={{fontSize:12}} value={oh.role||''}
                              onChange={e=>{
                                const upd=overhead.map((x,j)=>j===i?{...x,role:e.target.value,custom_label:''}:x);
                                saveRkOverhead(rkLocId,upd);bumpOh();
                              }}>
                              <option value="">— Rolle wählen —</option>
                              {OVERHEAD_ROLES.map(r=><option key={r.key} value={r.key}>{r.label}</option>)}
                              <option value="custom">Eigene Rolle...</option>
                            </select>
                            {oh.role==='custom'&&(
                              <input className="form-input" style={{marginTop:4,fontSize:12}}
                                value={oh.custom_label||''} placeholder="Bezeichnung eingeben"
                                onChange={e=>{
                                  const upd=overhead.map((x,j)=>j===i?{...x,custom_label:e.target.value}:x);
                                  saveRkOverhead(rkLocId,upd);bumpOh();
                                }}/>
                            )}
                          </div>
                          {/* Employee */}
                          <div>
                            <select className="form-select" style={{fontSize:12}} value={oh.emp_id||''}
                              onChange={e=>{
                                const upd=overhead.map((x,j)=>j===i?{...x,emp_id:e.target.value}:x);
                                saveRkOverhead(rkLocId,upd);bumpOh();
                              }}>
                              <option value="">— Mitarbeiter wählen —</option>
                              {allActiveEmps.map(e=>(
                                <option key={e.id} value={e.id}>
                                  {e.first_name} {e.last_name} ({e.staff_number||'—'})
                                </option>
                              ))}
                            </select>
                            {emp&&(
                              <div style={{fontSize:10,color:'var(--muted)',marginTop:2}}>
                                {emp.position||'—'} · {emp.hourly_rate||'?'} {emp.bank_currency||'ALL'}/h · {emp.work_hours||8}h/Tag
                              </div>
                            )}
                          </div>
                          {/* Calculated cost */}
                          <div style={{textAlign:'right',fontWeight:800,
                            fontSize:13,color:empCost>0?'var(--fg)':'var(--dim)'}}>
                            {empCost>0?(
                              <>
                                <div>{empCost.toLocaleString('de-DE')} {emp?.bank_currency||'ALL'}</div>
                                <div style={{fontSize:10,fontWeight:400,color:'var(--muted)'}}>/{' '}Monat</div>
                              </>
                            ):'— Kein MA'}
                          </div>
                          <button className="btn btn-sm" style={{color:'var(--red)'}}
                            onClick={()=>{
                              saveRkOverhead(rkLocId,overhead.filter((_,j)=>j!==i));
                              bumpOh();
                            }}>×</button>
                        </div>
                      );
                    });
                    return(
                      <>
                        {rows}
                        {ohTotal>0&&(
                          <div style={{padding:'10px 16px',display:'flex',justifyContent:'flex-end',
                            gap:8,borderTop:'2px solid var(--border)',background:'var(--surface-2)'}}>
                            <span style={{fontSize:12,color:'var(--muted)'}}>Σ Overhead diese Fläche/Monat:</span>
                            <span style={{fontWeight:800,fontSize:14,color:'var(--fg)'}}>{ohTotal.toLocaleString('de-DE')} ALL</span>
                          </div>
                        )}
                      </>
                    );
                  })()}
                </div>
              </div>

              {/* Speichern */}
              <div style={{marginTop:12,display:'flex',justifyContent:'flex-end',gap:8}}>
                <div style={{fontSize:12,color:'var(--muted)',alignSelf:'center'}}>
                  Fixkosten sind vorausgefüllt und können monatlich angepasst werden.
                </div>
                <button className="btn btn-primary" onClick={()=>{
                  const upd={fix:rkData.fix,variable:rkData.variable};
                  saveRkData(rkYear,rkMonth,upd);
                  alert('Raumkosten ' + ['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'][rkMonth-1] + ' ' + rkYear + ' gespeichert!');
                }}>💾 Speichern</button>
              </div>
            </div>
          );
        })()}

        {/* SHIFT CFG */}
        {activeSection==='shift_cfg'&&(()=>{
          const allEntries=Object.entries(shiftCfg);
          const calcH=v=>{
            const m=v.match(/(\d{1,2}):(\d{2})-(\d{1,2}):(\d{2})/);
            if(!m)return{hours:0,net:0};
            const s=parseInt(m[1])*60+parseInt(m[2]),e=parseInt(m[3])*60+parseInt(m[4]),h=(e-s)/60;
            return{hours:Math.round(h*10)/10,net:Math.round((h-.5)*10)/10};
          };
          return(
            <div>
              <div className="card" style={{marginBottom:12}}>
                <div className="card-header">
                  <span className="card-title">Schichten pro Projekt und Skill</span>
                  <button className="btn btn-primary btn-sm" onClick={()=>{
                    const proj=window.prompt('Projekt-ID (z.B. proj_hc):');
                    if(!proj)return;
                    const skill=window.prompt('Skill-Key (z.B. sales) oder leer:');
                    const key=proj+'_'+(skill||'all');
                    if(shiftCfg[key]){alert('Existiert bereits.');return;}
                    saveShiftCfg({...shiftCfg,[key]:[]});
                  }}>+ Projekt / Skill</button>
                </div>
                <div style={{padding:'8px 16px 12px',fontSize:12,color:'var(--muted)'}}>Format HH:MM-HH:MM. Nettostunden = brutto minus 30 Min Pause.</div>
              </div>
              {allEntries.map(([key,shifts])=>{
                const lu=key.lastIndexOf('_');
                const projId=key.substring(0,lu);
                const skillKey=key.substring(lu+1);
                const proj=(projects||[]).find(p=>p.id===projId);
                const projName=proj?proj.name:projId;
                const skillLabel=skillKey==='all'?'Alle Skills':skillKey;
                return(
                  <div key={key} className="card" style={{marginBottom:10}}>
                    <div className="card-header">
                      <span className="card-title">{projName} <span style={{marginLeft:8,fontSize:11,padding:'2px 8px',borderRadius:4,background:'var(--blue-bg)',color:'var(--blue)',fontWeight:700}}>{skillLabel}</span></span>
                      <div style={{display:'flex',gap:6}}>
                        <button className="btn btn-sm btn-primary" onClick={()=>saveShiftCfg({...shiftCfg,[key]:[...shifts,{id:'sh_'+Date.now(),label:'Neue Schicht',value:'08:00-16:30',hours:8,net:7.5}]})}>+ Schicht</button>
                        <button className="btn btn-sm" style={{color:'var(--red)'}} onClick={()=>{if(!window.confirm('Loeschen?'))return;const u={...shiftCfg};delete u[key];saveShiftCfg(u);}}>x Eintrag</button>
                      </div>
                    </div>
                    <div>
                      {shifts.length===0&&<div style={{padding:'12px 16px',fontSize:12,color:'var(--muted)'}}>Noch keine Schichten.</div>}
                      {shifts.map((sh,i)=>(
                        <div key={sh.id||i} style={{display:'grid',gridTemplateColumns:'180px 160px 70px 70px auto',gap:8,padding:'10px 16px',borderBottom:'1px solid var(--border)',alignItems:'center'}}>
                          <input className="form-input" value={sh.label} placeholder="Bezeichnung" onChange={e=>saveShiftCfg({...shiftCfg,[key]:shifts.map((s,j)=>j===i?{...s,label:e.target.value}:s)})}/>
                          <input className="form-input" value={sh.value} placeholder="08:00-16:30" style={{fontWeight:700,fontFamily:'monospace'}} onChange={e=>{const {hours,net}=calcH(e.target.value);saveShiftCfg({...shiftCfg,[key]:shifts.map((s,j)=>j===i?{...s,value:e.target.value,hours,net}:s)});}}/>
                          <div style={{textAlign:'center'}}><div style={{fontWeight:700,fontSize:13}}>{sh.hours}h</div><div style={{fontSize:10,color:'var(--muted)'}}>brutto</div></div>
                          <div style={{textAlign:'center'}}><div style={{fontWeight:700,fontSize:13,color:'var(--blue)'}}>{sh.net}h</div><div style={{fontSize:10,color:'var(--muted)'}}>netto</div></div>
                          <button className="btn btn-sm" style={{color:'var(--red)'}} onClick={()=>saveShiftCfg({...shiftCfg,[key]:shifts.filter((_,j)=>j!==i)})}>x</button>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          );
        })()}

        {/* POSITIONS */}
        {activeSection==='positions'&&(
          <div className="card">
            <div className="card-header">
              <span className="card-title">💼 Positionen & Rollen</span>
              <span style={{fontSize:11,color:'var(--muted)'}}>Werden bei Mitarbeiteranlage zur Auswahl angeboten</span>
            </div>
            <div style={{padding:'12px 14px',borderBottom:'1px solid var(--border)',display:'flex',gap:8}}>
