InvoiceView:
function InvoiceView(){
  const COMPANIES = [
    {id:'parklane1', name:'Parklane GmbH'},
    {id:'parklane2', name:'Parklane Zwei GmbH'},
    {id:'parklane3', name:'Parklane Drei GmbH'},
    {id:'parklane4', name:'Parklane Vier GmbH'},
  ];

  const [company, setCompany] = useState(()=>localStorage.getItem('jsr_bk_company')||'parklane1');
  const [month, setMonth] = useState(()=>{
    const d=new Date(); return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0');
  });
  const [apiKey, setApiKey] = useState(()=>localStorage.getItem('jsr_anthropic_key')||'');
  const [showKeyInput, setShowKeyInput] = useState(false);
  const [processing, setProcessing] = useState(false);
  const [processLog, setProcessLog] = useState([]);
  const [activeUpload, setActiveUpload] = useState(null); // 'bank' | 'invoices'

  const [bankTx, setBankTx] = useState(()=>{
    const co=localStorage.getItem('jsr_bk_company')||'parklane1';
    try{return JSON.parse(localStorage.getItem('jsr_bank_tx_'+co+'_v1')||'{}');}catch(e){return {};}
  });
  const [invoices, setInvoices] = useState(()=>{
    const co=localStorage.getItem('jsr_bk_company')||'parklane1';
    try{return JSON.parse(localStorage.getItem('jsr_invoices_'+co+'_v1')||'{}');}catch(e){return {};}
  });
  const [showSidebar, setShowSidebar] = useState(true);

  function changeCompany(newCo){
    localStorage.setItem('jsr_bk_company', newCo);
    setCompany(newCo);
    // Reload data for new company
    try{setBankTx(JSON.parse(localStorage.getItem('jsr_bank_tx_'+newCo+'_v1')||'{}'));}catch(e){setBankTx({});}
    try{setInvoices(JSON.parse(localStorage.getItem('jsr_invoices_'+newCo+'_v1')||'{}'));}catch(e){setInvoices({});}
  }
  const [showDatevPreview, setShowDatevPreview] = useState(false);

  // Global running invoice counter across ALL months
  function getNextGlobalNumber(){
    try{
      const all = JSON.parse(localStorage.getItem('jsr_invoices_'+company+'_v1')||'{}');
      let max = 0;
      Object.values(all).forEach(monthInvs=>{
        (monthInvs||[]).forEach(inv=>{
          if(inv.global_nr && inv.global_nr>max) max=inv.global_nr;
        });
      });
      return max+1;
    }catch(e){return 1;}
  }

  // Generate document name: JSR-YYYY-NNN_FirmaKurz
  function genDocName(inv, globalNr){
    const firma = (inv.firma||'Unbekannt').replace(/[^a-zA-Z0-9]/g,'').slice(0,12);
    const year = (inv.rechnungsdatum||month).slice(0,4);
    return 'JSR-'+year+'-'+String(globalNr).padStart(4,'0')+'_'+firma;
  }

  useEffect(()=>{localStorage.setItem('jsr_bank_tx_'+company+'_v1',JSON.stringify(bankTx));},[bankTx]);
  useEffect(()=>{localStorage.setItem('jsr_invoices_'+company+'_v1',JSON.stringify(invoices));},[invoices]);

  // All months from Jan 2025 up to current month + 1
  const months = (()=>{
    const list=[];
    const now=new Date();
    const start=new Date(2025,0,1);
    const end=new Date(now.getFullYear(),now.getMonth()+1,1);
    let cur=new Date(start);
    while(cur<=end){
      list.push(cur.getFullYear()+'-'+String(cur.getMonth()+1).padStart(2,'0'));
      cur.setMonth(cur.getMonth()+1);
    }
    return list.reverse(); // newest first
  })();
  function fmtMonth(m){
    const [y,mo]=m.split('-');
    return new Date(y,mo-1,1).toLocaleDateString('de-DE',{month:'long',year:'numeric'});
  }
  function eur(v){return Number(v||0).toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2})+' €';}

  const monthTx = bankTx[month]||[];
  const monthInv = invoices[month]||[];

  // ── BANK CSV PARSER ──────────────────────────────────────────────
  function parseBankCSV(text){
    const lines = text.replace(/\r/g,'').split('\n').filter(l=>l.trim());
    const sep = lines[0].includes(';')?';':',';
    const header = lines[0].split(sep).map(h=>h.replace(/"/g,'').toLowerCase().trim());
    const rows = [];
    for(let i=1;i<lines.length;i++){
      const vals = lines[i].split(sep).map(v=>v.replace(/^"|"$/g,'').trim());
      const row = {};
      header.forEach((h,j)=>{row[h]=vals[j]||'';});
      const date = row['buchungstag']||row['date']||row['datum']||row['valuta']||'';
      const desc = row['verwendungszweck']||row['description']||row['buchungstext']||row['text']||'';
      const amount = parseFloat((row['betrag']||row['amount']||row['umsatz']||'0').replace(',','.').replace(/[^0-9.-]/g,''))||0;
      const creditor = row['beguenstigter/zahlungspflichtiger']||row['empfaenger']||row['name']||row['creditor']||'';
      if((date||desc)&&amount!==0){
        const salaryKw=['gehalt','lohn','salary','wage','entgelt','verg\u00fctung','sozialversicherung','lohnsteuer'];
        const isSalary=salaryKw.some(k=>(desc+' '+creditor).toLowerCase().includes(k));
        rows.push({id:'tx_'+Date.now()+'_'+i, date, desc, amount, creditor,
          type:amount<0?'debit':'credit',
          category:isSalary?'Lohn/Gehalt':'',
          matched_invoice:isSalary?'SALARY':null,
          status:isSalary?'salary':'open'});
      }
    }
    return rows;
  }

  function parseDate(dateStr){
    if(!dateStr) return null;
    const d1 = dateStr.match(/^(\d{1,2})\.(\d{1,2})\.(\d{2,4})$/);
    if(d1){const year=d1[3].length===2?'20'+d1[3]:d1[3];return year+'-'+d1[2].padStart(2,'0');}
    const d2 = dateStr.match(/^(\d{4})-(\d{2})-\d{2}$/);
    if(d2) return d2[1]+'-'+d2[2];
    const d3 = dateStr.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
    if(d3) return d3[3]+'-'+d3[2].padStart(2,'0');
    return null;
  }

  function handleBankUpload(e){
    const file = e.target.files[0];
    if(!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
      try{
        const text = ev.target.result.replace(/\uFEFF/,'');
        const rows = parseBankCSV(text);

        // Group by actual transaction month from date field
        const byMonth = {};
        rows.forEach(tx=>{
          const txMonth = parseDate(tx.date)||month;
          if(!byMonth[txMonth]) byMonth[txMonth]=[];
          byMonth[txMonth].push(tx);
        });

        const monthsSeen = Object.keys(byMonth).sort();
        let totalMatched = 0;
        const newBankTx = JSON.parse(JSON.stringify(bankTx));
        const newInvoices = JSON.parse(JSON.stringify(invoices));

        monthsSeen.forEach(txMonth=>{
          // Merge with existing, deduplicate by id
          const existing = newBankTx[txMonth]||[];
          const existingIds = new Set(existing.map(t=>t.id));
          const merged = [...existing, ...byMonth[txMonth].filter(t=>!existingIds.has(t.id))];
          newBankTx[txMonth] = merged;

          // Auto-match invoices for this month
          const invList = newInvoices[txMonth]||[];
          invList.forEach(inv=>{
            if(inv.status==='matched') return;
            const amount = Math.abs(inv.bruttobetrag||0);
            const tx = merged.find(t=>
              t.status==='open' &&
              Math.abs(Math.abs(t.amount)-amount)<0.02 &&
              (inv.firma&&(
                t.creditor.toLowerCase().includes((inv.firma||'').toLowerCase().slice(0,5))||
                t.desc.toLowerCase().includes((inv.firma||'').toLowerCase().slice(0,5))||
                (inv.zahlungsreferenz&&t.desc.toLowerCase().includes((inv.zahlungsreferenz||'').toLowerCase().slice(0,8)))
              ))
            );
            if(tx){
              const existing_matched = invList.filter(i=>i.status==='matched').length;
              const datevNr='RE-'+txMonth.replace('-','')+'-'+String(existing_matched+1).padStart(3,'0');
              inv.status='matched'; inv.matched_tx_id=tx.id; inv.datev_number=datevNr;
              tx.status='matched'; tx.matched_invoice=inv.id;
              totalMatched++;
            }
          });
          newInvoices[txMonth] = invList;
        });

        setBankTx(newBankTx);
        setInvoices(newInvoices);

        // Switch to month with most transactions
        const mainMonth = monthsSeen.reduce((a,b)=>(byMonth[a]||[]).length>=(byMonth[b]||[]).length?a:b, monthsSeen[0]);
        setMonth(mainMonth);

        const log = [
          '✓ '+rows.length+' Buchungen importiert',
          '✓ Monate: '+monthsSeen.map(m=>{
            const [y,mo]=m.split('-');
            return new Date(y,mo-1,1).toLocaleDateString('de-DE',{month:'short',year:'numeric'})+' ('+byMonth[m].length+')';
          }).join(', '),
        ];
        if(totalMatched>0) log.push('✓ Auto-Match: '+totalMatched+' Rechnungen zugeordnet');
        setProcessLog(log);
        e.target.value='';
      }catch(err){setProcessLog(['\u2717 Fehler: '+err.message]);}
    };
    reader.readAsText(file,'UTF-8');
  }

  // ── KI INVOICE PARSING ────────────────────────────────────────────
  async function parseInvoiceFile(file){
    if(!apiKey) throw new Error('Kein API-Key — bitte oben eintragen.');
    const isImage = file.type.startsWith('image/');
    const isPDF = file.type==='application/pdf';
    if(!isImage&&!isPDF) return null;
    const base64 = await new Promise((res,rej)=>{
      const r=new FileReader();
      r.onload=()=>res(r.result.split(',')[1]);
      r.onerror=rej;
      r.readAsDataURL(file);
    });
    const response = await fetch('https://api.anthropic.com/v1/messages',{
      method:'POST',
      headers:{
        'Content-Type':'application/json',
        'x-api-key':apiKey,
        'anthropic-version':'2023-06-01',
        'anthropic-dangerous-direct-browser-access':'true'
      },
      body:JSON.stringify({
        model:'claude-sonnet-4-20250514',
        max_tokens:1000,
        messages:[{role:'user',content:[
          {type:isPDF?'document':'image',source:{type:'base64',media_type:file.type,data:base64}},
          {type:'text',text:`Analysiere diese Rechnung und extrahiere als JSON (nur JSON, kein Text darum):
{
  "firma": "Name des Rechnungsstellers",
  "rechnungsnummer": "Rechnungsnummer",
  "rechnungsdatum": "YYYY-MM-DD",
  "faelligkeitsdatum": "YYYY-MM-DD oder null",
  "nettobetrag": 0.00,
  "umsatzsteuer_prozent": 19,
  "umsatzsteuer_betrag": 0.00,
  "bruttobetrag": 0.00,
  "waehrung": "EUR",
  "leistungsbeschreibung": "Was wurde gekauft",
  "iban": "IBAN oder null",
  "zahlungsreferenz": "Verwendungszweck oder null",
  "kategorie": "IT/Miete/Personal/Marketing/Versicherung/Medien/Sonstiges"
}`}
        ]}]
      })
    });
    const data = await response.json();
    const text = data.content?.map(c=>c.text||'').join('');
    return JSON.parse(text.replace(/```json|```/g,'').trim());
  }

  async function handleInvoiceUpload(e){
    const files = Array.from(e.target.files);
    if(!files.length) return;
    setProcessing(true);
    setProcessLog([]);
    const results = [];
    const txList = [...(bankTx[month]||[])];
    let autoMatched = 0;

    for(let i=0;i<files.length;i++){
      const file = files[i];
      setProcessLog(l=>[...l,'⏳ Lese: '+file.name+' ('+i+'1/'+files.length+')...']);
      try{
        const parsed = await parseInvoiceFile(file);
        if(!parsed) continue;

        // Try auto-match against bank transactions
        const amount = Math.abs(parsed.bruttobetrag||0);
        const tx = txList.find(t=>
          t.status==='open' &&
          Math.abs(Math.abs(t.amount)-amount)<0.02 &&
          (parsed.firma&&(
            t.creditor.toLowerCase().includes((parsed.firma||'').toLowerCase().slice(0,5))||
            t.desc.toLowerCase().includes((parsed.firma||'').toLowerCase().slice(0,5))||
            (parsed.zahlungsreferenz&&t.desc.toLowerCase().includes((parsed.zahlungsreferenz||'').toLowerCase().slice(0,8)))
          ))
        );

        const existingMatched = results.filter(r=>r.status==='matched').length +
          (invoices[month]||[]).filter(r=>r.status==='matched').length;
        const datevNr = tx ? 'RE-'+month.replace('-','')+'-'+String(existingMatched+autoMatched+1).padStart(3,'0') : null;

        if(tx){
          tx.status='matched';
          autoMatched++;
        }

        const globalNr = getNextGlobalNumber() + results.length;
        const docName = genDocName(parsed, globalNr);
        const inv = {
          id:'inv_'+Date.now()+'_'+i,
          filename:file.name,
          doc_name: docName,
          global_nr: globalNr,
          month,
          status: tx?'matched':'unmatched',
          matched_tx_id: tx?tx.id:null,
          datev_number: datevNr,
          ...parsed,
          uploaded_at:new Date().toISOString(),
        };
        results.push(inv);
        setProcessLog(l=>[...l,'✓ '+parsed.firma+' | '+eur(parsed.bruttobetrag)+(tx?' → ✅ Zugeordnet':' → ○ Kein Match')]);
      }catch(err){
        setProcessLog(l=>[...l,'✗ '+file.name+': '+err.message]);
      }
    }

    setBankTx(prev=>({...prev,[month]:txList}));
    setInvoices(prev=>({...prev,[month]:[...(prev[month]||[]),...results]}));
    setProcessing(false);
    e.target.value='';
  }

  // ── MANUAL ACTIONS ────────────────────────────────────────────────
  function toggleStatus(invId, newStatus){
    setInvoices(prev=>({...prev,[month]:(prev[month]||[]).map(i=>{
      if(i.id!==invId) return i;
      if(newStatus==='matched'){
        // find a candidate tx
        const txList = bankTx[month]||[];
        const amount = Math.abs(i.bruttobetrag||0);
        const tx = txList.find(t=>t.status==='open'&&Math.abs(Math.abs(t.amount)-amount)<1);
        if(tx){
          setBankTx(prev=>({...prev,[month]:(prev[month]||[]).map(t=>t.id===tx.id?{...t,status:'matched',matched_invoice:invId}:t)}));
          const n = (prev[month]||[]).filter(x=>x.status==='matched').length+1;
          return {...i,status:'matched',matched_tx_id:tx.id,datev_number:'RE-'+month.replace('-','')+'-'+String(n).padStart(3,'0')};
        }
      }
      return {...i,status:newStatus,matched_tx_id:null,datev_number:null};
    })}));
  }

  function deleteInvoice(id){
    if(!window.confirm('Rechnung löschen?')) return;
    setInvoices(prev=>({...prev,[month]:(prev[month]||[]).filter(i=>i.id!==id)}));
  }

  // ── DATEV EXPORT ─────────────────────────────────────────────────
  function processFolderFiles(files, companyName){
    setProcessing(true);
    setProcessLog([]);
    let idx = 0;
    const newBelegeMap = JSON.parse(JSON.stringify(invoices));

    function next(){
      if(idx>=files.length){
        // Auto-match for all affected months
        const affected=[...new Set(Object.values(newBelegeMap).flat().map(b=>b.month).filter(Boolean))];
        const nb={...newBelegeMap};
        // run matching inline
        const allBankTx={...bankTx};
        const allCcTx={...ccTx};
        Object.keys(nb).forEach(m=>{
          const mb=(nb[m]||[]).slice();
          const allT=(allBankTx[m]||[]).concat(allCcTx[m]||[]);
          const used={};
          mb.forEach(b=>{if(b.status==='matched'||b.status==='manual')used[b.tx_id]=true;});
          mb.forEach((b,i)=>{
            if(b.status==='matched'||b.status==='manual') return;
            const amt=Math.abs(b.bruttobetrag||0);
            if(!amt){mb[i]={...b,status:'unmatched',candidates:[]};return;}
            const cands=[];
            allT.forEach(tx=>{
              if(used[tx.id]) return;
              const ta=Math.abs(tx.amount||0),diff=Math.abs(ta-amt);
              const as=diff<0.05?1:diff<1?0.75:diff<5?0.3:0;
              if(!as) return;
              const a2=(b.firma||'').toLowerCase().replace(/[^a-z0-9]/g,'');
              const b2=(tx.creditor||tx.desc||'').toLowerCase().replace(/[^a-z0-9]/g,'');
              const ns=(a2&&b2&&(a2===b2||b2.includes(a2.slice(0,4))||a2.includes(b2.slice(0,4))))?0.7:0;
              const sc=as*0.7+ns*0.3;
              if(sc>0.35) cands.push({tx,score:sc,as});
            });
            cands.sort((a,b)=>b.score-a.score);
            if(!cands.length){mb[i]={...b,status:'unmatched',candidates:[]};}
            else if(cands[0].score>=0.85&&cands[0].as===1){used[cands[0].tx.id]=true;mb[i]={...b,status:'matched',matched_tx_id:cands[0].tx.id,candidates:[]};}
            else{mb[i]={...b,status:'uncertain',candidates:cands.slice(0,3)};}
          });
          nb[m]=mb;
        });
        setInvoices(nb);
        setProcessing(false);
        return;
      }
      const f=files[idx]; idx++;
      setProcessLog(l=>[...l,'Lese: '+f.name+' ('+idx+'/'+files.length+')...']);

      // Fetch file from local server
      fetch('http://localhost:4001/file?path='+encodeURIComponent(f.path))
        .then(r=>r.json())
        .then(fd=>{
          if(!fd.base64) throw new Error('Datei nicht lesbar');
          return new Promise((res,rej)=>{
            if(fd.mime.startsWith('image/')){
              const img=new Image();
              img.onload=()=>{
                const max=800;let w=img.width,h=img.height;
                if(w>max||h>max){const r=Math.min(max/w,max/h);w=Math.round(w*r);h=Math.round(h*r);}
                const c=document.createElement('canvas');c.width=w;c.height=h;
                c.getContext('2d').drawImage(img,0,0,w,h);
                res({b64:c.toDataURL('image/jpeg',0.82).split(',')[1],mime:'image/jpeg',fd});
              };
              img.onerror=()=>res({b64:fd.base64,mime:fd.mime,fd});
              img.src='data:'+fd.mime+';base64,'+fd.base64;
            } else {
              res({b64:fd.base64,mime:fd.mime,fd});
            }
          });
        })
        .then(({b64,mime,fd})=>{
          return fetch('https://api.anthropic.com/v1/messages',{
            method:'POST',
            headers:{'Content-Type':'application/json','x-api-key':apiKey,'anthropic-version':'2023-06-01','anthropic-dangerous-direct-browser-access':'true'},
            body:JSON.stringify({model:'claude-sonnet-4-20250514',max_tokens:600,messages:[{role:'user',content:[
              {type:mime.startsWith('image')?'image':'document',source:{type:'base64',media_type:mime,data:b64}},
              {type:'text',text:'Rechnung/Beleg als JSON (NUR JSON): {"firma":"","rechnungsnummer":"","rechnungsdatum":"YYYY-MM-DD","faelligkeitsdatum":null,"nettobetrag":0.00,"umsatzsteuer_prozent":0,"umsatzsteuer_betrag":0.00,"bruttobetrag":0.00,"waehrung":"EUR","leistungsbeschreibung":"","iban":null,"zahlungsreferenz":null,"kategorie":"IT/Miete/Personal/Marketing/Versicherung/Medien/Sonstiges"}'}
            ]}]})
          }).then(r=>r.json()).then(data=>{
            const txt=data.content?.map(c=>c.text||'').join('');
            const parsed=JSON.parse(txt.replace(/```json|```/g,'').trim());
            // Determine month from date
            const dateStr=parsed.rechnungsdatum||'';
            let bMonth=month;
            if(dateStr){const p=dateStr.match(/(\d{4})-(\d{2})/);if(p) bMonth=p[1]+'-'+p[2];}
            // Global number
            const allNums=Object.values(newBelegeMap).flat().map(x=>x.global_nr||0);
            const globalNr=(allNums.length?Math.max(...allNums):0)+1+idx;
            const firma=(parsed.firma||'Unbekannt').replace(/[^a-zA-Z0-9]/g,'').slice(0,12);
            const year=(parsed.rechnungsdatum||bMonth).slice(0,4);
            const docName='JSR-'+year+'-'+String(globalNr).padStart(4,'0')+'_'+firma;
            const inv2={
              id:'inv_'+Date.now()+'_'+idx,
              filename:f.name,doc_name:docName,global_nr:globalNr,
              month:bMonth,status:'unmatched',matched_tx_id:null,datev_number:null,
              ...parsed,uploaded_at:new Date().toISOString(),_server:f,
            };
            if(!newBelegeMap[bMonth]) newBelegeMap[bMonth]=[];
            newBelegeMap[bMonth].push(inv2);
            // Save back to server
            fetch('http://localhost:4001/save',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({company:companyName,month:bMonth,doc_name:docName,source_path:f.path,source_hash:f.hash,source_key:f.key})}).catch(()=>{});
            setProcessLog(l=>[...l,'✓ '+parsed.firma+' | '+eur(parsed.bruttobetrag)+' → '+docName]);
          });
        })
        .catch(err=>setProcessLog(l=>[...l,'✗ '+f.name+': '+err.message]))
        .finally(()=>next());
    }
    next();
  }

  function buildDatevRows(matchedInv){
    return matchedInv.map(inv=>{
      const tx=(bankTx[month]||[]).find(t=>t.id===inv.matched_tx_id);
      const date=(inv.rechnungsdatum||tx?.date||'').replace(/-/g,'').slice(4);
      const amount=Math.abs(inv.bruttobetrag||0);
      const gegenkonto='4'+(
        inv.kategorie==='IT'?'900':
        inv.kategorie==='Miete'?'200':
        inv.kategorie==='Personal'?'120':
        inv.kategorie==='Marketing'?'600':
        inv.kategorie==='Versicherung'?'360':
        inv.kategorie==='Medien'?'680':'980');
      return {
        datev_number: inv.datev_number||'',
        firma: inv.firma||'',
        rechnungsnummer: inv.rechnungsnummer||'',
        datum: inv.rechnungsdatum||tx?.date||'',
        netto: Math.abs(inv.nettobetrag||0),
        ust_pct: inv.umsatzsteuer_prozent||0,
        ust_betrag: Math.abs(inv.umsatzsteuer_betrag||0),
        brutto: amount,
        kategorie: inv.kategorie||'Sonstiges',
        konto: '1600',
        gegenkonto,
        buchungstext: (inv.firma||'').slice(0,30)+' '+(inv.leistungsbeschreibung||'').slice(0,20),
        datev_date: date,
        amount_str: amount.toFixed(2).replace('.',','),
      };
    });
  }

