AudioRecorder:
function AudioRecorder({onRecorded, maxSeconds}){
  const MAX = maxSeconds||30;
  const [state, setState] = useState('idle'); // idle | recording | done
  const [secs, setSecs] = useState(0);
  const mrRef = useRef(null);
  const timerRef = useRef(null);

  function start(){
    if(!navigator.mediaDevices||!navigator.mediaDevices.getUserMedia){
      alert('Mikrofon nicht verfügbar — bitte Datei hochladen.');return;
    }
    navigator.mediaDevices.getUserMedia({audio:true}).then(stream=>{
      const mime=MediaRecorder.isTypeSupported('audio/webm')?'audio/webm':
                 MediaRecorder.isTypeSupported('audio/mp4')?'audio/mp4':'audio/ogg';
      let mr;
      try{mr=new MediaRecorder(stream,{mimeType:mime});}catch(e){mr=new MediaRecorder(stream);}
      const chunks=[];
      mr.ondataavailable=e=>e.data&&e.data.size>0&&chunks.push(e.data);
      mr.onstop=()=>{
        clearInterval(timerRef.current);
        const blob=new Blob(chunks,{type:mime});
        const reader=new FileReader();
        reader.onload=ev=>onRecorded(ev.target.result);
        reader.readAsDataURL(blob);
        stream.getTracks().forEach(t=>t.stop());
        setState('done');setSecs(0);
      };
      mrRef.current=mr;
      mr.start(100);
      setState('recording');setSecs(0);
      timerRef.current=setInterval(()=>{
        setSecs(s=>{
          if(s+1>=MAX){mr.stop();return MAX;}
          return s+1;
        });
      },1000);
    }).catch(err=>{
      const msg=err.name==='NotAllowedError'
        ?'Mikrofon-Zugriff verweigert.\n\nBitte in den Browser-Einstellungen das Mikrofon für diese Seite erlauben, oder eine Audiodatei hochladen.'
        :'Kein Mikrofon gefunden. Bitte Audiodatei hochladen.';
      alert(msg);
    });
  }

  function stop(){
    clearInterval(timerRef.current);
    if(mrRef.current&&mrRef.current.state!=='inactive') mrRef.current.stop();
  }

  const pct=Math.round(secs/MAX*100);
  const overTime=pct>80;

  return(
    <div>
      {state==='recording'&&(
        <div style={{marginBottom:10}}>
          <div style={{display:'flex',justifyContent:'space-between',fontSize:11,color:'var(--muted)',marginBottom:4}}>
            <span style={{color:'var(--red)',fontWeight:600}}>⏺ Aufnahme läuft…</span>
            <span style={{fontWeight:700,color:overTime?'var(--amber)':'var(--muted)'}}>{secs}s / {MAX}s</span>
          </div>
          <div style={{height:5,background:'var(--border)',borderRadius:3,overflow:'hidden'}}>
            <div style={{height:5,borderRadius:3,width:pct+'%',
              background:overTime?'var(--amber)':'var(--red)',transition:'width .5s'}}/>
          </div>
        </div>
      )}
      <div style={{display:'flex',gap:8,flexWrap:'wrap'}}>
        {state!=='recording'?(
          <button type="button" className="btn btn-sm"
            onClick={start}
            style={{background:'var(--blue)',color:'white',border:'none',padding:'7px 14px',fontSize:12}}>
            🎙 {state==='done'?'Neu aufnehmen':'Jetzt aufnehmen'}
          </button>
        ):(
          <button type="button" className="btn btn-sm"
            onClick={stop}
            style={{background:'var(--red)',color:'white',border:'none',padding:'7px 14px',fontSize:12}}>
            ⏹ Stopp ({secs}s)
          </button>
        )}
        <label className="btn btn-sm" style={{cursor:'pointer',padding:'7px 14px',fontSize:12}}>
          📎 Datei hochladen
          <input type="file" accept="audio/*,.mp3,.wav,.m4a,.aac,.ogg,.webm" style={{display:'none'}}
            onChange={e=>{
              const file=e.target.files[0];if(!file)return;
              const reader=new FileReader();
              reader.onload=ev=>{onRecorded(ev.target.result);setState('done');};
              reader.readAsDataURL(file);
            }}/>
        </label>
      </div>
    </div>
  );
}

