function SpacesView({employees, projects, locations}){
  // ── STATE ──────────────────────────────────────────────────────────────
  const [spaces, setSpaces] = useState(()=>{try{return JSON.parse(localStorage.getItem('jsr_spaces_v1')||'[]');}catch(e){return [];}});
  const [selLocId, setSelLocId] = useState((locations&&locations[0])?locations[0].id:'tirana');
  const [selSpaceId, setSelSpaceId] = useState(null);
  const [selFloorIdx, setSelFloorIdx] = useState(0);
  const [view, setView] = useState('list'); // list | plan
  const [spaceModal, setSpaceModal] = useState(null); // null | {space} | {new}
  const [seatModal, setSeatModal] = useState(null);   // null | {seat, spaceId, floorIdx}
  const [draggingSeat, setDraggingSeat] = useState(null);
  const [dragOffset, setDragOffset] = useState({x:0,y:0});
  const planRef = useRef(null);

  useEffect(()=>{localStorage.setItem('jsr_spaces_v1',JSON.stringify(spaces));},[spaces]);

  // ── HELPERS ────────────────────────────────────────────────────────────
  const LOCS = locations||[{id:'tirana',name:'Tirana'},{id:'prishtina',name:'Prishtina'}];
  const SHIFTS=(()=>{try{const c=JSON.parse(localStorage.getItem('jsr_shift_cfg')||'{}');const all=[...new Set(Object.values(c).flat().map(s=>s.label))];return all.length>0?all:['Standard','Schicht 1','Schicht 2'];}catch(e){return['Standard'];}})();
  const TABLE_SIZES = [{v:1,label:'1er Einzelplatz'},{v:2,label:'2er Tisch'},{v:4,label:'4er Tisch'},{v:8,label:'8er Tisch'}];

  // Stable color per project - based on position in projects array
  function projColor(projId){
    if(!projId) return '#94a3b8';
    const COLORS=['#2563eb','#16a34a','#9333ea','#ea580c','#e11d48','#0891b2','#ca8a04','#be185d','#047857','#7c3aed'];
    const p=(projects||[]).find(x=>x.id===projId);
    if(p&&p.color&&p.color!=='#1d4ed8') return p.color; // use project's own color if customized
    const idx=(projects||[]).findIndex(x=>x.id===projId);
    return COLORS[Math.max(0,idx)%COLORS.length];
  }
  function projName(projId){
    if(!projId) return 'Frei';
    const p=(projects||[]).find(x=>x.id===projId);
    return p?p.name:projId;
  }
  function empName(empId){
    if(!empId) return '';
    const e=(employees||[]).find(x=>x.id===empId);
    return e?`${e.first_name} ${e.last_name}`:empId;
  }

  const filteredSpaces = selLocId ? spaces.filter(s=>s.location_id===selLocId) : spaces;
  const selSpace = selSpaceId ? spaces.find(s=>s.id===selSpaceId) : null;
  const selFloor = selSpace && selSpace.floors ? selSpace.floors[selFloorIdx] : null;

  // ── KPIs ───────────────────────────────────────────────────────────────
  function spaceKPIs(space){
    let total=0,free=0,assigned=0;
    (space.floors||[]).forEach(fl=>{
      (fl.seats||[]).forEach(seat=>{
        total++;
        const hasAssignment=(seat.assignments||[]).some(a=>a.emp_id||a.proj_id);
        if(hasAssignment) assigned++;
        else free++;
      });
    });
    return{total,free,assigned};
  }

  // ── SAVE SPACE ─────────────────────────────────────────────────────────
  function saveSpace(form){
    if(!form.name||!form.location_id) return alert('Name und Standort sind Pflicht.');
    if(form.id){
      setSpaces(ss=>ss.map(s=>s.id===form.id?{...s,...form}:s));
    } else {
      const newSpace={...form,id:'sp_'+Date.now(),floors:[{name:'EG',plan_url:'',seats:[]}]};
      setSpaces(ss=>[...ss,newSpace]);
    }
    setSpaceModal(null);
  }

  // ── UPLOAD FLOOR PLAN ──────────────────────────────────────────────────
  function uploadPlan(file, spaceId, floorIdx){
    if(!file) return;
    const reader=new FileReader();
    reader.onload=ev=>{
      setSpaces(ss=>ss.map(s=>s.id===spaceId?{...s,floors:s.floors.map((f,i)=>i===floorIdx?{...f,plan_url:ev.target.result}:f)}:s));
    };
    if(file.type==='application/pdf'){
      // Convert PDF page 1 to image via canvas using PDF.js would be ideal
      // For now store as data URL and render as object embed
      reader.readAsDataURL(file);
    } else {
      reader.readAsDataURL(file);
    }
  }

  // ── ADD FLOOR ──────────────────────────────────────────────────────────
  function addFloor(spaceId){
    setSpaces(ss=>ss.map(s=>s.id===spaceId?{...s,floors:[...(s.floors||[]),{name:'Stockwerk '+(s.floors||[]).length,plan_url:'',seats:[]}]}:s));
  }

  // ── SEAT OPERATIONS ────────────────────────────────────────────────────
  function addSeat(spaceId, floorIdx, form){
    const count=parseInt(form.table_size)||1;
    const tableId='t_'+Date.now();
    // Layout: seats in a row (2er), 2x2 (4er), 2x4 (8er)
    const LAYOUTS={
      1:[[0,0]],
      2:[[-0.6,0],[0.6,0]],
      4:[[-0.6,-0.6],[0.6,-0.6],[-0.6,0.6],[0.6,0.6]],
      8:[[-1.8,-0.6],[-0.6,-0.6],[0.6,-0.6],[1.8,-0.6],[-1.8,0.6],[-0.6,0.6],[0.6,0.6],[1.8,0.6]],
    };
    const SEAT_NAMES='ABCDEFGH';
    const SEAT_SIZE={1:8,2:7,4:6,8:5}; // % of canvas
    const sz=SEAT_SIZE[count]||6;
    const baseX=50, baseY=50;
    const offsets=LAYOUTS[count]||LAYOUTS[1];
    const newSeats=offsets.map((off,i)=>({
      id:'seat_'+Date.now()+'_'+i,
      label:(form.label||'Tisch')+(count>1?' '+SEAT_NAMES[i]:''),
      table_size:count,
      table_id:tableId,
      seat_pos:i,
      x: baseX + off[0]*sz*0.9,
      y: baseY + off[1]*sz*0.9,
      seat_w:sz, seat_h:sz,
      assignments:[{shift:'Standard',emp_id:(form.seat_assignments&&form.seat_assignments[i])||'',proj_id:form.proj_id||''}],
    }));
    setSpaces(ss=>ss.map(s=>s.id===spaceId?{...s,floors:s.floors.map((fl,i)=>i===floorIdx?{...fl,seats:[...(fl.seats||[]),...newSeats]}:fl)}:s));
  }

  function updateSeat(spaceId, floorIdx, seatId, updates){
    setSpaces(ss=>ss.map(s=>s.id===spaceId?{...s,floors:s.floors.map((f,i)=>i===floorIdx?{...f,seats:f.seats.map(seat=>seat.id===seatId?{...seat,...updates}:seat)}:f)}:s));
  }

  function removeSeat(spaceId, floorIdx, seatId){
    setSpaces(ss=>ss.map(s=>s.id===spaceId?{...s,floors:s.floors.map((f,i)=>i===floorIdx?{...f,seats:f.seats.filter(seat=>seat.id!==seatId)}:f)}:s));
  }

  function moveSeat(spaceId, floorIdx, seatId, x, y){
    updateSeat(spaceId,floorIdx,seatId,{x,y});
  }

  // ── DRAG HANDLING ──────────────────────────────────────────────────────
  function onPlanMouseDown(e, seat){
    e.preventDefault();
    const plan=planRef.current;
    if(!plan) return;
    const rect=plan.getBoundingClientRect();
    const scaleX=100/(rect.width||800);
    const scaleY=100/(rect.height||600);
    const sx=(e.clientX-rect.left)*scaleX - seat.x;
    const sy=(e.clientY-rect.top)*scaleY - seat.y;

    // Find all seats in the same table group
    const tableId=seat.table_id;
    const tableSeats=tableId
      ?(selFloor.seats||[]).filter(s=>s.table_id===tableId)
      :[seat];

    // Store initial positions of all table seats
    const initPositions={};
    tableSeats.forEach(s=>{ initPositions[s.id]={x:s.x,y:s.y}; });

    // Mark entire table as dragging
    setDraggingSeat(tableId||seat.id);

    function onMove(ev){
      const r=plan.getBoundingClientRect();
      const mx=(ev.clientX-r.left)*scaleX;
      const my=(ev.clientY-r.top)*scaleY;
      const dx=mx-sx-seat.x;
      const dy=my-sy-seat.y;
      // Move all seats in table by same delta
      setSpaces(ss=>ss.map(sp=>sp.id!==selSpaceId?sp:{...sp,floors:sp.floors.map((fl,fi)=>fi!==selFloorIdx?fl:{...fl,seats:fl.seats.map(s=>{
        if(!initPositions[s.id]) return s;
        const nx=Math.max(0,Math.min(95,initPositions[s.id].x+dx));
        const ny=Math.max(0,Math.min(95,initPositions[s.id].y+dy));
        return {...s,x:nx,y:ny};
      })})}));
    }
    function onUp(){
      setDraggingSeat(null);
      window.removeEventListener('mousemove',onMove);
      window.removeEventListener('mouseup',onUp);
    }
    window.addEventListener('mousemove',onMove);
    window.addEventListener('mouseup',onUp);
  }

  // ── SEAT COLOR ─────────────────────────────────────────────────────────
  function seatColor(seat){
    const assignments=seat.assignments||[];
    const projId=(assignments[0]||{}).proj_id||seat.proj_id||'';
    const empId=(assignments[0]||{}).emp_id||'';
    const hasAny=projId||empId;
    if(!hasAny) return {bg:'#e8edf5',border:'#b0bccc',text:'#64748b'};
    const color=projId?projColor(projId):'#64748b';
    return {bg:color, border:color, text:'#fff'};
  }

  // ══════════════════════════════════════════════════════════════════════════
  // RENDER
  // ══════════════════════════════════════════════════════════════════════════
  return(
    <div>
      {/* ── SPACE MODAL ── */}
      {spaceModal&&(
        <SpaceFormModal
          space={spaceModal.new?{location_id:spaceModal.location_id||''}:spaceModal}
          locations={LOCS}
          onSave={saveSpace}
          onClose={()=>setSpaceModal(null)}
        />
      )}

      {/* ── SEAT MODAL ── */}
      {seatModal&&(
        <SeatFormModal
          seat={seatModal.seat}
          spaceId={seatModal.spaceId}
          floorIdx={seatModal.floorIdx}
          projects={projects||[]}
          employees={employees||[]}
          onSave={(form)=>{
            if(seatModal.seat){
              updateSeat(seatModal.spaceId,seatModal.floorIdx,seatModal.seat.id,form);
            } else {
              addSeat(seatModal.spaceId,seatModal.floorIdx,form);
            }
            setSeatModal(null);
          }}
          onDelete={seatModal.seat?()=>{removeSeat(seatModal.spaceId,seatModal.floorIdx,seatModal.seat.id);setSeatModal(null);}:null}
          onClose={()=>setSeatModal(null)}
        />
      )}

      {/* ── HEADER ── */}
      <div style={{display:'flex',alignItems:'center',gap:12,marginBottom:16,flexWrap:'wrap'}}>
        <div style={{flex:1}}>
          <h2 style={{fontSize:18,fontWeight:700,margin:0}}>🏗 Spaces & Seats</h2>
          <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>Grundrisse · Sitzplanung · Kapazität</div>
        </div>
        <select className="form-select" style={{width:180}} value={selLocId} onChange={e=>{setSelLocId(e.target.value);setSelSpaceId(null);setView('list');}}>
          <option value="">Alle Standorte</option>
          {LOCS.map(l=><option key={l.id} value={l.id}>{l.name}</option>)}
        </select>
        {selSpace&&<button className="btn btn-sm" onClick={()=>{setSelSpaceId(null);setView('list');}}>← Zur Übersicht</button>}
        {!selSpace&&<button className="btn btn-primary btn-sm" onClick={()=>setSpaceModal({new:true,location_id:selLocId})}>+ Neuer Space</button>}
        {selSpace&&<button className="btn btn-sm" style={{background:'var(--blue)',color:'white',border:'none'}}
          onClick={()=>setSeatModal({seat:null,spaceId:selSpaceId,floorIdx:selFloorIdx})}>+ Seat hinzufügen</button>}
      </div>

      {/* ── SPACE LIST ── */}
      {!selSpace&&(
        <div>
          {filteredSpaces.length===0&&(
            <div className="card" style={{padding:40,textAlign:'center',color:'var(--muted)'}}>
              <div style={{fontSize:36,marginBottom:10}}>🏗</div>
              <div style={{fontWeight:600,marginBottom:6}}>Noch keine Spaces angelegt</div>
              <div style={{fontSize:12}}>Fläche + Grundriss anlegen und mit Seats bestücken</div>
              <button className="btn btn-primary" style={{marginTop:14}} onClick={()=>setSpaceModal({new:true,location_id:selLocId})}>+ Ersten Space anlegen</button>
            </div>
          )}
          <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))',gap:12}}>
            {filteredSpaces.map(space=>{
              const kpi=spaceKPIs(space);
              const loc=LOCS.find(l=>l.id===space.location_id);
              return(
                <div key={space.id} className="card" style={{cursor:'pointer',transition:'box-shadow .15s'}}
                  onClick={()=>{setSelSpaceId(space.id);setSelFloorIdx(0);setView('plan');}}>
                  {/* Floor plan thumbnail */}
                  <div style={{height:120,borderRadius:'var(--r)',background:'var(--surface-2)',marginBottom:12,
                    overflow:'hidden',display:'flex',alignItems:'center',justifyContent:'center',position:'relative'}}>
                    {(space.floors&&space.floors[0]&&space.floors[0].plan_url)
                      ?<img src={space.floors[0].plan_url} style={{width:'100%',height:'100%',objectFit:'contain'}} alt="Grundriss"/>
                      :<div style={{textAlign:'center',color:'var(--muted)',fontSize:12}}>
                        <div style={{fontSize:28,marginBottom:4}}>📐</div>
                        <div>Kein Grundriss</div>
                      </div>}
                    {/* Seat dots overlay */}
                    {(space.floors&&space.floors[0]&&space.floors[0].seats||[]).slice(0,20).map(seat=>{
                      const c=seatColor(seat);
                      return <div key={seat.id} style={{position:'absolute',
                        left:seat.x+'%',top:seat.y+'%',
                        width:8,height:8,borderRadius:'50%',
                        background:c.bg,border:'2px solid white',
                        transform:'translate(-50%,-50%)'
                      }}/>;
                    })}
                  </div>
                  <div style={{fontWeight:700,fontSize:14,marginBottom:2}}>{space.name}</div>
                  <div style={{fontSize:11,color:'var(--muted)',marginBottom:10}}>
                    {loc?.name||'—'} · {space.sqm||'?'} m² · {(space.floors||[]).length} Stockwerk{(space.floors||[]).length!==1?'e':''}
                  </div>
                  {/* KPIs */}
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr',gap:6}}>
                    {[['Gesamt',kpi.total,'var(--text)'],['Belegt',kpi.assigned,'var(--blue)'],['Frei',kpi.free,'var(--green)']].map(([l,v,c])=>(
                      <div key={l} style={{textAlign:'center',padding:'6px 4px',background:'var(--surface-2)',borderRadius:'var(--r)'}}>
                        <div style={{fontSize:18,fontWeight:800,color:c}}>{v}</div>
                        <div style={{fontSize:9,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em'}}>{l}</div>
                      </div>
                    ))}
                  </div>
                  {/* Floor pills */}
                  {(space.floors||[]).length>1&&(
                    <div style={{display:'flex',gap:4,marginTop:8,flexWrap:'wrap'}}>
                      {(space.floors||[]).map((fl,i)=>(
                        <span key={i} style={{fontSize:10,padding:'2px 7px',borderRadius:20,background:'var(--border)',color:'var(--muted)',fontWeight:600}}>
                          {fl.name||'EG'}
                        </span>
                      ))}
                    </div>
                  )}
                  <div style={{display:'flex',gap:6,marginTop:10}}>
                    <button className="btn btn-sm" style={{flex:1}} onClick={e=>{e.stopPropagation();setSpaceModal(space);}}>✏ Bearbeiten</button>
                    <button className="btn btn-sm" style={{color:'var(--red)'}} onClick={e=>{e.stopPropagation();if(window.confirm('Space löschen?'))setSpaces(ss=>ss.filter(s=>s.id!==space.id));}}>×</button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ── FLOOR PLAN VIEW ── */}
      {selSpace&&selFloor&&(
        <div>
          {/* Space info bar */}
          <div className="card" style={{padding:'10px 14px',marginBottom:12,display:'flex',alignItems:'center',gap:14,flexWrap:'wrap'}}>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:15}}>{selSpace.name}</div>
              <div style={{fontSize:11,color:'var(--muted)'}}>
                {LOCS.find(l=>l.id===selSpace.location_id)?.name||'—'} · {selSpace.sqm||'?'} m²
              </div>
            </div>
            {/* KPIs */}
            {(()=>{const k=spaceKPIs(selSpace);return(
              <div style={{display:'flex',gap:12}}>
                {[['Seats',k.total,'var(--text)'],['Belegt',k.assigned,'var(--blue)'],['Frei',k.free,'var(--green)']].map(([l,v,c])=>(
                  <div key={l} style={{textAlign:'center'}}>
                    <div style={{fontSize:20,fontWeight:800,color:c}}>{v}</div>
                    <div style={{fontSize:9,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em'}}>{l}</div>
                  </div>
                ))}
              </div>
            );})()}
            {/* Upload plan */}
            <label className="btn btn-sm" style={{cursor:'pointer'}}>
              📐 Grundriss {selFloor.plan_url?'aktualisieren':'hochladen'}
              <input type="file" accept="image/*,.pdf" style={{display:'none'}} onChange={e=>uploadPlan(e.target.files[0],selSpaceId,selFloorIdx)}/>
            </label>
            <button className="btn btn-sm" onClick={()=>addFloor(selSpaceId)}>+ Stockwerk</button>
          </div>

          {/* Floor tabs */}
          {(selSpace.floors||[]).length>1&&(
            <div style={{display:'flex',gap:6,marginBottom:10,flexWrap:'wrap'}}>
              {(selSpace.floors||[]).map((fl,i)=>(
                <button key={i} onClick={()=>setSelFloorIdx(i)}
                  style={{padding:'5px 14px',borderRadius:20,border:'1.5px solid '+(i===selFloorIdx?'var(--blue)':'var(--border)'),
                    background:i===selFloorIdx?'var(--blue-bg)':'transparent',
                    color:i===selFloorIdx?'var(--blue)':'var(--muted)',
                    fontSize:12,fontWeight:700,cursor:'pointer',fontFamily:'var(--font)'}}>
                  {fl.name||('Etage '+i)}
                </button>
              ))}
            </div>
          )}

          {/* Plan canvas */}
          <div className="card" style={{padding:0,overflow:'hidden'}}>
            <div ref={planRef} style={{position:'relative',width:'100%',paddingBottom:'62%',background:'#f8fafc',
              backgroundImage:'radial-gradient(circle,#cbd5e1 1px,transparent 1px)',backgroundSize:'20px 20px',
              cursor:'default',userSelect:'none'}}>

              {/* Floor plan image */}
              {selFloor.plan_url&&(
                <img src={selFloor.plan_url} alt="Grundriss"
                  style={{position:'absolute',inset:0,width:'100%',height:'100%',objectFit:'contain',opacity:.35,pointerEvents:'none'}}/>
              )}

              {/* Seats */}
              {(selFloor.seats||[]).map(seat=>{
                const c=seatColor(seat);
                const isDragging=draggingSeat===(seat.table_id||seat.id);
                const assignments=seat.assignments||[];
                const mainAssign=assignments[0]||{};
                const multiShift=assignments.length>1;
                const SEAT_W=seat.seat_w||7, SEAT_H=seat.seat_h||8;
                return(
                  <div key={seat.id}
                    onMouseDown={e=>onPlanMouseDown(e,seat)}
                    onClick={e=>{if(!isDragging)setSeatModal({seat,spaceId:selSpaceId,floorIdx:selFloorIdx});}}
                    style={{
                      position:'absolute',
                      left:seat.x+'%',top:seat.y+'%',
                      width:SEAT_W+'%',height:SEAT_H+'%',
                      transform:'translate(-50%,-50%)',
                      background:c.bg,border:'2px solid '+c.border,
                      borderRadius:4,cursor:'grab',
                      display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',
                      zIndex:isDragging?100:1,
                      boxShadow:isDragging?'0 4px 16px rgba(0,0,0,.2)':'0 1px 3px rgba(0,0,0,.08)',
                      transition:isDragging?'none':'box-shadow .15s',
                      overflow:'hidden',
                    }}>
                    {/* Initials or free */}
                    <div style={{fontSize:'clamp(6px,0.7vw,11px)',fontWeight:700,color:c.text,textAlign:'center',lineHeight:1.2,padding:'0 2px'}}>
                      {(()=>{
                      if(mainAssign.emp_id){
                        const e=(employees||[]).find(x=>x.id===mainAssign.emp_id);
                        return e?<span style={{fontSize:'clamp(7px,.8vw,12px)',fontWeight:800,color:'#fff',textShadow:'0 1px 2px rgba(0,0,0,.3)'}}>{e.first_name[0]}{e.last_name[0]}</span>:<span style={{color:'rgba(255,255,255,.7)',fontSize:'clamp(6px,.7vw,10px)'}}>?</span>;
                      }
                      if(mainAssign.proj_id){
                        const name=projName(mainAssign.proj_id)||'';
                        return <span style={{fontSize:'clamp(6px,.65vw,9px)',fontWeight:700,color:'rgba(255,255,255,.9)',textAlign:'center',padding:'0 2px',lineHeight:1.1,wordBreak:'break-all'}}>{name.slice(0,4)}</span>;
                      }
                      return <span style={{fontSize:'clamp(6px,.65vw,9px)',color:'#94a3b8'}}>○</span>;
                    })()}
                    </div>
                    {/* Multi-shift badge */}
                    {multiShift&&<div style={{position:'absolute',top:1,right:1,width:8,height:8,borderRadius:'50%',background:'var(--amber)',border:'1px solid white'}}/>}
                  </div>
                );
              })}

              {/* Empty state */}
              {!(selFloor.seats||[]).length&&(
                <div style={{position:'absolute',inset:0,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',color:'var(--muted)'}}>
                  {!selFloor.plan_url&&<div style={{fontSize:32,marginBottom:8}}>📐</div>}
                  <div style={{fontSize:13,fontWeight:600}}>
                    {!selFloor.plan_url?'Grundriss hochladen':'Seats hinzufügen'}
                  </div>
                  <div style={{fontSize:11,marginTop:4,color:'var(--dim)'}}>
                    {!selFloor.plan_url?'Dann Seats platzieren':'Klick auf "+ Seat" oben rechts'}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Legend */}
          <div style={{display:'flex',gap:12,marginTop:10,flexWrap:'wrap',alignItems:'center'}}>
            <span style={{fontSize:11,fontWeight:700,color:'var(--muted)'}}>Legende:</span>
            <div style={{display:'flex',alignItems:'center',gap:5,fontSize:11}}>
              <div style={{width:14,height:14,borderRadius:3,background:'#f1f5f9',border:'2px solid #cbd5e1'}}/>
              <span style={{color:'var(--muted)'}}>Frei</span>
            </div>
            {(projects||[]).slice(0,6).map(p=>(
              <div key={p.id} style={{display:'flex',alignItems:'center',gap:5,fontSize:11}}>
                <div style={{width:14,height:14,borderRadius:3,background:projColor(p.id),border:'2px solid '+projColor(p.id)}}/>
                <span style={{color:'var(--muted)'}}>{p.name}</span>
              </div>
            ))}
            <div style={{display:'flex',alignItems:'center',gap:5,fontSize:11,marginLeft:'auto'}}>
              <div style={{width:8,height:8,borderRadius:'50%',background:'var(--amber)'}}/>
              <span style={{color:'var(--muted)'}}>Mehrfach-Schicht</span>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

