// SPACE FORM MODAL
// ══════════════════════════════════════════════════════════════════════════════
function SpaceFormModal({space, locations, onSave, onClose}){
  const [form, setForm] = useState(()=>{const d=space||{name:'',location_id:'',sqm:'',description:''};return(!d.location_id&&locations&&locations[0])?{...d,location_id:locations[0].id}:d;});
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));
  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:440}}>
        <div className="modal-header">
          <span className="modal-title">{space?'Space bearbeiten':'Neuer Space'}</span>
          <button className="btn" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          <div className="form-group"><label className="form-label">Name *</label>
            <input className="form-input" value={form.name} onChange={e=>set('name',e.target.value)} placeholder="z.B. Büro A, Open Space 2. OG"/></div>
          <div className="form-row">
            <div className="form-group"><label className="form-label">Standort *</label>
              <select className="form-select" value={form.location_id} onChange={e=>set('location_id',e.target.value)}>
                <option value="">— wählen —</option>
                {(locations||[]).map(l=><option key={l.id} value={l.id}>{l.name}</option>)}
              </select></div>
            <div className="form-group"><label className="form-label">Fläche (m²)</label>
              <input className="form-input" type="number" min="0" value={form.sqm} onChange={e=>set('sqm',e.target.value)} placeholder="z.B. 120"/></div>
          </div>
          <div className="form-group"><label className="form-label">Beschreibung</label>
            <input className="form-input" value={form.description||''} onChange={e=>set('description',e.target.value)} placeholder="optional"/></div>
        </div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>Abbrechen</button>
          <button className="btn btn-primary" onClick={()=>onSave(form)}>Speichern</button>
        </div>
      </div>
    </div>
  );
}

