// SEAT FORM MODAL
// ══════════════════════════════════════════════════════════════════════════════
function SeatFormModal({seat, spaceId, floorIdx, projects, employees, onSave, onDelete, onClose}){
  const isNew=!seat;
  const SEAT_NAMES='ABCDEFGH';
  const [form, setForm] = useState(()=>{
    if(seat) return seat;
    return {label:'Tisch',table_size:1,proj_id:'',seat_assignments:[''],};
  });
  const set=(k,v)=>setForm(f=>({...f,[k]:v}));
  const count=parseInt(form.table_size)||1;

  // For existing single seat: shift assignments
  const [assignments, setAssignments] = useState(seat?seat.assignments||[{shift:'Standard',emp_id:'',proj_id:''}]:[]);
  function setAssign(i,k,v){setAssignments(a=>a.map((x,j)=>j===i?{...x,[k]:v}:x));}
  function addShift(){if(assignments.length>=3){alert('Max. 3 Schichten.');return;}setAssignments(a=>[...a,{shift:'Schicht '+(a.length+1),emp_id:'',proj_id:''}]);}

  const activeEmps=(employees||[]).filter(e=>['active','training','contract','training_planned'].includes(e.status));

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:520}}>
        <div className="modal-header">
          <span className="modal-title">{isNew?'Tisch / Seat anlegen':'Seat bearbeiten'}</span>
          <button className="btn" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {isNew?(
            <div>
              <div className="form-row">
                <div className="form-group"><label className="form-label">Bezeichnung</label>
                  <input className="form-input" value={form.label||''} onChange={e=>set('label',e.target.value)} placeholder="z.B. Reihe A, Tisch 1"/></div>
                <div className="form-group"><label className="form-label">Tisch-Typ</label>
                  <select className="form-select" value={count} onChange={e=>{const n=parseInt(e.target.value);set('table_size',n);set('seat_assignments',Array(n).fill(''));}}>
                    <option value={1}>1er — Einzelplatz</option>
                    <option value={2}>2er Tisch — 2 Seats</option>
                    <option value={4}>4er Tisch — 4 Seats</option>
                    <option value={8}>8er Tisch — 8 Seats</option>
                  </select></div>
              </div>
              <div className="form-group"><label className="form-label">Projekt (für alle Seats)</label>
                <select className="form-select" value={form.proj_id||''} onChange={e=>set('proj_id',e.target.value)}>
                  <option value="">— Frei / unzugewiesen —</option>
                  {(projects||[]).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
                </select></div>
              {/* Per-seat employee assignment */}
              {count>1&&(
                <div style={{borderTop:'1px solid var(--border)',paddingTop:12,marginTop:4}}>
                  <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em',marginBottom:10}}>
                    Mitarbeiter pro Seat (optional)
                  </div>
                  <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8}}>
                    {Array.from({length:count},(_,i)=>(
                      <div key={i} className="form-group" style={{margin:0}}>
                        <label className="form-label" style={{fontSize:10}}>Seat {SEAT_NAMES[i]}</label>
                        <select className="form-select" value={(form.seat_assignments||Array(count).fill(''))[i]||''}
                          onChange={e=>{
                            const current=form.seat_assignments||Array(count).fill('');
                            const padded=[...current,...Array(Math.max(0,count-current.length)).fill('')];
                            set('seat_assignments',padded.map((v,j)=>j===i?e.target.value:v));
                          }}>
                          <option value="">— Frei —</option>
                          {activeEmps.map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name}</option>)}
                        </select>
                      </div>
                    ))}
                  </div>
                </div>
              )}
              {count===1&&(
                <div className="form-group"><label className="form-label">Mitarbeiter</label>
                  <select className="form-select" value={(form.seat_assignments||[''])[0]||''}
                    onChange={e=>set('seat_assignments',[e.target.value])} style={{marginTop:4}}>
                    <option value="">— Frei —</option>
                    {activeEmps.map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name}</option>)}
                  </select>
                </div>
              )}
            </div>
          ):(
            <div>
              <div className="form-group"><label className="form-label">Bezeichnung</label>
                <input className="form-input" value={form.label||''} onChange={e=>set('label',e.target.value)}/></div>
              <div className="form-group"><label className="form-label">Projekt</label>
                <select className="form-select" value={(assignments[0]||{}).proj_id||''} onChange={e=>setAssign(0,'proj_id',e.target.value)}>
                  <option value="">— Frei —</option>
                  {(projects||[]).map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
                </select></div>
              <div style={{borderTop:'1px solid var(--border)',paddingTop:12,marginTop:4}}>
                <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:8}}>
                  <div style={{fontSize:11,fontWeight:700,color:'var(--muted)',textTransform:'uppercase',letterSpacing:'.06em'}}>Schicht-Belegung</div>
                  {assignments.length<3&&<button className="btn btn-sm" onClick={addShift}>+ Schicht</button>}
                </div>
                {assignments.map((a,i)=>(
                  <div key={i} style={{display:'grid',gridTemplateColumns:'90px 1fr auto',gap:8,marginBottom:8,alignItems:'end'}}>
                    <div className="form-group" style={{margin:0}}>
                      <label className="form-label" style={{fontSize:10}}>Schicht</label>
                      <input className="form-input" value={a.shift||''} onChange={e=>setAssign(i,'shift',e.target.value)} placeholder="Standard"/>
                    </div>
                    <div className="form-group" style={{margin:0}}>
                      <label className="form-label" style={{fontSize:10}}>Mitarbeiter</label>
                      <select className="form-select" value={a.emp_id||''} onChange={e=>setAssign(i,'emp_id',e.target.value)}>
                        <option value="">— Frei —</option>
                        {activeEmps.map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name}</option>)}
                      </select>
                    </div>
                    <button className="btn btn-sm" style={{color:'var(--red)',alignSelf:'flex-end'}}
                      onClick={()=>setAssignments(a=>a.filter((_,j)=>j!==i))} disabled={assignments.length<=1}>×</button>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
        <div className="modal-footer">
          {onDelete&&<button className="btn" style={{color:'var(--red)',marginRight:'auto'}} onClick={onDelete}>🗑 Löschen</button>}
          <button className="btn" onClick={onClose}>Abbrechen</button>
          <button className="btn btn-primary" onClick={()=>onSave(isNew?{...form}:{...form,assignments})}>Speichern</button>
        </div>
      </div>
    </div>
  );
}

