// ── PAYSLIP CALCULATION ENGINE ────────────────────────────────────────────
function calcAlbanianPayroll(slip, cfg){
  // cfg from localStorage via getPayrollCfg(location)
  const raw = (typeof getPayrollCfg !== 'undefined') ? getPayrollCfg(location) : {};
  const C = {
    pension_employee_pct: cfg.pension_employee_pct ?? 5,
    pension_employer_pct: cfg.pension_employer_pct ?? 5,
    health_employee:      cfg.health_employee ?? 30,
    health_employer:      cfg.health_employer ?? 35.08,
    tax_bracket1_max:     cfg.tax_bracket1_max ?? 250,
    tax_bracket2_max:     cfg.tax_bracket2_max ?? 450,
    tax_bracket2_pct:     cfg.tax_bracket2_pct ?? 8,
    tax_bracket3_pct:     cfg.tax_bracket3_pct ?? 10,
  };

  const hourlyRate = parseFloat(slip.hourly_rate||0);
  const workDays   = parseInt(slip.work_days||22);
  const hoursPerDay= parseFloat(slip.hours_per_day||8);
  const monthTarget= workDays * hoursPerDay;

  // Hours breakdown from payroll data
  const rec = slip._rec || {};
  const totalWorked   = parseFloat(rec.total_worked_hours || monthTarget);
  const satH          = parseFloat(rec.saturday_hours || 0);
  const sunH          = parseFloat(rec.sunday_hours || 0);
  const holH          = parseFloat(rec.holiday_hours || 0);
  const nightH        = parseFloat(rec.night_hours || 0);

  // Surcharge rates from cfg
  const scCfg = JSON.parse(typeof localStorage!=='undefined'?localStorage.getItem('jsr_surcharge_cfg')||'{}':'{}');
  const saP = (scCfg.surcharge_saturday??20)/100;
  const suP = (scCfg.surcharge_sunday??50)/100;
  const hoP = (scCfg.surcharge_holiday??50)/100;
  const niP = (scCfg.surcharge_night??25)/100;
  const otP = (scCfg.surcharge_overtime??30)/100;

  // Overtime = hours above monthly target
  const specialH = satH + sunH + holH;
  const overtimeH = Math.max(0, totalWorked - monthTarget);
  const otWeekday = Math.max(0, overtimeH - specialH);
  const isOT = overtimeH > 0;

  // Regular hours (Mo-Fr, no overtime)
  const regularH = Math.max(0, monthTarget - Math.max(0, specialH - overtimeH));

  // Gross from regular hours
  const grossRegular = Math.round(regularH * hourlyRate * 100) / 100;

  // Surcharges by rate
  const saRate = Math.max(saP, isOT ? otP : 0);
  const suRate = Math.max(suP, isOT ? otP : 0);
  const hoRate = Math.max(hoP, isOT ? otP : 0);
  const niRate = Math.max(niP, isOT ? otP : 0);

  const surcharge20 = satH * hourlyRate * saP;   // Saturday 20%
  const surcharge30 = otWeekday * hourlyRate * otP; // OT weekday 30%
  const surcharge50 = (sunH + holH) * hourlyRate * suP; // Sun/Holiday 50%
  // Night might be any rate - simplified: night hours * night pct
  const surchargeNight = nightH * hourlyRate * niP;

  // Adjust if Sa goes OT rate instead of Sa rate
  const saActual = satH * hourlyRate * saRate;
  const suActual = sunH * hourlyRate * suRate;
  const hoActual = holH * hourlyRate * hoRate;

  const totalSurcharge = Math.round((otWeekday * hourlyRate * otP + saActual + suActual + hoActual + surchargeNight) * 100) / 100;

  // Deductions from rec
  const absenceDays    = parseFloat(rec.deduction_absence_days || 0);
  const absenceDeduct  = absenceDays * hourlyRate * hoursPerDay;
  const advanceDeduct  = parseFloat(rec.deduction_social || 0);
  const otherDeduct    = parseFloat(rec.deduction_other || 0);

  // Bonuses
  const referralBonus  = parseFloat(rec.referral_bonus || 0);
  const targetBonus    = parseFloat(rec.target_bonus || 0);
  const specialBonus   = parseFloat(rec.special_bonus || 0);
  const totalBonus     = referralBonus + targetBonus + specialBonus;

  // Health insurance (employer pays, but shown on slip)
  const healthEmployee = C.health_employee;
  const healthEmployer = C.health_employer;

  // BRUTTOGEHALT TOTAL
  const grossTotal = grossRegular + totalSurcharge + totalBonus;

  // Pension
  const pensionEmployee = Math.round(grossTotal * C.pension_employee_pct / 100 * 100) / 100;
  const pensionEmployer = Math.round(grossTotal * C.pension_employer_pct / 100 * 100) / 100;

  // Income before tax = gross - employee pension
  const incomeBeforeTax = grossTotal - pensionEmployee;

  // Albanian income tax
  let incomeTax = 0;
  const b1 = C.tax_bracket1_max;   // 250
  const b2 = C.tax_bracket2_max;   // 450
  const p2 = C.tax_bracket2_pct / 100; // 8%
  const p3 = C.tax_bracket3_pct / 100; // 10%
  if(incomeBeforeTax > b1){
    const in2 = Math.min(incomeBeforeTax, b2) - b1;
    incomeTax += in2 * p2;
  }
  if(incomeBeforeTax > b2){
    incomeTax += (incomeBeforeTax - b2) * p3;
  }
  incomeTax = Math.round(incomeTax * 100) / 100;

  // NET
  const netPay = Math.round((grossTotal - pensionEmployee - incomeTax - healthEmployee - absenceDeduct - advanceDeduct - otherDeduct) * 100) / 100;

  return {
    // Hours
    monthTarget, regularH, totalWorked, overtimeH, otWeekday, satH, sunH, holH, nightH,
    // Rates
    hourlyRate, saRate, suRate, hoRate, otP, niP,
    // Gross
    grossRegular, totalSurcharge,
    surcharge20: Math.round(saActual*100)/100,
    surcharge30: Math.round(otWeekday*hourlyRate*otP*100)/100,
    surcharge50: Math.round((suActual+hoActual)*100)/100,
    // Bonuses
    referralBonus, targetBonus, specialBonus, totalBonus,
    // Insurance
    healthEmployee, healthEmployer,
    // Totals
    grossTotal: Math.round(grossTotal*100)/100,
    pensionEmployee, pensionEmployer,
    incomeBeforeTax: Math.round(incomeBeforeTax*100)/100,
    incomeTax,
    // Deductions
    absenceDays, absenceDeduct: Math.round(absenceDeduct*100)/100,
    advanceDeduct, otherDeduct,
    // Net
    netPay: Math.max(0, netPay),
    C,
  };
}

