// ══════════════════════════════════════════════════════════════════════════════
// PAYSLIP PREVIEW MODAL
// ══════════════════════════════════════════════════════════════════════════════
function PayslipPreviewModal({slip, onClose, onApprove, onRetract}){
  const isApproved = slip.status==='confirmed'||slip.status==='paid';
  const isLocked   = slip.status==='paid';
  const c = slip._calc||{};
  const eur = v=>(parseFloat(v||0)).toLocaleString('de-DE',{minimumFractionDigits:2,maximumFractionDigits:2})+' €';

  // Generate payslip HTML and inject into iframe
  const iframeRef = useRef(null);
  useEffect(()=>{
    if(!iframeRef.current) return;
    const html = generatePayslipHTML(slip._calc||{...slip,emp:slip.emp||slip,monthLabel:slip.month});
    const doc = iframeRef.current.contentDocument||iframeRef.current.contentWindow.document;
    doc.open(); doc.write(html); doc.close();
  },[slip]);

  function printSlip(){
    if(!iframeRef.current) return;
    iframeRef.current.contentWindow.print();
  }

  function downloadSlip(){
    const html = generatePayslipHTML(slip._calc||{...slip,emp:slip.emp||slip,monthLabel:slip.month});
    const blob = new Blob([html],{type:'text/html;charset=utf-8'});
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href=url; a.download='Gehaltsabrechnung_'+slip.first_name+'_'+slip.last_name+'_'+slip.month+'.html';
    a.click(); URL.revokeObjectURL(url);
  }

  function exportCSV(){
    const rows=[
      ['Gehaltsabrechnung',c.monthLabel||slip.month,'',''],
      ['Name',slip.first_name+' '+slip.last_name,'',''],
      ['Personal-ID',slip.staff_number||'','',''],
      ['','','',''],
      ['Bruttogehalt regulär',c.grossRegular||'','€',''],
      ['Gesamt Zuschläge',c.grossSurcharges||'','€',''],
      ['Boni',c.totalBonuses||'','€',''],
      ['KV Arbeitgeber',c.kvEmployer||'','€',''],
      ['Total Bruttogehalt',c.grossTotal||slip.gross,'€',''],
      ['','','',''],
      ['Rentenbeitrag AN',c.pensionEmployee||'','€',''],
      ['Rentenbeitrag AG',c.pensionEmployer||'','€',''],
      ['Einkommensteuer',c.incomeTax||'','€',''],
      ['KV Arbeitnehmer',c.kvEmployee||'','€',''],
      ['','','',''],
      ['NETTO ZU AUSZAHLUNG',c.netPay||slip.net,'€',''],
    ];
    const csv='\uFEFF'+rows.map(r=>r.map(v=>'"'+String(v||'').replace(/"/g,'""')+'"').join(';')).join('\n');
    const blob=new Blob([csv],{type:'text/csv;charset=utf-8'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');
    a.href=url; a.download='Gehaltsabrechnung_'+slip.first_name+'_'+slip.month+'.csv';
    a.click(); URL.revokeObjectURL(url);
  }

  function sendEmail(){
    const sub=encodeURIComponent('Gehaltsabrechnung '+(c.monthLabel||slip.month)+' — '+slip.first_name+' '+slip.last_name);
    const body=encodeURIComponent('Liebe/r '+slip.first_name+',\n\nIhre Gehaltsabrechnung für '+(c.monthLabel||slip.month)+':\n\nBruttogehalt: '+eur(c.grossTotal||slip.gross)+'\nNetto: '+eur(c.netPay||slip.net)+'\n\nMit freundlichen Grüßen\nJSR BPO GmbH');
    window.open('mailto:'+(slip.emp&&slip.emp.email||slip.email||'')+'?subject='+sub+'&body='+body);
  }

  return(
    <div className="modal-overlay">
      <div className="modal" style={{width:'96vw',maxWidth:1100,maxHeight:'97vh',display:'flex',flexDirection:'column'}}>

        {/* Header */}
        <div className="modal-header" style={{flexShrink:0}}>
          <div>
            <div style={{fontWeight:700,fontSize:15}}>
              Gehaltsabrechnung — {slip.first_name} {slip.last_name}
            </div>
            <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>
              {c.monthLabel||slip.month} · #{slip.staff_number||'—'}
              {isLocked&&<span style={{marginLeft:10,fontSize:11,padding:'2px 8px',borderRadius:20,background:'var(--green-bg)',color:'var(--green)',fontWeight:700,border:'1px solid rgba(5,150,105,.2)'}}>🔒 Freigegeben & gesperrt</span>}
              {!isLocked&&isApproved&&<span style={{marginLeft:10,fontSize:11,padding:'2px 8px',borderRadius:20,background:'var(--blue-bg)',color:'var(--blue)',fontWeight:700}}>✅ Bestätigt</span>}
              {!isApproved&&<span style={{marginLeft:10,fontSize:11,padding:'2px 8px',borderRadius:20,background:'rgba(217,119,6,.1)',color:'var(--amber)',fontWeight:700}}>✏ Entwurf</span>}
            </div>
          </div>
          <button className="btn" onClick={onClose}>×</button>
        </div>

        {/* Approval warning bar */}
        {!isApproved&&(
          <div style={{padding:'8px 16px',background:'rgba(217,119,6,.08)',borderBottom:'1px solid rgba(217,119,6,.2)',display:'flex',alignItems:'center',gap:10,flexShrink:0}}>
            <span style={{fontSize:18}}>⚠️</span>
            <span style={{fontSize:12,color:'var(--amber)',fontWeight:600,flex:1}}>
              Bitte prüfen und freigeben — erst danach kann die Abrechnung heruntergeladen oder versandt werden.
            </span>
            {onApprove&&(
              <button className="btn btn-primary" style={{background:'var(--green)',border:'none',flexShrink:0}}
                onClick={onApprove}>
                ✅ Jetzt freigeben
              </button>
            )}
          </div>
        )}

        {/* IFRAME PREVIEW */}
        <div style={{flex:1,overflow:'hidden',background:'#f1f5f9',padding:'8px',minHeight:0}}>
          <iframe
            ref={iframeRef}
            style={{width:'100%',height:'100%',border:'none',borderRadius:6,background:'#fff',
              boxShadow:'0 2px 12px rgba(0,0,0,.1)'}}
            title="Gehaltsabrechnung Vorschau"
          />
        </div>

        {/* Footer actions */}
        <div className="modal-footer" style={{flexShrink:0,flexWrap:'wrap',gap:6}}>
          {onRetract&&!isLocked&&(
            <button className="btn btn-sm" style={{color:'var(--red)',marginRight:'auto'}} onClick={onRetract}>
              ↩ Zurückziehen
            </button>
          )}
          {isApproved?(
            <>
              <button className="btn btn-sm" onClick={sendEmail}>✉ E-Mail</button>
              <button className="btn btn-sm" onClick={printSlip}>🖨 Drucken</button>
              <button className="btn btn-sm" onClick={exportCSV}>📊 CSV</button>
              <button className="btn btn-sm" style={{background:'var(--blue)',color:'white',border:'none'}} onClick={downloadSlip}>⬇ Download</button>
            </>
          ):(
            <span style={{fontSize:11,color:'var(--muted)',alignSelf:'center',marginLeft:'auto'}}>
              Erst freigeben um herunterzuladen
            </span>
          )}
          <button className="btn" onClick={onClose}>Schließen</button>
        </div>

      </div>
    </div>
  );
}

