function PayslipArchiveView({payslips, employees, projects, fmtMonth, eur, onOpen}){
  const [filterEmp, setFilterEmp] = useState('all');
  const [filterYear, setFilterYear] = useState(new Date().getFullYear().toString());

  // Flatten all slips
  const allSlips = Object.entries(payslips||{}).flatMap(([month,slips])=>
    (slips||[]).map(s=>({...s,month}))
  ).filter(s=>filterYear==='all'||s.month?.startsWith(filterYear))
   .filter(s=>filterEmp==='all'||s.emp_id===filterEmp)
   .sort((a,b)=>b.month?.localeCompare(a.month));

  const years=[...new Set(Object.keys(payslips||{}).map(m=>m.slice(0,4)))].sort().reverse();
  const emps=[...new Set(allSlips.map(s=>s.emp_id))].map(id=>(employees||[]).find(e=>e.id===id)).filter(Boolean);

  return(
    <div>
      <div style={{display:'flex',gap:10,marginBottom:14,flexWrap:'wrap'}}>
        <select className="form-select" style={{width:140}} value={filterYear} onChange={e=>setFilterYear(e.target.value)}>
          <option value="all">Alle Jahre</option>
          {years.map(y=><option key={y} value={y}>{y}</option>)}
        </select>
        <select className="form-select" style={{width:220}} value={filterEmp} onChange={e=>setFilterEmp(e.target.value)}>
          <option value="all">Alle Mitarbeiter</option>
          {emps.map(e=><option key={e.id} value={e.id}>{e.first_name} {e.last_name} (#{e.staff_number})</option>)}
        </select>
        <span style={{fontSize:12,color:'var(--muted)',alignSelf:'center'}}>{allSlips.length} Abrechnungen</span>
      </div>

      <div className="card">
        <table>
          <thead><tr>
            <th>Monat</th><th>Mitarbeiter</th><th style={{textAlign:'right'}}>Brutto</th>
            <th style={{textAlign:'right'}}>Netto</th><th>Status</th><th>Aktionen</th>
          </tr></thead>
          <tbody>
            {allSlips.length===0&&<tr><td colSpan={6} style={{textAlign:'center',padding:24,color:'var(--muted)'}}>Keine Abrechnungen im Archiv</td></tr>}
            {allSlips.map((s,i)=>{
              const cfg=JSON.parse(localStorage.getItem('jsr_payroll_cfg_al') || localStorage.getItem('jsr_payroll_cfg_xk') || '{}'||'{}');
              const salaryData=JSON.parse(localStorage.getItem('jsr_payroll_v1')||'{}');
              const rec=((salaryData[s.month]||[]).find(r=>r.emp_id===s.emp_id))||{};
              const P=calcAlbanianPayroll({...s,_rec:rec},cfg);
              const statusCfg={
                draft:{label:'✏ Entwurf',color:'var(--amber)'},
                confirmed:{label:'✅ Bestätigt',color:'var(--blue)'},
                paid:{label:'🔒 Freigegeben',color:'var(--green)'},
              }[s.status]||{label:s.status,color:'var(--muted)'};
              return(
                <tr key={i} className="table-row-hover" onClick={()=>onOpen(s)}>
                  <td style={{fontWeight:600}}>{fmtMonth(s.month)}</td>
                  <td>
                    <div style={{fontWeight:600,fontSize:13}}>{s.first_name} {s.last_name}</div>
                    <div style={{fontSize:11,color:'var(--muted)'}}>#{s.staff_number}</div>
                  </td>
                  <td style={{textAlign:'right',fontFamily:'var(--mono)',fontWeight:700}}>{eur(s.gross||P.grossTotal)}</td>
                  <td style={{textAlign:'right',fontFamily:'var(--mono)',fontWeight:700,color:'var(--green)'}}>{eur(P.netPay)}</td>
                  <td><span style={{fontSize:11,fontWeight:700,color:statusCfg.color}}>{statusCfg.label}</span></td>
                  <td onClick={e=>e.stopPropagation()}>
                    <button className="btn btn-sm" onClick={()=>onOpen(s)}>👁 Öffnen</button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

PayslipEngine:
// ══════════════════════════════════════════════════════════════════════════════
// PAYSLIP ENGINE — Full Albanian payroll calculation
// ══════════════════════════════════════════════════════════════════════════════

function getPayrollCfg(location){
  // jsr_payroll_cfg_al = Albanien (Tirana), jsr_payroll_cfg_xk = Kosovo (Prishtina)
  const isKosovo = location && (
    String(location).toLowerCase().includes('prishtina') ||
    String(location).toLowerCase().includes('pristina') ||
    String(location).toLowerCase().includes('kosovo') ||
    String(location).toLowerCase() === 'xk'
  );
  const key = isKosovo ? 'jsr_payroll_cfg_xk' : 'jsr_payroll_cfg_al';
  try{ return JSON.parse(localStorage.getItem(key)||'null') || {}; }
  catch(e){ return {}; }
}

function calcFullPayslip(emp, month, salaryRec, employees, absences){
  const cfg = getPayrollCfg(emp.location||emp.location_id||'');
  const r   = parseFloat(emp.hourly_rate||0);
  const hpd = parseFloat(emp.work_hours||8);

  // ── WORK DAYS ──────────────────────────────────────────────────────────────
  const [y,m] = month.split('-').map(Number);
  let weekdays=0; const d=new Date(y,m-1,1);
  while(d.getMonth()===m-1){if(d.getDay()>0&&d.getDay()<6)weekdays++;d.setDate(d.getDate()+1);}
  const monthTarget = weekdays * hpd;

  // ── SURCHARGE CONFIG ───────────────────────────────────────────────────────
  const sc = JSON.parse(localStorage.getItem('jsr_surcharge_cfg')||'{}');
  const P  = (k,def)=>((sc[k]!==undefined?sc[k]:def)/100);
  const saP=P('surcharge_saturday',20), suP=P('surcharge_sunday',50);
  const hoP=P('surcharge_holiday',50),  niP=P('surcharge_night',25);
  const otP=P('surcharge_overtime',30);

  // ── HOURS ──────────────────────────────────────────────────────────────────
  const rec = salaryRec||{};
  const totalWorked = parseFloat(rec.total_worked_hours||monthTarget);
  const saH = parseFloat(rec.saturday_hours||0);
  const suH = parseFloat(rec.sunday_hours||0);
  const hoH = parseFloat(rec.holiday_hours||0);
  const niH = parseFloat(rec.night_hours||0);
  const overtimeH = Math.max(0, totalWorked - monthTarget);
  const specialH  = saH+suH+hoH;
  const pureOtH   = Math.max(0, overtimeH - specialH);
  const isOT      = overtimeH > 0;
  const saRate    = Math.max(saP, isOT?otP:0);
  const suRate    = Math.max(suP, isOT?otP:0);
  const hoRate    = Math.max(hoP, isOT?otP:0);
  const niRate    = Math.max(niP, isOT?otP:0);

  // Categorize overtime hours by bracket (20%/30%/50%)
  const h20 = saH * (saRate===0.20?1:0);
  const h30 = pureOtH + saH*(saRate===0.30?1:0) + suH*(suRate===0.30?1:0) + hoH*(hoRate===0.30?1:0) + niH*(niRate===0.30?1:0);
  const h50 = suH*(suRate===0.50?1:0) + hoH*(hoRate===0.50?1:0) + niH*(niRate===0.50?1:0);

  // ── ABSENCE / DEDUCTIONS ──────────────────────────────────────────────────
  const absenceDays = parseFloat(rec.deduction_absence_days||0);
  const dailyRate   = r * hpd;
  const absenceDeduct = Math.round(absenceDays * dailyRate * 100)/100;
  const advanceDeduct = parseFloat(rec.deduction_social||0); // Vorschuss
  const otherDeduct   = parseFloat(rec.deduction_other||0);

  // ── REGULAR GROSS ─────────────────────────────────────────────────────────
  const regularHours = Math.max(0, monthTarget - absenceDays*hpd);
  const grossRegular = Math.round(regularHours * r * 100)/100;

  // ── SURCHARGE GROSS ───────────────────────────────────────────────────────
  const gross20 = Math.round(h20 * r * saRate * 100)/100;
  const gross30 = Math.round(h30 * r * otP    * 100)/100;
  const gross50 = Math.round(h50 * r * suRate * 100)/100;
  const grossSurcharges = gross20 + gross30 + gross50;

  // ── BONUSES ───────────────────────────────────────────────────────────────
  const bonusPerf    = parseFloat(rec.target_bonus||0);
  const bonusSpecial = parseFloat(rec.special_bonus||0);
  const bonusReferral= parseFloat(rec.referral_bonus||0);
  const totalBonuses = bonusPerf + bonusSpecial + bonusReferral;

  // ── KV (Krankenversicherung) ───────────────────────────────────────────────
  // Country-specific fallback defaults
  const isKv = (emp.location||'').toLowerCase().includes('prishtina')||(emp.location||'').toLowerCase().includes('kosovo');
  const defKvEr = isKv ? 0     : 35.08;
  const defKvEe = isKv ? 0     : 30.00;
  const defB1   = isKv ? 0     : 250;
  const defB2   = isKv ? 960   : 450;
  const defT1   = isKv ? 0     : 0;
  const defT2   = isKv ? 4     : 8;
  const defT3   = isKv ? 10    : 10;
  const kvEmployer = parseFloat(cfg.kv_employer!==undefined?cfg.kv_employer:defKvEr);
  const kvEmployee = parseFloat(cfg.kv_employee!==undefined?cfg.kv_employee:defKvEe);

  // ── GROSS TOTAL ───────────────────────────────────────────────────────────
  const grossTotal = grossRegular + grossSurcharges + totalBonuses + kvEmployer;

  // ── PENSION ───────────────────────────────────────────────────────────────
  const pensionEmpPct = parseFloat(cfg.pension_employee_pct!==undefined?cfg.pension_employee_pct:5)/100;
  const pensionEmrPct = parseFloat(cfg.pension_employer_pct!==undefined?cfg.pension_employer_pct:5)/100;
  const pensionEmployee = Math.round(grossTotal * pensionEmpPct * 100)/100;
  const pensionEmployer = Math.round(grossTotal * pensionEmrPct * 100)/100;
  const pensionTotal    = pensionEmployee + pensionEmployer;

  // ── INCOME TAX ────────────────────────────────────────────────────────────
  const taxableIncome = grossTotal - pensionEmployee;
  const b1max = parseFloat(cfg.tax_bracket1_max!==undefined?cfg.tax_bracket1_max:defB1);
  const b2max = parseFloat(cfg.tax_bracket2_max!==undefined?cfg.tax_bracket2_max:defB2);
  const b1pct = parseFloat(cfg.tax_bracket1_pct!==undefined?cfg.tax_bracket1_pct:defT1)/100;
  const b2pct = parseFloat(cfg.tax_bracket2_pct!==undefined?cfg.tax_bracket2_pct:defT2)/100;
  const b3pct = parseFloat(cfg.tax_bracket3_pct!==undefined?cfg.tax_bracket3_pct:defT3)/100;
  let incomeTax=0;
  if(taxableIncome>b2max){
    incomeTax = Math.round(((b1max*b1pct) + ((b2max-b1max)*b2pct) + ((taxableIncome-b2max)*b3pct))*100)/100;
  } else if(taxableIncome>b1max){
    incomeTax = Math.round(((b1max*b1pct) + ((taxableIncome-b1max)*b2pct))*100)/100;
  } else {
    incomeTax = Math.round(taxableIncome*b1pct*100)/100;
  }

  // ── NET ───────────────────────────────────────────────────────────────────
  const netPay = Math.round((grossTotal - pensionEmployee - incomeTax - kvEmployee - absenceDeduct - advanceDeduct - otherDeduct)*100)/100;

  // ── VACATION ──────────────────────────────────────────────────────────────
  const vacCalc = calcVacationEntitlement(emp, month);
  const vacationQuota = vacCalc.quota;
  const vacUsed  = vacCalc.used;
  const vacLeft  = vacCalc.remaining;
  // Absences stored in emp.absences[] within jsr_emp_v3 - no separate key
  const absRec = (emp.absences||[]);
  const vacMonth= absRec.filter(a=>a.type==='vacation'&&(a.date||'').startsWith(month)).length;
  const sickYear= absRec.filter(a=>a.type==='sick'&&(a.date||'').startsWith(month.slice(0,4))).length;
  const sickMonth=absRec.filter(a=>a.type==='sick'&&(a.date||'').startsWith(month)).length;

  return {
    // Meta
    emp, month, monthLabel: new Date(y,m-1,1).toLocaleDateString('de-DE',{month:'long',year:'numeric'}),
    weekdays, hpd, r,
    // Hours
    monthTarget, totalWorked, regularHours,
    saH, suH, hoH, niH, overtimeH, pureOtH, specialH,
    h20, h30, h50, saRate, suRate, hoRate,
    // Gross
    grossRegular, gross20, gross30, gross50, grossSurcharges,
    // Bonuses
    bonusPerf, bonusSpecial, bonusReferral, totalBonuses,
    // KV
    kvEmployer, kvEmployee,
    // Gross total
    grossTotal,
    // Pension
    pensionEmpPct, pensionEmrPct, pensionEmployee, pensionEmployer, pensionTotal,
    // Tax
    taxableIncome, b1max, b2max, b1pct, b2pct, b3pct, incomeTax,
    // Deductions
    absenceDays, absenceDeduct, advanceDeduct, otherDeduct,
    // Net
    netPay,
    // Vacation
    vacationQuota, vacUsed, vacMonth, vacLeft, sickYear, sickMonth,
  };
}

