// ══════════════════════════════════════════════════════════════════════════════
// GOOGLE SHEET SYNC ENGINE
// Sheet: 1SU1OoiHH1zYUN7BsXreossjWijqintl9zcJw3asBM2k
// Columns: A=Zeitstempel B=Name C=Telefon D=Deutsch E=CC-Erfahrung F=CC-Name G=Start H=Arbeitszeit
// ══════════════════════════════════════════════════════════════════════════════

async function syncGoogleDoc(cfg, dryRun){
  const docId = (cfg&&cfg.doc_id) || '1SU1OoiHH1zYUN7BsXreossjWijqintl9zcJw3asBM2k';
  const gid   = (cfg&&cfg.gid)    || '817355119';

  const url = 'https://docs.google.com/spreadsheets/d/'+docId+'/gviz/tq?tqx=out:csv&gid='+gid;

  const resp = await fetch(url);
  if(!resp.ok) throw new Error('HTTP '+resp.status+' — Sheet nicht erreichbar. Bitte "Jeder mit dem Link kann ansehen" setzen.');
  const text = await resp.text();

  // CSV parser
  function parseCSV(text){
    const lines = text.split('\n').filter(l=>l.trim());
    return lines.map(line=>{
      const cols=[]; let cur=''; let inQ=false;
      for(let i=0;i<line.length;i++){
        const ch=line[i];
        if(ch==='"'&&!inQ){inQ=true;}
        else if(ch==='"'&&inQ&&line[i+1]==='"'){cur+='"';i++;}
        else if(ch==='"'&&inQ){inQ=false;}
        else if(ch===','&&!inQ){cols.push(cur.trim());cur='';}
        else{cur+=ch;}
      }
      cols.push(cur.trim());
      return cols;
    });
  }

  const rows = parseCSV(text);
  const dataRows = rows.slice(1); // skip header row
  if(dryRun) return dataRows.length;

  // Column mapping (0-indexed):
  // A=0 Zeitstempel | B=1 Vor- und Nachname | C=2 Telefonnummer
  // D=3 Deutschniveau | E=4 CC-Erfahrung | F=5 CC-Name | G=6 Startdatum | H=7 Arbeitszeit
  // Override with cfg if set
  function ci(letter, fallback){
    if(cfg&&cfg['col_'+letter]) return cfg['col_'+letter].toUpperCase().charCodeAt(0)-65;
    return fallback;
  }
  const COL = {
    date:       ci('date',    0),  // A Zeitstempel
    fullname:   ci('name',    1),  // B Vor- und Nachname
    phone:      ci('phone',   2),  // C Telefonnummer
    level:      ci('level',   3),  // D Deutschniveau
    cc_exp:     ci('cc_exp',  4),  // E CC-Erfahrung
    cc_name:    ci('cc_name', 5),  // F CC-Name
    start_date: ci('start',   6),  // G Wann anfangen
    work_hours: ci('hours',   7),  // H Arbeitszeit
  };

  // Load existing CVs for dedup
  let existing = [];
  try{ existing = JSON.parse(localStorage.getItem('jsr_cvs_v1')||'[]'); }catch(e){}
  const existingPhones = new Set(existing.map(c=>(c.phone||'').replace(/\s/g,'').replace(/^\+/,'')));

  const today = new Date().toISOString().slice(0,10);
  let added = 0;

  dataRows.forEach((row, i)=>{
    const fullname   = (row[COL.fullname]||'').trim();
    const phone      = (row[COL.phone]||'').trim();
    const rawDate    = (row[COL.date]||'').trim();
    const level      = (row[COL.level]||'').trim();
    const ccExp      = (row[COL.cc_exp]||'').trim();
    const ccName     = (row[COL.cc_name]||'').trim();
    const startDate  = (row[COL.start_date]||'').trim();
    const workHours  = (row[COL.work_hours]||'').trim();

    if(!fullname && !phone) return;

    // Dedup by phone number (normalized)
    const phoneNorm = phone.replace(/\s/g,'').replace(/^\+/,'');
    if(phoneNorm && existingPhones.has(phoneNorm)) return;
    if(phoneNorm) existingPhones.add(phoneNorm);

    // Split full name into first + last
    const nameParts = fullname.split(/\s+/);
    const firstName = nameParts[0]||'';
    const lastName  = nameParts.slice(1).join(' ')||'';

    // Parse entry date from timestamp (DD.MM.YYYY or MM/DD/YYYY or ISO)
    let cvDate = today;
    if(rawDate){
      const dmy = rawDate.match(/(\d{1,2})\.(\d{1,2})\.(\d{4})/);
      const mdy = rawDate.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/);
      const iso = rawDate.match(/(\d{4})-(\d{2})-(\d{2})/);
      if(dmy)      cvDate = dmy[3]+'-'+dmy[2].padStart(2,'0')+'-'+dmy[1].padStart(2,'0');
      else if(mdy) cvDate = mdy[3]+'-'+mdy[1].padStart(2,'0')+'-'+mdy[2].padStart(2,'0');
      else if(iso) cvDate = iso[0];
    }

    // Map Arbeitszeit to work_hours value
    let workHoursVal = '8';
    if(workHours){
      if(workHours.includes('4')||workHours.toLowerCase().includes('teilzeit')||workHours.includes('halbt')) workHoursVal='4';
      else if(workHours.includes('6')) workHoursVal='6';
      else if(workHours.includes('8')||workHours.toLowerCase().includes('vollzeit')||workHours.toLowerCase().includes('full')) workHoursVal='8';
    }

    // Build work_history note
    let workHistory = '';
    if(ccExp&&ccExp.toLowerCase()!=='nein'&&ccExp!=='0'&&ccExp!=='') workHistory += 'CC-Erfahrung: '+ccExp;
    if(ccName) workHistory += (workHistory?' · ':'')+ccName;

    const cv = {
      id:             'cv_gs_'+Date.now()+'_'+i,
      status:         'cv_inbound',
      source:         'Google Sheet',
      cv_date:        cvDate,
      first_name:     firstName,
      last_name:      lastName,
      phone:          phone,
      email:          '',
      language_level: level,
      work_hours:     workHoursVal,
      available_from: startDate,
      work_history:   workHistory,
      notes:          'Import: '+new Date().toLocaleDateString('de-DE')+(rawDate?' · Eingang: '+rawDate:''),
      photo_color:    '#7c3aed',
    };
    existing.push(cv);
    added++;
  });

  if(added>0){
    localStorage.setItem('jsr_cvs_v1', JSON.stringify(existing));
    localStorage.setItem('jsr_gdoc_last_sync', new Date().toISOString());
    localStorage.setItem('jsr_gdoc_last_count', String(added));
  } else {
    localStorage.setItem('jsr_gdoc_last_sync', new Date().toISOString());
    localStorage.setItem('jsr_gdoc_last_count', '0');
  }

  return added;
}

// ── AUTO-SCHEDULER: 08:00 / 12:00 / 17:00 ──────────────────────────────────
(function scheduleGDocSync(){
  const SYNC_HOURS = [8, 12, 17];
  function msUntilNext(){
    const now = new Date();
    for(const h of SYNC_HOURS){
      const next = new Date(now); next.setHours(h,0,0,0);
      if(next > now) return next - now;
    }
    const tomorrow = new Date(now); tomorrow.setDate(tomorrow.getDate()+1); tomorrow.setHours(8,0,0,0);
    return tomorrow - now;
  }
  function doSync(){
    const cfg = JSON.parse(localStorage.getItem('jsr_gdoc_sync')||'{}');
    syncGoogleDoc(cfg, false)
      .then(n=>{ if(n>0){ console.log('[GDoc] '+n+' neue Bewerber'); window.dispatchEvent(new Event('jsr_cvs_updated')); }})
      .catch(e=>console.warn('[GDoc Sync Fehler]', e.message));
    setTimeout(doSync, msUntilNext());
  }
  setTimeout(doSync, msUntilNext());
})();

