// VACATION ENTITLEMENT ENGINE
// Calculates vacation days based on contract start, seniority, admin config
// ══════════════════════════════════════════════════════════════════════════════
function calcVacationEntitlement(emp, forMonth){
  // Only active employees get vacation
  if(!emp||!['active'].includes(emp.status)) return {quota:0,used:0,remaining:0,note:'Kein Anspruch (nicht aktiv)'};

  const startDate = emp.contract_start||emp.start_date||'';
  if(!startDate) return {quota:0,used:0,remaining:0,note:'Kein Startdatum'};

  const cfg = JSON.parse(localStorage.getItem('jsr_vacation_cfg')||'null')||{year1_days:18,year2_days:20,seniority:[]};
  const start = new Date(startDate);
  const refDate = forMonth ? new Date(forMonth+'-01') : new Date();
  const refYear = refDate.getFullYear();

  // Years of service at reference date
  const yearsOfService = (refDate - start) / (365.25 * 24 * 3600 * 1000);

  // Base days per year based on service year
  let baseDays = yearsOfService < 1 ? cfg.year1_days : cfg.year2_days;

  // Extra days from seniority brackets
  const seniority = (cfg.seniority||[]).sort((a,b)=>b.years_from-a.years_from);
  for(const s of seniority){
    if(yearsOfService >= s.years_from){
      baseDays += (s.extra_days||0);
      break;
    }
  }

  // Calculate PROPORTIONAL quota for this calendar year
  // Start of this year or contract start (whichever is later)
  const yearStart = new Date(refYear+'-01-01');
  const yearEnd   = new Date(refYear+'-12-31');
  const effectiveStart = start > yearStart ? start : yearStart;
  const effectiveEnd   = refDate < yearEnd ? refDate : yearEnd;

  // Days in the year the employee has been/will be active
  const daysInYear = (yearEnd - yearStart) / (24*3600*1000) + 1; // 365 or 366
  const activeDays = Math.max(0, (effectiveEnd - effectiveStart) / (24*3600*1000) + 1);
  const quota = Math.round(baseDays * activeDays / daysInYear * 10) / 10;

  // Count used vacation days this year
  let used = 0;
  try{
    // Absences are stored in emp.absences[] within jsr_emp_v3
    const empData = emp || JSON.parse(localStorage.getItem('jsr_emp_v3')||'[]').find(e=>e.id===emp.id) || {};
    const absences = empData.absences || [];
    used = absences.filter(a=>
      a.type==='vacation' &&
      (a.date||'').startsWith(String(refYear))
    ).length;
  }catch(e){}

  const remaining = Math.max(0, Math.round((quota - used)*10)/10);

  return {
    quota,
    used,
    remaining,
    baseDays,
    yearsOfService: Math.round(yearsOfService*10)/10,
    note: yearsOfService<1
      ? '1. Jahr: '+cfg.year1_days+' Tage/Jahr → anteilig '+quota+' Tage'
      : 'Ab 2. Jahr: '+cfg.year2_days+' Tage/Jahr → anteilig '+quota+' Tage',
  };
}

