function savePerfData(d){ localStorage.setItem('jsr_perf_v1', JSON.stringify(d)); }

// Get ISO week number
function getISOWeek(date){
  const d = new Date(date);
  d.setHours(0,0,0,0);
  d.setDate(d.getDate()+4-(d.getDay()||7));
  const yearStart = new Date(d.getFullYear(),0,1);
  return {kw: Math.ceil((((d-yearStart)/86400000)+1)/7), year: d.getFullYear()};
}

// Get monday of a given week
function weekMonday(year, kw){
  const jan4 = new Date(year,0,4);
  const jan4Day = jan4.getDay()||7;
  const monday = new Date(jan4.getTime() - (jan4Day-1)*86400000 + (kw-1)*7*86400000);
  return monday.toISOString().slice(0,10);
}

// Evaluate a value against thresholds
function evalKpi(kpi, value){
  if(value===null||value===undefined||value==='') return null;
  const v = parseFloat(value);
  if(isNaN(v)) return null;
  // For AHT: lower thresholds checked first (min=0 catches <14)
  for(const t of kpi.thresholds){
    if(v>=t.min && v<=t.max) return t;
  }
  return kpi.thresholds[kpi.thresholds.length-1]; // fallback to last
}

// Get KPIs relevant for an employee (by project + skills)
function getEmpKpis(emp){
  const cfg = getKpiCfg();
  const projSkill = emp.project_skill||emp.primary_skill||'';
  return cfg.filter(k=>{
    // Strict match: KPI must match employee's project AND skill
    // If KPI has no project restriction → show for all (legacy/global KPIs)
    const projOk = !k.project_id || k.project_id===emp.project_id;
    // If KPI has no skill restriction → show for all on that project
    const skillOk = !k.skill || (projSkill && k.skill===projSkill);
    return projOk && skillOk;
  });
}

// Get performance entries for employee, week
function getEmpWeekPerf(empId, year, kw){
  const data = getPerfData();
  return (data[empId]||[]).filter(e=>e.year===year&&e.kw===kw);
}

// Get last N weeks with entries for employee
function getEmpPerfHistory(empId, n=12){
  const data = getPerfData();
  const entries = data[empId]||[];
  const weeks = {};
  entries.forEach(e=>{ const key=e.year+'-'+String(e.kw).padStart(2,'0'); if(!weeks[key])weeks[key]=[]; weeks[key].push(e); });
  return Object.entries(weeks).sort((a,b)=>b[0].localeCompare(a[0])).slice(0,n).map(([k,v])=>({key:k,entries:v,year:parseInt(k),kw:parseInt(k.split('-')[1])}));
}

