function PerformanceView({employees, projects}){
  const now = new Date();
  const {kw: currentKw, year: currentYear} = getISOWeek(now);
  const [selKw, setSelKw] = useState(currentKw);
  const [selYear, setSelYear] = useState(currentYear);
  const [selProj, setSelProj] = useState('all');
  const [editEmp, setEditEmp] = useState(null);
  const [entries, setEntries] = useState({});
  const [saved, setSaved] = useState(false);
  const [rankView, setRankView] = useState(false);

  const activeEmps = employees.filter(e=>e.status==='active');
  const kpiCfg = getKpiCfg();

  // Load entries for selected week
  useEffect(()=>{
    const data = getPerfData();
    const weekEntries = {};
    activeEmps.forEach(emp=>{
      const empEntries = (data[emp.id]||[]).filter(e=>e.kw===selKw&&e.year===selYear);
      if(empEntries.length) weekEntries[emp.id] = empEntries;
    });
    setEntries(weekEntries);
  },[selKw, selYear]);

  const filteredEmps = selProj==='all' ? activeEmps : activeEmps.filter(e=>e.project_id===selProj);

  // Get KW options (current + last 12 weeks)
  const kwOptions = [];
  for(let i=0; i<12; i++){
    let kw=currentKw-i, yr=currentYear;
    if(kw<=0){kw+=52;yr--;}
    kwOptions.push({kw,yr});
  }

  function openEdit(emp){
    const data = getPerfData();
    const existing = (data[emp.id]||[]).filter(e=>e.kw===selKw&&e.year===selYear);
    const vals = {};
    existing.forEach(e=>{ vals[e.kpi_id]=e.value; });
    setEditEmp({emp, vals});
  }

  function saveEntry(){
    if(!editEmp) return;
    const {emp, vals} = editEmp;
    const data = getPerfData();
    if(!data[emp.id]) data[emp.id]=[];
    // Remove old entries for this week
    data[emp.id] = data[emp.id].filter(e=>!(e.kw===selKw&&e.year===selYear));
    // Add new entries
    const empKpis = getEmpKpis(emp); // uses emp.project_skill as KEY
    empKpis.forEach(kpi=>{
      const v = vals[kpi.id];
      if(v!==undefined&&v!==''){
        data[emp.id].push({kpi_id:kpi.id, value:parseFloat(v), kw:selKw, year:selYear, ts:Date.now()});
      }
    });
    savePerfData(data);
    // Reload
    const weekEntries = {};
    activeEmps.forEach(e=>{
      const empEntries = (data[e.id]||[]).filter(en=>en.kw===selKw&&en.year===selYear);
      if(empEntries.length) weekEntries[e.id] = empEntries;
    });
    setEntries(weekEntries);
    setEditEmp(null);
    setSaved(true);
    setTimeout(()=>setSaved(false),2000);
  }

  const BADGE = (kpi, value)=>{
    const t = evalKpi(kpi, value);
    if(!t) return <span style={{color:'var(--dim)',fontSize:11}}>—</span>;
    return(
      <span style={{padding:'2px 8px',borderRadius:20,background:t.bg,color:t.color,
        fontWeight:700,fontSize:11,whiteSpace:'nowrap'}}>
        {t.icon} {t.label}
      </span>
    );
  };

  // Ranking for current week by project
  const getRanking = (projId)=>{
    const projEmps = activeEmps.filter(e=>e.project_id===projId);
    const scored = projEmps.map(emp=>{
      const empKpis = getEmpKpis(emp); // uses emp.project_skill as KEY
      const empEntries = (entries[emp.id]||[]);
      if(!empEntries.length) return null;
      // Simple score: count "green" (excellent) thresholds hit
      let score=0, total=0;
      empKpis.forEach(kpi=>{
        const entry = empEntries.find(e=>e.kpi_id===kpi.id);
        if(!entry) return;
        const t = evalKpi(kpi, entry.value);
        if(!t) return;
        total++;
        const idx = kpi.thresholds.indexOf(t);
        score += (kpi.thresholds.length-idx); // higher = better
      });
      return {emp, score, total};
    }).filter(Boolean).sort((a,b)=>b.score-a.score);
    return scored;
  };

  return(
    <div>
      {/* Edit Modal */}
      {editEmp&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:560,maxWidth:"95vw"}}>
            <div className="modal-header">
              <div>
                <div style={{fontWeight:700,fontSize:15}}>
                  KW {selKw}/{selYear} — {editEmp.emp.first_name} {editEmp.emp.last_name}
                </div>
                <div style={{fontSize:12,color:'var(--muted)',marginTop:2}}>
                  {(projects.find(p=>p.id===editEmp.emp.project_id)||{}).name||''} ·{' '}
                  {(editEmp.emp.skills||[]).join(', ')||'—'}
                </div>
              </div>
              <button className="btn" onClick={()=>setEditEmp(null)}>×</button>
            </div>
            <div className="modal-body">
              {getEmpKpis(editEmp.emp).length===0&&(
                <div style={{padding:20,textAlign:'center',color:'var(--muted)',fontSize:13}}>
                  Keine KPIs für diesen Mitarbeiter konfiguriert.<br/>
                  Bitte im Admin unter "KPI-Konfiguration" anlegen.
                </div>
              )}
              {getEmpKpis(editEmp.emp).map(kpi=>{
                const val = editEmp.vals[kpi.id]??'';
                const t = evalKpi(kpi, val);
                return(
                  <div key={kpi.id} style={{marginBottom:16}}>
                    <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:6}}>
                      <label style={{fontWeight:700,fontSize:13}}>{kpi.name}</label>
                      {t&&<span style={{padding:'2px 10px',borderRadius:20,background:t.bg,color:t.color,fontWeight:700,fontSize:12}}>{t.icon} {t.label}</span>}
                    </div>
                    <div style={{display:'flex',alignItems:'center',gap:8}}>
                      <input type="number" step="0.01" value={val}
                        onChange={e=>setEditEmp(prev=>({...prev,vals:{...prev.vals,[kpi.id]:e.target.value}}))}
                        className="form-input"
                        style={{flex:1,fontSize:18,fontWeight:700,textAlign:'center',
                          borderColor:t?t.color:'var(--border)',color:t?t.color:'var(--text)'}}
                        placeholder={kpi.unit==='%'?'z.B. 55':'z.B. 14.5'}
                      />
                      <span style={{color:'var(--muted)',fontSize:13,minWidth:30}}>{kpi.unit||''}</span>
                    </div>
                    <div style={{display:'flex',gap:4,marginTop:6,flexWrap:'wrap'}}>
                      {kpi.thresholds.map((t,i)=>(
                        <span key={i} style={{fontSize:10,padding:'1px 6px',borderRadius:20,
                          background:t.bg,color:t.color,fontWeight:600}}>
                          {t.icon} {t.label}: {t.min}{kpi.unit==='%'?'%':''}{t.max<999?'–'+t.max+(kpi.unit==='%'?'%':''):'+'}{' '}
                        </span>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
            <div className="modal-footer">
              <button className="btn" onClick={()=>setEditEmp(null)}>Abbrechen</button>
              <button className="btn btn-primary" onClick={saveEntry}>💾 Speichern</button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:16,flexWrap:'wrap'}}>
        <div style={{fontWeight:800,fontSize:18}}>📊 Performance</div>
        <div style={{flex:1}}/>
        {saved&&<span style={{color:'var(--green)',fontWeight:700,fontSize:13}}>✓ Gespeichert</span>}
        <select className="form-select" style={{width:'auto'}} value={selProj} onChange={e=>setSelProj(e.target.value)}>
          <option value="all">Alle Projekte</option>
          {projects.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
        </select>
        <select className="form-select" style={{width:'auto'}} value={selKw+'-'+selYear}
          onChange={e=>{const [kw,yr]=e.target.value.split('-');setSelKw(parseInt(kw));setSelYear(parseInt(yr));}}>
          {kwOptions.map(({kw,yr})=>(
            <option key={kw+'-'+yr} value={kw+'-'+yr}>
              KW {kw}/{yr} {kw===currentKw&&yr===currentYear?'(aktuell)':''}
            </option>
          ))}
        </select>
        <button className="btn btn-sm" style={{background:rankView?'var(--blue)':'',color:rankView?'white':'',border:'1.5px solid var(--blue)'}}
