                    <div style={{fontSize:11,color:'var(--muted)'}}>{emp.project_skill||'kein Skill'} · {(emp.skills||[]).slice(0,2).join(', ')||'—'}</div>
                  </td>
                  <td>
                    {empKpis.length===0&&<span style={{fontSize:11,color:'var(--red)',fontWeight:600}}>⚠ Skill: {emp.project_skill||'—'}</span>}
                    {empKpis.length>0&&!hasData&&<span style={{fontSize:11,color:'var(--dim)'}}>Noch nicht eingetragen</span>}
                    {hasData&&(
                      <div style={{display:'flex',flexWrap:'wrap',gap:4}}>
                        {empKpis.map(kpi=>{
                          const entry = empEntries.find(e=>e.kpi_id===kpi.id);
                          if(!entry) return null;
                          const t = evalKpi(kpi, entry.value);
                          if(!t) return null;
                          return(
                            <span key={kpi.id} style={{padding:'2px 8px',borderRadius:20,
                              background:t.bg,color:t.color,fontWeight:700,fontSize:11}}>
                              {kpi.name}: {entry.value}{kpi.unit} {t.icon}
                            </span>
                          );
                        })}
                      </div>
                    )}
                  </td>
                  <td style={{textAlign:'center'}}>
                    <button className="btn btn-sm" style={{background:hasData?'var(--green)':'var(--blue)',color:'white',border:'none'}}
                      onClick={e=>{e.stopPropagation();openEdit(emp);}}>
                      {hasData?'✏ Bearbeiten':'+ Eintragen'}
                    </button>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table></div>
      </div>
    </div>
  );
}

