function PerformanceCard({emp, compact=false, showRank=false, allEmps=[], projects=[]}){
  // Get last week performance
  const now = new Date();
  const {kw: currentKw, year: currentYear} = getISOWeek(now);
  let kw = currentKw-1, yr = currentYear;
  if(kw<=0){kw+=52;yr--;}

  const kpiCfg = getKpiCfg();
  const empKpis = getEmpKpis(emp);
  const data = getPerfData();
  const entries = (data[emp.id]||[]).filter(e=>e.kw===kw&&e.year===yr);

  if(!entries.length||!empKpis.length) return null;

  // Overall score for loyalty badge
  let greenCount=0, yellowCount=0, redCount=0, total=0;
  const kpiResults = empKpis.map(kpi=>{
    const entry = entries.find(e=>e.kpi_id===kpi.id);
    if(!entry) return null;
    const t = evalKpi(kpi, entry.value);
    if(!t) return null;
    total++;
    const idx = kpi.thresholds.indexOf(t);
    if(idx===0) greenCount++;
    else if(idx===1) yellowCount++;
    else redCount++;
    return {kpi, entry, t};
  }).filter(Boolean);

  if(!kpiResults.length) return null;

  // Overall badge
  const overallBadge = greenCount===total
    ? {label:'Killer Performance 🔥', color:'#064e3b', bg:'#ecfdf5', icon:'🤩'}
    : greenCount+yellowCount===total
    ? {label:'Rockstar ⭐', color:'#065f46', bg:'#d1fae5', icon:'😎'}
    : redCount===0
    ? {label:'Gute Leistung 👍', color:'#92400e', bg:'#fef3c7', icon:'😊'}
    : {label:'Weiter kämpfen! 💪', color:'#991b1b', bg:'#fef2f2', icon:'😤'};

  // Ranking in same project
  let rank=null, rankTotal=null;
  if(showRank&&allEmps.length){
    const peers = allEmps.filter(e=>e.project_id===emp.project_id&&e.status==='active');
    const pData = getPerfData();
    const scored = peers.map(pe=>{
      const pKpis=getEmpKpis(pe), pEntries=(pData[pe.id]||[]).filter(e=>e.kw===kw&&e.year===yr);
      if(!pEntries.length) return {id:pe.id,score:0};
      let sc=0;
      pKpis.forEach(kpi=>{const en=pEntries.find(e=>e.kpi_id===kpi.id);if(!en)return;const t=evalKpi(kpi,en.value);if(!t)return;sc+=(kpi.thresholds.length-kpi.thresholds.indexOf(t));});
      return {id:pe.id,score:sc};
    }).sort((a,b)=>b.score-a.score);
    rank=(scored.findIndex(s=>s.id===emp.id))+1;
    rankTotal=scored.filter(s=>s.score>0).length;
  }

  const proj = projects.find(p=>p.id===emp.project_id);

  if(compact){
    return(
      <div style={{padding:'10px 14px',background:overallBadge.bg,borderRadius:'var(--r)',
        border:'1px solid '+overallBadge.color+'33',display:'flex',alignItems:'center',gap:10}}>
        <span style={{fontSize:24}}>{overallBadge.icon}</span>
        <div style={{flex:1}}>
          <div style={{fontWeight:800,color:overallBadge.color,fontSize:14}}>{overallBadge.label}</div>
          <div style={{fontSize:11,color:overallBadge.color,opacity:.7}}>KW {kw}/{yr}</div>
        </div>
        {rank&&<div style={{textAlign:'center'}}>
          <div style={{fontWeight:900,fontSize:18,color:overallBadge.color}}>#{rank}</div>
          <div style={{fontSize:9,color:overallBadge.color,opacity:.7}}>von {rankTotal}</div>
        </div>}
      </div>
    );
  }

  return(
    <div className="card">
      {/* Header */}
      <div style={{padding:'12px 14px',borderBottom:'1px solid var(--border)',
        display:'flex',alignItems:'center',gap:12,
        background:'linear-gradient(135deg,'+overallBadge.bg+',white)'}}>
        <span style={{fontSize:32}}>{overallBadge.icon}</span>
        <div style={{flex:1}}>
          <div style={{fontWeight:900,fontSize:15,color:overallBadge.color}}>{overallBadge.label}</div>
          <div style={{fontSize:11,color:'var(--muted)',marginTop:2}}>
            Performance KW {kw}/{yr} · {proj?.name||''}
          </div>
        </div>
        {rank&&(
          <div style={{textAlign:'center',padding:'8px 12px',background:overallBadge.bg,
            borderRadius:'var(--r)',border:'1px solid '+overallBadge.color+'44'}}>
            <div style={{fontWeight:900,fontSize:22,color:overallBadge.color}}>#{rank}</div>
            <div style={{fontSize:9,color:overallBadge.color,textTransform:'uppercase',letterSpacing:'.06em'}}>von {rankTotal}</div>
          </div>
        )}
      </div>

      {/* KPI Badges */}
      <div style={{padding:'12px 14px',display:'flex',flexWrap:'wrap',gap:8}}>
        {kpiResults.map(({kpi,entry,t})=>(
          <div key={kpi.id} style={{padding:'8px 12px',borderRadius:'var(--r)',
            background:t.bg,border:'1px solid '+t.color+'33',
            display:'flex',flexDirection:'column',alignItems:'center',minWidth:80}}>
            <div style={{fontSize:20,marginBottom:2}}>{t.icon}</div>
            <div style={{fontWeight:900,fontSize:16,color:t.color,fontFamily:'var(--mono)'}}>
              {entry.value}{kpi.unit}
            </div>
            <div style={{fontSize:10,color:t.color,fontWeight:700,textAlign:'center'}}>{kpi.name}</div>
            <div style={{fontSize:9,color:t.color,opacity:.8,textAlign:'center',marginTop:1}}>{t.label}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

WorkforcePlanningView:
// ═══════════════════════════════════════════════════════════════════
// WORKFORCE PLANNING VIEW
// Struktur: Projekt → Skill → Monat → 4 KWs → pro Tag: Schicht + Stunden
// Vernetzt mit: Mitarbeiter (Abwesenheiten, Skill, Projekt), Forecast
// ═══════════════════════════════════════════════════════════════════

function WorkforcePlanningView({employees, projects, showToast}){
  const today = new Date();
  const [selYear,  setSelYear]  = useState(today.getFullYear());
  const [selMonth, setSelMonth] = useState(today.getMonth()+1); // 1-12
  const [selProjId, setSelProjId] = useState('');
  const [selSkill,  setSelSkill]  = useState(''); // '' = alle Skills zusammen
  const [plans, setPlans] = useState(()=>{
    try{return JSON.parse(localStorage.getItem('jsr_workforce_plans')||'{}');}catch(e){return{};}
  });
  const [editCell, setEditCell] = useState(null); // {empId, date, field}
  const [shiftModal, setShiftModal] = useState(null); // {empId, date}
  const [forecastModal, setForecastModal] = useState(null); // {kw, year}

  // ── PERSIST ───────────────────────────────────────────────────────
  useEffect(()=>{localStorage.setItem('jsr_workforce_plans',JSON.stringify(plans));},[plans]);

  // ── HELPERS ───────────────────────────────────────────────────────
  const DAYS = ['MO','DI','MI','DO','FR','SA','SO'];
  const getShiftConfig=()=>{try{return JSON.parse(localStorage.getItem('jsr_shift_cfg')||'{}');}catch(e){return{};}};
  const getProjShifts=(projId,skill)=>{const cfg=getShiftConfig();const key=projId&&skill?projId+'_'+skill:projId?projId+'_all':'';const found=cfg[key]||cfg[projId+'_all']||[];return [...found,{id:'frei',label:'Frei',value:'',hours:0,net:0}];};
  const SHIFTS=getProjShifts(selProjId,selSkill);

  function getShiftMeta(shiftVal){
    if(!shiftVal || shiftVal===0 || shiftVal==='0') return {hours:0,net:0};
    if(shiftVal==='Urlaub'||shiftVal==='Krank') return {hours:0,net:0,special:shiftVal};
    const s=SHIFTS.find(x=>x.value===shiftVal);
    if(s) return {hours:s.hours,net:s.net};
    // Parse custom HH:MM-HH:MM
    const m=shiftVal.match(/(\d{2}):(\d{2})-(\d{2}):(\d{2})/);
    if(m){
      const start=parseInt(m[1])*60+parseInt(m[2]);
      const end=parseInt(m[3])*60+parseInt(m[4]);
      const total=(end-start)/60;
      return {hours:total, net:total-0.5};
    }
    return {hours:0,net:0};
  }

  // Get ISO week number
  function getKW(date){
    const d=new Date(Date.UTC(date.getFullYear(),date.getMonth(),date.getDate()));
    const dayNum=d.getUTCDay()||7;
    d.setUTCDate(d.getUTCDate()+4-dayNum);
    const yearStart=new Date(Date.UTC(d.getUTCFullYear(),0,1));
    return Math.ceil((((d-yearStart)/86400000)+1)/7);
  }

  // Get all Mondays of a month → gives us weeks
  function getWeeksOfMonth(year,month){
    const weeks=[];
    const d=new Date(year,month-1,1);
    // Find first Monday on or before month start
    const dow=d.getDay(); // 0=Sun
    const offset=dow===0?-6:1-dow;
    d.setDate(d.getDate()+offset);
    while(d.getMonth()<month-1||(d.getFullYear()===year&&d.getMonth()===month-1)||
      (d.getMonth()===month-1)){
      if(d.getFullYear()>year||(d.getFullYear()===year&&d.getMonth()>month-1)) break;
      const weekDays=[];
      for(let i=0;i<7;i++){
        weekDays.push(new Date(d.getFullYear(),d.getMonth(),d.getDate()+i));
      }
      weeks.push({kw:getKW(d), days:weekDays});
      d.setDate(d.getDate()+7);
      if(weeks.length>=6) break;
    }
    return weeks;
  }

  // Plan key: projId_skill_year_month
  function planKey(){
    return `${selProjId}_${selSkill||'all'}_${selYear}_${String(selMonth).padStart(2,'0')}`;
  }

  function getPlan(){return plans[planKey()]||{};}

  function setDayEntry(empId, dateStr, shift){
    const key=planKey();
    const meta=getShiftMeta(shift);
    setPlans(p=>({...p,[key]:{...p[key],[`${empId}_${dateStr}`]:{shift,hours:meta.hours,net:meta.net}}}));
  }

  function getForecast(kw){
    const key=planKey();
    return plans[`forecast_${key}`]?.[String(kw)]||{MO:0,DI:0,MI:0,DO:0,FR:0,SA:0,SO:0};
  }

  function setForecast(kw,dayKey,val){
    const key=planKey();
    const fkey=`forecast_${key}`;
    const kwStr=String(kw);setPlans(p=>({...p,[fkey]:{...p[fkey],[kwStr]:{...(p[fkey]?.[kwStr]||{}),[dayKey]:parseFloat(val)||0}}}));
  }

  // ── FILTER EMPLOYEES ──────────────────────────────────────────────
  const projEmployees = (employees||[]).filter(e=>{
    if(e.status!=='active') return false;
    if(!selProjId) return false;
    if(e.project_id!==selProjId) return false;
    if(selSkill && e.project_skill!==selSkill) return false;
    return true;
  });

  // Check if employee is absent on a date
  function getAbsenceOnDate(emp, dateStr){
    const absences=emp.absences||[];
    return absences.find(a=>{
      if(!a.from||!a.to) return false;
      return dateStr>=a.from && dateStr<=a.to;
    });
  }

  // Get entry for employee on date
  function getEntry(empId, dateStr){
    return getPlan()[`${empId}_${dateStr}`]||null;
  }

  // ── SELECTED PROJECT / SKILLS ──────────────────────────────────────
  const selProj = (projects||[]).find(p=>p.id===selProjId);
  const projSkills = selProj?.skills||[];

  // ── COMPUTE WEEK TOTALS ────────────────────────────────────────────
  function getWeekTotals(weekDays){
    const totals={};
    DAYS.forEach((d,i)=>{
      const dateStr=weekDays[i]?.toISOString().slice(0,10);
      if(!dateStr) return;
      let sumHours=0, sumNet=0;
      projEmployees.forEach(emp=>{
        const entry=getEntry(emp.id,dateStr);
        const absence=getAbsenceOnDate(emp,dateStr);
        if(absence) return; // absent = 0
        if(entry){sumHours+=entry.hours||0;sumNet+=entry.net||0;}
      });
      totals[d]={hours:sumHours, net:sumNet};
    });
    return totals;
  }

  const weeks=getWeeksOfMonth(selYear,selMonth);
  const MONTHS=['Januar','Februar','März','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];

  // ── EMPLOYEE MONTH SUMMARY ────────────────────────────────────────
  function getEmpMonthSummary(emp){
    let totalHours=0, totalNet=0, plannedDays=0;
    weeks.forEach(({days})=>{
      days.forEach(day=>{
        const dateStr=day.toISOString().slice(0,10);
        const entry=getEntry(emp.id,dateStr);
        const absence=getAbsenceOnDate(emp,dateStr);
        if(entry&&!absence){
          totalHours+=entry.hours||0;
          totalNet+=entry.net||0;
          if(entry.hours>0) plannedDays++;
        }
      });
    });
    return {totalHours,totalNet,plannedDays};
  }

  const [importPreview, setImportPreview] = useState(null);
  const [importModalOpen, setImportModalOpen] = useState(false);
  const [aiImportPrompt, setAiImportPrompt] = useState('');
  const [pendingFile, setPendingFile] = useState(null);
  const [pendingFileRows, setPendingFileRows] = useState(null);
  const [aiImportLoading, setAiImportLoading] = useState(false);

  // ── PREDEFINED IMPORTERS ──────────────────────────────────────────
  // Each importer knows how to read a specific Excel format from a client
  const BUILTIN_IMPORTERS = [
    {
      id:'holidaycheck_sales',
      label:'Holidaycheck — Sales',
      description:'Sheet "Tagesplanung": KW(A), Datum(D), FC Sales(F), FC Backoffice(G). Intervalle: Sheet "Intervallplanung".',
      skill:'sales',
      fn: (wb) => parseHolidaycheckFormat(wb,'sales'),
    },
    {
      id:'holidaycheck_support',
      label:'Holidaycheck — Support',
      description:'Sheet "Tagesplanung": KW(A), Datum(D), FC Sales(F) als Support-Stunden. Intervalle: Sheet "Intervallplanung".',
      skill:'support',
      fn: (wb) => parseHolidaycheckFormat(wb,'support'),
    },
  ];

  // Load custom AI-generated importers from localStorage
  const customImporters = (() => {
    try { return JSON.parse(localStorage.getItem('jsr_custom_importers')||'[]'); }
    catch(e) { return []; }
  })();

  const allImporters = [
    ...BUILTIN_IMPORTERS,
    ...customImporters.map(ci=>({
      ...ci,
      isCustom: true,
      fn: (wb) => parseWithAiMapping(wb, ci.mapping),
    })),
  ];

  // ── HOLIDAYCHECK FORMAT PARSER ────────────────────────────────────
  function parseHolidaycheckFormat(wb, skill) {
    const DAYMAP = {'Montag':'MO','Dienstag':'DI','Mittwoch':'MI','Donnerstag':'DO','Freitag':'FR','Samstag':'SA','Sonntag':'SO'};
    const wsName = wb.SheetNames.find(n=>n.toLowerCase().includes('tagesplan')) || wb.SheetNames[0];
    const rows = XLSX.utils.sheet_to_json(wb.Sheets[wsName], {header:1, defval:null});

    // Parse intervals
    const intervals = {};
    const wsIntName = wb.SheetNames.find(n=>n.toLowerCase().includes('intervall'));
    if(wsIntName) {
      const intRows = XLSX.utils.sheet_to_json(wb.Sheets[wsIntName], {header:1, defval:null});
      intRows.slice(1).forEach(row=>{
        if(!row[0]||!row[1]) return;
        const d = row[0] instanceof Date ? row[0].toISOString().slice(0,10) : String(row[0]).slice(0,10);
        if(!intervals[d]) intervals[d]=[];
        const tv = row[1];
        let ts = '';
        if(tv instanceof Date) ts = tv.toTimeString().slice(0,5);
        else if(typeof tv==='number') ts = new Date(Math.round(tv*86400000)).toISOString().slice(11,16);
        else ts = String(tv).slice(0,5);
        intervals[d].push({time:ts, calls:parseFloat(row[2])||0, hours:parseFloat(row[3])||0});
      });
    }

    let aht=0, avail=0;
    const days = [];
    let totalHours = 0;
    rows.forEach(row=>{
      if(row[8]&&String(row[8]).includes('AHT')) aht = parseFloat(row[9])||aht;
      if(row[8]&&String(row[8]).includes('Avail')) avail = parseFloat(row[9])||avail;
      if(!row[0]||typeof row[0]!=='number'||!row[3]) return;
      const kw = parseInt(row[0]);
      if(isNaN(kw)||kw<1||kw>54) return;
      const dateVal = row[3];
      if(!(dateVal instanceof Date)) return;
      const dateStr = dateVal.toISOString().slice(0,10);
      const weekdayTxt = String(row[1]||'');
      const fcSales = parseFloat(row[5])||parseFloat(row[4])||0;
      const fcBackoffice = parseFloat(row[6])||0;
      if(fcSales<=0&&fcBackoffice<=0) return;
      const dayIntervals = intervals[dateStr]||[];
      const maxH = dayIntervals.length>0 ? Math.max(...dayIntervals.map(i=>i.hours)) : 0;
      const fcForSkill = skill==='support' ? fcSales : fcSales;
      days.push({date:dateStr, kw, weekday:weekdayTxt, dayKey:DAYMAP[weekdayTxt]||'MO',
        fcSales:fcForSkill, fcBackoffice, intervals:dayIntervals, maxIntervalHours:maxH});
      totalHours += fcForSkill;
    });
    return {days, aht, avail, totalHours};
  }

  // ── AI MAPPING PARSER (from saved KI-generated mapping) ──────────
  function parseWithAiMapping(wb, mapping) {
    const wsName = wb.SheetNames.find(n=>n.toLowerCase().includes(mapping.sheetFilter||'')) || wb.SheetNames[mapping.sheetIndex||0];
    const rows = XLSX.utils.sheet_to_json(wb.Sheets[wsName], {header:1, defval:null});
    const DAYMAP = {'Montag':'MO','Dienstag':'DI','Mittwoch':'MI','Donnerstag':'DO','Freitag':'FR','Samstag':'SA','Sonntag':'SO',
      'Monday':'MO','Tuesday':'DI','Wednesday':'MI','Thursday':'DO','Friday':'FR','Saturday':'SA','Sunday':'SO'};
    const days = [];
    let totalHours = 0;
    const startRow = mapping.headerRow||1;
    rows.slice(startRow).forEach(row=>{
      const kw = parseInt(row[mapping.colKw||0]);
      if(isNaN(kw)||kw<1||kw>54) return;
      const dateVal = row[mapping.colDate||3];
      if(!dateVal) return;
      const dateStr = dateVal instanceof Date ? dateVal.toISOString().slice(0,10) : String(dateVal).slice(0,10);
      const weekdayTxt = String(row[mapping.colWeekday||1]||'');
      const fcHours = parseFloat(row[mapping.colFcHours||5])||0;
      if(fcHours<=0) return;
      days.push({date:dateStr, kw, weekday:weekdayTxt, dayKey:DAYMAP[weekdayTxt]||'MO',
        fcSales:fcHours, fcBackoffice:0, intervals:[], maxIntervalHours:0});
      totalHours += fcHours;
    });
    return {days, aht:0, avail:0, totalHours};
  }

  // ── RUN BUILTIN IMPORTER ──────────────────────────────────────────
  function runBuiltinImporter(file, parserFn, skill) {
    const reader = new FileReader();
    reader.onload = ev => {
      try {
        const wb = XLSX.read(new Uint8Array(ev.target.result), {type:'array', cellDates:true});
        const result = parserFn(wb);
        if(!result.days||result.days.length===0) {
          alert('Keine Daten gefunden. Bitte prüfe ob das richtige File für diesen Importer gewählt wurde.');
          return;
        }
        setImportPreview({filename:file.name, skill:skill||selSkill||'all', ...result});
        setImportModalOpen(false);
      } catch(err) {
        alert('Fehler beim Lesen: '+err.message);
      }
    };
    reader.readAsArrayBuffer(file);
  }

  // ── AI IMPORTER ───────────────────────────────────────────────────
  async function runAiImporter(file, prompt) {
    setAiImportLoading(true);
    try {
      // Read file content for AI
      const reader = new FileReader();
      reader.onload = async ev => {
        try {
          const wb = XLSX.read(new Uint8Array(ev.target.result), {type:'array', cellDates:true});
          // Build preview of first rows for AI
          const sheetPreviews = wb.SheetNames.slice(0,3).map(name=>{
            const rows = XLSX.utils.sheet_to_json(wb.Sheets[name], {header:1, defval:null}).slice(0,5);
            return {name, rows};
          });
          const previewText = sheetPreviews.map(s=>'Sheet "'+s.name+'":\n'+s.rows.map(r=>r.map(v=>v===null?'':String(v||'').slice(0,20)).join(' | ')).join('\n')).join('\n\n');;

          const aiKey = localStorage.getItem('jsr_anthropic_key')||'';
          if(!aiKey) {
            alert('Kein API-Key hinterlegt. Bitte unter Admin → System → API-Key eingeben.');
            setAiImportLoading(false);
            return;
          }

          const sysPrompt = 'Du bist ein Daten-Mapping-Experte. Analysiere die Excel-Vorschau und erstelle ein JSON-Mapping-Objekt.'+
            ' Antworte NUR mit einem validen JSON-Objekt, kein Markdown, keine Erklärung.'+
            ' Format: {"sheetFilter":"tagesplan","sheetIndex":0,"headerRow":1,"colKw":0,"colDate":3,"colWeekday":1,"colFcHours":5,"description":"kurze Beschreibung"}'+
            ' Alle col-Werte sind 0-basierte Spalten-Indizes.';

          const resp = await fetch('https://api.anthropic.com/v1/messages', {
            method:'POST',
