                            border:'1.5px solid var(--border)',background:'var(--surface-2)',
                            fontFamily:'var(--font)',transition:'all .15s',
                          }}
                          onMouseOver={e=>{e.currentTarget.style.borderColor='var(--blue)';e.currentTarget.style.background='var(--blue-bg)';}}
                          onMouseOut={e=>{e.currentTarget.style.borderColor='var(--border)';e.currentTarget.style.background='var(--surface-2)';}}>
                          <div style={{fontWeight:700,fontSize:13,marginBottom:3,color:'var(--fg)'}}>{imp.label}</div>
                          <div style={{fontSize:11,color:'var(--muted)',lineHeight:1.4}}>{imp.description}</div>
                          {imp.isCustom&&(
                            <div style={{marginTop:4,fontSize:10,color:'var(--blue)'}}>✨ KI-generiert</div>
                          )}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Section 2: AI Importer */}
                  <div>
                    <div style={{fontSize:12,fontWeight:800,color:'var(--muted)',textTransform:'uppercase',
                      letterSpacing:'.06em',marginBottom:10,paddingBottom:6,borderBottom:'1px solid var(--border)'}}>
                      🤖 KI-Importer — Neues Format beschreiben
                    </div>
                    {pendingFileRows&&(
                      <div style={{marginBottom:10,padding:'8px 10px',background:'var(--surface-3)',
                        borderRadius:'var(--r)',fontSize:11,color:'var(--muted)'}}>
                        <b>Erkannte Sheets:</b> {pendingFileRows.map(s=>s.name).join(', ')}<br/>
                        <b>Erste Spalten ({pendingFileRows[0]?.name}):</b>{' '}
                        {(pendingFileRows[0]?.rows[0]||[]).filter(Boolean).slice(0,6).join(' | ')}
                      </div>
                    )}
                    <textarea
                      value={aiImportPrompt}
                      onChange={e=>setAiImportPrompt(e.target.value)}
                      rows={3}
                      style={{width:'100%',padding:'10px',borderRadius:'var(--r)',fontSize:13,
                        border:'1.5px solid var(--border)',fontFamily:'var(--font)',resize:'vertical',
                        background:'var(--surface)',color:'var(--fg)',marginBottom:8,boxSizing:'border-box'}}
                      placeholder='Beschreibe was importiert werden soll, z.B.: "Hole den täglichen Stundenbedarf Sales aus Spalte F, Datum aus Spalte D, KW aus A. Intervalle sind im Sheet Intervallplanung."'
                    />
                    <button
                      className="btn btn-primary"
                      disabled={!aiImportPrompt.trim()||aiImportLoading}
                      onClick={()=>runAiImporter(pendingFile, aiImportPrompt)}
                      style={{width:'100%',padding:'10px',fontSize:13,fontWeight:700}}>
                      {aiImportLoading?(
                        <><span style={{display:'inline-block',animation:'spin 1s linear infinite',marginRight:6}}>⏳</span>KI analysiert...</>
                      ):'🤖 KI-Importer starten'}
                    </button>
                  </div>
                </>
              )}

              {!pendingFile&&(
                <div style={{textAlign:'center',color:'var(--dim)',fontSize:12,padding:'8px 0'}}>
                  Bitte zuerst eine Excel-Datei auswählen.
                </div>
              )}
            </div>
          </div>
        </div>
      )}

            {/* ── FORECAST MODAL ── */}
      {forecastModal&&(()=>{
        const kw=forecastModal.kw;
        const existing=getForecast(kw);
        return(
          <div className="modal-overlay">
            <div className="modal" style={{width:520}}>
              <div className="modal-header">
                <span className="modal-title">📊 Forecast KW {kw} — manuell</span>
                <button className="btn" onClick={()=>setForecastModal(null)}>×</button>
              </div>
              <div className="modal-body">
                <div style={{fontSize:12,color:'var(--muted)',marginBottom:14}}>
                  Benötigte Netto-Stunden pro Tag (aus Auftraggeber-Forecast oder eigener Einschätzung).
                </div>
                <div style={{display:'grid',gridTemplateColumns:'repeat(7,1fr)',gap:10}}>
                  {['MO','DI','MI','DO','FR','SA','SO'].map(d=>(
                    <div key={d} style={{textAlign:'center'}}>
                      <label style={{display:'block',fontSize:11,fontWeight:700,
                        color:'var(--muted)',marginBottom:4}}>{d}</label>
                      <input type="number" min="0" max="999" step="0.5"
                        id={'fc_'+kw+'_'+d}
                        defaultValue={existing[d]||''}
                        placeholder="0"
                        style={{width:'100%',padding:'8px 4px',textAlign:'center',
                          fontSize:16,fontWeight:800,
                          border:'2px solid var(--border)',borderRadius:'var(--r)',
                          fontFamily:'var(--font)',background:'var(--surface)',color:'var(--fg)'}}
                      />
                    </div>
                  ))}
                </div>
                <div style={{marginTop:14,padding:'10px 12px',background:'var(--surface-2)',
                  borderRadius:'var(--r)',fontSize:11,color:'var(--muted)'}}>
                  Upload-Funktion (CSV vom Auftraggeber) folgt in einem spaeteren Release.
                </div>
              </div>
              <div className="modal-footer">
                <button className="btn" onClick={()=>setForecastModal(null)}>Abbrechen</button>
                <button className="btn btn-primary" onClick={()=>{
                  ['MO','DI','MI','DO','FR','SA','SO'].forEach(d=>{
                    const el=document.getElementById('fc_'+kw+'_'+d);
                    if(el) setForecast(kw,d,el.value);
                  });
                  setForecastModal(null);
                }}>Speichern</button>
              </div>
            </div>
          </div>
        );
      })()}

      {/* ── SHIFT PICKER MODAL ── */}
      {shiftModal&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:360}}>
            <div className="modal-header">
              <span className="modal-title">
                Schicht zuweisen — {shiftModal.dateStr}
              </span>
              <button className="btn" onClick={()=>setShiftModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{marginBottom:12,fontSize:12,color:'var(--muted)'}}>
                {(employees||[]).find(e=>e.id===shiftModal.empId)?.first_name}{' '}
                {(employees||[]).find(e=>e.id===shiftModal.empId)?.last_name}
              </div>
              <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:8,marginBottom:12}}>
                {SHIFTS.map(s=>(
                  <button key={s.value} className="btn"
                    style={{
                      padding:'10px 8px',textAlign:'left',fontSize:12,
                      background:shiftModal.currentShift===s.value?'var(--blue-bg)':'var(--surface-2)',
                      color:shiftModal.currentShift===s.value?'var(--blue)':'var(--fg)',
                      border:shiftModal.currentShift===s.value?'2px solid var(--blue)':'1px solid var(--border)',
                      borderRadius:'var(--r)',
                    }}
                    onClick={()=>{
                      setDayEntry(shiftModal.empId,shiftModal.dateStr,s.value);
                      setShiftModal(null);
                    }}>
                    <div style={{fontWeight:700}}>{s.label}</div>
                    <div style={{fontSize:10,color:'var(--muted)',marginTop:2}}>
                      {s.value||'Kein Einsatz'} {s.hours>0?`· ${s.hours}h (${s.net}h netto)`:''}
                    </div>
                  </button>
                ))}
              </div>
              <div style={{borderTop:'1px solid var(--border)',paddingTop:10}}>
                <div style={{fontSize:11,fontWeight:700,marginBottom:6,color:'var(--muted)'}}>Eigene Zeit eingeben:</div>
                <div style={{display:'flex',gap:6}}>
                  <input className="form-input" placeholder="z.B. 09:00-18:00"
                    defaultValue={shiftModal.currentShift}
                    id="custom-shift-input"/>
                  <button className="btn btn-primary" onClick={()=>{
                    const val=document.getElementById('custom-shift-input').value.trim();
                    if(val){setDayEntry(shiftModal.empId,shiftModal.dateStr,val);}
                    setShiftModal(null);
                  }}>OK</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── FORECAST MODAL ── */}
      {forecastModal&&(
        <div className="modal-overlay">
          <div className="modal" style={{width:480}}>
            <div className="modal-header">
              <span className="modal-title">📊 Forecast KW {forecastModal.kw}</span>
              <button className="btn" onClick={()=>setForecastModal(null)}>×</button>
            </div>
            <div className="modal-body">
              <div style={{fontSize:12,color:'var(--muted)',marginBottom:12}}>
                Benötigte Netto-Stunden pro Tag (aus Auftraggeber-Forecast)
              </div>
              <div style={{display:'grid',gridTemplateColumns:'repeat(7,1fr)',gap:8}}>
                {DAYS.map(d=>(
                  <div key={d}>
                    <label className="form-label" style={{fontSize:11,textAlign:'center',display:'block'}}>{d}</label>
                    <input type="number" className="form-input" style={{textAlign:'center',fontSize:13,fontWeight:700}}
                      min="0" step="0.5"
                      key={d+forecastModal.kw} defaultValue={getForecast(forecastModal.kw)[d]||''}
                      onChange={e=>setForecast(forecastModal.kw,d,e.target.value)}
                      placeholder="0"/>
                  </div>
                ))}
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-primary" onClick={()=>setForecastModal(null)}>Speichern</button>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}
